        private void AutoFishLog(string message)
        {
            if (!MasterLogAutoFish || string.IsNullOrEmpty(message))
            {
                return;
            }

            ModLogger.Msg("[AutoFishing] " + message);
        }

        private void StrangerChatLog(string message)
        {
            if (!MasterLogStrangerChat || string.IsNullOrEmpty(message))
            {
                return;
            }

            ModLogger.Msg("[StrangerChat] " + message);
        }
        
