        private void DrawRoundedPanel(Rect rect, float radius, Color fill, Color border, float borderWidth, Color topAccent)
        {
            this.EnsureUiPrimitiveTextures();

            float corner = Mathf.Clamp(radius, 0f, Mathf.Min(rect.width, rect.height) * 0.5f);
            if (corner <= 0.5f)
            {
                GUI.color = fill;
                GUI.DrawTexture(rect, Texture2D.whiteTexture);
                GUI.color = Color.white;
            }
            else
            {
                float diameter = corner * 2f;
                Rect center = new Rect(rect.x + corner, rect.y + corner, rect.width - diameter, rect.height - diameter);
                Rect top = new Rect(rect.x + corner, rect.y, rect.width - diameter, corner);
                Rect bottom = new Rect(rect.x + corner, rect.yMax - corner, rect.width - diameter, corner);
                Rect left = new Rect(rect.x, rect.y + corner, corner, rect.height - diameter);
                Rect right = new Rect(rect.xMax - corner, rect.y + corner, corner, rect.height - diameter);
                Rect topLeft = new Rect(rect.x, rect.y, corner, corner);
                Rect topRight = new Rect(rect.xMax - corner, rect.y, corner, corner);
                Rect bottomLeft = new Rect(rect.x, rect.yMax - corner, corner, corner);
                Rect bottomRight = new Rect(rect.xMax - corner, rect.yMax - corner, corner, corner);

                GUI.color = fill;
                GUI.DrawTexture(center, Texture2D.whiteTexture);
                GUI.DrawTexture(top, Texture2D.whiteTexture);
                GUI.DrawTexture(bottom, Texture2D.whiteTexture);
                GUI.DrawTexture(left, Texture2D.whiteTexture);
                GUI.DrawTexture(right, Texture2D.whiteTexture);
                GUI.BeginGroup(topLeft);
                GUI.DrawTexture(new Rect(0f, 0f, diameter, diameter), this.uiCircleTexture);
                GUI.EndGroup();
                GUI.BeginGroup(topRight);
                GUI.DrawTexture(new Rect(-corner, 0f, diameter, diameter), this.uiCircleTexture);
                GUI.EndGroup();
                GUI.BeginGroup(bottomLeft);
                GUI.DrawTexture(new Rect(0f, -corner, diameter, diameter), this.uiCircleTexture);
                GUI.EndGroup();
                GUI.BeginGroup(bottomRight);
                GUI.DrawTexture(new Rect(-corner, -corner, diameter, diameter), this.uiCircleTexture);
                GUI.EndGroup();
                GUI.color = Color.white;
            }

            if (borderWidth > 0f)
            {
                GUI.color = border.a > 0f ? border : new Color(1f, 1f, 1f, 0.12f);
                GUI.DrawTexture(new Rect(rect.x, rect.y, rect.width, borderWidth), Texture2D.whiteTexture);
                GUI.DrawTexture(new Rect(rect.x, rect.yMax - borderWidth, rect.width, borderWidth), Texture2D.whiteTexture);
                GUI.DrawTexture(new Rect(rect.x, rect.y, borderWidth, rect.height), Texture2D.whiteTexture);
                GUI.DrawTexture(new Rect(rect.xMax - borderWidth, rect.y, borderWidth, rect.height), Texture2D.whiteTexture);
                GUI.color = Color.white;

                if (topAccent.a > 0f)
                {
                    GUI.color = topAccent;
                    GUI.DrawTexture(new Rect(rect.x + 1f, rect.y + 1f, rect.width - 2f, 1.5f), Texture2D.whiteTexture);
                    GUI.color = Color.white;
                }
            }
        }

        private float GetSelectedTabEstimatedHeight()
        {
            // Dynamic height calculation - future-proof for UI changes
            return this.GetSelectedTabCalculatedHeight();
        }

        private float GetSelectedTabCalculatedHeight()
        {
            if (this.selectedTab == 0)
            {
                return this.CalculateSelfTabHeight();
            }
            if (this.selectedTab == 2)
            {
                return this.CalculateAutoFarmTabHeight();
            }
            if (this.selectedTab == 3)
            {
                return this.CalculateFeaturesTabHeight();
            }
            if (this.selectedTab == 8)
            {
                return this.CalculateNewFeaturesTabHeight();
            }
            if (this.selectedTab == 4)
            {
                return this.CalculateRadarTabHeight();
            }
            if (this.selectedTab == 5)
            {
                return this.CalculateTeleportTabHeight();
            }
            if (this.selectedTab == 6)
            {
                return this.CalculateBulkSelectorTabHeight();
            }
            if (this.selectedTab == 7)
            {
                return this.CalculateSettingsTabHeight();
            }
            return 740f; // Default fallback
        }

        private float CalculateSelfTabHeight()
        {
            int num = 0 + 25; // startY is 0 for calculation

            if (this.selfSubTab == 0)
            {
                // Camera Toggle
                num += 30;

                if (this.mouseLookEnabled)
                {
                    // Crosshair toggle
                    num += 30;
                }

                // Noclip Toggle
                num += 30;

                // Noclip Speed label and slider
                num += 22 + 30;

                // Noclip Boost label and slider
                num += 22 + 30;

                // Anti AFK toggle
                num += 26;

                // AFK interval label and slider
                num += 22 + 30;

                // Help text
                return (float)num + 160f;
            }

            // Building sub-tab: Bypass overlap toggle
            if (this.selfSubTab == 1)
            {
                num += 26; // Header
                num += 36; // Toggle
                // Credits text
                return (float)num + 50f;
            }

            return (float)num + 50f;
        }

        private float CalculateAutoFarmTabHeight()
        {
            if (this.autoFarmSubTab == 1)
            {
                return this.CalculateTreeFarmTabHeight();
            }
            if (this.autoFarmSubTab == 2)
            {
                return this.CalculateNewSubTabHeight();
            }
            if (this.autoFarmSubTab == 3)
            {
                return 980f; // Insect farm tab height estimate
            }
            if (this.autoFarmSubTab == 4)
            {
                return 980f; // Bird farm tab height estimate
            }

            // Main tab content - estimate based on typical layout
            return 780f; // Conservative estimate for main foraging tab
        }

        private float CalculateTreeFarmTabHeight()
        {
            // Chop & Mine now includes a larger Aura section; keep scroll content tall enough
            // so status rows (targets/tree hits/bush picks/last) are always reachable.
            return 1500f;
        }

        private float CalculateNewSubTabHeight()
        {
            // Fish farming tab - estimate based on settings and toggles
            return 780f; // Conservative estimate
        }

        private float CalculateFeaturesTabHeight()
        {
            if (this.automationSubTab == 1)
            {
                float height = 550f;
                if (this.autoEatFoodDropdownOpen)
                {
                    height += 240f;
                }
                if (this.customFoodPickMode && this.autoEatFoodType == this.autoEatFoodOptions.Length - 1)
                {
                    height += 310f;
                }
                return height;
            }

            if (this.automationSubTab == 4)
            {
                return 980f;
            }

            if (this.automationSubTab == 3)
            {
                return this.forceOpenShopDropdownOpen ? 1028f : 808f;
            }

            if (this.automationSubTab == 5)
            {
                return this.netCookRecipeDropdownOpen ? 760f : 540f;
            }

            if (this.automationSubTab == 6)
            {
                return 620f;
            }

            if (this.automationSubTab == 7)
            {
                return 820f;
            }

            return 900f;
        }

        private float CalculateRadarTabHeight()
        {
            // Radar settings tab
            return 1180f; // Conservative estimate
        }

        private float CalculateTeleportTabHeight()
        {
            // Teleport tab with various sub-tabs
            if (this.teleportSubTab == 0) return 620f;
            if (this.teleportSubTab == 1) return 80f + (this.animalCareLocations.Length * 45f);
            if (this.teleportSubTab == 2) return 110f + (Math.Max(1, this.cachedNpcTeleportEntries != null ? this.cachedNpcTeleportEntries.Count : 0) * 45f);
            if (this.teleportSubTab == 3) return 80f + (this.fastTravelLocations.Count * 45f);
            if (this.teleportSubTab == 4) return 80f + (this.eventLocations.Count * 45f);
            if (this.teleportSubTab == 5) return 80f + (this.houseLocations.Length * 45f);
            if (this.teleportSubTab == 6) return 180f + (this.customTeleportList.Count * 38f);
            if (this.teleportSubTab == 7) return 180f;
            return 420f; // XYZ fallback
        }

        private float CalculateBulkSelectorTabHeight()
        {
            // Items selector tab
            return 780f; // Conservative estimate
        }

        private float CalculateSettingsTabHeight()
        {
            // Settings tab with sub-tabs
            if (this.settingsSubTab == 1)
            {
                return string.IsNullOrEmpty(this.keyBindingActive) ? 1680f : 300f;
            }
            if (this.settingsSubTab == 2)
            {
                return this.uiThemePickerOpen ? 1180f : 860f;
            }
            return 940f; // Default settings height
        }

