        private bool TryGetManagedInteractPlayerObject(object interactSystemObj, out object playerObj, out string source)
        {
            playerObj = null;
            source = "none";
            if (interactSystemObj == null)
            {
                return false;
            }

            foreach (string memberName in new string[] { "player", "_interactor", "interactor" })
            {
                if (this.TryGetObjectMember(interactSystemObj, memberName, out playerObj) && playerObj != null)
                {
                    source = interactSystemObj.GetType().Name + "." + memberName;
                    return true;
                }
            }

            return false;
        }

        private bool TryGetManagedPlayerEntityObject(object playerObj, out object entityObj, out string source)
        {
            entityObj = null;
            source = "none";
            if (playerObj == null)
            {
                return false;
            }

            foreach (string memberName in new string[] { "entity", "Entity", "_entity" })
            {
                if (this.TryGetObjectMember(playerObj, memberName, out entityObj) && entityObj != null)
                {
                    source = playerObj.GetType().Name + "." + memberName;
                    return true;
                }
            }

            if (this.TryGetObjectMember(playerObj, "viewEntityArg", out object viewEntityArg) && viewEntityArg != null)
            {
                if (this.TryGetObjectMember(viewEntityArg, "entity", out entityObj) && entityObj != null)
                {
                    source = playerObj.GetType().Name + ".viewEntityArg.entity";
                    return true;
                }
            }

            try
            {
                MethodInfo getEntityMethod = playerObj.GetType().GetMethod("get_entity", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance)
                    ?? playerObj.GetType().GetMethod("GetEntity", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                if (getEntityMethod != null)
                {
                    entityObj = getEntityMethod.Invoke(playerObj, null);
                    if (entityObj != null)
                    {
                        source = playerObj.GetType().Name + "." + getEntityMethod.Name + "()";
                        return true;
                    }
                }
            }
            catch { }

            Type currentType = playerObj.GetType();
            while (currentType != null)
            {
                try
                {
                    PropertyInfo property = currentType.GetProperty("entity", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance)
                        ?? currentType.GetProperty("Entity", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                    if (property != null)
                    {
                        entityObj = property.GetValue(playerObj, null);
                        if (entityObj != null)
                        {
                            source = currentType.Name + "." + property.Name;
                            return true;
                        }
                    }
                }
                catch { }

                try
                {
                    FieldInfo field = currentType.GetField("entity", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance)
                        ?? currentType.GetField("_entity", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                    if (field != null)
                    {
                        entityObj = field.GetValue(playerObj);
                        if (entityObj != null)
                        {
                            source = currentType.Name + "." + field.Name;
                            return true;
                        }
                    }
                }
                catch { }

                try
                {
                    foreach (MethodInfo method in currentType.GetMethods(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance))
                    {
                        if (method == null || method.GetParameters().Length != 0)
                        {
                            continue;
                        }

                        string methodName = method.Name ?? string.Empty;
                        if (!methodName.Equals("get_entity", StringComparison.OrdinalIgnoreCase)
                            && !methodName.Equals("GetEntity", StringComparison.OrdinalIgnoreCase)
                            && !methodName.EndsWith(".get_entity", StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        entityObj = method.Invoke(playerObj, null);
                        if (entityObj != null)
                        {
                            source = currentType.Name + "." + methodName + "()";
                            return true;
                        }
                    }
                }
                catch { }

                currentType = currentType.BaseType;
            }

            try
            {
                foreach (Type iface in playerObj.GetType().GetInterfaces())
                {
                    if (iface == null)
                    {
                        continue;
                    }

                    PropertyInfo ifaceProperty = iface.GetProperty("entity") ?? iface.GetProperty("Entity");
                    if (ifaceProperty != null)
                    {
                        entityObj = ifaceProperty.GetValue(playerObj, null);
                        if (entityObj != null)
                        {
                            source = iface.Name + "." + ifaceProperty.Name;
                            return true;
                        }
                    }

                    MethodInfo ifaceMethod = iface.GetMethod("get_entity") ?? iface.GetMethod("GetEntity");
                    if (ifaceMethod != null)
                    {
                        entityObj = ifaceMethod.Invoke(playerObj, null);
                        if (entityObj != null)
                        {
                            source = iface.Name + "." + ifaceMethod.Name + "()";
                            return true;
                        }
                    }
                }
            }
            catch { }

            return false;
        }

        private bool TryGetManagedSweepNetManagerObject(object interactSystemObj, object playerObj, out object managerObj, out string source)
        {
            managerObj = null;
            source = "none";

            object handholdObj = null;
            string handholdSource = string.Empty;
            if (interactSystemObj != null)
            {
                foreach (string memberName in new string[] { "_handhold", "handhold" })
                {
                    if (this.TryGetObjectMember(interactSystemObj, memberName, out handholdObj) && handholdObj != null)
                    {
                        handholdSource = interactSystemObj.GetType().Name + "." + memberName;
                        break;
                    }
                }
            }

            if (handholdObj == null && playerObj != null)
            {
                object equipComponent;
                if (this.TryInvokeZeroArgMember(playerObj, out equipComponent, "get_equipComponent", "GetEquipComponent")
                    || this.TryGetObjectMember(playerObj, "equipComponent", out equipComponent)
                    || this.TryGetObjectMember(playerObj, "_equipComponent", out equipComponent))
                {
                    if (equipComponent != null)
                    {
                        if ((this.TryInvokeZeroArgMember(equipComponent, out handholdObj, "get_handhold", "GetHandhold")
                            || this.TryGetObjectMember(equipComponent, "handhold", out handholdObj)
                            || this.TryGetObjectMember(equipComponent, "_handhold", out handholdObj)) && handholdObj != null)
                        {
                            handholdSource = equipComponent.GetType().Name + ".handhold";
                        }
                    }
                }
            }

            if (handholdObj == null)
            {
                return false;
            }

            string className = handholdObj.GetType().FullName ?? handholdObj.GetType().Name ?? string.Empty;
            if (className.IndexOf("SweepNet", StringComparison.OrdinalIgnoreCase) < 0)
            {
                source = handholdSource + " [not sweep net: " + className + "]";
                return false;
            }

            if (!(this.TryGetObjectMember(handholdObj, "_insectManager", out managerObj) || this.TryGetObjectMember(handholdObj, "insectManager", out managerObj)) || managerObj == null)
            {
                source = handholdSource + "._insectManager";
                return false;
            }

            source = handholdSource + "._insectManager";
            return true;
        }

        private bool TryGetManagedBirdScannerObject(object interactSystemObj, object playerObj, out object scannerObj, out string source)
        {
            scannerObj = null;
            source = "none";

            object handholdObj = null;
            string handholdSource = string.Empty;
            if (interactSystemObj != null)
            {
                foreach (string memberName in new string[] { "_handhold", "handhold" })
                {
                    if (this.TryGetObjectMember(interactSystemObj, memberName, out handholdObj) && handholdObj != null)
                    {
                        handholdSource = interactSystemObj.GetType().Name + "." + memberName;
                        break;
                    }
                }
            }

            if (handholdObj == null && playerObj != null)
            {
                object equipComponent;
                if (this.TryInvokeZeroArgMember(playerObj, out equipComponent, "get_equipComponent", "GetEquipComponent")
                    || this.TryGetObjectMember(playerObj, "equipComponent", out equipComponent)
                    || this.TryGetObjectMember(playerObj, "_equipComponent", out equipComponent))
                {
                    if (equipComponent != null)
                    {
                        if ((this.TryInvokeZeroArgMember(equipComponent, out handholdObj, "get_handhold", "GetHandhold")
                            || this.TryGetObjectMember(equipComponent, "handhold", out handholdObj)
                            || this.TryGetObjectMember(equipComponent, "_handhold", out handholdObj)) && handholdObj != null)
                        {
                            handholdSource = equipComponent.GetType().Name + ".handhold";
                        }
                    }
                }
            }

            if (handholdObj == null)
            {
                return false;
            }

            string className = handholdObj.GetType().FullName ?? handholdObj.GetType().Name ?? string.Empty;
            bool looksLikeBirdScanner = className.IndexOf("BirdScanner", StringComparison.OrdinalIgnoreCase) >= 0
                || (className.IndexOf("bird", StringComparison.OrdinalIgnoreCase) >= 0 && className.IndexOf("scan", StringComparison.OrdinalIgnoreCase) >= 0)
                || className.IndexOf("Scanner", StringComparison.OrdinalIgnoreCase) >= 0;

            if (this.TryGetObjectMember(handholdObj, "_scanner", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "scanner", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "_birdScanner", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "birdScanner", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "_scannerStatusPanel", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "scannerStatusPanel", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "_scanComponent", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "scanComponent", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "_photoTargetManager", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "photoTargetManager", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "_birdManager", out scannerObj)
                || this.TryGetObjectMember(handholdObj, "birdManager", out scannerObj))
            {
                if (scannerObj != null)
                {
                    source = handholdSource + ".scanner";
                    return true;
                }
            }

            if (!looksLikeBirdScanner)
            {
                source = handholdSource + " [not bird scanner: " + className + "]";
                return false;
            }

            scannerObj = handholdObj;
            source = handholdSource;
            return true;
        }

        private IntPtr FindAuraMonoMethodOnHierarchy(IntPtr classPtr, string methodName, int paramCount)
        {
            if (classPtr == IntPtr.Zero || string.IsNullOrEmpty(methodName) || auraMonoClassGetMethodFromName == null)
            {
                return IntPtr.Zero;
            }

            AuraMonoMethodCacheKey cacheKey = new AuraMonoMethodCacheKey(classPtr, methodName, paramCount);
            if (this.auraMonoMethodLookupCache.TryGetValue(cacheKey, out IntPtr cachedMethod))
            {
                return cachedMethod;
            }

            IntPtr current = classPtr;
            while (current != IntPtr.Zero)
            {
                IntPtr method = auraMonoClassGetMethodFromName(current, methodName, paramCount);
                if (method != IntPtr.Zero)
                {
                    this.auraMonoMethodLookupCache[cacheKey] = method;
                    return method;
                }

                current = auraMonoClassGetParent != null ? auraMonoClassGetParent(current) : IntPtr.Zero;
            }

            this.auraMonoMethodLookupCache[cacheKey] = IntPtr.Zero;
            return IntPtr.Zero;
        }

        private IntPtr FindAuraMonoFieldOnHierarchy(IntPtr classPtr, string fieldName)
        {
            if (classPtr == IntPtr.Zero || string.IsNullOrEmpty(fieldName) || auraMonoClassGetFieldFromName == null)
            {
                return IntPtr.Zero;
            }

            AuraMonoFieldCacheKey cacheKey = new AuraMonoFieldCacheKey(classPtr, fieldName);
            if (this.auraMonoFieldLookupCache.TryGetValue(cacheKey, out IntPtr cachedField))
            {
                return cachedField;
            }

            IntPtr current = classPtr;
            while (current != IntPtr.Zero)
            {
                IntPtr field = auraMonoClassGetFieldFromName(current, fieldName);
                if (field != IntPtr.Zero)
                {
                    this.auraMonoFieldLookupCache[cacheKey] = field;
                    return field;
                }

                current = auraMonoClassGetParent != null ? auraMonoClassGetParent(current) : IntPtr.Zero;
            }

            this.auraMonoFieldLookupCache[cacheKey] = IntPtr.Zero;
            return IntPtr.Zero;
        }

