        private int TryMarkManagerFindEntitiesSelectedAuraMono(IntPtr managerObj, IntPtr bugDictObj)
        {
            if (managerObj == IntPtr.Zero || bugDictObj == IntPtr.Zero || auraMonoObjectGetClass == null || auraMonoRuntimeInvoke == null)
            {
                return 0;
            }

            try
            {
                if (!this.TryReadAuraMonoObjectField(managerObj, out IntPtr findEntitiesObj, "_findEntities", "findEntities") || findEntitiesObj == IntPtr.Zero)
                {
                    return 0;
                }

                IntPtr listClass = auraMonoObjectGetClass(findEntitiesObj);
                IntPtr getCountMethod = this.FindAuraMonoMethodOnHierarchy(listClass, "get_Count", 0);
                IntPtr getItemMethod = this.FindAuraMonoMethodOnHierarchy(listClass, "get_Item", 1);
                IntPtr dictClass = auraMonoObjectGetClass(bugDictObj);
                IntPtr setItemMethod = this.FindAuraMonoMethodOnHierarchy(dictClass, "set_Item", 2);
                if (getCountMethod == IntPtr.Zero || getItemMethod == IntPtr.Zero || setItemMethod == IntPtr.Zero)
                {
                    return 0;
                }

                int count = this.GetAuraMonoIntCount(findEntitiesObj, getCountMethod);
                int marked = 0;
                for (int i = 0; i < count && i < 64; i++)
                {
                    IntPtr itemObj;
                    unsafe
                    {
                        IntPtr exc = IntPtr.Zero;
                        IntPtr* args = stackalloc IntPtr[1];
                        args[0] = (IntPtr)(&i);
                        itemObj = auraMonoRuntimeInvoke(getItemMethod, findEntitiesObj, (IntPtr)args, ref exc);
                        if (exc != IntPtr.Zero || itemObj == IntPtr.Zero)
                        {
                            continue;
                        }
                    }

                    unsafe
                    {
                        bool selected = true;
                        IntPtr exc = IntPtr.Zero;
                        IntPtr* args = stackalloc IntPtr[2];
                        args[0] = itemObj;
                        args[1] = (IntPtr)(&selected);
                        auraMonoRuntimeInvoke(setItemMethod, bugDictObj, (IntPtr)args, ref exc);
                        if (exc == IntPtr.Zero)
                        {
                            marked++;
                        }
                    }
                }

                return marked;
            }
            catch (Exception ex)
            {
                this.InsectFarmNetLog("TryMarkManagerFindEntitiesSelectedAuraMono error: " + ex.Message);
                return 0;
            }
        }

        private bool TryExtractCatchTargetsFromManagerResultAuraMono(IntPtr listObj, Vector3 playerPos, float scanRange, int batchSize, List<uint> ids, List<Vector3> positions)
        {
            if (listObj == IntPtr.Zero || ids == null || positions == null || auraMonoObjectGetClass == null || auraMonoRuntimeInvoke == null)
            {
                return false;
            }

            ids.Clear();
            positions.Clear();
            float effectiveCatchRange = scanRange > 0f ? Mathf.Min(scanRange, 20f) : 20f;

            IntPtr listClass = auraMonoObjectGetClass(listObj);
            IntPtr getCountMethod = this.FindAuraMonoMethodOnHierarchy(listClass, "get_Count", 0);
            IntPtr getItemMethod = this.FindAuraMonoMethodOnHierarchy(listClass, "get_Item", 1);
            if (getCountMethod == IntPtr.Zero || getItemMethod == IntPtr.Zero)
            {
                return false;
            }

            int count = this.GetAuraMonoIntCount(listObj, getCountMethod);
            List<(uint id, Vector3 pos, float dist)> collected = new List<(uint, Vector3, float)>();
            for (int i = 0; i < count; i++)
            {
                IntPtr itemObj;
                unsafe
                {
                    IntPtr exc = IntPtr.Zero;
                    IntPtr* args = stackalloc IntPtr[1];
                    args[0] = (IntPtr)(&i);
                    itemObj = auraMonoRuntimeInvoke(getItemMethod, listObj, (IntPtr)args, ref exc);
                    if (exc != IntPtr.Zero || itemObj == IntPtr.Zero)
                    {
                        continue;
                    }
                }

                uint netId = this.TryReadAuraMonoUIntField(itemObj, "netId", "ownerNetId", "NetId", "insectNetId", "entityNetId", "Item1");
                if (netId == 0U)
                {
                    continue;
                }

                Vector3 pos = this.TryReadAuraMonoVector3Field(itemObj, "position", "pos", "Position", "Item2");
                float dist = Vector3.Distance(playerPos, pos);
                if (effectiveCatchRange > 0f && dist > effectiveCatchRange)
                {
                    continue;
                }

                collected.Add((netId, pos, dist));
            }

            if (collected.Count == 0)
            {
                return false;
            }

            collected.Sort((a, b) => a.dist.CompareTo(b.dist));
            HashSet<uint> seen = new HashSet<uint>();
            foreach ((uint id, Vector3 pos, float dist) item in collected)
            {
                if (ids.Count >= batchSize)
                {
                    break;
                }

                if (!seen.Add(item.id))
                {
                    continue;
                }

                ids.Add(item.id);
                positions.Add(item.pos);
                this.InsectFarmNetLog($"Aura mono target netId={item.id} distance={item.dist:F2} pos={item.pos}");
            }

            return ids.Count > 0;
        }

        private uint TryReadAuraMonoUIntField(IntPtr obj, params string[] fieldNames)
        {
            if (obj == IntPtr.Zero || fieldNames == null || fieldNames.Length == 0 || auraMonoFieldGetValueObject == null || auraMonoObjectGetClass == null)
            {
                return 0U;
            }

            IntPtr classPtr = auraMonoObjectGetClass(obj);
            if (classPtr == IntPtr.Zero)
            {
                return 0U;
            }

            foreach (string fieldName in fieldNames)
            {
                IntPtr field = this.FindAuraMonoFieldOnHierarchy(classPtr, fieldName);
                if (field == IntPtr.Zero)
                {
                    continue;
                }

                IntPtr boxed = auraMonoFieldGetValueObject(this.auraMonoRootDomain, field, obj);
                if (boxed == IntPtr.Zero)
                {
                    continue;
                }

                if (this.TryUnboxMonoUInt32(boxed, out uint value))
                {
                    return value;
                }

                ulong fallback = this.TryReadMonoUnsignedIntegral(boxed);
                if (fallback > 0UL && fallback <= uint.MaxValue)
                {
                    return (uint)fallback;
                }
            }

            return 0U;
        }

        private unsafe Vector3 TryReadAuraMonoVector3Field(IntPtr obj, params string[] fieldNames)
        {
            if (obj == IntPtr.Zero || fieldNames == null || fieldNames.Length == 0 || auraMonoFieldGetValueObject == null || auraMonoObjectUnbox == null || auraMonoObjectGetClass == null)
            {
                return Vector3.zero;
            }

            IntPtr classPtr = auraMonoObjectGetClass(obj);
            if (classPtr == IntPtr.Zero)
            {
                return Vector3.zero;
            }

            foreach (string fieldName in fieldNames)
            {
                IntPtr field = this.FindAuraMonoFieldOnHierarchy(classPtr, fieldName);
                if (field == IntPtr.Zero)
                {
                    continue;
                }

                IntPtr boxed = auraMonoFieldGetValueObject(this.auraMonoRootDomain, field, obj);
                if (boxed == IntPtr.Zero)
                {
                    continue;
                }

                IntPtr raw = auraMonoObjectUnbox(boxed);
                if (raw == IntPtr.Zero)
                {
                    continue;
                }

                return *(Vector3*)raw;
            }

            return Vector3.zero;
        }

        private bool TryInvokeZeroArgMember(object instance, out object value, params string[] methodNames)
        {
            value = null;
            if (instance == null || methodNames == null || methodNames.Length == 0)
            {
                return false;
            }

            Type currentType = instance.GetType();
            while (currentType != null)
            {
                foreach (string methodName in methodNames)
                {
                    try
                    {
                        MethodInfo method = currentType.GetMethod(methodName, BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, Type.EmptyTypes, null);
                        if (method == null)
                        {
                            continue;
                        }

                        value = method.Invoke(instance, null);
                        if (value != null)
                        {
                            return true;
                        }
                    }
                    catch { }
                }

                currentType = currentType.BaseType;
            }

            return false;
        }

        private int TryMarkManagerFindEntitiesSelectedManaged(object managerObj, object bugDictObj)
        {
            if (managerObj == null || bugDictObj == null)
            {
                return 0;
            }

            try
            {
                if (!(this.TryGetObjectMember(managerObj, "_findEntities", out object findEntities) || this.TryGetObjectMember(managerObj, "findEntities", out findEntities)) || findEntities == null)
                {
                    return 0;
                }

                Type listType = findEntities.GetType();
                MethodInfo getCountMethod = listType.GetMethod("get_Count", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                MethodInfo getItemMethod = listType.GetMethod("get_Item", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                MethodInfo setItemMethod = bugDictObj.GetType().GetMethod("set_Item", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                if (getCountMethod == null || getItemMethod == null || setItemMethod == null)
                {
                    return 0;
                }

                int count = Convert.ToInt32(getCountMethod.Invoke(findEntities, null));
                int marked = 0;
                for (int i = 0; i < count && i < 64; i++)
                {
                    object item = getItemMethod.Invoke(findEntities, new object[] { i });
                    if (item == null)
                    {
                        continue;
                    }

                    setItemMethod.Invoke(bugDictObj, new object[] { item, true });
                    marked++;
                }

                return marked;
            }
            catch (Exception ex)
            {
                this.InsectFarmNetLog("TryMarkManagerFindEntitiesSelectedManaged error: " + ex.Message);
                return 0;
            }
        }

        private bool TryExtractCatchTargetsFromManagerResultManaged(object listObj, Vector3 playerPos, float scanRange, int batchSize, List<uint> ids, List<Vector3> positions)
        {
            if (listObj == null)
            {
                return false;
            }

            try
            {
                float effectiveCatchRange = scanRange > 0f ? Mathf.Min(scanRange, 20f) : 20f;
                Type listType = listObj.GetType();
                MethodInfo getCountMethod = listType.GetMethod("get_Count", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                MethodInfo getItemMethod = listType.GetMethod("get_Item", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                if (getCountMethod == null || getItemMethod == null)
                {
                    return false;
                }

                int count = Convert.ToInt32(getCountMethod.Invoke(listObj, null));
                List<(uint id, Vector3 pos, float dist)> collected = new List<(uint, Vector3, float)>();
                for (int i = 0; i < count; i++)
                {
                    object item = getItemMethod.Invoke(listObj, new object[] { i });
                    if (item == null)
                    {
                        continue;
                    }

                    if (!this.TryResolveNetIdFromManagedObject(item, out uint netId, out string source) || netId == 0U)
                    {
                        continue;
                    }

                    Vector3 pos;
                    if (!this.TryResolvePositionFromManagedObject(item, out pos))
                    {
                        pos = Vector3.zero;
                    }

                    float dist = Vector3.Distance(playerPos, pos);
                    if (pos != Vector3.zero && dist <= effectiveCatchRange)
                    {
                        collected.Add((netId, pos, dist));
                        this.InsectFarmNetLog($"Managed target netId={netId} via {source} dist={dist:F2}");
                    }
                }

                collected.Sort((a, b) => a.dist.CompareTo(b.dist));
                HashSet<uint> seen = new HashSet<uint>();
                foreach (var item in collected)
                {
                    if (ids.Count >= batchSize)
                    {
                        break;
                    }

                    if (seen.Add(item.id))
                    {
                        ids.Add(item.id);
                        positions.Add(item.pos);
                    }
                }

                return ids.Count > 0;
            }
            catch (Exception ex)
            {
                this.InsectFarmNetLog("TryExtractCatchTargetsFromManagerResultManaged error: " + ex);
                return false;
            }
        }

        private bool TryResolveNetIdFromManagedObject(object obj, out uint netId, out string source, int depth = 0)
        {
            netId = 0U;
            source = "none";
            if (obj == null || depth > 3)
            {
                return false;
            }

            foreach (string memberName in new string[] { "netId", "NetId", "ownerNetId", "entityNetId", "insectNetId", "mNetId", "_netId", "Id", "id", "Item1" })
            {
                if (this.TryGetUIntMember(obj, memberName, out netId) && netId != 0U)
                {
                    source = obj.GetType().Name + "." + memberName;
                    return true;
                }
            }

            foreach (string memberName in new string[] { "entity", "Entity", "_entity", "target", "Target", "Item1" })
            {
                if (this.TryGetObjectMember(obj, memberName, out object nestedObj) && nestedObj != null)
                {
                    if (this.TryResolveNetIdFromManagedObject(nestedObj, out netId, out string nestedSource, depth + 1))
                    {
                        source = obj.GetType().Name + "." + memberName + "->" + nestedSource;
                        return true;
                    }
                }
            }

            return false;
        }

        private bool TryResolvePositionFromManagedObject(object obj, out Vector3 position, int depth = 0)
        {
            position = Vector3.zero;
            if (obj == null || depth > 3)
            {
                return false;
            }

            foreach (string memberName in new string[] { "position", "pos", "Position", "Item2" })
            {
                if (this.TryGetObjectMember(obj, memberName, out object rawValue) && rawValue is Vector3 vector)
                {
                    position = vector;
                    return true;
                }
            }

            foreach (string memberName in new string[] { "entity", "Entity", "_entity", "transform", "_transform" })
            {
                if (this.TryGetObjectMember(obj, memberName, out object nestedObj) && nestedObj != null)
                {
                    if (nestedObj is Transform transform)
                    {
                        position = transform.position;
                        return true;
                    }

                    if (this.TryResolvePositionFromManagedObject(nestedObj, out position, depth + 1))
                    {
                        return true;
                    }
                }
            }

            return false;
        }

        private bool TryFindPlayerEntityObject(GameObject player, out Il2CppObject entityObj, out string source)
        {
            entityObj = null;
            source = "none";
            if (player == null)
            {
                return false;
            }

            Component[] allComponents = player.GetComponentsInChildren<Component>(true);
            foreach (Component comp in allComponents)
            {
                if (comp == null) continue;
                var ilType = comp.GetIl2CppType();
                if (ilType == null) continue;
                foreach (string member in new string[] { "entity", "Entity", "_entity" })
                {
                    if (this.TryReadObjectMember(ilType, comp.TryCast<Il2CppObject>(), member, out entityObj) && entityObj != null)
                    {
                        source = ilType.Name + "." + member;
                        return true;
                    }
                }

                try
                {
                    var getEntityMethod = ilType.GetMethod("get_entity") ?? ilType.GetMethod("GetEntity");
                    if (getEntityMethod != null)
                    {
                        Il2CppObject maybeEntity = getEntityMethod.Invoke(comp.TryCast<Il2CppObject>(), null);
                        if (maybeEntity != null)
                        {
                            source = ilType.Name + "." + getEntityMethod.Name + "()";
                            entityObj = maybeEntity;
                            return true;
                        }
                    }
                }
                catch { }
            }

            Transform parent = player.transform.parent;
            int parentDepth = 0;
            while (parent != null && parentDepth < 3)
            {
                Component[] parentComponents = parent.GetComponents<Component>();
                foreach (Component comp in parentComponents)
                {
                    if (comp == null) continue;
                    var ilType = comp.GetIl2CppType();
                    if (ilType == null) continue;
                    foreach (string member in new string[] { "entity", "Entity", "_entity" })
                    {
                        if (this.TryReadObjectMember(ilType, comp.TryCast<Il2CppObject>(), member, out entityObj) && entityObj != null)
                        {
                            source = "parent/" + ilType.Name + "." + member;
                            return true;
                        }
                    }

                    try
                    {
                        var getEntityMethod = ilType.GetMethod("get_entity") ?? ilType.GetMethod("GetEntity");
                        if (getEntityMethod != null)
                        {
                            Il2CppObject maybeEntity = getEntityMethod.Invoke(comp.TryCast<Il2CppObject>(), null);
                            if (maybeEntity != null)
                            {
                                source = "parent/" + ilType.Name + "." + getEntityMethod.Name + "()";
                                entityObj = maybeEntity;
                                return true;
                            }
                        }
                    }
                    catch { }
                }

                parent = parent.parent;
                parentDepth++;
            }

            return false;
        }

        private bool TryFindSweepNetManagerObject(GameObject player, out Il2CppObject managerObj, out string source)
        {
            managerObj = null;
            source = "none";
            if (player == null)
            {
                return false;
            }

            Component[] components = player.GetComponentsInChildren<Component>(true);
            foreach (Component comp in components)
            {
                if (comp == null)
                {
                    continue;
                }

                var ilType = comp.GetIl2CppType();
                if (ilType == null)
                {
                    continue;
                }

                string typeName = (ilType.FullName ?? ilType.Name ?? string.Empty);
                bool looksLikeSweepNet = typeName.IndexOf("SweepNet", StringComparison.OrdinalIgnoreCase) >= 0;
                Il2CppObject found = this.ReadIl2CppObjectMember(comp.TryCast<Il2CppObject>(), "_insectManager")
                    ?? this.ReadIl2CppObjectMember(comp.TryCast<Il2CppObject>(), "insectManager");
                if (found != null)
                {
                    managerObj = found;
                    source = typeName + (looksLikeSweepNet ? " [SweepNet]" : string.Empty);
                    return true;
                }
            }

            return false;
        }

        private Il2CppObject ReadIl2CppObjectMember(Il2CppObject obj, string memberName)
        {
            if (obj == null || string.IsNullOrEmpty(memberName))
            {
                return null;
            }

            try
            {
                var ilType = obj.GetIl2CppType();
                if (ilType == null)
                {
                    return null;
                }

                if (this.TryReadObjectMember(ilType, obj, memberName, out Il2CppObject value))
                {
                    return value;
                }
            }
            catch { }

            return null;
        }

        private int TryMarkManagerFindEntitiesSelected(Il2CppObject managerObj, Il2CppObject bugDictObj)
        {
            if (managerObj == null || bugDictObj == null)
            {
                return 0;
            }

            try
            {
                Il2CppObject findEntities = this.ReadIl2CppObjectMember(managerObj, "_findEntities");
                if (findEntities == null)
                {
                    return 0;
                }

                var listType = findEntities.GetIl2CppType();
                var countProp = listType.GetProperty("Count");
                var itemMethod = listType.GetMethod("get_Item");
                var setItemMethod = bugDictObj.GetIl2CppType().GetMethod("set_Item");
                if (countProp == null || itemMethod == null || setItemMethod == null)
                {
                    return 0;
                }

                int count = countProp.GetValue(findEntities).Unbox<int>();
                int marked = 0;
                for (int i = 0; i < count && i < 64; i++)
                {
                    Il2CppObject item = itemMethod.Invoke(findEntities, new Il2CppReferenceArray<Il2CppObject>(new Il2CppObject[] { this.BoxInt(i) }));
                    if (item == null)
                    {
                        continue;
                    }

                    setItemMethod.Invoke(bugDictObj, new Il2CppReferenceArray<Il2CppObject>(new Il2CppObject[] { item, this.BoxBool(true) }));
                    marked++;
                }

                return marked;
            }
            catch (Exception ex)
            {
                this.InsectFarmNetLog("TryMarkManagerFindEntitiesSelected error: " + ex.Message);
                return 0;
            }
        }

        private bool TryExtractCatchTargetsFromManagerResult(Il2CppObject listObj, Vector3 playerPos, float scanRange, int batchSize, List<uint> ids, List<Vector3> positions)
        {
            if (listObj == null)
            {
                return false;
            }

            try
            {
                float effectiveCatchRange = scanRange > 0f ? Mathf.Min(scanRange, 20f) : 20f;
                var listType = listObj.GetIl2CppType();
                var countProp = listType.GetProperty("Count");
                var itemMethod = listType.GetMethod("get_Item");
                if (countProp == null || itemMethod == null)
                {
                    return false;
                }

                int count = countProp.GetValue(listObj).Unbox<int>();
                List<(uint id, Vector3 pos, float dist)> collected = new List<(uint, Vector3, float)>();
                for (int i = 0; i < count; i++)
                {
                    Il2CppObject item = itemMethod.Invoke(listObj, new Il2CppReferenceArray<Il2CppObject>(new Il2CppObject[] { this.BoxInt(i) }));
                    if (item == null)
                    {
                        continue;
                    }

                    if (!this.TryResolveNetIdFromIl2CppObject(item, out uint netId, out string source) || netId == 0U)
                    {
                        continue;
                    }

                    Vector3 pos = this.TryReadVector3Member(item, "position", out Vector3 positionValue)
                        ? positionValue
                        : this.TryReadVector3Member(item, "pos", out Vector3 posValue)
                            ? posValue
                            : this.TryReadVector3Member(item, "Position", out Vector3 posValue2)
                                ? posValue2
                                : Vector3.zero;

                    float dist = Vector3.Distance(playerPos, pos);
                    if (pos != Vector3.zero && dist <= effectiveCatchRange)
                    {
                        collected.Add((netId, pos, dist));
                        this.InsectFarmNetLog($"Manager target netId={netId} via {source} dist={dist:F2}");
                    }
                }

                collected.Sort((a, b) => a.dist.CompareTo(b.dist));
                HashSet<uint> seen = new HashSet<uint>();
                foreach (var item in collected)
                {
                    if (ids.Count >= batchSize)
                    {
                        break;
                    }

                    if (seen.Add(item.id))
                    {
                        ids.Add(item.id);
                        positions.Add(item.pos);
                    }
                }

                return ids.Count > 0;
            }
            catch (Exception ex)
            {
                this.InsectFarmNetLog("TryExtractCatchTargetsFromManagerResult error: " + ex);
                return false;
            }
        }

        private bool TryReadVector3Member(Il2CppObject obj, string memberName, out Vector3 value)
        {
            value = Vector3.zero;
            if (obj == null || string.IsNullOrEmpty(memberName))
            {
                return false;
            }

            try
            {
                var ilType = obj.GetIl2CppType();
                if (ilType == null)
                {
                    return false;
                }

                Il2CppFieldInfo field = ilType.GetField(memberName, (Il2CppBindingFlags)62);
                Il2CppObject boxed = field != null ? field.GetValue(obj) : null;
                if (boxed == null)
                {
                    var prop = ilType.GetProperty(memberName);
                    boxed = prop != null ? (prop.GetValue(obj) as Il2CppObject) : null;
                }

                if (boxed == null)
                {
                    return false;
                }

                var boxedType = boxed.GetIl2CppType();
                float x = boxedType.GetField("x").GetValue(boxed).Unbox<float>();
                float y = boxedType.GetField("y").GetValue(boxed).Unbox<float>();
                float z = boxedType.GetField("z").GetValue(boxed).Unbox<float>();
                value = new Vector3(x, y, z);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private bool TryResolveNetIdFromGameObject(GameObject obj, out uint netId, out string source)
        {
            netId = 0U;
            source = "none";
            if (obj == null)
            {
                return false;
            }

            try
            {
                foreach (Component comp in obj.GetComponents<Component>())
                {
                    if (comp == null)
                    {
                        continue;
                    }

                    if (this.TryResolveNetIdFromComponent(comp, out netId, out source))
                    {
                        return true;
                    }
                }
            }
            catch (Exception ex)
            {
                this.InsectFarmNetLog("TryResolveNetIdFromGameObject error on " + obj.name + ": " + ex.Message);
            }

            return false;
        }

        private bool TryResolveNetIdFromComponent(Component comp, out uint netId, out string source)
        {
            netId = 0U;
            source = "none";
            if (comp == null)
            {
                return false;
            }

            try
            {
                var ilType = comp.GetIl2CppType();
                if (ilType == null)
                {
                    return false;
                }

                string[] directMembers = new string[] { "netId", "NetId", "ownerNetId", "entityNetId", "insectNetId", "mNetId", "_netId", "Id", "id" };
                foreach (string member in directMembers)
                {
                    if (this.TryReadUIntMember(ilType, comp.TryCast<Il2CppObject>(), member, out netId))
                    {
                        source = ilType.Name + "." + member;
                        return true;
                    }
                }

                string[] entityMembers = new string[] { "entity", "Entity", "_entity", "ownerEntity", "targetEntity" };
                foreach (string member in entityMembers)
                {
                    if (this.TryReadObjectMember(ilType, comp.TryCast<Il2CppObject>(), member, out Il2CppObject nestedObj) && nestedObj != null)
                    {
                        if (this.TryResolveNetIdFromIl2CppObject(nestedObj, out netId, out string nestedSource))
                        {
                            source = ilType.Name + "." + member + "->" + nestedSource;
                            return true;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                this.InsectFarmNetLog("TryResolveNetIdFromComponent error: " + ex.Message);
            }

            return false;
        }

        private bool TryResolveNetIdFromIl2CppObject(Il2CppObject obj, out uint netId, out string source)
        {
            netId = 0U;
            source = "none";
            if (obj == null)
            {
                return false;
            }

            try
            {
                var ilType = obj.GetIl2CppType();
                if (ilType == null)
                {
                    return false;
                }

                string[] members = new string[] { "netId", "NetId", "ownerNetId", "entityNetId", "insectNetId", "mNetId", "_netId", "Id", "id", "Item1" };
                foreach (string member in members)
                {
                    if (this.TryReadUIntMember(ilType, obj, member, out netId))
                    {
                        source = ilType.Name + "." + member;
                        return true;
                    }
                }
            }
            catch (Exception ex)
            {
                this.InsectFarmNetLog("TryResolveNetIdFromIl2CppObject error: " + ex.Message);
            }

            return false;
        }

        private bool TryReadUIntMember(Il2CppType ilType, Il2CppObject instance, string memberName, out uint value)
        {
            value = 0U;
            if (ilType == null || instance == null || string.IsNullOrEmpty(memberName))
            {
                return false;
            }

            try
            {
                Il2CppFieldInfo field = ilType.GetField(memberName, (Il2CppBindingFlags)62);
                if (field != null)
                {
                    object fieldValue = field.GetValue(instance);
                    if (this.TryConvertToUInt(fieldValue, out value))
                    {
                        return true;
                    }
                }
            }
            catch { }

            try
            {
                var prop = ilType.GetProperty(memberName);
                if (prop != null)
                {
                    object propValue = prop.GetValue(instance);
                    if (this.TryConvertToUInt(propValue, out value))
                    {
                        return true;
                    }
                }
            }
            catch { }

            return false;
        }

