                    if (value != null)
                    {
                        return true;
                    }
                }
            }
            catch { }

            return false;
        }

        private bool TryConvertToUInt(object rawValue, out uint value)
        {
            value = 0U;
            if (rawValue == null)
            {
                return false;
            }

            try
            {
                if (rawValue is uint uintValue)
                {
                    value = uintValue;
                    return value != 0U;
                }
                if (rawValue is int intValue)
                {
                    if (intValue > 0)
                    {
                        value = (uint)intValue;
                        return true;
                    }
                    return false;
                }

                string s = rawValue.ToString();
                if (string.IsNullOrEmpty(s))
                {
                    return false;
                }

                s = new string(s.Where(char.IsDigit).ToArray());
                if (uint.TryParse(s, out value))
                {
                    return value != 0U;
                }
            }
            catch { }

            return false;
        }

        private bool TryConvertToInt(object rawValue, out int value)
        {
            value = 0;
            if (rawValue == null)
            {
                return false;
            }

            try
            {
                if (rawValue is int intValue)
                {
                    value = intValue;
                    return value != 0;
                }
                if (rawValue is uint uintValue && uintValue <= int.MaxValue)
                {
                    value = (int)uintValue;
                    return value != 0;
                }

                string s = rawValue.ToString();
                if (string.IsNullOrEmpty(s))
                {
                    return false;
                }

                s = new string(s.Where(c => char.IsDigit(c) || c == '-').ToArray());
                if (int.TryParse(s, out value))
                {
                    return value != 0;
                }
            }
            catch { }

            return false;
        }

