                    if (f == IntPtr.Zero) f = this.FindAuraMonoFieldOnHierarchy(detailClass, "PerfectStar");
                    if (f == IntPtr.Zero) f = this.FindAuraMonoFieldOnHierarchy(detailClass, "perfectStar");
