        private bool TryOpenWeatherExchangeShopPanelByStoreId(int storeId, int slotId, string label)
        {
            if (storeId <= 0)
            {
                this.forceOpenShopStatus = "Invalid store id for " + label + ".";
                this.LogForceOpenShop(this.forceOpenShopStatus);
                return false;
