        private void AddMenuNotification(string message, Color color, float duration = 5f, bool force = false)
        {
            this.AddOrUpdateMenuNotification(null, message, color, duration, force);
        }

        private int birdMaxPhotoScareNotificationTotal = 0;

        private int GetNextBirdMaxPhotoScareNotificationTotal(string key)
        {
            float now = Time.unscaledTime;
            bool activeNotificationFound = false;
            for (int i = 0; i < this.menuNotifications.Count; i++)
            {
                HeartopiaComplete.MenuNotification existing = this.menuNotifications[i];
                if (existing != null
                    && existing.ExpireAt > now
                    && string.Equals(existing.Key, key, StringComparison.Ordinal))
                {
                    activeNotificationFound = true;
                    break;
                }
            }

            if (!activeNotificationFound)
            {
                this.birdMaxPhotoScareNotificationTotal = 0;
            }

            this.birdMaxPhotoScareNotificationTotal++;
            return this.birdMaxPhotoScareNotificationTotal;
        }

        private void AddOrUpdateMenuNotification(string key, string message, Color color, float duration = 5f, bool force = false)
        {
            if (!force && !this.notificationsEnabled)
            {
                return;
            }

            float now = Time.unscaledTime;
            float safeDuration = Mathf.Max(0.1f, duration);
            if (!string.IsNullOrWhiteSpace(key))
            {
                for (int i = 0; i < this.menuNotifications.Count; i++)
                {
                    HeartopiaComplete.MenuNotification existing = this.menuNotifications[i];
                    if (existing == null || !string.Equals(existing.Key, key, StringComparison.Ordinal))
                    {
                        continue;
                    }

                    existing.Message = this.L(message);
                    existing.Color = color;
                    existing.ExpireAt = now + safeDuration;
                    existing.Duration = safeDuration;
                    existing.Force = force;
                    return;
                }
            }

            this.menuNotifications.Add(new HeartopiaComplete.MenuNotification
            {
                Key = key,
                Message = this.L(message),
                Color = color,
                CreatedAt = now,
                ExpireAt = now + safeDuration,
                Duration = safeDuration,
                Force = force
            });
            if (this.menuNotifications.Count > 6)
            {
                this.menuNotifications.RemoveAt(0);
            }
        }

        public void UI_AddMenuNotification(string message, Color color, float duration = 5f)
        {
            this.AddMenuNotification(message, color, duration);
        }

        private void DrawMenuNotifications(Rect area)
        {
            float now = Time.unscaledTime;
            this.menuNotifications.RemoveAll(n => n == null || n.ExpireAt <= now);
            if (this.menuNotifications.Count == 0)
            {
                return;
            }

            bool drawAll = this.notificationsEnabled;
            if (!drawAll)
            {
                bool hasForcedNotification = false;
                for (int i = 0; i < this.menuNotifications.Count; i++)
                {
                    if (this.menuNotifications[i] != null && this.menuNotifications[i].Force)
                    {
                        hasForcedNotification = true;
                        break;
                    }
                }

                if (!hasForcedNotification)
                {
                    return;
                }
            }

            GUIStyle style = new GUIStyle(GUI.skin.label);
            style.fontSize = 12;
            style.fontStyle = FontStyle.Bold;
            style.alignment = TextAnchor.MiddleLeft;
            style.wordWrap = true;

            float maxWidth = Mathf.Clamp(Screen.width * 0.44f, 260f, 520f);
            List<HeartopiaComplete.MenuNotification> visibleNotifications = new List<HeartopiaComplete.MenuNotification>();
            for (int i = this.menuNotifications.Count - 1; i >= 0; i--)
            {
                HeartopiaComplete.MenuNotification item = this.menuNotifications[i];
                if (!drawAll && !item.Force)
                {
                    continue;
                }

                visibleNotifications.Add(item);
            }

            if (visibleNotifications.Count == 0)
            {
                return;
            }

            List<float> boxHeights = new List<float>(visibleNotifications.Count);
            List<float> boxWidths = new List<float>(visibleNotifications.Count);
            float totalHeight = 0f;
            for (int i = 0; i < visibleNotifications.Count; i++)
            {
                HeartopiaComplete.MenuNotification item = visibleNotifications[i];
                GUIContent content = new GUIContent(item.Message ?? string.Empty);
                Vector2 measured = style.CalcSize(content);
                float boxWidth = Mathf.Clamp(measured.x + 46f, area.width, maxWidth);
                float textWidth = boxWidth - 28f;
                float textHeight = Mathf.Clamp(style.CalcHeight(content, textWidth), 18f, 92f);
                float boxHeight = Mathf.Clamp(textHeight + 20f, 42f, 112f);
                boxWidths.Add(boxWidth);
                boxHeights.Add(boxHeight);
                totalHeight += boxHeight;
                if (i < visibleNotifications.Count - 1)
                {
                    totalHeight += 6f;
                }
            }

            float xMargin = 20f;
            float topY = 14f;
            float middleY = Mathf.Max(14f, (Screen.height - totalHeight) * 0.5f);
            float bottomY = Mathf.Max(14f, Screen.height - totalHeight - 20f);
            float y = topY;
            switch (this.notificationPosition)
            {
                case 1:
                case 6:
                    y = middleY;
                    break;
                case 2:
                case 4:
                case 7:
                    y = bottomY;
                    break;
                default:
                    y = topY;
                    break;
            }

            for (int i = 0; i < visibleNotifications.Count; i++)
            {
                HeartopiaComplete.MenuNotification item = visibleNotifications[i];

                float remain = Mathf.Clamp01((item.ExpireAt - now) / item.Duration);

                // Smooth in/out animation.
                float inAnim = Mathf.Clamp01((now - item.CreatedAt) / 0.12f);
                float outAnim = Mathf.Clamp01((item.ExpireAt - now) / 0.18f);
                float anim = Mathf.Min(inAnim, outAnim);
                float alpha = Mathf.Lerp(0f, 1f, anim);
                float slide = (1f - anim) * 18f;
                float boxWidth = boxWidths[i];
                float boxHeight = boxHeights[i];
                float boxX;
                switch (this.notificationPosition)
                {
                    case 0:
                    case 1:
                    case 2:
                        boxX = xMargin - slide;
                        break;
                    case 3:
                    case 4:
                        boxX = (Screen.width - boxWidth) * 0.5f;
                        break;
                    default:
                        boxX = Screen.width - boxWidth - xMargin + slide;
                        break;
                }

                Rect box = new Rect(boxX, y, boxWidth, boxHeight);
                Rect shadow = new Rect(box.x + 2f, box.y + 3f, box.width, box.height);
                Rect accentStrip = new Rect(box.x, box.y, 4f, box.height);
                Rect messageRect = new Rect(box.x + 18f, box.y + 6f, box.width - 28f, box.height - 16f);
                Rect progressBg = new Rect(box.x + 10f, box.y + box.height - 8f, box.width - 20f, 3f);
                Rect progressFg = new Rect(progressBg.x, progressBg.y, progressBg.width * remain, progressBg.height);

                Color cardBg = new Color(0.04f, 0.06f, 0.09f, 0.93f * alpha);
                Color shadowBg = new Color(0f, 0f, 0f, 0.32f * alpha);
                Color stripColor = new Color(item.Color.r, item.Color.g, item.Color.b, 0.95f * alpha);
                Color progressBgColor = new Color(0.2f, 0.24f, 0.32f, 0.6f * alpha);
                Color progressColor = new Color(item.Color.r, item.Color.g, item.Color.b, 0.95f * alpha);

                GUI.color = shadowBg;
                GUI.DrawTexture(shadow, Texture2D.whiteTexture);
                GUI.color = cardBg;
                GUI.DrawTexture(box, Texture2D.whiteTexture);
                GUI.color = stripColor;
                GUI.DrawTexture(accentStrip, Texture2D.whiteTexture);
                GUI.color = progressBgColor;
                GUI.DrawTexture(progressBg, Texture2D.whiteTexture);
                GUI.color = progressColor;
                GUI.DrawTexture(progressFg, Texture2D.whiteTexture);
                GUI.color = Color.white;

                style.normal.textColor = new Color(0.94f, 0.96f, 1f, alpha);
                GUI.Label(messageRect, item.Message, style);

                // small status dot icon
                this.EnsureUiPrimitiveTextures();
                GUI.color = stripColor;
                GUI.DrawTexture(new Rect(box.x + 8f, box.y + 16f, 6f, 6f), this.uiCircleTexture);
                GUI.color = Color.white;

                y += boxHeight + 6f;
                if (y > Screen.height - 42f)
                {
                    break;
                }
            }
        }

        private void UpdateGameUiClickBlockState()
        {
            bool shouldBlock = this.showMenu && this.blockGameUiWhenMenuOpen && !this.autoBuyEnabled;
            if (shouldBlock && !this.eventSystemBlockedByMenu)
            {
                EventSystem current = EventSystem.current;
                if (current != null)
                {
                    this.blockedEventSystem = current;
                    this.eventSystemPrevEnabled = current.enabled;
                    current.SetSelectedGameObject(null);
                    current.enabled = false;
                    this.eventSystemBlockedByMenu = true;
                }
            }
            else if (!shouldBlock && this.eventSystemBlockedByMenu)
            {
                EventSystem restoreTarget = this.blockedEventSystem != null ? this.blockedEventSystem : EventSystem.current;
                if (restoreTarget != null)
                {
                    restoreTarget.enabled = this.eventSystemPrevEnabled;
                    restoreTarget.SetSelectedGameObject(null);
                    restoreTarget.sendNavigationEvents = true;
                }
                this.eventSystemBlockedByMenu = false;
                this.blockedEventSystem = null;
            }
        }

        public static bool ShouldBlockGameplayInput()
        {
            HeartopiaComplete instance = HeartopiaComplete.Instance;
            return instance != null &&
                   ((instance.showMenu && instance.blockGameUiWhenMenuOpen) ||
                    Time.unscaledTime < instance.blockInputReleaseUntil);
        }

        // Blocks player movement while the mod menu is open (with "block game input" enabled).
        // The game does NOT move the local player via Unity's CharacterController.Move, so the
        // Harmony Move patch can't stop it — movement goes through MonoInputManager. We disable
        // the Move InputEvent there instead. Edge-triggered so the disable refcount stays balanced.
        private void UpdateMenuMovementInputBlock()
        {
            bool shouldBlock = ShouldBlockGameplayInput();
            if (shouldBlock == this.menuMoveInputDisabled)
            {
                return;
            }

            // InputEvent.Move == 0 (ScriptsRefactory.BaseService.Input.InputEvent).
            const int InputEventMove = 0;
            if (shouldBlock)
            {
                // Only flip our state once the disable actually lands, so we don't leave an
                // unbalanced Enable later if the input manager wasn't ready yet (retry next frame).
                if (this.TrySetMonoInputDisabled(InputEventMove, true))
                {
                    this.menuMoveInputDisabled = true;
                }
            }
            else
            {
                this.TrySetMonoInputDisabled(InputEventMove, false);
                this.menuMoveInputDisabled = false;
            }
        }

        public static bool ShouldForceMouseLookButton(int button)
        {
            return false;
        }

        private bool TryGetManagedViewModuleSelfPlayerObject(out object playerObj, out string source)
        {
            playerObj = null;
            source = "none";

            try
            {
                Type entityManagerType = this.FindLoadedType(
                    "XDTLevelAndEntity.BaseSystem.EntityManager",
                    "ScriptsRefactory.LevelAndEntity.BaseSystem.EntityManager",
                    "Il2CppXDTLevelAndEntity.BaseSystem.EntityManager",
                    "EntityManager");
                if (entityManagerType == null)
                {
                    return false;
                }

                PropertyInfo instanceProperty = entityManagerType.GetProperty("Instance", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static);
                object entityManager = instanceProperty != null ? instanceProperty.GetValue(null, null) : null;
                if (entityManager == null)
                {
                    return false;
                }

                if (this.TryGetObjectMember(entityManager, "selfPlayer", out object selfPlayerObj) && selfPlayerObj != null)
                {
                    playerObj = selfPlayerObj;
                    source = "EntityManager.Instance.selfPlayer";
                    return true;
                }
            }
            catch { }

            return false;
        }

        private bool TryGetManagedViewModuleSelfPlayerEntityObject(out object entityObj, out string source)
        {
            entityObj = null;
            source = "none";

            try
            {
                Type entityManagerType = this.FindLoadedType(
                    "ScriptsRefactory.LevelAndEntity.BaseSystem.EntityManager",
                    "EntityManager");
                if (entityManagerType == null)
                {
                    return false;
                }

                PropertyInfo instanceProperty = entityManagerType.GetProperty("Instance", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static);
                object entityManager = instanceProperty != null ? instanceProperty.GetValue(null, null) : null;
                if (entityManager == null)
                {
                    return false;
                }

                if (this.TryGetObjectMember(entityManager, "selfPlayer", out entityObj) && entityObj != null)
                {
                    source = "EntityManager.Instance.selfPlayer";
                    return true;
                }
            }
            catch { }

            return false;
        }

        private bool TryInvokeMethodByName(object target, string methodName, out object result, object[] args)
        {
            result = null;
            if (target == null || string.IsNullOrWhiteSpace(methodName))
            {
                return false;
            }

            try
            {
                MethodInfo[] methods = target.GetType().GetMethods(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance);
                for (int i = 0; i < methods.Length; i++)
                {
                    MethodInfo method = methods[i];
                    if (method == null || !string.Equals(method.Name, methodName, StringComparison.Ordinal))
                    {
                        continue;
                    }

                    ParameterInfo[] parameters = method.GetParameters();
                    if ((args == null ? 0 : args.Length) != parameters.Length)
                    {
                        continue;
                    }

                    result = method.Invoke(target, args);
                    return true;
                }
            }
            catch { }

            return false;
        }

