        private Texture2D MakeThemeTexture(Color color)
        {
            Texture2D texture = new Texture2D(1, 1, TextureFormat.RGBA32, false);
            texture.hideFlags = HideFlags.DontUnloadUnusedAsset;
            texture.wrapMode = TextureWrapMode.Clamp;
            texture.filterMode = FilterMode.Bilinear;
            texture.SetPixel(0, 0, color);
            texture.Apply();
            this.themeTextures.Add(texture);
            return texture;
        }

        private Texture2D CreateRadarIconFallbackTexture(string key, Color primary, Color secondary, bool ring = false, bool diamond = false, bool addStem = false)
        {
            Texture2D texture = new Texture2D(32, 32, TextureFormat.RGBA32, false);
            texture.hideFlags = HideFlags.DontUnloadUnusedAsset;
            texture.wrapMode = TextureWrapMode.Clamp;
            texture.filterMode = FilterMode.Bilinear;

            Vector2 center = new Vector2(15.5f, 15.5f);
            for (int y = 0; y < 32; y++)
            {
                for (int x = 0; x < 32; x++)
                {
                    Color pixel = Color.clear;
                    float dx = x - center.x;
                    float dy = y - center.y;
                    float distance = Mathf.Sqrt(dx * dx + dy * dy);
                    float manhattan = Mathf.Abs(dx) + Mathf.Abs(dy);

                    if (diamond)
                    {
                        if (manhattan <= 10.5f)
                        {
                            pixel = primary;
                        }
                        if (manhattan <= 4.5f)
                        {
                            pixel = secondary;
                        }
                    }
                    else if (ring)
                    {
                        if (distance <= 11f && distance >= 7.5f)
                        {
                            pixel = primary;
                        }
                        else if (distance < 7.5f)
                        {
                            pixel = secondary;
                        }
                    }
                    else
                    {
                        if (distance <= 11f)
                        {
                            pixel = primary;
                        }
                        if (distance <= 5.5f)
                        {
                            pixel = secondary;
                        }
                    }

                    if (addStem && x >= 13 && x <= 18 && y >= 20 && y <= 30)
                    {
                        pixel = secondary;
                    }

                    texture.SetPixel(x, y, pixel);
                }
            }

            texture.Apply();
            this.radarIconEspTextures[key] = texture;
            return texture;
        }

