                    if (!this.autoSculptureIconRapidEnabled) this.lastSculptIconClickTime = 0f;
                }
                num += 30;
                GUI.Label(new Rect(left, (float)num, 360f, 20f), this.LF("Interval: {0:F0}ms", this.sculptIconClickInterval * 1000f));
                num += 22;
