                else
                {
                    autoBuyBodyHeight += 92f;
                    if ((this.autoBuySelectedStore == 1 && this.autoBuyEnabled) ||
                        (this.autoBuySelectedStore == 2 && this.autoBuyBirdEnabled) ||
