                });
                IntPtr tableDataClass = ecsImage != IntPtr.Zero && auraMonoClassFromName != null
                    ? auraMonoClassFromName(ecsImage, string.Empty, "TableData")
                    : IntPtr.Zero;
                if (tableDataClass == IntPtr.Zero && ecsImage != IntPtr.Zero && auraMonoClassFromName != null)
