        private bool TryResolveAuraMonoLevelObjectManager(out IntPtr managerObj, out IntPtr classPtr, out string status)
        {
            managerObj = IntPtr.Zero;
            classPtr = IntPtr.Zero;
            status = "AuraMono API unavailable.";

            if (!this.EnsureAuraMonoApiReady() || !this.AttachAuraMonoThread() || auraMonoClassFromName == null || auraMonoRuntimeInvoke == null)
            {
                return false;
            }

            IntPtr image = this.FindAuraMonoImage(new string[] { "XDTDataAndProtocol", "XDTDataAndProtocol.dll", "XDTLevelAndEntity", "XDTLevelAndEntity.dll" });
            if (image != IntPtr.Zero)
            {
                classPtr = auraMonoClassFromName(image, "ScriptsRefactory.LevelAndEntity", "LevelObjectManager");
            }

            if (classPtr == IntPtr.Zero)
            {
                classPtr = this.FindAuraMonoClassAcrossLoadedAssemblies("ScriptsRefactory.LevelAndEntity", "LevelObjectManager");
            }

            if (classPtr == IntPtr.Zero)
            {
                classPtr = this.FindAuraMonoClassAcrossLoadedAssemblies("XDTDataAndProtocol.ScriptsRefactory.LevelAndEntity", "LevelObjectManager");
            }

            if (classPtr == IntPtr.Zero)
            {
                status = "LevelObjectManager class unavailable.";
                return false;
            }

            if (!this.TryGetAuraMonoStaticObjectField(classPtr, "_instance", out managerObj) || managerObj == IntPtr.Zero)
            {
                IntPtr getInstanceMethod = this.FindAuraMonoMethodOnHierarchy(classPtr, "get_Instance", 0);
                if (getInstanceMethod != IntPtr.Zero)
                {
                    IntPtr exc = IntPtr.Zero;
                    managerObj = auraMonoRuntimeInvoke(getInstanceMethod, IntPtr.Zero, IntPtr.Zero, ref exc);
                    if (exc != IntPtr.Zero)
                    {
                        managerObj = IntPtr.Zero;
                    }
                }
            }

            if (managerObj == IntPtr.Zero)
            {
                status = "LevelObjectManager instance unavailable.";
                return false;
            }

            status = "AuraMono LevelObjectManager ready.";
            return true;
        }

        private bool TryGetMonoUInt64Member(IntPtr obj, string memberName, out ulong value)
        {
            value = 0UL;
            if (!this.TryGetMonoObjectMember(obj, memberName, out IntPtr boxed) || boxed == IntPtr.Zero)
            {
                return false;
            }

            value = this.TryReadMonoUnsignedIntegral(boxed);
            return true;
        }

        private bool TryGetMonoBoolMember(IntPtr obj, string memberName, out bool value)
        {
            value = false;
            if (!this.TryGetMonoObjectMember(obj, memberName, out IntPtr boxed) || boxed == IntPtr.Zero)
            {
                return false;
            }

            return this.TryUnboxMonoBoolean(boxed, out value);
        }

        private bool TryGetNetCookScanOrigin(out Vector3 origin, out string status)
        {
            origin = Vector3.zero;
            status = "No scan origin.";

            try
            {
                GameObject player = GetPlayer();
                if (player != null && player.transform != null)
                {
                    origin = player.transform.position;
                    status = "Player origin";
                    return true;
                }

                Camera mainCamera = Camera.main;
                if (mainCamera != null && mainCamera.transform != null)
                {
                    origin = mainCamera.transform.position;
                    status = "Camera origin";
                    return true;
                }

                status = "Player and camera unavailable.";
                return false;
            }
            catch (Exception ex)
            {
                status = "Scan origin exception: " + ex.Message;
                return false;
            }
        }

        private bool TryGetNetCookLevelObjectPosition(object levelObject, out Vector3 position)
        {
            position = Vector3.zero;

            try
            {
                if (this.TryGetManagedMemberValue(levelObject, "position") is Vector3 directPosition)
                {
                    position = directPosition;
                    return true;
                }

                if (this.TryGetManagedMemberValue(levelObject, "worldPosition") is Vector3 worldPosition)
                {
                    position = worldPosition;
                    return true;
                }

                object ownerEntity = this.TryGetManagedMemberValue(levelObject, "ownerEntity");
                if (ownerEntity != null)
                {
                    if (this.TryGetManagedMemberValue(ownerEntity, "position") is Vector3 entityPosition)
                    {
                        position = entityPosition;
                        return true;
                    }

                    object transformComponent = this.TryGetManagedMemberValue(ownerEntity, "transformComponent");
                    if (transformComponent != null)
                    {
                        if (this.TryGetManagedMemberValue(transformComponent, "position") is Vector3 transformPosition)
                        {
                            position = transformPosition;
                            return true;
                        }

                        if (this.TryGetManagedMemberValue(transformComponent, "worldPosition") is Vector3 transformWorldPosition)
                        {
                            position = transformWorldPosition;
                            return true;
                        }
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        private bool TryGetCurrentFocusedLevelObjectNetId(out ulong levelObjectNetId, out string status)
        {
            levelObjectNetId = 0UL;
            status = "Focused target unavailable.";

            try
            {
                if (!this.TryGetManagedSelfPlayerObject(out object playerObj, out _)
                    && !this.TryGetManagedSelfPlayerEntityObject(out playerObj, out _))
                {
                    status = "Self player unavailable.";
                    this.NetCookLog(status);
                    return false;
                }

                object playerStatus = this.TryGetManagedMemberValue(playerObj, "Status") ?? this.TryGetManagedMemberValue(playerObj, "status");
                if (playerStatus == null)
                {
                    status = "Player status unavailable.";
                    this.NetCookLog(status);
                    return false;
                }

                object focusUiStatus = this.TryGetManagedMemberValue(playerStatus, "FocusUIStatus") ?? this.TryGetManagedMemberValue(playerStatus, "focusUIStatus");
                if (focusUiStatus == null)
                {
                    status = "Focus UI status unavailable.";
                    this.NetCookLog(status);
                    return false;
                }

                if (!this.TryReadManagedUInt64Member(focusUiStatus, "FocusLevelObject", out levelObjectNetId)
                    && !this.TryReadManagedUInt64Member(focusUiStatus, "focusLevelObject", out levelObjectNetId))
                {
                    status = "Focus level object unavailable.";
                    this.NetCookLog(status);
                    return false;
                }

                if (levelObjectNetId == 0UL)
                {
                    status = "No focused level object.";
                    this.NetCookLog(status);
                    return false;
                }

                status = "Focused target ready.";
                this.NetCookLog("FocusLevelObject=" + levelObjectNetId);
                return true;
            }
            catch (Exception ex)
            {
                status = "Focused target exception: " + ex.Message;
                this.NetCookLog(status);
                return false;
            }
        }

        private bool TryGetCurrentInteractTargetLevelObjects(List<ulong> candidateLevelObjects, out string status, HashSet<ulong> candidateLevelObjectSet = null)
        {
            status = "Interact targets unavailable.";
            if (candidateLevelObjects == null)
            {
                this.NetCookLog("Candidate target list was null.");
                return false;
            }

            try
            {
                if (!this.TryGetManagedInteractSystemObject(out object interactSystemObj, out _))
                {
                    this.NetCookLog("InteractSystem unavailable. Trying static interact target helpers...");
                    return this.TryGetCurrentInteractTargetLevelObjectsViaStaticHelper(candidateLevelObjects, out status, candidateLevelObjectSet);
                }

                MethodInfo getInteractTargetListMethod = null;
                if (interactSystemObj is Type interactStaticType)
                {
                    getInteractTargetListMethod = interactStaticType.GetMethod("GetInteractTargetList", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static, null, new Type[] { typeof(List<ulong>) }, null);
                }
                else
                {
                    getInteractTargetListMethod = interactSystemObj.GetType().GetMethod("GetInteractTargetList", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, new Type[] { typeof(List<ulong>) }, null);
                }
                if (getInteractTargetListMethod == null)
                {
                    this.NetCookLog("GetInteractTargetList unavailable on primary object. Trying static interact target helpers...");
                    return this.TryGetCurrentInteractTargetLevelObjectsViaStaticHelper(candidateLevelObjects, out status, candidateLevelObjectSet);
                }

                List<ulong> interactTargets = new List<ulong>(8);
                object invokeResult = getInteractTargetListMethod.Invoke(interactSystemObj is Type ? null : interactSystemObj, new object[] { interactTargets });
                int targetCount = 0;
                if (invokeResult is int count)
                {
                    targetCount = count;
                }
                else
                {
                    targetCount = interactTargets.Count;
                }

                if (NetCookLogsEnabled)
                {
                    this.NetCookLog("GetInteractTargetList returned count=" + targetCount + " targets=[" + string.Join(", ", interactTargets) + "]");
                }

                for (int i = 0; i < interactTargets.Count; i++)
                {
                    ulong targetLevelObjectNetId = interactTargets[i];
                    if (!AddNetCookCandidateLevelObject(candidateLevelObjects, candidateLevelObjectSet, targetLevelObjectNetId))
                    {
                        continue;
                    }
                }

                status = "Interact targets ready: " + targetCount;
                return targetCount > 0;
            }
            catch (Exception ex)
            {
                status = "Interact target exception: " + ex.Message;
                this.NetCookLog(status);
                return false;
            }
        }

        private bool TryGetCurrentInteractTargetLevelObjectsViaStaticHelper(List<ulong> candidateLevelObjects, out string status, HashSet<ulong> candidateLevelObjectSet = null)
        {
            status = "Static interact target helper unavailable.";
            if (candidateLevelObjects == null)
            {
                return false;
            }

            try
            {
                List<ulong> interactTargets = new List<ulong>(8);
                object invokeResult = null;

                Type entityHelperType = this.FindLoadedType("XDTLevelAndEntity.Utils.EntityHelper", "EntityHelper");
                MethodInfo helperMethod = entityHelperType != null
                    ? entityHelperType.GetMethod("GetPlayerInteractTargetList", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static, null, new Type[] { typeof(List<ulong>) }, null)
                    : null;
                if (helperMethod != null)
                {
                    invokeResult = helperMethod.Invoke(null, new object[] { interactTargets });
                    this.NetCookLog("EntityHelper.GetPlayerInteractTargetList used.");
                }
                else
                {
                    Type playerInteractionType = this.FindLoadedType(
                        "XDTLevelAndEntity.Gameplay.Interaction.PlayerInteraction",
                        "PlayerInteraction");
                    MethodInfo directMethod = playerInteractionType != null
                        ? playerInteractionType.GetMethod("GetInteractTargetList", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static, null, new Type[] { typeof(List<ulong>) }, null)
                        : null;
                    if (directMethod == null)
                    {
                        this.NetCookLog(status);
                        return false;
                    }

                    invokeResult = directMethod.Invoke(null, new object[] { interactTargets });
                    this.NetCookLog("PlayerInteraction.GetInteractTargetList used.");
                }

                int targetCount = 0;
                if (invokeResult is int count)
                {
                    targetCount = count;
                }
                else
                {
                    targetCount = interactTargets.Count;
                }

                if (NetCookLogsEnabled)
                {
                    this.NetCookLog("Static interact helper returned count=" + targetCount + " targets=[" + string.Join(", ", interactTargets) + "]");
                }

                for (int i = 0; i < interactTargets.Count; i++)
                {
                    ulong targetLevelObjectNetId = interactTargets[i];
                    if (!AddNetCookCandidateLevelObject(candidateLevelObjects, candidateLevelObjectSet, targetLevelObjectNetId))
                    {
                        continue;
                    }
                }

                status = "Static interact targets ready: " + targetCount;
                return targetCount > 0;
            }
            catch (Exception ex)
            {
                status = "Static interact target exception: " + ex.Message;
                this.NetCookLog(status);
                return false;
            }
        }

        private bool TryResolveNetCookContextFromLevelObject(ulong levelObjectNetId, out uint cookerNetId, out int cookerStaticId, out int cookerType, out string status)
        {
            cookerNetId = 0U;
            cookerStaticId = 0;
            cookerType = 0;
            status = "Level object is not a cooker.";
            this.NetCookLog("Resolving level object " + levelObjectNetId + "...");

            try
            {
                Type levelObjectManagerType = this.FindLevelObjectManagerRuntimeType();
                if (levelObjectManagerType == null)
                {
                    status = "LevelObjectManager unavailable.";
                    this.NetCookLog(status);
                    return false;
                }

                PropertyInfo instanceProperty = levelObjectManagerType.GetProperty("Instance", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static);
                object levelObjectManager = instanceProperty != null ? instanceProperty.GetValue(null, null) : null;
                if (levelObjectManager == null)
                {
                    status = "LevelObjectManager instance unavailable.";
                    this.NetCookLog(status);
                    return false;
                }

                MethodInfo getLevelObjectMethod = levelObjectManagerType.GetMethod("GetLevelObject", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, new Type[] { typeof(ulong) }, null)
                    ?? levelObjectManagerType.GetMethod("GetLevelObject", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, new Type[] { typeof(ulong), typeof(int) }, null);
                if (getLevelObjectMethod == null)
                {
                    status = "GetLevelObject unavailable.";
                    this.NetCookLog(status);
                    return false;
                }

                object levelObject = getLevelObjectMethod.GetParameters().Length == 1
                    ? getLevelObjectMethod.Invoke(levelObjectManager, new object[] { levelObjectNetId })
                    : getLevelObjectMethod.Invoke(levelObjectManager, new object[] { levelObjectNetId, 0 });
                if (levelObject == null)
                {
                    status = "Target level object missing.";
                    this.NetCookLog(status + " netId=" + levelObjectNetId);
                    return false;
                }

                if (!this.TryReadManagedUInt32Member(levelObject, "ownerNetId", out cookerNetId) || cookerNetId == 0U)
                {
                    status = "Cooker owner net id missing.";
                    this.NetCookLog(status);
                    return false;
                }

                this.NetCookLog("Level object " + levelObjectNetId + " ownerNetId=" + cookerNetId);

                object ownerEntity = this.TryGetManagedMemberValue(levelObject, "ownerEntity");
                if (ownerEntity == null)
                {
                    status = "Cooker owner entity missing.";
                    this.NetCookLog(status);
                    return false;
                }

                object transformComponent = this.TryGetManagedMemberValue(ownerEntity, "transformComponent");
                if (transformComponent == null)
                {
                    status = "Cooker transform component missing.";
                    this.NetCookLog(status);
                    return false;
                }

                string transformTypeName = transformComponent.GetType().FullName ?? transformComponent.GetType().Name;
                this.NetCookLog("Transform component type=" + transformTypeName);
                if (transformTypeName.IndexOf("WorldCookerComponent", StringComparison.OrdinalIgnoreCase) < 0)
                {
                    status = "Current target is not a world cooker.";
                    this.NetCookLog(status);
                    return false;
                }

                object componentData = this.TryGetManagedMemberValue(transformComponent, "ComponentData");
                if (componentData == null || !this.TryReadManagedInt32Member(componentData, "staticId", out cookerStaticId) || cookerStaticId <= 0)
                {
                    status = "Cooker static id missing.";
                    this.NetCookLog(status);
                    return false;
                }

                this.NetCookLog("Cooker staticId=" + cookerStaticId);

                if (!this.TryGetCookerTypeForStaticId(cookerStaticId, out cookerType))
                {
                    status = "Cooker type lookup failed.";
                    this.NetCookLog(status);
                    return false;
                }

                status = "Cooker context ready.";
                this.NetCookLog("Cooker type=" + cookerType);
                return true;
            }
            catch (Exception ex)
            {
                status = "Cooker resolve exception: " + ex.Message;
                this.NetCookLog(status);
                return false;
            }
        }

        private bool TryGetCookerTypeForStaticId(int cookerStaticId, out int cookerType)
        {
            cookerType = 0;
            if (cookerStaticId <= 0)
            {
                return false;
            }

            if (this.netCookCookerTypeCache.TryGetValue(cookerStaticId, out cookerType))
            {
                return cookerType > 0;
            }

            if (this.netCookCookerTypeFailedStaticIds.Contains(cookerStaticId))
            {
                return false;
            }

            try
            {
                Type tableDataType = this.FindLoadedType("TableData", "EcsClient.TableData");
                if (tableDataType == null)
                {
                    this.NetCookLog("GetCookerType failed: TableData unavailable.");
                    this.netCookCookerTypeFailedStaticIds.Add(cookerStaticId);
                    return false;
                }

                MethodInfo getCookerMethod = tableDataType.GetMethod("GetCooker", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static, null, new Type[] { typeof(int), typeof(bool) }, null);
                if (getCookerMethod == null)
                {
                    this.NetCookLog("GetCookerType failed: GetCooker unavailable.");
                    this.netCookCookerTypeFailedStaticIds.Add(cookerStaticId);
                    return false;
                }

                object cookerData = getCookerMethod.Invoke(null, new object[] { cookerStaticId, false });
                if (cookerData == null)
                {
                    this.NetCookLog("GetCookerType failed: cooker data null for staticId=" + cookerStaticId);
                    this.netCookCookerTypeFailedStaticIds.Add(cookerStaticId);
                    return false;
                }

                if (!this.TryGetObjectMember(cookerData, "cookerType", out object cookerTypeObj) || cookerTypeObj == null)
                {
                    this.NetCookLog("GetCookerType failed: cookerType member missing for staticId=" + cookerStaticId);
                    this.netCookCookerTypeFailedStaticIds.Add(cookerStaticId);
                    return false;
                }

                cookerType = Convert.ToInt32(cookerTypeObj);
                this.netCookCookerTypeCache[cookerStaticId] = cookerType;
                this.NetCookLog("GetCookerType staticId=" + cookerStaticId + " => cookerType=" + cookerType);
                return cookerType > 0;
            }
            catch (Exception ex)
            {
                this.NetCookLog("GetCookerType exception for staticId=" + cookerStaticId + ": " + ex.Message);
                this.netCookCookerTypeFailedStaticIds.Add(cookerStaticId);
                cookerType = 0;
                return false;
            }
        }

