        private bool DrawRadarDropdownOption(int y, string label, bool selected)
        {
            Rect optionRect = new Rect(28f, y, 252f, 26f);
            GUIStyle optionStyle = this.themeTopTabStyle ?? this.themePanelStyle ?? GUI.skin.box;
            GUIStyle optionSelectedStyle = this.themeTopTabActiveStyle ?? this.themePrimaryButtonStyle ?? GUI.skin.box;
            GUI.Box(optionRect, "", selected ? optionSelectedStyle : optionStyle);

            if (GUI.Button(optionRect, "", GUIStyle.none))
            {
                return !selected;
            }

            GUIStyle labelStyle = new GUIStyle(GUI.skin.label);
            labelStyle.fontSize = 12;
            labelStyle.fontStyle = FontStyle.Bold;
            labelStyle.alignment = TextAnchor.MiddleCenter;
            labelStyle.normal.textColor = selected ? Color.white : new Color(this.uiTextR, this.uiTextG, this.uiTextB);
            GUI.Label(optionRect, this.L(label), labelStyle);

            return selected;
        }

        private string GetRadarSelectionSummary(List<string> selected)
        {
            if (selected == null || selected.Count == 0)
            {
                return this.L("None");
            }

            string joined = string.Join(", ", selected.Select(new Func<string, string>(this.L)).ToArray());
            const int maxLen = 30;
            if (joined.Length <= maxLen)
            {
                return joined;
            }

            return joined.Substring(0, maxLen - 3) + "...";
        }

        private void RemoveTrackedMarkersByNameContains(string targetNamePart)
        {
            if (string.IsNullOrEmpty(targetNamePart) || this.radarContainer == null)
            {
                return;
            }

            List<GameObject> markersToDestroy = new List<GameObject>();
            List<int> trackedIdsToRemove = new List<int>();

            foreach (KeyValuePair<int, GameObject> entry in this.trackedObjectMarkers)
            {
                GameObject marker = entry.Value;
                if (marker == null || !marker.name.StartsWith("TrackedMarker_"))
                {
                    continue;
                }

                GameObject target = null;
                foreach (KeyValuePair<GameObject, GameObject> mapping in this.markerToTarget)
                {
                    if (mapping.Key == marker)
                    {
                        target = mapping.Value;
                        break;
                    }
                }

                if (target != null && target.name.ToLower().Contains(targetNamePart))
                {
                    markersToDestroy.Add(marker);
                    trackedIdsToRemove.Add(entry.Key);
                }
            }

            foreach (GameObject marker in markersToDestroy)
            {
                this.markerToTarget.Remove(marker);
                Object.Destroy(marker);
            }

            foreach (int id in trackedIdsToRemove)
            {
                this.trackedObjectMarkers.Remove(id);
            }
        }

        private bool IsLikelyWorldMiscTarget(GameObject obj)
        {
            if (obj == null || !obj.activeInHierarchy)
            {
                return false;
            }

            Renderer r = obj.GetComponent<Renderer>();
            if (r != null)
            {
                return true;
            }

            return obj.GetComponentInChildren<Renderer>(true) != null;
        }

        private bool ShouldTrackBubbleObject(string lowerName)
        {
            if (string.IsNullOrEmpty(lowerName))
            {
                return false;
            }

            // Safe world-space bubble collectible visuals seen in Heartopia.
            if (lowerName.Contains("p_bubble_bubble_") && lowerName.Contains("(clone)"))
            {
                return true;
            }

            return false;
        }

        private bool IsUsableBubbleSceneObject(GameObject candidate)
        {
            if (candidate == null)
            {
                return false;
            }

            try
            {
                if (!candidate.scene.IsValid() || !candidate.scene.isLoaded)
                {
                    return false;
                }
            }
            catch
            {
                return false;
            }

            if ((candidate.hideFlags & HideFlags.HideAndDontSave) != 0)
            {
                return false;
            }

            if (!candidate.activeInHierarchy)
            {
                return false;
            }

            if (string.IsNullOrEmpty(candidate.name))
            {
                return false;
            }

            string lowerName = candidate.name.ToLowerInvariant();
            if (!this.ShouldTrackBubbleObject(lowerName))
            {
                return false;
            }

            // Keep the safe scan focused on world visuals instead of UI or unloaded assets.
            if (candidate.GetComponent<Canvas>() != null)
            {
                return false;
            }

            return this.HasLiveBubbleVisual(candidate);
        }

        private bool HasLiveBubbleVisual(GameObject candidate)
        {
            if (candidate == null || !candidate.activeInHierarchy)
            {
                return false;
            }

            try
            {
                Component[] components = candidate.GetComponentsInChildren<Component>(false);
                if (components != null)
                {
                    for (int i = 0; i < components.Length; i++)
                    {
                        Component component = components[i];
                        if (component == null || component.gameObject == null || !component.gameObject.activeInHierarchy)
                        {
                            continue;
                        }

                        Type componentType = component.GetType();
                        if (componentType == null || !string.Equals(componentType.Name, "ParticleSystem", StringComparison.Ordinal))
                        {
                            continue;
                        }

                        bool isPlaying = false;
                        int particleCount = 0;
                        bool isAlive = false;
                        try
                        {
                            PropertyInfo isPlayingProperty = componentType.GetProperty("isPlaying", BindingFlags.Public | BindingFlags.Instance);
                            if (isPlayingProperty != null)
                            {
                                object raw = isPlayingProperty.GetValue(component, null);
                                if (raw is bool rawBool)
                                {
                                    isPlaying = rawBool;
                                }
                            }
                        }
                        catch
                        {
                        }

                        try
                        {
                            PropertyInfo countProperty = componentType.GetProperty("particleCount", BindingFlags.Public | BindingFlags.Instance);
                            if (countProperty != null)
                            {
                                object raw = countProperty.GetValue(component, null);
                                if (raw != null)
                                {
                                    particleCount = Convert.ToInt32(raw);
                                }
                            }
                        }
                        catch
                        {
                        }

                        try
                        {
                            MethodInfo isAliveMethod = componentType.GetMethod("IsAlive", new Type[] { typeof(bool) });
                            if (isAliveMethod != null)
                            {
                                object raw = isAliveMethod.Invoke(component, new object[] { true });
                                if (raw is bool rawBool)
                                {
                                    isAlive = rawBool;
                                }
                            }
                        }
                        catch
                        {
                        }

                        if (isPlaying || particleCount > 0 || isAlive)
                        {
                            return true;
                        }
                    }
                }
            }
            catch
            {
            }

            try
            {
                Renderer[] renderers = candidate.GetComponentsInChildren<Renderer>(false);
                if (renderers != null)
                {
                    for (int i = 0; i < renderers.Length; i++)
                    {
                        Renderer renderer = renderers[i];
                        if (renderer != null && renderer.enabled && renderer.gameObject.activeInHierarchy)
                        {
                            return true;
                        }
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        private bool HasChildComponentNamed(Transform root, string componentTypeName)
        {
            if (root == null || string.IsNullOrEmpty(componentTypeName))
            {
                return false;
            }

            try
            {
                int childCount = root.childCount;
                for (int i = 0; i < childCount; i++)
                {
                    Transform child = root.GetChild(i);
                    if (child == null)
                    {
                        continue;
                    }

                    Component[] components = child.GetComponents<Component>();
                    if (components != null)
                    {
                        for (int j = 0; j < components.Length; j++)
                        {
                            Component component = components[j];
                            if (component != null && string.Equals(component.GetType().Name, componentTypeName, StringComparison.Ordinal))
                            {
                                return true;
                            }
                        }
                    }

                    if (this.HasChildComponentNamed(child, componentTypeName))
                    {
                        return true;
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        private bool TryGetAllSpawnedBubblePositionsSceneScan(Dictionary<int, Vector3> positions, out string status)
        {
            status = "Bubble scene scan unavailable";
            if (positions == null)
            {
                return false;
            }

            positions.Clear();
            this.bubbleRadarSceneTargets.Clear();

            try
            {
                GameObject[] sceneObjects = Resources.FindObjectsOfTypeAll<GameObject>();
                if (sceneObjects == null || sceneObjects.Length == 0)
                {
                    status = "Bubble scene scan found no objects";
                    return false;
                }

                int resolvedCount = 0;
                for (int i = 0; i < sceneObjects.Length; i++)
                {
                    GameObject candidate = sceneObjects[i];
                    try
                    {
                        if (!this.IsUsableBubbleSceneObject(candidate))
                        {
                            continue;
                        }

                        Vector3 bubblePos = candidate.transform.position;
                        if (bubblePos == Vector3.zero)
                        {
                            Component ps = candidate.GetComponent("ParticleSystem");
                            if (ps == null)
                            {
                                ps = this.FindChildComponentByName(candidate.transform, "ParticleSystem");
                            }

                            if (ps != null)
                            {
                                bubblePos = ps.transform.position;
                            }
                        }

                        if (bubblePos == Vector3.zero)
                        {
                            continue;
                        }

                        int instanceId = candidate.GetInstanceID();
                        positions[instanceId] = bubblePos;
                        this.bubbleRadarSceneTargets[instanceId] = candidate;
                        resolvedCount++;
                    }
                    catch
                    {
                        // Scene objects may be destroyed or reloaded while scanning; skip safely.
                    }
                }

                status = "Bubble scene scan resolved " + resolvedCount.ToString() + " bubble(s).";
                this.BubbleRadarLog("Scene bubble scan complete. resolved=" + resolvedCount.ToString() + " marker(s)");
                return resolvedCount > 0;
            }
            catch (Exception ex)
            {
                status = "Bubble scene scan failed: " + ex.GetType().Name + ": " + ex.Message;
                this.BubbleRadarLog("Scene bubble scan failed: " + ex.GetType().Name + " - " + ex.Message);
                return false;
            }
        }

        private Component FindChildComponentByName(Transform root, string componentTypeName)
        {
            if (root == null || string.IsNullOrEmpty(componentTypeName))
            {
                return null;
            }

            try
            {
                int childCount = root.childCount;
                for (int i = 0; i < childCount; i++)
                {
                    Transform child = root.GetChild(i);
                    if (child == null)
                    {
                        continue;
                    }

                    Component[] components = child.GetComponents<Component>();
                    if (components != null)
                    {
                        for (int j = 0; j < components.Length; j++)
                        {
                            Component component = components[j];
                            if (component != null && string.Equals(component.GetType().Name, componentTypeName, StringComparison.Ordinal))
                            {
                                return component;
                            }
                        }
                    }

                    Component nested = this.FindChildComponentByName(child, componentTypeName);
                    if (nested != null)
                    {
                        return nested;
                    }
                }
            }
            catch
            {
            }

            return null;
        }

        private bool TryGetAllSpawnedBubblePositionsManagedEntities(Dictionary<int, Vector3> positions, out string status)
        {
            status = "Bubble entity scan unavailable";
            if (positions == null)
            {
                return false;
            }

            positions.Clear();

            try
            {
                float now = Time.unscaledTime;
                if (now < this.nextBubbleEntityTypeResolveAttemptAt)
                {
                    status = "Bubble entity type resolve throttled";
                    return false;
                }

                this.nextBubbleEntityTypeResolveAttemptAt = now + BubbleRadarEntityTypeResolveRetryInterval;

                Type entitiesType = this.FindEntitiesRuntimeType();
                Type bubbleComponentType = this.FindBubbleComponentRuntimeType();
                if (entitiesType == null || bubbleComponentType == null)
                {
                    status = "Bubble entity types unavailable. entities=" + (entitiesType != null ? entitiesType.FullName : "null") + " bubble=" + (bubbleComponentType != null ? bubbleComponentType.FullName : "null");
                    this.BubbleRadarLogThrottled("managed-types-missing", status, 8f);
                    return false;
                }

                this.nextBubbleEntityTypeResolveAttemptAt = -999f;

                MethodInfo getComponentsMethod = entitiesType.GetMethods(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static)
                    .FirstOrDefault(m => m.Name == "GetComponents" && m.IsGenericMethodDefinition && m.GetParameters().Length == 1);
                if (getComponentsMethod == null)
                {
                    status = "Entities.GetComponents unavailable";
                    return false;
                }

                Type listType = typeof(List<>).MakeGenericType(bubbleComponentType);
                object componentList = Activator.CreateInstance(listType);
                object[] args = new object[] { componentList };
                getComponentsMethod.MakeGenericMethod(bubbleComponentType).Invoke(null, args);
                object results = args[0] ?? componentList;

                if (!(results is System.Collections.IEnumerable enumerable))
                {
                    status = "Bubble component list not enumerable";
                    return false;
                }

                int resolvedCount = 0;
                foreach (object component in enumerable)
                {
                    if (component == null)
                    {
                        continue;
                    }

                    try
                    {
                        if (!this.TryResolveManagedBubbleMarker(component, out int markerId, out Vector3 bubblePos))
                        {
                            continue;
                        }

                        positions[markerId] = bubblePos;
                        resolvedCount++;
                    }
                    catch
                    {
                    }
                }

                status = "Bubble entity scan resolved " + resolvedCount.ToString() + " bubble(s).";
                this.BubbleRadarLog("Managed bubble entity scan complete. resolved=" + resolvedCount.ToString() + " marker(s)");
                return resolvedCount > 0;
            }
            catch (Exception ex)
            {
                status = "Bubble entity scan failed: " + ex.GetType().Name + ": " + ex.Message;
                this.BubbleRadarLog("Managed bubble entity scan failed: " + ex.GetType().Name + " - " + ex.Message);
                return false;
            }
        }

        private Type FindBubbleComponentRuntimeType()
        {
            Type resolved = this.FindLoadedType(
                "XDTLevelAndEntity.Gameplay.Component.Bubble.BubbleComponent",
                "XDTLevelAndEntity.GamePlay.Component.Bubble.BubbleComponent",
                "Il2CppXDTLevelAndEntity.Gameplay.Component.Bubble.BubbleComponent",
                "Il2CppXDTLevelAndEntity.GamePlay.Component.Bubble.BubbleComponent",
                "BubbleComponent")
                ?? this.FindLoadedTypeBySuffix(
                    "Gameplay.Component.Bubble.BubbleComponent",
                    "GamePlay.Component.Bubble.BubbleComponent",
                    ".BubbleComponent");
            if (resolved != null)
            {
                return resolved;
            }

            try
            {
                foreach (Assembly assembly in AppDomain.CurrentDomain.GetAssemblies())
                {
                    Type[] types;
                    try
                    {
                        types = assembly.GetTypes();
                    }
                    catch
                    {
                        continue;
                    }

                    foreach (Type type in types)
                    {
                        if (type == null || !string.Equals(type.Name, "BubbleComponent", StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        string fullName = type.FullName ?? string.Empty;
                        if (fullName.IndexOf("Chat", StringComparison.OrdinalIgnoreCase) >= 0
                            || fullName.IndexOf("Widget", StringComparison.OrdinalIgnoreCase) >= 0)
                        {
                            continue;
                        }

                        if (type.GetProperty("ComponentData", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance) != null
                            || type.GetField("_componentData", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance) != null)
                        {
                            return type;
                        }
                    }
                }
            }
            catch
            {
            }

            return null;
        }

        private bool TryResolveManagedBubbleMarker(object bubbleComponent, out int markerId, out Vector3 position)
        {
            markerId = 0;
            position = Vector3.zero;
            if (bubbleComponent == null)
            {
                return false;
            }

            object componentData = this.TryGetManagedMemberValue(bubbleComponent, "ComponentData")
                ?? this.TryGetManagedMemberValue(bubbleComponent, "_componentData")
                ?? this.TryGetManagedMemberValue(bubbleComponent, "componentData");
            if (componentData == null)
            {
                return false;
            }

            int bubbleId = this.TryReadIntMember(componentData, "bubbleId", out int resolvedBubbleId) ? resolvedBubbleId : 0;
            uint netId = 0U;
            object entityObj = this.TryGetManagedMemberValue(bubbleComponent, "entity");
            if (entityObj != null)
            {
                if (!this.TryReadManagedNetIdMember(entityObj, "netId", out netId))
                {
                    this.TryInvokeManagedNetIdMethod(entityObj, "GetNetId", out netId);
                }

                if (this.TryGetObjectMember(entityObj, "position", out object entityPositionObj) && entityPositionObj is Vector3 entityPosition && entityPosition != Vector3.zero)
                {
                    position = entityPosition;
                }
                else if (this.TryGetObjectMember(entityObj, "worldPosition", out object entityWorldPositionObj) && entityWorldPositionObj is Vector3 entityWorldPosition && entityWorldPosition != Vector3.zero)
                {
                    position = entityWorldPosition;
                }
            }

            if (position == Vector3.zero && this.TryGetObjectMember(bubbleComponent, "transform", out object transformObj) && transformObj is Transform componentTransform && componentTransform != null)
            {
                position = componentTransform.position;
            }

            if (position == Vector3.zero && this.TryGetObjectMember(componentData, "bornPosition", out object bornPositionObj) && bornPositionObj is Vector3 bornPosition && bornPosition != Vector3.zero)
            {
                position = bornPosition;
            }

            if (position == Vector3.zero && this.TryGetObjectMember(componentData, "tarPosition", out object targetPositionObj) && targetPositionObj is Vector3 targetPosition && targetPosition != Vector3.zero)
            {
                position = targetPosition;
            }

            if (position == Vector3.zero && netId != 0U)
            {
                if (!this.TryGetEntityPositionByNetIdMono(netId, out position))
                {
                    this.TryGetEntityPositionByNetId(netId, out position);
                }
            }

            if (netId != 0U)
            {
                markerId = unchecked((int)netId);
            }
            else if (bubbleId != 0)
            {
                markerId = bubbleId;
            }
            else if (this.TryReadFloatMember(componentData, "bubbleLocationID", out float bubbleLocationId) && Math.Abs(bubbleLocationId) > 0.001f)
            {
                markerId = Mathf.RoundToInt(bubbleLocationId * 1000f);
            }

            if (markerId == 0 && position != Vector3.zero)
            {
                markerId = (Mathf.RoundToInt(position.x * 10f) * 397) ^ Mathf.RoundToInt(position.z * 10f);
            }

            return markerId != 0 && position != Vector3.zero;
        }

        private bool TryGetAllSpawnedBubblePositions(Dictionary<int, Vector3> positions, out string status)
        {
            status = "Bubble service unavailable";
            if (positions == null)
            {
                return false;
            }

            positions.Clear();

            try
            {
                if (!this.TryGetBubbleClientService(out object bubbleService, out status) || bubbleService == null)
                {
                    bool entityResolved = this.TryGetAllSpawnedBubblePositionsManagedEntities(positions, out string entityStatus);
                    if (entityResolved)
                    {
                        status = "Bubble entity scan ready. " + entityStatus;
                        return true;
                    }

                    string auraStatus = "Aura bubble scan disabled by safe mode";
                    bool auraResolved = false;
                    if (BubbleRadarUnsafeAuraMonoScanEnabled)
                    {
                        auraResolved = this.TryGetAllSpawnedBubblePositionsAuraMonoSafe(positions, out auraStatus);
                        if (auraResolved)
                        {
                            status = "Aura bubble scan ready. " + auraStatus;
                            return true;
                        }
                    }

                    bool auraCoolingDown = !string.IsNullOrEmpty(auraStatus)
                        && (auraStatus.IndexOf("throttled", StringComparison.OrdinalIgnoreCase) >= 0
                            || auraStatus.IndexOf("waiting for world settle", StringComparison.OrdinalIgnoreCase) >= 0);
                    if (auraCoolingDown && this.lastAuraBubbleScanSuccessAt > 0f)
                    {
                        status = "Aura bubble snapshot retained. " + auraStatus;
                        return false;
                    }

                    bool sceneResolved = this.TryGetAllSpawnedBubblePositionsSceneScan(positions, out string sceneStatus);
                    status = sceneResolved
                        ? status + " | Bubble scene scan ready. " + sceneStatus
                        : status + " | Entity fallback: " + entityStatus + " | Aura fallback: " + auraStatus + " | Scene fallback: " + sceneStatus;
                    return sceneResolved;
                }

                Type runtimeType = bubbleService.GetType();
                if (this.cachedBubbleClientServiceGetAllMethod == null || this.cachedBubbleClientServiceGetAllMethod.DeclaringType != runtimeType)
                {
                    this.cachedBubbleClientServiceGetAllMethod = runtimeType.GetMethods(BindingFlags.Public | BindingFlags.Instance)
                        .FirstOrDefault(m => m.Name == "GmGetAllBubble" && m.GetParameters().Length >= 1);
                }

                if (this.cachedBubbleClientServiceGetAllMethod == null)
                {
                    status = "BubbleClientService.GmGetAllBubble unavailable";
                    return false;
                }

                ParameterInfo[] parameters = this.cachedBubbleClientServiceGetAllMethod.GetParameters();
                Type ecsEntityType = this.ResolveBubbleEntityListElementType(parameters[0].ParameterType);
                if (ecsEntityType == null)
                {
                    status = "Bubble entity list type unavailable";
                    return false;
                }

                Type listType = typeof(List<>).MakeGenericType(ecsEntityType);
                object bubbleList = Activator.CreateInstance(listType);
                object[] args = parameters.Length >= 2
                    ? new object[] { bubbleList, -1 }
                    : new object[] { bubbleList };
                this.cachedBubbleClientServiceGetAllMethod.Invoke(bubbleService, args);

                if (!(bubbleList is System.Collections.IEnumerable enumerable))
                {
                    status = "Bubble list not enumerable";
                    return false;
                }

                int resolvedCount = 0;
                foreach (object bubbleEntity in enumerable)
                {
                    if (!this.TryResolveBubbleEntityMarker(bubbleEntity, out int markerId, out Vector3 bubblePos))
                    {
                        continue;
                    }

                    positions[markerId] = bubblePos;
                    resolvedCount++;
                }

                status = "Bubble ECS scan resolved " + resolvedCount.ToString() + " bubble(s).";
                this.BubbleRadarLog("ECS bubble fetch complete. resolved=" + resolvedCount.ToString() + " marker(s)");
                return resolvedCount > 0;
            }
            catch (Exception ex)
            {
                this.BubbleRadarLog("ECS bubble fetch failed: " + ex.GetType().Name + " - " + ex.Message);
                bool entityResolved = this.TryGetAllSpawnedBubblePositionsManagedEntities(positions, out string entityStatus);
                if (entityResolved)
                {
                    status = "Bubble ECS scan failed: " + ex.GetType().Name + " | Bubble entity scan ready. " + entityStatus;
                    return true;
                }

                string auraStatus = "Aura bubble scan disabled by safe mode";
                bool auraResolved = false;
                if (BubbleRadarUnsafeAuraMonoScanEnabled)
                {
                    auraResolved = this.TryGetAllSpawnedBubblePositionsAuraMonoSafe(positions, out auraStatus);
                    if (auraResolved)
                    {
                        status = "Bubble ECS scan failed: " + ex.GetType().Name + " | Aura bubble scan ready. " + auraStatus;
                        return true;
                    }
                }

                bool auraCoolingDown = !string.IsNullOrEmpty(auraStatus)
                    && (auraStatus.IndexOf("throttled", StringComparison.OrdinalIgnoreCase) >= 0
                        || auraStatus.IndexOf("waiting for world settle", StringComparison.OrdinalIgnoreCase) >= 0);
                if (auraCoolingDown && this.lastAuraBubbleScanSuccessAt > 0f)
                {
                    status = "Bubble ECS scan failed: " + ex.GetType().Name + " | Aura bubble snapshot retained. " + auraStatus;
                    return false;
                }

                bool sceneResolved = this.TryGetAllSpawnedBubblePositionsSceneScan(positions, out string sceneStatus);
                status = sceneResolved
                    ? "Bubble ECS scan failed: " + ex.GetType().Name + " | Bubble scene scan ready. " + sceneStatus
                    : "Bubble ECS scan failed: " + ex.GetType().Name + " | Entity fallback: " + entityStatus + " | Aura fallback: " + auraStatus + " | Scene fallback: " + sceneStatus;
                return sceneResolved;
            }
        }

        private bool TryGetBubbleClientService(out object bubbleService, out string status)
        {
            bubbleService = null;
            status = "Bubble service unavailable";

            try
            {
                if (this.cachedBubbleClientServiceTryGetMethod == null || this.cachedBubbleClientServiceType == null)
                {
                    float now = Time.unscaledTime;
                    if (now < this.nextBubbleClientServiceResolveAttemptAt)
                    {
                        status = "Bubble service resolve throttled";
                        this.BubbleRadarLogThrottled("service-throttled", "Bubble service resolve throttled.", 4f);
                        return false;
                    }

                    this.nextBubbleClientServiceResolveAttemptAt = now + BubbleRadarServiceResolveRetryInterval;

                    Type ecsServiceType = this.FindLoadedType(
                        "XDTDataAndProtocol.ProtocolService.EcsService",
                        "Il2CppXDTDataAndProtocol.ProtocolService.EcsService",
                        "EcsService")
                        ?? this.FindLoadedTypeBySuffix("ProtocolService.EcsService", "EcsService")
                        ?? this.FindLoadedEcsServiceType();
                    Type bubbleServiceType = this.FindLoadedType(
                        "XDTDataAndProtocol.ProtocolService.Bubble.IBubbleService",
                        "Il2CppXDTDataAndProtocol.ProtocolService.Bubble.IBubbleService",
                        "IBubbleService",
                        "ClientSystem.Bubble.BubbleClientService",
                        "Il2CppClientSystem.Bubble.BubbleClientService",
                        "BubbleClientService")
                        ?? this.FindLoadedTypeBySuffix("Bubble.IBubbleService", "IBubbleService", "Bubble.BubbleClientService", "BubbleClientService")
                        ?? this.FindLoadedBubbleServiceType();
                    if (ecsServiceType == null || bubbleServiceType == null)
                    {
                        status = "Bubble service types unavailable";
                        this.BubbleRadarLogThrottled("service-types-missing", "Bubble service types unavailable. ecs=" + (ecsServiceType != null ? ecsServiceType.FullName : "null") + " bubble=" + (bubbleServiceType != null ? bubbleServiceType.FullName : "null"), 8f);
                        return false;
                    }

                    MethodInfo tryGetMethod = ecsServiceType.GetMethods(BindingFlags.Public | BindingFlags.Static)
                        .FirstOrDefault(m => m.Name == "TryGet" && m.IsGenericMethodDefinition && m.GetParameters().Length == 2);
                    if (tryGetMethod == null)
                    {
                        status = "EcsService.TryGet unavailable";
                        this.nextBubbleClientServiceResolveAttemptAt = now + BubbleRadarServiceResolveRetryInterval;
                        this.BubbleRadarLogThrottled("service-tryget-missing", "EcsService.TryGet unavailable for bubble radar.", 8f);
                        return false;
                    }

                    this.cachedBubbleClientServiceType = bubbleServiceType;
                    this.cachedBubbleClientServiceTryGetMethod = tryGetMethod.MakeGenericMethod(bubbleServiceType);
                    this.nextBubbleClientServiceResolveAttemptAt = -999f;
                    this.BubbleRadarLog("Resolved bubble service types. ecs=" + ecsServiceType.FullName + " bubble=" + bubbleServiceType.FullName);
                }

                object[] serviceArgs = new object[] { null, true };
                object serviceResult = this.cachedBubbleClientServiceTryGetMethod.Invoke(null, serviceArgs);
                if (!(serviceResult is bool) || !(bool)serviceResult || serviceArgs[0] == null)
                {
                    status = "IBubbleService unavailable";
                    this.BubbleRadarLogThrottled("service-unavailable", "IBubbleService unavailable.", 4f);
                    return false;
                }

                bubbleService = serviceArgs[0];
                status = "Bubble service ready";
                this.BubbleRadarLogThrottled("service-ready", "Bubble service ready via " + bubbleService.GetType().FullName, 12f);
                return true;
            }
            catch (Exception ex)
            {
                status = "Bubble service resolve failed: " + ex.GetType().Name;
                this.BubbleRadarLog("Bubble service resolve failed: " + ex.GetType().Name + " - " + ex.Message);
                return false;
            }
        }

        private bool TryGetAllSpawnedBubblePositionsAuraMono(Dictionary<int, Vector3> positions, out string status)
        {
            status = "Aura bubble scan unavailable";
            if (positions == null)
            {
                return false;
            }

            positions.Clear();

            try
            {
                if (!this.TryEnumerateAuraMonoLoadedEntityObjects(out List<IntPtr> entityObjects, out string entityStatus) || entityObjects == null || entityObjects.Count == 0)
                {
                    status = "Aura entity enumeration unavailable: " + entityStatus;
                    return false;
                }

                int inspected = 0;
                int bubbleMatches = 0;
                foreach (IntPtr entityObj in entityObjects)
                {
                    if (entityObj == IntPtr.Zero)
                    {
                        continue;
                    }

                    inspected++;
                    if (!this.TryResolveAuraMonoBubbleEntityMarker(entityObj, out int markerId, out Vector3 bubblePos))
                    {
                        continue;
                    }

                    positions[markerId] = bubblePos;
                    bubbleMatches++;
                }

                status = bubbleMatches > 0
                    ? $"Aura bubble scan resolved {bubbleMatches}/{inspected} bubble(s)"
                    : (inspected > 0 ? $"Aura bubble scan inspected {inspected} entities but found no bubbles" : "Aura bubble entity list empty");
                this.BubbleRadarLog("Aura bubble scan complete. inspected=" + inspected + " resolved=" + bubbleMatches);
                return bubbleMatches > 0;
            }
            catch (Exception ex)
            {
                status = "Aura bubble scan exception: " + ex.GetType().Name + ": " + ex.Message;
                this.BubbleRadarLog("Aura bubble scan exception: " + ex.GetType().Name + " - " + ex.Message);
                return false;
            }
        }

        private bool TryGetAllSpawnedBubblePositionsAuraMonoSafe(Dictionary<int, Vector3> positions, out string status)
        {
            status = "Aura bubble scan throttled";
            if (positions == null)
            {
                return false;
            }

            float now = Time.unscaledTime;
            if (this.bubbleRadarActivatedAt > 0f && now - this.bubbleRadarActivatedAt < BubbleRadarAuraInitialSettleDelay)
            {
                status = "Aura bubble scan waiting for world settle";
                this.BubbleRadarLogThrottled("aura-scan-settle", "Aura bubble scan waiting for world settle.", 4f);
                return false;
            }

            if (now < this.nextAuraBubbleScanAttemptAt)
            {
                this.BubbleRadarLogThrottled("aura-scan-throttled", "Aura bubble scan throttled.", 6f);
                return false;
            }

            bool resolved = this.TryGetAllSpawnedBubblePositionsAuraMono(positions, out status);
            if (resolved)
            {
                this.lastAuraBubbleScanSuccessAt = now;
                this.lastAuraBubbleScanFailureAt = -999f;
                this.bubbleRadarAuraConsecutiveFailures = 0;
                this.nextAuraBubbleScanAttemptAt = now + BubbleRadarAuraSuccessRefreshInterval;
                return true;
            }

            this.lastAuraBubbleScanFailureAt = now;
            this.bubbleRadarAuraConsecutiveFailures = Mathf.Min(this.bubbleRadarAuraConsecutiveFailures + 1, 6);
            float retryDelay = Mathf.Min(
                BubbleRadarAuraRetryInterval * Mathf.Pow(1.5f, this.bubbleRadarAuraConsecutiveFailures - 1),
                BubbleRadarAuraMaxFailureBackoff);
            this.nextAuraBubbleScanAttemptAt = now + retryDelay;
            return false;
        }

        private bool TryResolveAuraMonoBubbleEntityMarker(IntPtr entityObj, out int markerId, out Vector3 position)
        {
            markerId = 0;
            position = Vector3.zero;
            if (entityObj == IntPtr.Zero || !this.EnsureAuraMonoApiReady() || !this.AttachAuraMonoThread() || auraMonoObjectGetClass == null)
            {
                return false;
            }

            try
            {
                IntPtr entityClass = auraMonoObjectGetClass(entityObj);
                if (entityClass == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr getAllComponentsMethod = this.FindAuraMonoMethodOnHierarchy(entityClass, "GetAllComponents", 0);
                if (getAllComponentsMethod == IntPtr.Zero || auraMonoRuntimeInvoke == null)
                {
                    return false;
                }

                IntPtr invokeExc = IntPtr.Zero;
                IntPtr componentsObj = auraMonoRuntimeInvoke(getAllComponentsMethod, entityObj, IntPtr.Zero, ref invokeExc);
                if (invokeExc != IntPtr.Zero || componentsObj == IntPtr.Zero)
                {
                    return false;
                }

                List<IntPtr> components = this.bubbleRadarAuraComponentsBuffer;
                components.Clear();
                if (!this.TryEnumerateAuraMonoCollectionItems(componentsObj, components) || components.Count <= 0)
                {
                    return false;
                }

                bool hasBubbleSignature = false;
                int bid = 0;
                int refreshType = 0;
                uint netId = 0U;
                for (int i = 0; i < components.Count && i < 96; i++)
                {
                    IntPtr componentObj = components[i];
                    if (componentObj == IntPtr.Zero)
                    {
                        continue;
                    }

                    string className = this.GetAuraMonoClassDisplayName(auraMonoObjectGetClass(componentObj));
                    if (string.IsNullOrEmpty(className) || className.IndexOf("Bubble", StringComparison.OrdinalIgnoreCase) < 0)
                    {
                        continue;
                    }

                    hasBubbleSignature = true;

                    if (className.IndexOf("BubbleLocationComponent", StringComparison.OrdinalIgnoreCase) >= 0)
                    {
                        if (!this.TryResolveAuraMonoBubbleLocation(componentObj, out position))
                        {
                            this.TryResolveAuraMonoBubbleLocationFromNestedData(componentObj, out position);
                        }
                    }
                    else if (className.IndexOf("BubbleIdComponent", StringComparison.OrdinalIgnoreCase) >= 0)
                    {
                        this.TryGetMonoInt32Member(componentObj, "bid", out bid);
                        this.TryGetMonoInt32Member(componentObj, "type", out refreshType);
                        if (netId == 0U)
                        {
                            this.TryGetMonoUInt32Member(componentObj, "netId", out netId);
                            if (netId == 0U)
                            {
                                this.TryGetMonoUInt32Member(componentObj, "_netId", out netId);
                            }
                        }
                    }
                }

                if (!hasBubbleSignature)
                {
                    return false;
                }

                if (netId == 0U)
                {
                    this.TryGetAuraMonoEntityNetId(entityObj, out netId);
                }

                if (position == Vector3.zero)
                {
                    this.TryGetAuraMonoEntityPosition(entityObj, out position);
                }

                if (position == Vector3.zero && netId != 0U)
                {
                    if (!this.TryGetEntityPositionByNetIdMono(netId, out position))
                    {
                        this.TryGetEntityPositionByNetId(netId, out position);
                    }
                }

                if (netId != 0U)
                {
                    markerId = unchecked((int)netId);
                }

                if (markerId == 0 && (bid != 0 || refreshType != 0))
                {
                    markerId = (bid * 397) ^ (refreshType * 31);
                }

                if (markerId == 0 && position != Vector3.zero)
                {
                    markerId = (Mathf.RoundToInt(position.x * 10f) * 397) ^ Mathf.RoundToInt(position.z * 10f);
                }

                return markerId != 0 && position != Vector3.zero;
            }
            catch (Exception ex)
            {
                this.BubbleRadarLogThrottled("aura-entity-resolve-error", "Aura bubble entity resolve error: " + ex.GetType().Name + " - " + ex.Message, 6f);
                return false;
            }
        }

        private bool TryResolveAuraMonoBubbleLocation(IntPtr componentObj, out Vector3 position)
        {
            position = Vector3.zero;
            if (componentObj == IntPtr.Zero)
            {
                return false;
            }

            foreach (string memberName in new[] { "value", "Value", "position", "Position", "worldPosition", "WorldPosition" })
            {
                if (this.TryGetMonoVector3Member(componentObj, memberName, out position) && position != Vector3.zero)
                {
                    return true;
                }
            }

            return false;
        }

        private bool TryResolveAuraMonoBubbleLocationFromNestedData(IntPtr componentObj, out Vector3 position)
        {
            position = Vector3.zero;
            if (componentObj == IntPtr.Zero)
            {
                return false;
            }

            foreach (string dataMemberName in new[] { "ComponentData", "_componentData", "componentData", "data", "_data" })
            {
                if (!this.TryGetMonoObjectMember(componentObj, dataMemberName, out IntPtr dataObj) || dataObj == IntPtr.Zero)
                {
                    continue;
                }

                if (this.TryResolveAuraMonoBubbleLocation(dataObj, out position))
                {
                    return true;
                }
            }

            return false;
        }

        private Type ResolveBubbleEntityListElementType(Type listType)
        {
            if (listType == null)
            {
                return null;
            }

            if (listType.IsGenericType)
            {
                Type[] args = listType.GetGenericArguments();
                if (args.Length == 1)
                {
                    return args[0];
                }
            }

            Type listInterface = listType.GetInterfaces()
                .FirstOrDefault(t => t.IsGenericType && t.GetGenericTypeDefinition() == typeof(IList<>));
            if (listInterface != null)
            {
                Type[] args = listInterface.GetGenericArguments();
                if (args.Length == 1)
                {
                    return args[0];
                }
            }

            return null;
        }

        private bool TryResolveBubbleEntityMarker(object bubbleEntity, out int markerId, out Vector3 position)
        {
            markerId = 0;
            position = Vector3.zero;

            if (bubbleEntity == null)
            {
                return false;
            }

            try
            {
                if (this.cachedBubbleOptDataType == null)
                {
                    this.cachedBubbleOptDataType = this.FindLoadedType(
                        "XDT.Scene.Shared.Entity.EntityOptData.BubbleEntityOptData",
                        "Il2CppXDT.Scene.Shared.Entity.EntityOptData.BubbleEntityOptData",
                        "BubbleEntityOptData")
                        ?? this.FindLoadedTypeBySuffix("BubbleEntityOptData");
                }

                if (this.cachedBubbleOptDataType == null)
                {
                    return false;
                }

                if (this.cachedBubbleOptDataAsMethod == null)
                {
                    this.cachedBubbleOptDataAsMethod = this.cachedBubbleOptDataType.GetMethods(BindingFlags.Public | BindingFlags.Static)
                        .FirstOrDefault(m => m.Name == "As" && m.GetParameters().Length >= 1);
                }

                if (this.cachedBubbleOptDataAsMethod == null)
                {
                    return false;
                }

                ParameterInfo[] asParameters = this.cachedBubbleOptDataAsMethod.GetParameters();
                object[] asArgs = asParameters.Length >= 2
                    ? new object[] { bubbleEntity, Activator.CreateInstance(asParameters[1].ParameterType) }
                    : new object[] { bubbleEntity };
                object bubbleOptData = this.cachedBubbleOptDataAsMethod.Invoke(null, asArgs);
                if (bubbleOptData == null)
                {
                    return false;
                }

                if (this.cachedBubbleOptDataGetNetIdMethod == null)
                {
                    this.cachedBubbleOptDataGetNetIdMethod = this.cachedBubbleOptDataType.GetMethod("GetNetId", BindingFlags.Public | BindingFlags.Instance);
                }

                uint netId = 0U;
                if (this.cachedBubbleOptDataGetNetIdMethod != null)
                {
                    object netIdObj = this.cachedBubbleOptDataGetNetIdMethod.Invoke(bubbleOptData, null);
                    this.TryConvertToUInt(netIdObj, out netId);
                }

                if (this.cachedBubbleLocationComponentType == null)
                {
                    this.cachedBubbleLocationComponentType = this.FindLoadedType(
                        "XDT.Scene.Shared.Modules.Bubble.BubbleLocationComponent",
                        "Il2CppXDT.Scene.Shared.Modules.Bubble.BubbleLocationComponent",
                        "BubbleLocationComponent")
                        ?? this.FindLoadedTypeBySuffix("BubbleLocationComponent");
                }

                if (this.TryGetBubbleOptComponentValue(bubbleOptData, "BubbleLocationComponent", this.cachedBubbleLocationComponentType, out object locationCompObj)
                    && this.TryGetObjectMember(locationCompObj, "value", out object locationValueObj)
                    && locationValueObj is Vector3 locationVector)
                {
                    position = locationVector;
                }

                if (position == Vector3.zero && netId != 0U)
                {
                    if (!this.TryGetEntityPositionByNetIdMono(netId, out position))
                    {
                        this.TryGetEntityPositionByNetId(netId, out position);
                    }
                }

                if (netId != 0U)
                {
                    markerId = unchecked((int)netId);
                }

                if (markerId == 0)
                {
                    if (this.cachedBubbleIdComponentType == null)
                    {
                        this.cachedBubbleIdComponentType = this.FindLoadedType(
                            "XDT.Scene.Shared.Modules.Bubble.BubbleIdComponent",
                            "Il2CppXDT.Scene.Shared.Modules.Bubble.BubbleIdComponent",
                            "BubbleIdComponent")
                            ?? this.FindLoadedTypeBySuffix("BubbleIdComponent");
                    }

                    if (this.TryGetBubbleOptComponentValue(bubbleOptData, "BubbleIdComponent", this.cachedBubbleIdComponentType, out object bubbleIdCompObj))
                    {
                        int bid = this.TryReadIntMember(bubbleIdCompObj, "bid", out int bidValue) ? bidValue : 0;
                        int refreshType = this.TryReadIntMember(bubbleIdCompObj, "type", out int typeValue) ? typeValue : 0;
                        float bubbleLocationId = this.TryReadFloatMember(bubbleIdCompObj, "bubbleLocationId", out float locationIdValue) ? locationIdValue : 0f;
                        markerId = (bid * 397) ^ (refreshType * 31) ^ Mathf.RoundToInt(bubbleLocationId * 1000f);
                        if (markerId == 0)
                        {
                            markerId = (Mathf.RoundToInt(position.x * 10f) * 397) ^ Mathf.RoundToInt(position.z * 10f);
                        }
                    }
                }

                return markerId != 0 && position != Vector3.zero;
            }
            catch
            {
                return false;
            }
        }

        private bool TryGetBubbleOptComponentValue(object bubbleOptData, string propertyName, Type componentType, out object componentValue)
        {
            componentValue = null;
            if (bubbleOptData == null || componentType == null)
            {
                return false;
            }

            try
            {
                PropertyInfo componentProperty = null;
                if (propertyName == "BubbleLocationComponent")
                {
                    if (this.cachedBubbleOptDataLocationProperty == null)
                    {
                        this.cachedBubbleOptDataLocationProperty = this.cachedBubbleOptDataType.GetProperty(propertyName, BindingFlags.Public | BindingFlags.Instance);
                    }
                    componentProperty = this.cachedBubbleOptDataLocationProperty;
                }
                else if (propertyName == "BubbleIdComponent")
                {
                    if (this.cachedBubbleOptDataIdProperty == null)
                    {
                        this.cachedBubbleOptDataIdProperty = this.cachedBubbleOptDataType.GetProperty(propertyName, BindingFlags.Public | BindingFlags.Instance);
                    }
                    componentProperty = this.cachedBubbleOptDataIdProperty;
                }
                else
                {
                    componentProperty = this.cachedBubbleOptDataType.GetProperty(propertyName, BindingFlags.Public | BindingFlags.Instance);
                }

                if (componentProperty == null)
                {
                    return false;
                }

                object entityDataOptObj = componentProperty.GetValue(bubbleOptData, null);
                if (entityDataOptObj == null)
                {
                    return false;
                }

                if (this.cachedEntityDataOptTryGetValueMethod == null)
                {
                    Type entityDataOptType = this.FindLoadedType("XDT.Scene.Shared.Entity.EntityOptData.EntityDataOpt", "EntityDataOpt");
                    if (entityDataOptType == null)
                    {
                        return false;
                    }

                    this.cachedEntityDataOptTryGetValueMethod = entityDataOptType.GetMethods(BindingFlags.Public | BindingFlags.Static)
                        .FirstOrDefault(m => m.Name == "TryGetValue" && m.IsGenericMethodDefinition && m.GetParameters().Length == 2);
                }

                if (this.cachedEntityDataOptTryGetValueMethod == null)
                {
                    return false;
                }

                object[] args = new object[] { entityDataOptObj, null };
                object result = this.cachedEntityDataOptTryGetValueMethod.MakeGenericMethod(componentType).Invoke(null, args);
                if (result is bool && (bool)result && args[1] != null)
                {
                    componentValue = args[1];
                    return true;
                }
            }
            catch
            {
            }

            return false;
        }

        private bool TryReadIntMember(object instance, string memberName, out int value)
        {
            value = 0;
            if (instance == null || string.IsNullOrEmpty(memberName))
            {
                return false;
            }

            try
            {
                if (!this.TryGetObjectMember(instance, memberName, out object raw) || raw == null)
                {
                    return false;
                }

                if (raw is Enum)
                {
                    value = Convert.ToInt32(raw);
                    return true;
                }

                value = Convert.ToInt32(raw);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private bool TryReadFloatMember(object instance, string memberName, out float value)
        {
            value = 0f;
            if (instance == null || string.IsNullOrEmpty(memberName))
            {
                return false;
            }

            try
            {
                if (!this.TryGetObjectMember(instance, memberName, out object raw) || raw == null)
                {
                    return false;
                }

                value = Convert.ToSingle(raw);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private bool ShouldRetainEmptyBubbleSceneSnapshot(Vector3 scanOrigin)
        {
            return this.bubbleRadarSnapshotPositions.Count > 0;
        }

        private bool ShouldRetainMissingBubbleSceneMarker(Vector3 scanOrigin, Vector3 lastKnownBubblePos)
        {
            float retainDistanceSqr = BubbleRadarSceneMissingRetainMinDistance * BubbleRadarSceneMissingRetainMinDistance;
            return (scanOrigin - lastKnownBubblePos).sqrMagnitude >= retainDistanceSqr;
        }

        private void SyncBubbleRadarMarkers(Vector3 scanOrigin, Material xRay, Material bg)
        {
            float now = Time.unscaledTime;
            float sinceLastRefresh = now - this._cachedBubbleRadarAt;
            bool snapshotEmpty = this.bubbleRadarSnapshotPositions.Count == 0;
            float rescanMoveThresholdSqr = BubbleRadarRescanMoveThreshold * BubbleRadarRescanMoveThreshold;
            bool movedFarEnough = this.bubbleRadarHasLastScanOrigin
                && (scanOrigin - this.bubbleRadarLastScanOrigin).sqrMagnitude >= rescanMoveThresholdSqr;
            bool shouldRefresh = this.bubbleRadarForceRefresh
                || (snapshotEmpty ? sinceLastRefresh > BubbleRadarEmptyRefreshInterval : sinceLastRefresh > BubbleRadarRefreshInterval)
                || (movedFarEnough && sinceLastRefresh > BubbleRadarMovedRefreshInterval);

            if (shouldRefresh)
            {
                Dictionary<int, Vector3> refreshedSnapshot = new Dictionary<int, Vector3>();
                bool refreshed = this.TryGetAllSpawnedBubblePositions(refreshedSnapshot, out string refreshStatus);
                bool sceneOnlySnapshot = !string.IsNullOrEmpty(refreshStatus)
                    && refreshStatus.IndexOf("Bubble scene scan", StringComparison.OrdinalIgnoreCase) >= 0
                    && refreshStatus.IndexOf("Bubble entity scan ready", StringComparison.OrdinalIgnoreCase) < 0
                    && refreshStatus.IndexOf("Bubble ECS scan resolved", StringComparison.OrdinalIgnoreCase) < 0
                    && refreshStatus.IndexOf("Bubble service ready", StringComparison.OrdinalIgnoreCase) < 0;
                bool retainedSnapshot = !string.IsNullOrEmpty(refreshStatus)
                    && refreshStatus.IndexOf("snapshot retained", StringComparison.OrdinalIgnoreCase) >= 0;

                if (refreshed)
                {
                    if (sceneOnlySnapshot)
                    {
                        foreach (int staleBubbleId in this.bubbleRadarSnapshotPositions.Keys.ToArray())
                        {
                            if (!refreshedSnapshot.ContainsKey(staleBubbleId))
                            {
                                Vector3 lastKnownBubblePos = this.bubbleRadarSnapshotPositions[staleBubbleId];
                                if (this.ShouldRetainMissingBubbleSceneMarker(scanOrigin, lastKnownBubblePos))
                                {
                                    continue;
                                }

                                this.RemoveBubbleTrackedMarker(staleBubbleId);
                                this.bubbleRadarSnapshotPositions.Remove(staleBubbleId);
                            }
                        }

                        foreach (KeyValuePair<int, Vector3> entry in refreshedSnapshot)
                        {
                            this.bubbleRadarSnapshotPositions[entry.Key] = entry.Value;
                        }
                    }
                    else
                    {
                        this.bubbleRadarSnapshotPositions.Clear();
                        foreach (KeyValuePair<int, Vector3> entry in refreshedSnapshot)
                        {
                            this.bubbleRadarSnapshotPositions[entry.Key] = entry.Value;
                        }
                    }
                }
                else if (sceneOnlySnapshot)
                {
                    if (this.ShouldRetainEmptyBubbleSceneSnapshot(scanOrigin))
                    {
                        refreshStatus += " | Empty scene scan retained last bubble snapshot.";
                    }
                    else
                    {
                        this.ClearBubbleTrackedMarkers();
                        this.bubbleRadarSnapshotPositions.Clear();
                    }
                }
                else if (!sceneOnlySnapshot && !retainedSnapshot)
                {
                    this.bubbleRadarSnapshotPositions.Clear();
                }

                this._cachedBubbleRadarAt = now;
                this.bubbleRadarLastScanOrigin = scanOrigin;
                this.bubbleRadarHasLastScanOrigin = true;
                this.bubbleRadarForceRefresh = false;
                this.BubbleRadarLogThrottled("refresh", "Bubble snapshot refresh " + (refreshed ? "ok" : "empty") + ". " + refreshStatus, 1.5f);
            }

            if (!shouldRefresh && now < this.nextBubbleMarkerSyncAt)
            {
                return;
            }

            this.nextBubbleMarkerSyncAt = now + BubbleRadarMarkerSyncInterval;
            float maxBubbleRange = Mathf.Max(BubbleRadarMaxDistance, this.radarMaxDistance);
            float maxBubbleRangeSqr = maxBubbleRange * maxBubbleRange;
            this.bubbleRadarSeenIds.Clear();

            foreach (int bubbleId in this.bubbleRadarSnapshotPositions.Keys.ToArray())
            {
                Vector3 bubblePos = this.bubbleRadarSnapshotPositions[bubbleId];
                bool hasSceneTarget = this.bubbleRadarSceneTargets.TryGetValue(bubbleId, out GameObject bubbleTarget);
                if (hasSceneTarget && !this.IsUsableBubbleSceneObject(bubbleTarget))
                {
                    if (this.ShouldRetainMissingBubbleSceneMarker(scanOrigin, bubblePos))
                    {
                        this.bubbleRadarSceneTargets.Remove(bubbleId);
                        hasSceneTarget = false;
                        bubbleTarget = null;
                    }
                    else
                    {
                        this.RemoveBubbleTrackedMarker(bubbleId);
                        this.bubbleRadarSnapshotPositions.Remove(bubbleId);
                        continue;
                    }
                }

                if (hasSceneTarget)
                {
                    bubblePos = bubbleTarget.transform.position;
                    this.bubbleRadarSnapshotPositions[bubbleId] = bubblePos;
                }

                if ((scanOrigin - bubblePos).sqrMagnitude > maxBubbleRangeSqr)
                {
                    continue;
                }

                this.bubbleRadarSeenIds.Add(bubbleId);
                this.bubbleRadarTrackedPositions[bubbleId] = bubblePos;
                this.bubbleRadarLastSeenAt[bubbleId] = now;

                if (this.trackedBubbleMarkers.TryGetValue(bubbleId, out GameObject existingMarker) && existingMarker != null)
                {
                    continue;
                }

                GameObject bubbleMarker = this.CreateMarker(bubblePos, "bubble", xRay, bg, bubbleTarget);
                if (bubbleMarker == null)
                {
                    continue;
                }

                bubbleMarker.name = BubbleTrackedMarkerPrefix + bubbleId.ToString();
                this.trackedBubbleMarkers[bubbleId] = bubbleMarker;
            }

            this.radarCleanupTrackedIds.Clear();
            foreach (KeyValuePair<int, GameObject> tracked in this.trackedBubbleMarkers)
            {
                if (tracked.Value == null)
                {
                    this.radarCleanupTrackedIds.Add(tracked.Key);
                    continue;
                }

                if (this.bubbleRadarSeenIds.Contains(tracked.Key))
                {
                    continue;
                }

                if (!this.bubbleRadarLastSeenAt.TryGetValue(tracked.Key, out float lastSeenAt) || now - lastSeenAt > BubbleRadarMarkerGraceSeconds)
                {
                    this.radarCleanupTrackedIds.Add(tracked.Key);
                }
            }

            foreach (int bubbleId in this.radarCleanupTrackedIds)
            {
                this.RemoveBubbleTrackedMarker(bubbleId);
            }

            if (BubbleRadarDebugLoggingEnabled)
            {
                this.BubbleRadarLogThrottled(
                    "sync-summary",
                    "Marker sync complete. snapshot=" + this.bubbleRadarSnapshotPositions.Count.ToString()
                        + " inRange=" + this.bubbleRadarSeenIds.Count.ToString()
                        + " tracked=" + this.trackedBubbleMarkers.Count.ToString()
                        + " maxRange=" + maxBubbleRange.ToString("F0") + "m",
                    10f);
            }
        }

        private void RemoveBubbleTrackedMarker(int bubbleId)
        {
            if (this.trackedBubbleMarkers.TryGetValue(bubbleId, out GameObject marker) && marker != null)
            {
                this.RemoveMarkerMetadata(marker);
                this.RemoveTrackedMarkerMapping(marker);
                Object.Destroy(marker);
            }

            this.trackedBubbleMarkers.Remove(bubbleId);
            this.bubbleRadarTrackedPositions.Remove(bubbleId);
            this.bubbleRadarSceneTargets.Remove(bubbleId);
            this.bubbleRadarLastSeenAt.Remove(bubbleId);
        }

        private void ClearBubbleTrackedMarkers()
        {
            this.radarCleanupTrackedIds.Clear();
            foreach (KeyValuePair<int, GameObject> entry in this.trackedBubbleMarkers)
            {
                if (entry.Value != null)
                {
                    this.RemoveMarkerMetadata(entry.Value);
                    this.RemoveTrackedMarkerMapping(entry.Value);
                    Object.Destroy(entry.Value);
                }
                this.radarCleanupTrackedIds.Add(entry.Key);
            }

            foreach (int bubbleId in this.radarCleanupTrackedIds)
            {
                this.trackedBubbleMarkers.Remove(bubbleId);
            }

            this.bubbleRadarTrackedPositions.Clear();
            this.bubbleRadarSnapshotPositions.Clear();
            this.bubbleRadarSceneTargets.Clear();
            this.bubbleRadarSeenIds.Clear();
            this.bubbleRadarLastSeenAt.Clear();
        }

        private bool TryParseBubbleTrackedMarkerId(string markerName, out int bubbleId)
        {
            bubbleId = 0;
            if (string.IsNullOrEmpty(markerName) || !markerName.StartsWith(BubbleTrackedMarkerPrefix, StringComparison.Ordinal))
            {
                return false;
            }

            return int.TryParse(markerName.Substring(BubbleTrackedMarkerPrefix.Length), out bubbleId);
        }

        private bool ShouldTrackBirdObject(string lowerName)
        {
            return !string.IsNullOrEmpty(lowerName)
                && lowerName.StartsWith("p_bird_bird", StringComparison.Ordinal)
                && lowerName.EndsWith("(clone)", StringComparison.Ordinal)
                && !lowerName.Contains("birdscanner");
        }

        private bool ShouldTrackInsectObject(string lowerName)
        {
            // Must have p_insect_insect prefix AND (clone) suffix
            return lowerName.Contains("p_insect_insect") && lowerName.Contains("(clone)");
        }

        private bool IsOtherPlayerSkeletonGameObject(GameObject obj)
        {
            if (obj == null || !obj.activeInHierarchy)
            {
                return false;
            }

            GameObject localPlayer = GetLocalPlayer();
            if (localPlayer != null && ReferenceEquals(obj, localPlayer))
            {
                return false;
            }

            string name = obj.name;
            return !string.IsNullOrEmpty(name) && name.Contains("p_player_skeleton");
        }

        private struct HideAndSeekMorphRadarSpot
        {
            public uint MarkerNetId;
            public Vector3 Position;
        }

        private void SyncHideAndSeekMorphRadarMarkers(Vector3 scanOrigin, Material xRay, Material bg, float maxRange)
        {
            if (!this.showOtherPlayersRadar || this.radarContainer == null)
            {
                return;
            }

            float maxRangeSqr = maxRange * maxRange;
            this.hideAndSeekMorphSeenNetIds.Clear();
            this.hideAndSeekMorphCollectBuffer.Clear();
            this.TryCollectHideAndSeekMorphRadarSpots(this.hideAndSeekMorphCollectBuffer);

            for (int i = 0; i < this.hideAndSeekMorphCollectBuffer.Count; i++)
            {
                HideAndSeekMorphRadarSpot spot = this.hideAndSeekMorphCollectBuffer[i];
                if (spot.MarkerNetId == 0U || spot.Position.sqrMagnitude < 0.01f)
                {
                    continue;
                }

                if ((scanOrigin - spot.Position).sqrMagnitude > maxRangeSqr)
                {
                    continue;
                }

                this.hideAndSeekMorphSeenNetIds.Add(spot.MarkerNetId);
                this.hideAndSeekMorphTrackedPositions[spot.MarkerNetId] = spot.Position;

                if (this.trackedHideAndSeekMorphMarkers.TryGetValue(spot.MarkerNetId, out GameObject existingMarker) && existingMarker != null)
                {
                    continue;
                }

                GameObject morphMarker = this.CreateMarker(spot.Position, "otherplayermorph", xRay, bg, null);
                if (morphMarker == null)
                {
                    continue;
                }

                morphMarker.name = HideAndSeekMorphMarkerPrefix + spot.MarkerNetId.ToString();
                this.trackedHideAndSeekMorphMarkers[spot.MarkerNetId] = morphMarker;
            }

            this.radarCleanupTrackedIds.Clear();
            foreach (KeyValuePair<uint, GameObject> tracked in this.trackedHideAndSeekMorphMarkers)
            {
                if (tracked.Value == null || !this.hideAndSeekMorphSeenNetIds.Contains(tracked.Key))
                {
                    this.radarCleanupTrackedIds.Add((int)tracked.Key);
                }
            }

            for (int i = 0; i < this.radarCleanupTrackedIds.Count; i++)
            {
                this.RemoveHideAndSeekMorphMarker((uint)this.radarCleanupTrackedIds[i]);
            }
        }

        private void RemoveHideAndSeekMorphMarker(uint markerNetId)
        {
            if (this.trackedHideAndSeekMorphMarkers.TryGetValue(markerNetId, out GameObject marker) && marker != null)
            {
                this.RemoveMarkerMetadata(marker);
                Object.Destroy(marker);
            }

            this.trackedHideAndSeekMorphMarkers.Remove(markerNetId);
            this.hideAndSeekMorphTrackedPositions.Remove(markerNetId);
        }

        private void ClearHideAndSeekMorphMarkers()
        {
            this.radarCleanupTrackedIds.Clear();
            foreach (KeyValuePair<uint, GameObject> entry in this.trackedHideAndSeekMorphMarkers)
            {
                if (entry.Value != null)
                {
                    this.RemoveMarkerMetadata(entry.Value);
                    Object.Destroy(entry.Value);
                }

                this.radarCleanupTrackedIds.Add((int)entry.Key);
            }

            for (int i = 0; i < this.radarCleanupTrackedIds.Count; i++)
            {
                this.trackedHideAndSeekMorphMarkers.Remove((uint)this.radarCleanupTrackedIds[i]);
            }

            this.hideAndSeekMorphTrackedPositions.Clear();
            this.hideAndSeekMorphSeenNetIds.Clear();
