        private bool TryReadStringMember(Il2CppType ilType, Il2CppObject instance, string memberName, out string value)
        {
            value = string.Empty;
            if (ilType == null || instance == null || string.IsNullOrEmpty(memberName))
            {
                return false;
            }

            try
            {
                Il2CppFieldInfo field = ilType.GetField(memberName, (Il2CppBindingFlags)62);
                object fieldValue = field != null ? field.GetValue(instance) : null;
                if (fieldValue != null)
                {
                    value = fieldValue.ToString();
                    return !string.IsNullOrWhiteSpace(value);
                }
            }
            catch
            {
            }

            try
            {
                Il2CppPropertyInfo prop = ilType.GetProperty(memberName);
                object propValue = prop != null ? prop.GetValue(instance) : null;
                if (propValue != null)
                {
                    value = propValue.ToString();
                    return !string.IsNullOrWhiteSpace(value);
                }
            }
            catch
            {
            }

            return false;
        }

        private bool TryExtractNpcPositionFromIl2CppObject(Il2CppObject npcObject, out Vector3 position)
        {
            position = Vector3.zero;
            if (npcObject == null)
            {
                return false;
            }

            try
            {
                if (this.TryReadVector3Member(npcObject, "position", out position) && position != Vector3.zero)
                {
                    return true;
                }

                Il2CppType ilType = npcObject.GetIl2CppType();
                foreach (string member in new string[] { "entity", "Entity", "_entity" })
                {
                    if (this.TryReadObjectMember(ilType, npcObject, member, out Il2CppObject entityObj) && entityObj != null)
                    {
                        if (this.TryReadVector3Member(entityObj, "position", out position) && position != Vector3.zero)
                        {
                            return true;
                        }
                        if (this.TryReadVector3Member(entityObj, "worldPosition", out position) && position != Vector3.zero)
                        {
                            return true;
                        }
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        private Il2CppType TryGetNpcTeleportIl2CppType(params string[] typeNames)
        {
            if (typeNames == null)
            {
                return null;
            }

            string[] assemblies = new string[]
            {
                "XDTLevelAndEntity",
                "XDTLevelAndEntity.dll",
                "Assembly-CSharp",
                "Assembly-CSharp.dll"
            };

            foreach (string typeName in typeNames)
            {
                if (string.IsNullOrWhiteSpace(typeName))
                {
                    continue;
                }

                try
                {
                    Il2CppType direct = Il2CppType.GetType(typeName);
                    if (direct != null)
                    {
                        return direct;
                    }
                }
                catch
                {
                }

                foreach (string assemblyName in assemblies)
                {
                    try
                    {
                        Il2CppType qualified = Il2CppType.GetType(typeName + ", " + assemblyName);
                        if (qualified != null)
                        {
                            return qualified;
                        }
                    }
                    catch
                    {
                    }
                }
            }

            return null;
        }

        private bool TryGetMonoStringMember(IntPtr obj, string memberName, out string value)
        {
            value = string.Empty;
            IntPtr stringObj;
            return this.TryGetMonoObjectMember(obj, memberName, out stringObj) && this.TryReadMonoString(stringObj, out value);
        }

        private bool TryReadMonoString(IntPtr monoStringObj, out string value)
        {
            value = string.Empty;
            if (monoStringObj == IntPtr.Zero || auraMonoStringToUtf8 == null)
            {
                return false;
            }

            IntPtr utf8Ptr = IntPtr.Zero;
            try
            {
                utf8Ptr = auraMonoStringToUtf8(monoStringObj);
                if (utf8Ptr == IntPtr.Zero)
                {
                    return false;
                }

                value = Marshal.PtrToStringUTF8(utf8Ptr) ?? string.Empty;
                return !string.IsNullOrWhiteSpace(value);
            }
            catch
            {
                value = string.Empty;
                return false;
            }
            finally
            {
                if (utf8Ptr != IntPtr.Zero && auraMonoFree != null)
                {
                    try
                    {
                        auraMonoFree(utf8Ptr);
                    }
                    catch
                    {
                    }
                }
            }
        }

        private int PopulateLiveNpcEntriesFromMapSpots(List<KeyValuePair<string, Vector3>> entries, Dictionary<string, int> indexByName, Dictionary<string, int> npcIdMap)
        {
            int num = 0;
            try
            {
                Type type = this.FindLoadedType("XDTGameSystem.GameplaySystem.MapSpots.MapSpotsSystem", "MapSpotsSystem");
                if (type == null)
                {
                    return 0;
                }

                object obj = type.GetProperty("Instance", BindingFlags.Public | BindingFlags.Static)?.GetValue(null, null);
                if (obj == null)
                {
                    FieldInfo fieldInfo = type.GetField("Instance", BindingFlags.Public | BindingFlags.Static);
                    if (fieldInfo != null)
                    {
                        obj = fieldInfo.GetValue(null);
                    }
                }
                if (obj == null)
                {
                    return 0;
                }

                MethodInfo methodInfo = obj.GetType().GetMethod("GetMapSpots", BindingFlags.Public | BindingFlags.Instance, null, Type.EmptyTypes, null);
                if (methodInfo == null)
                {
                    return 0;
                }

                IEnumerable enumerable = methodInfo.Invoke(obj, null) as IEnumerable;
                if (enumerable == null)
                {
                    return 0;
                }

                Dictionary<int, string> dictionary = new Dictionary<int, string>();
                foreach (string npcName in this.GetNpcTeleportPreferredNames())
                {
                    int num2;
                    if (this.TryResolveNpcTeleportId(npcName, npcIdMap, out num2) && !dictionary.ContainsKey(num2))
                    {
                        dictionary[num2] = npcName;
                    }
                }

                foreach (object obj2 in enumerable)
                {
                    if (obj2 == null)
                    {
                        continue;
                    }

                    object obj3;
                    if (!this.TryGetObjectMember(obj2, "category", out obj3) || obj3 == null || !string.Equals(obj3.ToString(), "Npc", StringComparison.OrdinalIgnoreCase))
                    {
                        continue;
                    }

                    object obj4;
                    object obj5;
                    if (!this.TryGetObjectMember(obj2, "usageId", out obj4) || !this.TryGetObjectMember(obj2, "position", out obj5) || !(obj5 is Vector3))
                    {
                        continue;
                    }

                    int num3;
                    try
                    {
                        num3 = Convert.ToInt32(obj4);
                    }
                    catch
                    {
                        continue;
                    }

                    string value;
                    if (!dictionary.TryGetValue(num3, out value))
                    {
                        continue;
                    }

                    this.AddOrUpdateNpcTeleportEntry(entries, indexByName, value, (Vector3)obj5);
                    num++;
                }
            }
            catch
            {
            }

            return num;
        }

        private List<KeyValuePair<string, Vector3>> GetTeleportNpcEntries(bool forceRefresh = false)
        {
            if (!forceRefresh)
            {
                return this.cachedNpcTeleportEntries ?? new List<KeyValuePair<string, Vector3>>();
            }

            if (!NpcTeleportLiveLocationEnabled)
            {
                this.npcTeleportStatus = "NPC teleport disabled";
                this.cachedNpcTeleportEntries = new List<KeyValuePair<string, Vector3>>();
                return this.cachedNpcTeleportEntries;
            }

            if (GetPlayer() == null)
            {
                this.npcTeleportStatus = "Not Ready";
                this.cachedNpcTeleportEntries = new List<KeyValuePair<string, Vector3>>();
                this.LogNpcTeleportDebug("GetTeleportNpcEntries: player not ready");
                return this.cachedNpcTeleportEntries;
            }

            List<KeyValuePair<string, Vector3>> list = new List<KeyValuePair<string, Vector3>>();
            Dictionary<string, int> dictionary = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            int liveMatches = this.PopulateLiveNpcEntriesFromUnityObjects(list, dictionary);
            Dictionary<string, int> npcTeleportIdMap = this.GetNpcTeleportIdMap();
            this.LogNpcTeleportDebug("GetTeleportNpcEntries: idMapCount=" + npcTeleportIdMap.Count + " cacheReady=" + this.npcTeleportIdCacheReady + " resolveStatus=" + this.npcTeleportIdResolveStatus);
            List<KeyValuePair<string, int>> npcCandidates = this.GetNpcTeleportCandidates(npcTeleportIdMap);
            int resolvedIds = 0;
            int totalTargets = npcCandidates.Count;
            foreach (KeyValuePair<string, int> npcCandidate in npcCandidates)
            {
                if (npcCandidate.Value <= 0)
                {
                    continue;
                }
                resolvedIds++;
                Vector3 vector;
                if (this.TryGetLiveNpcPositionById(npcCandidate.Value, out vector) || this.TryGetLiveNpcPositionByIdMono(npcCandidate.Value, out vector))
                {
                    this.AddOrUpdateNpcTeleportEntry(list, dictionary, npcCandidate.Key, vector);
                    liveMatches = Math.Max(liveMatches, list.Count);
                }
            }

            this.cachedNpcTeleportEntries = list;
            this.npcTeleportStatus = (liveMatches > 0)
                ? string.Format("Live NPCs: {0}/{1}", liveMatches, totalTargets)
                : (resolvedIds > 0
                    ? string.Format("No live NPC positions found ({0}/{1} ids resolved)", resolvedIds, totalTargets)
                    : ("No NPC ids resolved" + (string.IsNullOrEmpty(this.npcTeleportIdResolveStatus) ? string.Empty : (" [" + this.npcTeleportIdResolveStatus + "]"))));
            this.LogNpcTeleportDebug("GetTeleportNpcEntries: built entries count=" + list.Count + " resolvedIds=" + resolvedIds + " liveMatches=" + liveMatches + " status=" + this.npcTeleportStatus);
            return this.cachedNpcTeleportEntries;
        }

        private Type FindLoadedType(params string[] names)
        {
            string cacheKey = names != null && names.Length > 0 ? string.Join("|", names) : string.Empty;
            if (!string.IsNullOrEmpty(cacheKey) && this.loadedTypeLookupCache.TryGetValue(cacheKey, out Type cachedType) && cachedType != null)
            {
                return cachedType;
            }

            if (!string.IsNullOrEmpty(cacheKey) && this.loadedTypeMissCacheUntil.TryGetValue(cacheKey, out float missCacheUntil))
            {
                if (Time.unscaledTime < missCacheUntil)
                {
                    return null;
                }

                this.loadedTypeMissCacheUntil.Remove(cacheKey);
            }

            Assembly[] assemblies = AppDomain.CurrentDomain.GetAssemblies();
            foreach (string text in names)
            {
                if (string.IsNullOrEmpty(text))
                {
                    continue;
                }

                Type type = Type.GetType(text, false);
                if (type != null)
                {
                    if (!string.IsNullOrEmpty(cacheKey))
                    {
                        this.loadedTypeLookupCache[cacheKey] = type;
                        this.loadedTypeMissCacheUntil.Remove(cacheKey);
                    }

                    return type;
                }
                foreach (Assembly assembly in assemblies)
                {
                    Type type2 = assembly.GetType(text, false);
                    if (type2 != null)
                    {
                        if (!string.IsNullOrEmpty(cacheKey))
                        {
                            this.loadedTypeLookupCache[cacheKey] = type2;
                            this.loadedTypeMissCacheUntil.Remove(cacheKey);
                        }

                        return type2;
                    }
                }
            }
            foreach (Assembly assembly2 in assemblies)
            {
                Type[] types;
                try
                {
                    types = assembly2.GetTypes();
                }
                catch (ReflectionTypeLoadException ex)
                {
                    types = ex.Types;
                }
                catch
                {
                    continue;
                }
                if (types == null)
                {
                    continue;
                }
                foreach (Type type3 in types)
                {
                    if (!(type3 == null))
                    {
                        foreach (string text2 in names)
                        {
                            if (string.IsNullOrEmpty(text2))
                            {
                                continue;
                            }

                            if (string.Equals(type3.FullName, text2, StringComparison.Ordinal) || string.Equals(type3.Name, text2, StringComparison.Ordinal))
                            {
                                if (!string.IsNullOrEmpty(cacheKey))
                                {
                                    this.loadedTypeLookupCache[cacheKey] = type3;
                                    this.loadedTypeMissCacheUntil.Remove(cacheKey);
                                }

                                return type3;
                            }
                        }
                    }
                }
            }
            if (!string.IsNullOrEmpty(cacheKey))
            {
                this.loadedTypeMissCacheUntil[cacheKey] = Time.unscaledTime + LoadedTypeMissCacheSeconds;
            }
            return null;
        }

        private Type FindLoadedTypeBySuffix(params string[] suffixes)
        {
            if (suffixes == null || suffixes.Length == 0)
            {
                return null;
            }

            string cacheKey = "suffix:" + string.Join("|", suffixes);
            if (this.loadedTypeLookupCache.TryGetValue(cacheKey, out Type cachedType) && cachedType != null)
            {
                return cachedType;
            }

            foreach (Assembly assembly in AppDomain.CurrentDomain.GetAssemblies())
            {
                Type[] types;
                try
                {
                    types = assembly.GetTypes();
                }
                catch (ReflectionTypeLoadException ex)
                {
                    types = ex.Types;
                }
                catch
                {
                    continue;
                }

                if (types == null)
                {
                    continue;
                }

                foreach (Type type in types)
                {
                    if (type == null)
                    {
                        continue;
                    }

                    string fullName = type.FullName ?? string.Empty;
                    string name = type.Name ?? string.Empty;
                    foreach (string suffix in suffixes)
                    {
                        if (string.IsNullOrEmpty(suffix))
                        {
                            continue;
                        }

                        if (fullName.EndsWith(suffix, StringComparison.Ordinal) || name.EndsWith(suffix, StringComparison.Ordinal))
                        {
                            this.loadedTypeLookupCache[cacheKey] = type;
                            return type;
                        }
                    }
                }
            }

            if (!string.IsNullOrEmpty(cacheKey))
            {
                this.loadedTypeMissCacheUntil[cacheKey] = Time.unscaledTime + LoadedTypeMissCacheSeconds;
            }

            return null;
        }

        private Type FindLoadedTypeByFullName(string fullName)
        {
            if (string.IsNullOrEmpty(fullName))
            {
                return null;
            }

            return this.FindLoadedType(fullName);
        }

        private static string BuildMethodLookupCacheKey(Type type, string name, BindingFlags flags, Type[] parameterTypes, int paramCountOnly)
        {
            if (type == null || string.IsNullOrEmpty(name))
            {
                return string.Empty;
            }

            string typeName = type.FullName ?? type.Name ?? type.GetHashCode().ToString();
            if (paramCountOnly >= 0)
            {
                return typeName + "|pc:" + paramCountOnly + "|" + name + "|" + (int)flags;
            }

            Type[] types = parameterTypes ?? Type.EmptyTypes;
            if (types.Length == 0)
            {
                return typeName + "|sig:|" + name + "|" + (int)flags;
            }

            StringBuilder sb = new StringBuilder(typeName.Length + name.Length + (types.Length * 16));
            sb.Append(typeName).Append("|sig:").Append(name).Append('|').Append((int)flags);
            for (int i = 0; i < types.Length; i++)
            {
                Type pt = types[i];
                sb.Append('|').Append(pt?.FullName ?? "_");
            }

            return sb.ToString();
        }

        private MethodInfo ResolveCachedMethodQuiet(Type type, string name, BindingFlags flags, Type[] parameterTypes)
        {
            if (type == null || string.IsNullOrEmpty(name))
            {
                return null;
            }

            Type[] resolvedParameterTypes = parameterTypes ?? Type.EmptyTypes;
            const BindingFlags flatten = BindingFlags.FlattenHierarchy;
            BindingFlags resolvedFlags = flags | flatten;
            string cacheKey = BuildMethodLookupCacheKey(type, name, resolvedFlags, resolvedParameterTypes, -1);
            if (!string.IsNullOrEmpty(cacheKey))
            {
                if (this.methodLookupCache.TryGetValue(cacheKey, out MethodInfo cachedMethod))
                {
                    return cachedMethod;
                }

                if (this.methodMissCacheUntil.TryGetValue(cacheKey, out float missCacheUntil))
                {
                    if (Time.unscaledTime < missCacheUntil)
                    {
                        return null;
                    }

                    this.methodMissCacheUntil.Remove(cacheKey);
                }
            }

            MethodInfo method = type.GetMethod(name, resolvedFlags, null, resolvedParameterTypes, null);
            if (!string.IsNullOrEmpty(cacheKey))
            {
                if (method != null)
                {
                    this.methodLookupCache[cacheKey] = method;
                    this.methodMissCacheUntil.Remove(cacheKey);
                }
                else
                {
                    this.methodMissCacheUntil[cacheKey] = Time.unscaledTime + LoadedMethodMissCacheSeconds;
                }
            }

            return method;
        }

        private MethodInfo ResolveCachedMethodByParamCountQuiet(Type type, string name, int paramCount)
        {
            if (type == null || string.IsNullOrEmpty(name))
            {
                return null;
            }

            const BindingFlags flags = BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static
                | BindingFlags.Instance | BindingFlags.FlattenHierarchy;
            string cacheKey = BuildMethodLookupCacheKey(type, name, flags, null, paramCount);
            if (!string.IsNullOrEmpty(cacheKey))
            {
                if (this.methodLookupCache.TryGetValue(cacheKey, out MethodInfo cachedMethod))
                {
                    return cachedMethod;
                }

                if (this.methodMissCacheUntil.TryGetValue(cacheKey, out float missCacheUntil))
                {
                    if (Time.unscaledTime < missCacheUntil)
                    {
                        return null;
                    }

                    this.methodMissCacheUntil.Remove(cacheKey);
                }
            }

            MethodInfo resolved = null;
            MethodInfo[] methods = type.GetMethods(flags);
            for (int i = 0; i < methods.Length; i++)
            {
                MethodInfo candidate = methods[i];
                if (!string.Equals(candidate.Name, name, StringComparison.Ordinal))
                {
                    continue;
                }

                ParameterInfo[] parameters = candidate.GetParameters();
                if (parameters != null && parameters.Length == paramCount)
                {
                    resolved = candidate;
                    break;
                }
            }

            if (!string.IsNullOrEmpty(cacheKey))
            {
                if (resolved != null)
                {
                    this.methodLookupCache[cacheKey] = resolved;
                    this.methodMissCacheUntil.Remove(cacheKey);
                }
                else
                {
                    this.methodMissCacheUntil[cacheKey] = Time.unscaledTime + LoadedMethodMissCacheSeconds;
                }
            }

            return resolved;
        }

        private MethodInfo GetMethodQuiet(Type type, string name, BindingFlags flags, Type[] parameterTypes)
        {
            return this.ResolveCachedMethodQuiet(type, name, flags, parameterTypes);
        }

        private MethodInfo GetMethodByNameAndParamCountQuiet(Type type, string name, int paramCount)
        {
            return this.ResolveCachedMethodByParamCountQuiet(type, name, paramCount);
        }

        private string DescribeType(Type type)
        {
            if (type == null)
            {
                return "null";
            }

            string assemblyName = string.Empty;
            try
            {
                Assembly ownerAssembly = type.Assembly;
                assemblyName = ownerAssembly != null ? ownerAssembly.GetName().Name : string.Empty;
            }
            catch
            {
            }

            return string.IsNullOrEmpty(assemblyName)
                ? (type.FullName ?? type.Name ?? "unknown")
                : (type.FullName ?? type.Name ?? "unknown") + "@" + assemblyName;
        }

        private Type FindLevelObjectManagerRuntimeType()
        {
            Type resolved = this.FindLoadedType(
                "ScriptsRefactory.LevelAndEntity.LevelObjectManager",
                "XDTDataAndProtocol.ScriptsRefactory.LevelAndEntity.LevelObjectManager",
                "LevelObjectManager");
            if (resolved != null)
            {
                return resolved;
            }

            try
            {
                foreach (Assembly assembly in AppDomain.CurrentDomain.GetAssemblies())
                {
                    Type[] types;
                    try
                    {
                        types = assembly.GetTypes();
                    }
                    catch
                    {
                        continue;
                    }

                    foreach (Type type in types)
                    {
                        if (type == null)
                        {
                            continue;
                        }

                        string fullName = type.FullName ?? type.Name ?? string.Empty;
                        if (fullName.IndexOf("LevelObjectManager", StringComparison.OrdinalIgnoreCase) < 0)
                        {
                            continue;
                        }

                        PropertyInfo instanceProperty = type.GetProperty("Instance", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static);
                        MethodInfo getLevelObjectMethod = type.GetMethod("GetLevelObject", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, new Type[] { typeof(ulong) }, null);
                        if (instanceProperty != null && getLevelObjectMethod != null)
                        {
                            return type;
                        }
                    }
                }
            }
            catch
            {
            }

            return null;
        }

