        // Cached local player lookup to avoid expensive per-frame scans.
        private static GameObject cachedLocalPlayer = null;
        private static float lastLocalPlayerCheckTime = -999f;
        private const float LOCAL_PLAYER_CACHE_INTERVAL = 1f; // seconds

        // Return the local player's skeleton GameObject (`p_player_skeleton(Clone)`).
        // Resolved with a targeted GameObject.Find. NOTE: the game does NOT parent a Camera under the
        // player skeleton on this build — the Main Camera lives under `GameApp/startup_root(Clone)` —
        // so the old FindObjectsOfType + GetComponentInChildren<Camera> "local player" disambiguation
        // never matched and always fell through to this same GameObject.Find (verified via in-game
        // hierarchy diagnostics: hasCamera=False, 1 match, ~3000 objects scanned for nothing). The full
        // scene scan was dropped. In multiplayer with several p_player_skeleton(Clone) this returns the
        // first match; correct local-player disambiguation would need to map the selfPlayer ECS entity
        // to its GameObject.
        public static GameObject GetLocalPlayer()
        {
            // Quick return if cached and valid
            try
            {
                if (cachedLocalPlayer != null && cachedLocalPlayer.activeInHierarchy)
                {
                    return cachedLocalPlayer;
                }
            }
            catch
            {
                cachedLocalPlayer = null;
            }

            // Throttle re-resolves to once per interval REGARDLESS of cache state, so a missing player
            // (world loading, between worlds, despawned) doesn't hit GameObject.Find every call from the
            // hot Transform.position / CharacterController.Move patches. A miss returns the (null/stale)
            // cache and retries at most once per second.
            if (Time.unscaledTime - lastLocalPlayerCheckTime < LOCAL_PLAYER_CACHE_INTERVAL)
            {
                return cachedLocalPlayer;
            }

            lastLocalPlayerCheckTime = Time.unscaledTime;
            cachedLocalPlayer = GameObject.Find("p_player_skeleton(Clone)");
            return cachedLocalPlayer;
        }

        private GameObject GetPlayer() => GetLocalPlayer();

        // Returns the player's root GameObject if available (fallback to GetPlayer)
        private GameObject FindPlayerRoot()
        {
            try
            {
                GameObject p = GetPlayer();
                if (p == null) return null;
                if (p.transform == null) return p;
                Transform root = p.transform.root;
                if (root != null && root.gameObject != null) return root.gameObject;
                return p;
            }
            catch
            {
                return GetPlayer();
            }
        }

        private void TeleportTo(Vector3 targetPos)
        {
            this.EnsurePositionOverridePatched();
            this.EnsureMovePatched();
            OverridePosition = targetPos;
            OverridePlayerPosition = true;
            teleportFramesRemaining = 10;
            GameObject p = GetPlayer();
            if (p != null)
            {
                p.transform.position = targetPos;
                if (p.transform.root != null) p.transform.root.position = targetPos;
            }
        }

        private void SyncTeleportPosition()
        {
            if (OverridePlayerPosition && teleportFramesRemaining > 0)
            {
                teleportFramesRemaining--;
                GameObject p = GetPlayer();
                if (p != null)
                {
                    p.transform.position = OverridePosition;
                    if (p.transform.root != null) p.transform.root.position = OverridePosition;
                }
                if (teleportFramesRemaining <= 0)
                {
                    OverridePlayerPosition = false;
                    try
                    {
                        if (this.isResourceFarmTeleport)
                        {
                            this.OnTeleportArrivedResource();
                        }
                    }
                    catch { }
                }
            }
        }

        // --- Auto Buy helpers + logic ---
        private void StartAutoBuy()
        {
            try
            {
                GameObject p = GameObject.Find("p_player_skeleton(Clone)");
                if (p != null) this.autoBuySavedPosition = p.transform.position;
                this.autoBuySubState = 1; // teleporting
                this.autoBuyStepTimer = Time.unscaledTime + 0.1f;
                this.autoBuyShopWaitStartedAt = 0f;
                this.autoBuyStoreSelectRetryCount = 0;
                this.autoBuyPreviousGameSpeed = this.gameSpeed;
                this.SetGameSpeed(5f);
                this.autoBuyForcedGameSpeed = true;
                this.autoBuyCurrentIngredientIndex = 0;
                this.autoBuyPurchasedCount = 0;
                this.autoBuyShopScrollStep = -1;
                this.autoBuyPopupCloseRetryAt = 0f;
                this.autoBuyPopupSlowScanAt = 0f;
                this.TeleportToLocation(this.autoBuyNearbyPos);
                LogAutoBuy(" Started: teleporting to nearby position first (Game Speed x5.0)");
            }
            catch (Exception ex) { LogAutoBuy(" Start error: " + ex.Message); this.StopAutoBuy("Start error"); }
        }

        private void StopAutoBuy(string reason)
        {
            LogAutoBuy(" Stopped: " + reason);
            this.CloseAutoBuyPanels();
            this.autoBuyEnabled = false;
            this.autoBuySubState = 0;
            this.autoBuyShopScrollStep = -1;
            this.autoBuyPopupCloseRetryAt = 0f;
            this.autoBuyPopupSlowScanAt = 0f;
            if (this.autoBuyForcedGameSpeed)
            {
                this.SetGameSpeed(Mathf.Max(1f, this.autoBuyPreviousGameSpeed));
                this.autoBuyForcedGameSpeed = false;
            }
            try
            {
                EventSystem current = EventSystem.current;
                EventSystem restoreTarget = this.blockedEventSystem != null ? this.blockedEventSystem : current;
                if (restoreTarget != null)
                {
                    restoreTarget.enabled = true;
                }
                this.eventSystemBlockedByMenu = false;
                this.blockedEventSystem = null;
                if (current != null)
                {
                    current.SetSelectedGameObject(null);
                    current.sendNavigationEvents = true;
                }
            }
            catch { }
            // teleport back if we have a saved position
            if (this.autoBuySavedPosition != Vector3.zero)
            {
                this.TeleportToLocation(this.autoBuySavedPosition);
                this.autoBuySavedPosition = Vector3.zero;
            }
        }

        private void LogAutoBuy(string message)
        {
            if (this.autoBuyLogsEnabled)
            {
                ModLogger.Msg("[AutoBuy] " + message);
            }
        }

        private void CloseAutoBuyPanels()
        {
            try
            {
                this.TryCloseAutoBuyObtainedPopup();
                string[] forceHidePanels = new string[]
                {
                    "GameApp/startup_root(Clone)/XDRUIRoot/Top/AlertRewardPanel(Clone)"
                };
                for (int i = 0; i < forceHidePanels.Length; i++)
                {
                    GameObject panel = GameObject.Find(forceHidePanels[i]);
                    if (panel != null && panel.activeInHierarchy) SimulateClick(panel);
                }

                // Dialogue panel close/back
                this.ClickButtonIfExists("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)/AniRoot@go@ani/back@btn");
                this.ClickButtonIfExists("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)/AniRoot@go@ani/exit@btn@go");

                // Some dialogue steps require clicking content/background to advance before close works.
                // Use exact inspector-confirmed paths first, then generic dialogue advance fallback.
                string[] dialogueTapPaths = new string[]
                {
                    "GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)/AniRoot@go@ani/main@go/DialogMsgWidget@go@w/content@go/text@list@t/Viewport/textContent@t/DialogueTextWidget(Clone)/content@txt",
                    "GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)/AniRoot@go@ani/main@go/DialogMsgWidget@go@w/content@go/bg",
                    "GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)/AniRoot@go@ani/main@go/DialogMsgWidget@go@w/content@go",
                    "GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)/AniRoot@go@ani/main@go/DialogMsgWidget@go@w"
                };

                for (int i = 0; i < dialogueTapPaths.Length; i++)
                {
                    GameObject go = GameObject.Find(dialogueTapPaths[i]);
                    if (go != null && go.activeInHierarchy)
                    {
                        SimulateClick(go);
                    }
                }

                this.TryAdvanceDialogueText();

                // Try closing SalePanel and ShopPanel using generic close/back buttons.
                string[] panelPaths = new string[]
                {
                    "GameApp/startup_root(Clone)/XDUIRoot/Top/SalePanel(Clone)",
                    "GameApp/startup_root(Clone)/XDUIRoot/Full/ShopPanel(Clone)"
                };

                for (int p = 0; p < panelPaths.Length; p++)
                {
                    GameObject panel = GameObject.Find(panelPaths[p]);
                    if (panel == null || !panel.activeInHierarchy) continue;

                    Button[] buttons = panel.GetComponentsInChildren<Button>(true);
                    for (int i = 0; i < buttons.Length; i++)
                    {
                        Button b = buttons[i];
                        if (b == null || !b.interactable || !b.gameObject.activeInHierarchy) continue;
                        string n = (b.name ?? string.Empty).ToLowerInvariant();
                        if (n.Contains("close") || n.Contains("back") || n.Contains("return") || n.Contains("exit") || n.Contains("cancel"))
                        {
                            b.onClick.Invoke();
                            break;
                        }
                    }
                }
            }
            catch { }
        }

        private bool TryCloseAutoBuyObtainedPopup()
        {
            try
            {
                string panelPath = "GameApp/startup_root(Clone)/XDUIRoot/Top/AlertRewardPanel(Clone)";
                GameObject rewardPanel = GameObject.Find(panelPath);
                
                // Only proceed if panel is actually detected
                if (rewardPanel == null || !rewardPanel.activeInHierarchy)
                {
                    return false;
                }

                // Track that we detected the panel - we'll verify it closes after attempting
                bool attemptedClose = false;

                if (this.TryCloseAlertRewardPopupViaTipManager())
                {
                    attemptedClose = true;
                }

                if (!attemptedClose && this.TryInvokeAlertRewardPanelConfirm(rewardPanel))
                {
                    attemptedClose = true;
                }

                string confirmPath = panelPath + "/AniRoot@ani/mask/operatorsframe/confirm@btn";
                if (!attemptedClose && this.ClickButtonIfExistsReturn(confirmPath))
                {
                    attemptedClose = true;
                }

                if (!attemptedClose)
                {
                    string[] directPaths = new string[]
                    {
                        panelPath + "/AniRoot@ani/popup/background",
                        panelPath + "/AniRoot@ani/mask",
                        panelPath + "/AniRoot@ani/popup/content/rewards@list/Viewport/Content/RewardWidget(Clone)/cell@btn"
                    };

                    for (int i = 0; i < directPaths.Length; i++)
                    {
                        GameObject target = GameObject.Find(directPaths[i]);
                        if (target != null && target.activeInHierarchy && (this.DirectClickGameButtonReturn(target) || SimulateClick(target)))
                        {
                            attemptedClose = true;
                            break;
                        }
                    }
                }

                if (!attemptedClose)
                {
                    if (this.DirectClickGameButtonReturn(rewardPanel) || SimulateClick(rewardPanel))
                    {
                        attemptedClose = true;
                    }
                    else
                    {
                        this.SendLeftClickInputTap();
                        this.SendEnterMessage();
                        this.SendEscMessage();
                        attemptedClose = true;
                    }
                }

                if (!attemptedClose && Time.unscaledTime >= this.autoBuyPopupSlowScanAt)
                {
                    this.autoBuyPopupSlowScanAt = Time.unscaledTime + 1f;
                    // Use Object.FindObjectsOfType (active-only) instead of Resources.FindObjectsOfTypeAll (all including inactive)
                    Transform[] allTransforms = Object.FindObjectsOfType<Transform>();
                    for (int i = 0; i < allTransforms.Length; i++)
                    {
                        Transform tr = allTransforms[i];
                        if (tr == null) continue;
                        string name = tr.name ?? string.Empty;
                        if (!name.Equals("AlertRewardPanel(Clone)", StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        GameObject go = tr.gameObject;
                        if (go == null || !go.activeInHierarchy) continue;
                        if (this.DirectClickGameButtonReturn(go) || SimulateClick(go))
                        {
                            attemptedClose = true;
                            break;
                        }
                    }
                }

                // Verify the panel actually closed before returning true
                if (attemptedClose)
                {
                    GameObject verifyPanel = GameObject.Find(panelPath);
                    if (verifyPanel == null || !verifyPanel.activeInHierarchy)
                    {
                        LogAutoBuy(" Obtained popup closed successfully");
                        return true;
                    }
                    // Panel still exists, don't return true yet - let caller retry
                    LogAutoBuy(" Attempted to close popup but panel still visible");
                    return false;
                }
            }
            catch { }
            return false;
        }

        private bool TryCloseAlertRewardPopupViaTipManager()
        {
            try
            {
                if (this.TryCloseAlertRewardPopupViaTipManagerMono())
                {
                    return true;
                }

                // Resolve types and methods once and cache them (avoids repeated FindLoadedType + GetMethods per 0.12s call)
                if (!this.tipManagerReflectionInitialized)
                {
                    this.tipManagerReflectionInitialized = true;
                    this.cachedTipManagerType = this.FindLoadedType("XDTGame.UI.Panel.Tip.TipManager", "TipManager");
                    this.cachedAlertRewardPanelType = this.FindLoadedType("XDTGame.UI.Panel.AlertRewardPanel", "AlertRewardPanel");
                    if (this.cachedTipManagerType != null)
                    {
                        this.cachedTipInstanceProp = this.cachedTipManagerType.GetProperty("Instance", BindingFlags.Public | BindingFlags.Static);
                        this.cachedGetTipByTypeMethod = this.cachedTipManagerType.GetMethod("GetTip", BindingFlags.Public | BindingFlags.Instance, null, new Type[] { typeof(Type) }, null);
                        this.cachedTipPanelField = this.cachedTipManagerType.GetField("_tipPanel", BindingFlags.Instance | BindingFlags.NonPublic);
                        if (this.cachedAlertRewardPanelType != null)
                        {
                            foreach (MethodInfo method in this.cachedTipManagerType.GetMethods(BindingFlags.Public | BindingFlags.Instance))
                            {
                                if (method.Name == "GetTip" && method.IsGenericMethodDefinition && method.GetParameters().Length == 0)
                                    this.cachedGetTipGenericMethod = method.MakeGenericMethod(this.cachedAlertRewardPanelType);
                                else if (method.Name == "CloseTip" && method.IsGenericMethodDefinition && method.GetParameters().Length == 0)
                                    this.cachedCloseTipGenericMethod = method.MakeGenericMethod(this.cachedAlertRewardPanelType);
                            }
                            this.cachedAlertPanelClearMethod = this.cachedAlertRewardPanelType.GetMethod("Clear", BindingFlags.Public | BindingFlags.Instance);
                        }
                    }
                }

                Type tipManagerType = this.cachedTipManagerType;
                Type alertRewardPanelType = this.cachedAlertRewardPanelType;
                if (tipManagerType == null || alertRewardPanelType == null)
                {
                    return false;
                }

                PropertyInfo instanceProp = this.cachedTipInstanceProp;
                object tipManager = instanceProp != null ? instanceProp.GetValue(null, null) : null;
                if (tipManager == null)
                {
                    return false;
                }

                MethodInfo getTipByTypeMethod = this.cachedGetTipByTypeMethod;
                object liveTip = getTipByTypeMethod != null ? getTipByTypeMethod.Invoke(tipManager, new object[] { alertRewardPanelType }) : null;
                if (liveTip != null)
                {
                    MethodInfo closeSelfGeneric = liveTip.GetType().GetMethod("Close", BindingFlags.Instance | BindingFlags.NonPublic);
                    if (closeSelfGeneric != null && closeSelfGeneric.IsGenericMethodDefinition)
                    {
                        closeSelfGeneric.MakeGenericMethod(alertRewardPanelType).Invoke(liveTip, null);
                        return true;
                    }
                }

                MethodInfo getTipMethod = this.cachedGetTipGenericMethod;
                MethodInfo closeTipMethod = this.cachedCloseTipGenericMethod;

                if (getTipMethod != null)
                {
                    object tip = getTipMethod.Invoke(tipManager, null);
                    if (tip != null)
                    {
                        MethodInfo clearMethod = this.cachedAlertPanelClearMethod;
                        if (clearMethod != null)
                        {
                            clearMethod.Invoke(tip, null);
                        }
                    }
                }

                if (closeTipMethod != null)
                {
                    closeTipMethod.Invoke(tipManager, null);
                    return true;
                }

                FieldInfo tipPanelField = this.cachedTipPanelField;
                object tipPanel = tipPanelField != null ? tipPanelField.GetValue(tipManager) : null;
                if (tipPanel != null)
                {
                    FieldInfo tipClassifiesField = tipPanel.GetType().GetField("_tipClassifies", BindingFlags.Instance | BindingFlags.NonPublic);
                    System.Collections.IDictionary tipClassifies = tipClassifiesField != null ? tipClassifiesField.GetValue(tipPanel) as System.Collections.IDictionary : null;
                    if (tipClassifies != null)
                    {
                        foreach (object classifyObj in tipClassifies.Values)
                        {
                            if (classifyObj == null) continue;
                            MethodInfo closeTipByType = classifyObj.GetType().GetMethod("CloseTip", BindingFlags.Public | BindingFlags.Instance, null, new Type[] { typeof(Type) }, null);
                            if (closeTipByType == null) continue;
                            closeTipByType.Invoke(classifyObj, new object[] { alertRewardPanelType });
                        }

                        if (getTipByTypeMethod != null)
                        {
                            object stillOpen = getTipByTypeMethod.Invoke(tipManager, new object[] { alertRewardPanelType });
                            if (stillOpen == null)
                            {
                                return true;
                            }
                        }
                    }
                }
            }
            catch { }

            return false;
        }

        private unsafe bool TryCloseAlertRewardPopupViaTipManagerMono()
        {
            try
            {
                this.ResolveAuraFarmRuntimeMethodsViaMono();
                if (!this.EnsureAuraMonoApiReady() || !this.AttachAuraMonoThread() || auraMonoClassFromName == null || auraMonoClassGetMethodFromName == null || auraMonoRuntimeInvoke == null || auraMonoStringNew == null || this.auraMonoTypeGetTypeMethodPtr == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr levelImage = this.FindAuraMonoImage(new string[]
                {
                    "XDTLevelAndEntity",
                    "XDTLevelAndEntity.dll"
                });
                IntPtr tipManagerClass = levelImage != IntPtr.Zero ? auraMonoClassFromName(levelImage, "XDTGame.UI.Panel.Tip", "TipManager") : IntPtr.Zero;
                if (tipManagerClass == IntPtr.Zero)
                {
                    tipManagerClass = this.FindAuraMonoClassAcrossLoadedAssemblies("XDTGame.UI.Panel.Tip", "TipManager");
                }

                IntPtr alertRewardPanelClass = levelImage != IntPtr.Zero ? auraMonoClassFromName(levelImage, "XDTGame.UI.Panel", "AlertRewardPanel") : IntPtr.Zero;
                if (alertRewardPanelClass == IntPtr.Zero)
                {
                    alertRewardPanelClass = this.FindAuraMonoClassAcrossLoadedAssemblies("XDTGame.UI.Panel", "AlertRewardPanel");
                }

                if (tipManagerClass == IntPtr.Zero || alertRewardPanelClass == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr getInstanceMethod = auraMonoClassGetMethodFromName(tipManagerClass, "get_Instance", 0);
                IntPtr getTipByTypeMethod = auraMonoClassGetMethodFromName(tipManagerClass, "GetTip", 1);
                IntPtr clearMethod = auraMonoClassGetMethodFromName(alertRewardPanelClass, "Clear", 0);
                IntPtr displayMethod = auraMonoClassGetMethodFromName(alertRewardPanelClass, "Display", 0);
                if (getInstanceMethod == IntPtr.Zero || getTipByTypeMethod == IntPtr.Zero || clearMethod == IntPtr.Zero || displayMethod == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr tipManagerObj = IntPtr.Zero;
                IntPtr exc = IntPtr.Zero;
                tipManagerObj = auraMonoRuntimeInvoke(getInstanceMethod, IntPtr.Zero, IntPtr.Zero, ref exc);
                if (exc != IntPtr.Zero || tipManagerObj == IntPtr.Zero)
                {
                    return false;
                }

                string[] typeNameCandidates = new string[]
                {
                    "XDTGame.UI.Panel.AlertRewardPanel, XDTLevelAndEntity",
                    "XDTGame.UI.Panel.AlertRewardPanel, XDTLevelAndEntity.dll"
                };

                IntPtr typeObj = IntPtr.Zero;
                for (int i = 0; i < typeNameCandidates.Length && typeObj == IntPtr.Zero; i++)
                {
                    IntPtr typeNameStr = auraMonoStringNew(this.auraMonoRootDomain, typeNameCandidates[i]);
                    if (typeNameStr == IntPtr.Zero)
                    {
                        continue;
                    }

                    exc = IntPtr.Zero;
                    IntPtr* typeArgs = stackalloc IntPtr[1];
                    typeArgs[0] = typeNameStr;
                    typeObj = auraMonoRuntimeInvoke(this.auraMonoTypeGetTypeMethodPtr, IntPtr.Zero, (IntPtr)typeArgs, ref exc);
                    if (exc != IntPtr.Zero)
                    {
                        typeObj = IntPtr.Zero;
                    }
                }

                if (typeObj == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr tipObj = IntPtr.Zero;
                exc = IntPtr.Zero;
                IntPtr* args = stackalloc IntPtr[1];
                args[0] = typeObj;
                tipObj = auraMonoRuntimeInvoke(getTipByTypeMethod, tipManagerObj, (IntPtr)args, ref exc);
                if (exc != IntPtr.Zero || tipObj == IntPtr.Zero)
                {
                    return false;
                }

                exc = IntPtr.Zero;
                auraMonoRuntimeInvoke(clearMethod, tipObj, IntPtr.Zero, ref exc);
                if (exc != IntPtr.Zero)
                {
                    return false;
                }

                exc = IntPtr.Zero;
                auraMonoRuntimeInvoke(displayMethod, tipObj, IntPtr.Zero, ref exc);
                if (exc != IntPtr.Zero)
                {
                    return false;
                }

                exc = IntPtr.Zero;
                IntPtr stillOpen = auraMonoRuntimeInvoke(getTipByTypeMethod, tipManagerObj, (IntPtr)args, ref exc);
                return exc == IntPtr.Zero && stillOpen == IntPtr.Zero;
            }
            catch
            {
                return false;
            }
        }

        private bool DirectClickGameButtonReturn(GameObject buttonObj)
        {
            if (buttonObj == null || !buttonObj.activeInHierarchy)
            {
                return false;
            }

            try
            {
                this.DirectClickGameButton(buttonObj);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private bool TryInvokeAlertRewardPanelConfirm(GameObject rewardPanel)
        {
            if (rewardPanel == null)
            {
                return false;
            }

            try
            {
                Transform[] chain = new Transform[]
                {
                    rewardPanel.transform,
                    rewardPanel.transform.parent,
                    rewardPanel.transform.parent != null ? rewardPanel.transform.parent.parent : null
                };

                for (int i = 0; i < chain.Length; i++)
                {
                    Transform tr = chain[i];
                    if (tr == null) continue;
                    Component[] components = tr.GetComponents<Component>();
                    for (int j = 0; j < components.Length; j++)
                    {
                        Component component = components[j];
                        if (component == null) continue;
                        Type type = component.GetType();
                        string typeName = type.Name ?? string.Empty;
                        if (!typeName.Equals("AlertRewardPanel", StringComparison.OrdinalIgnoreCase))
                        {
                            continue;
                        }

                        MethodInfo clickConfirm = type.GetMethod("ClickConfirm", BindingFlags.Instance | BindingFlags.NonPublic);
                        if (clickConfirm != null)
                        {
                            ParameterInfo[] parameters = clickConfirm.GetParameters();
                            object[] args = parameters.Length == 1 ? new object[] { null } : null;
                            clickConfirm.Invoke(component, args);
                            return true;
                        }

                        MethodInfo display = type.GetMethod("Display", BindingFlags.Instance | BindingFlags.NonPublic);
                        if (display != null)
                        {
                            display.Invoke(component, null);
                            return true;
                        }
                    }
                }
            }
            catch { }

            return false;
        }

        private bool TryClickNpcChatIcon()
        {
            try
            {
                // Preferred: use IconsBarWidget candidates and score by known interaction sprite IDs.
                // From user logs this UI exposes two candidates: ui_dynamic_interaction_301 and ui_dynamic_interaction_3010.
                try
                {
                    var listRoot = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Bottom/TrackingPanel(Clone)/tracking_bar@w/tracking_common@list/IconsBarWidget(Clone)/root_visible@go/cells@t/cells@list");
                    if (listRoot != null)
                    {
                        Transform bestCell = null;
                        string bestSprite = string.Empty;
                        int bestScore = int.MinValue;

                        int childCount = listRoot.transform.childCount;
                        for (int ci = 0; ci < childCount; ci++)
                        {
                            var cell = listRoot.transform.GetChild(ci);
                            if (cell == null || !cell.gameObject.activeInHierarchy) continue;

                            var cellImgs = cell.GetComponentsInChildren<Image>(true);
                            if (cellImgs == null || cellImgs.Length == 0) continue;

                            string iconSprite = string.Empty;
                            for (int ii = 0; ii < cellImgs.Length; ii++)
                            {
                                var im = cellImgs[ii];
                                if (im == null || im.sprite == null) continue;

                                string imgName = (im.name ?? string.Empty).ToLowerInvariant();
                                string sp = (im.sprite.name ?? string.Empty).ToLowerInvariant();
                                if (imgName.Contains("icon@img@btn") || sp.Contains("ui_dynamic_interaction_"))
                                {
                                    iconSprite = sp;
                                    break;
                                }

                                if (string.IsNullOrEmpty(iconSprite))
                                {
                                    iconSprite = sp;
                                }
                            }

                            if (string.IsNullOrEmpty(iconSprite)) continue;

                            int score = 0;
                            // Prefer the exact observed NPC interaction icon first.
                            if (iconSprite.Contains("ui_dynamic_interaction_301(clone)") || iconSprite.EndsWith("_301")) score += 120;
                            else if (iconSprite.Contains("ui_dynamic_interaction_3010(clone)") || iconSprite.EndsWith("_3010")) score += 90;

                            if (iconSprite.Contains("chat") || iconSprite.Contains("talk") || iconSprite.Contains("bubble") || iconSprite.Contains("dialog")) score += 40;

                            if (score > bestScore)
                            {
                                bestScore = score;
                                bestCell = cell;
                                bestSprite = iconSprite;
                            }
                        }

                        if (bestCell != null && bestScore > 0)
                        {
                            var iconBtnNode = bestCell.Find("root_visible@go/icon@img@btn");
                            if (iconBtnNode != null)
                            {
                                var iconBtn = iconBtnNode.GetComponent<Button>();
                                if (iconBtn != null && iconBtn.interactable)
                                {
                                    iconBtn.onClick.Invoke();
                                    LogAutoBuy(" Clicked interaction icon: " + bestSprite);
                                    return true;
                                }

                                if (SimulateClick(iconBtnNode.gameObject))
                                {
                                    LogAutoBuy(" SimClicked interaction icon: " + bestSprite);
                                    return true;
                                }
                            }

                            var btn = bestCell.GetComponentInChildren<Button>(true);
                            if (btn != null && btn.interactable)
                            {
                                btn.onClick.Invoke();
                                LogAutoBuy(" Clicked best IconsBarWidget cell: " + bestSprite);
                                return true;
                            }
                        }
                    }
                }
                catch (Exception ex) { LogAutoBuy(" IconsBarWidget search error: " + ex.Message); }
                var imgs = Object.FindObjectsOfType<Image>();
                foreach (var img in imgs)
                {
                    if (img == null || img.sprite == null || !img.gameObject.activeInHierarchy) continue;
                    string s = img.sprite.name.ToLowerInvariant();
                    if (s.Contains("chat") || s.Contains("talk") || s.Contains("bubble") || s.Contains("dialog") || s.Contains("petplay"))
                    {
                        var btn = img.GetComponentInParent<Button>();
                        if (btn != null && btn.interactable) { btn.onClick.Invoke(); LogAutoBuy(" Clicked chat Button"); return true; }
                        Transform t = img.transform;
                        for (int i = 0; i < 6 && t != null; i++)
                        {
                            if (SimulateClick(t.gameObject)) { LogAutoBuy(" Simulated click on chat UI"); return true; }
                            t = t.parent;
                        }
                    }
                }
            }
            catch (Exception ex) { LogAutoBuy(" TryClickNpcChatIcon error: " + ex.Message); }
            // Prefer dialog-specific icon GameObjects by name to avoid global player-chat icon
            try
            {
                // Single pass through active-only transforms (replaces 5x Resources.FindObjectsOfTypeAll which includes inactive objects)
                Transform[] activeTransforms = Object.FindObjectsOfType<Transform>();
                for (int ti = 0; ti < activeTransforms.Length; ti++)
                {
                    Transform tr = activeTransforms[ti];
                    try
                    {
                        if (tr == null) continue;
                        string trName = tr.name;
                        if (string.IsNullOrEmpty(trName)) continue;
                        if (!trName.Contains("CommonIconForDialog") && !trName.Contains("CommonIconForCookNormalDialog") &&
                            !trName.Contains("CommonIconForCookDangerDialog") && !trName.Contains("CommonIconForRecycleDialog")) continue;
                        // find a Button or Image child to click
                        var btn = tr.GetComponentInChildren<Button>(true);
                        if (btn != null && btn.interactable) { btn.onClick.Invoke(); if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] Clicked preferred icon '{trName}'"); }
                            // verify dialogue opened
                            var dlg = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)");
                            if (dlg != null && dlg.activeInHierarchy) return true;
                        }
                        var img = tr.GetComponentInChildren<Image>(true);
                        if (img != null)
                        {
                            if (img.GetComponentInParent<Button>() is Button b && b.interactable) { b.onClick.Invoke(); if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] Clicked preferred image button '{trName}'"); } var dlg2 = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)"); if (dlg2 != null && dlg2.activeInHierarchy) return true; }
                            if (SimulateClick(img.gameObject)) { if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] SimClicked preferred image '{trName}'"); } var dlg3 = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)"); if (dlg3 != null && dlg3.activeInHierarchy) return true; }
                        }
                    }
                    catch { }
                }
            }
            catch (Exception ex) { LogAutoBuy(" Preferred icon search error: " + ex.Message); }

            // Fallback: find NPC name Texts and click nearby Image UI (chat bubble above NPC)
            try
            {
                Camera cam = Camera.main;
                if (cam != null)
                {
                    var texts = Object.FindObjectsOfType<Text>();
                    // Hoist Image scan outside the Text loop: was O(NxM), now O(N+M)
                    var allImgs = Object.FindObjectsOfType<Image>();
                    foreach (var t in texts)
                    {
                        try
                        {
                            if (t == null || !t.gameObject.activeInHierarchy) continue;
                            string txt = t.text ?? "";
                            if (string.IsNullOrWhiteSpace(txt)) continue;
                            // avoid UI menu texts by ignoring DialoguePanel and other known panels
                            if (t.transform.IsChildOf(GameObject.Find("GameApp/startup_root(Clone)")?.transform) == false) continue;
                            Vector3 worldPos = t.transform.position;
                            Vector3 screen = cam.WorldToScreenPoint(worldPos);
                            if (screen.z < 0) continue;
                            // search images near this screen point
                            foreach (var im in allImgs)
                            {
                                if (im == null || !im.gameObject.activeInHierarchy) continue;
                                Vector3 imScreen = cam.WorldToScreenPoint(im.transform.position);
                                if (imScreen.z < 0) continue;
                                float dist = Vector2.Distance(new Vector2(screen.x, screen.y), new Vector2(imScreen.x, imScreen.y));
                                if (dist < 140f)
                                {
                                    // likely the bubble icon above this NPC
                                    var btn = im.GetComponentInParent<Button>();
                                    if (btn != null && btn.interactable) { btn.onClick.Invoke(); if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] Clicked nearby UI '{im.name}' near name '{txt}'"); } return true; }
                                    if (SimulateClick(im.gameObject)) { if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] SimClicked nearby UI '{im.name}' near name '{txt}'"); } return true; }
                                }
                            }
                        }
                        catch { }
                    }
                }
            }
            catch (Exception ex) { LogAutoBuy(" Fallback detection error: " + ex.Message); }

            return false;
        }

        private bool ClickDialogueOptionByTitle(string title)
        {
            try
            {
                GameObject panel = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)");
                if (panel == null || !panel.activeInHierarchy) return false;
                Transform viewportContent = panel.transform.Find("AniRoot@go@ani/option@w/option@list/Viewport/Content");
                if (viewportContent == null)
                {
                    var allChildren = panel.GetComponentsInChildren<Transform>(true);
                    for (int i = 0; i < allChildren.Length; i++)
                    {
                        var child = allChildren[i];
                        if (child != null && child.name != null && child.name.Contains("ImageTextBtnWidget")) { viewportContent = child.parent; break; }
                    }
                    if (viewportContent == null) return false;
                }
                string lower = title.ToLowerInvariant();
                int childCount = viewportContent.childCount;
                for (int ci = 0; ci < childCount; ci++)
                {
                    Transform cell = viewportContent.GetChild(ci);
                    if (cell == null) continue;
                    var titleTxtTransform = cell.Find("AniRoot@go@ani/cell@btn/title@txt");
                    Text titleTxt = null;
                    if (titleTxtTransform != null) titleTxt = titleTxtTransform.GetComponent<Text>();
                    if (titleTxt == null) titleTxt = cell.GetComponentInChildren<Text>(true);
                    if (titleTxt != null && titleTxt.text != null && titleTxt.text.ToLowerInvariant().Contains(lower))
                    {
                        var btn = cell.GetComponentInChildren<Button>(true);
                        if (btn != null && btn.interactable) { btn.onClick.Invoke(); if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] Selected dialog option \"{titleTxt.text}\""); } return true; }
                        if (SimulateClick(cell.gameObject)) { if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] SimClicked dialog option \"{titleTxt.text}\""); } return true; }
                    }
                }
            }
            catch (Exception ex) { LogAutoBuy(" ClickDialogueOptionByTitle error: " + ex.Message); }
            return false;
        }

        private bool ClickDialogueOptionByKeywords(string[] keywords)
        {
            try
            {
                GameObject panel = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)");
                if (panel == null || !panel.activeInHierarchy) return false;

                Transform viewportContent = panel.transform.Find("AniRoot@go@ani/option@w/option@list/Viewport/Content");
                if (viewportContent == null || viewportContent.childCount <= 0) return false;

                int bestIndex = -1;
                int bestScore = int.MinValue;

                for (int ci = 0; ci < viewportContent.childCount; ci++)
                {
                    Transform cell = viewportContent.GetChild(ci);
                    if (cell == null || !cell.gameObject.activeInHierarchy) continue;

                    string textLower = string.Empty;
                    Text titleTxt = cell.Find("AniRoot@go@ani/cell@btn/title@txt")?.GetComponent<Text>() ?? cell.GetComponentInChildren<Text>(true);
                    if (titleTxt != null && !string.IsNullOrEmpty(titleTxt.text))
                    {
                        textLower = titleTxt.text.ToLowerInvariant();
                    }

                    int score = 0;
                    if (!string.IsNullOrEmpty(textLower))
                    {
                        for (int k = 0; k < keywords.Length; k++)
                        {
                            string kw = keywords[k];
                            if (string.IsNullOrEmpty(kw)) continue;
                            string kwLower = kw.ToLowerInvariant();
                            if (textLower.Contains(kwLower)) score += 20;
                        }

                        if (textLower.Contains("cooking store")) score += 100;
                        else if (textLower.Contains("cook") && textLower.Contains("store")) score += 80;
                    }

                    // Icon fallback: shopping/cart-like option often has a cart/store icon.
                    Image[] imgs = cell.GetComponentsInChildren<Image>(true);
                    for (int i = 0; i < imgs.Length; i++)
                    {
                        Image im = imgs[i];
                        if (im == null || im.sprite == null) continue;
                        string sp = im.sprite.name.ToLowerInvariant();
                        if (sp.Contains("shop") || sp.Contains("store") || sp.Contains("cart")) score += 25;
                    }

                    if (score > bestScore)
                    {
                        bestScore = score;
                        bestIndex = ci;
                    }
                }

                if (bestIndex < 0 || bestScore <= 0) return false;

                Transform bestCell = viewportContent.GetChild(bestIndex);
                if (bestCell == null) return false;

                Button btn = bestCell.GetComponentInChildren<Button>(true);
                if (btn != null && btn.interactable)
                {
                    btn.onClick.Invoke();
                    LogAutoBuy(" Selected dialog option by keyword score=" + bestScore);
                    return true;
                }

                if (SimulateClick(bestCell.gameObject))
                {
                    LogAutoBuy(" SimClicked dialog option by keyword score=" + bestScore);
                    return true;
                }
            }
            catch (Exception ex)
            {
                LogAutoBuy(" ClickDialogueOptionByKeywords error: " + ex.Message);
            }

            return false;
        }

