        private bool TryAdvanceDialogueText()
        {
            try
            {
                GameObject panel = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)");
                if (panel == null || !panel.activeInHierarchy) return false;

                // First try explicit next/continue/skip style buttons.
                Button[] buttons = panel.GetComponentsInChildren<Button>(true);
                for (int i = 0; i < buttons.Length; i++)
                {
                    Button b = buttons[i];
                    if (b == null || !b.interactable || !b.gameObject.activeInHierarchy) continue;
                    string n = (b.name ?? string.Empty).ToLowerInvariant();
                    if (n.Contains("next") || n.Contains("continue") || n.Contains("skip") || n.Contains("content"))
                    {
                        b.onClick.Invoke();
                        return true;
                    }
                }

                // Fallback: click likely dialogue content regions to finish typewriter text.
                string[] clickPaths = new string[]
                {
                    // Exact paths from UI inspector (most reliable for skipping typewriter text)
                    "AniRoot@go@ani/main@go/DialogMsgWidget@go@w/content@go/text@list@t/Viewport/textContent@t/DialogueTextWidget(Clone)/content@txt",
                    "AniRoot@go@ani/main@go/DialogMsgWidget@go@w/content@go/bg",
                    "AniRoot@go@ani/content@w",
                    "AniRoot@go@ani/content@w/content@txt",
                    "AniRoot@go@ani/content@w/content@go",
                    "AniRoot@go@ani/main@go/DialogMsgWidget@go@w/content@go",
                    "AniRoot@go@ani"
                };

                bool clickedAny = false;
                for (int i = 0; i < clickPaths.Length; i++)
                {
                    Transform t = panel.transform.Find(clickPaths[i]);
                    if (t == null || !t.gameObject.activeInHierarchy) continue;
                    if (SimulateClick(t.gameObject)) clickedAny = true;
                }

                if (clickedAny) return true;

                // Broad fallback: find the first interactable button that is NOT inside the options
                // list AND not a back/exit/close button. Catches transparent click-to-advance buttons
                // used by simple farewell dialogues like "Thank you for your patronage."
                Transform optionContent = panel.transform.Find("AniRoot@go@ani/option@w/option@list/Viewport/Content");
                Button[] allButtons = panel.GetComponentsInChildren<Button>(true);
                for (int i = 0; i < allButtons.Length; i++)
                {
                    Button b = allButtons[i];
                    if (b == null || !b.interactable || !b.gameObject.activeInHierarchy) continue;
                    if (optionContent != null && b.transform.IsChildOf(optionContent)) continue;
                    string n = (b.name ?? string.Empty).ToLowerInvariant();
                    if (n.Contains("back") || n.Contains("exit") || n.Contains("close") || n.Contains("cancel")) continue;
                    b.onClick.Invoke();
                    return true;
                }

                return SimulateClick(panel);
            }
            catch { }

            return false;
        }

        private bool IsGoldCurrencyItem(Transform goodsWidget)
        {
            try
            {
                // Check currency icon path: AniRoot@ani/info@group/currency@go/currency@w/Group/icon@img
                Transform iconImg = goodsWidget.Find("AniRoot@ani/info@group/currency@go/currency@w/Group/icon@img")
                    ?? goodsWidget.Find("AniRoot@ani/info@group/currency@go/icon@img")
                    ?? goodsWidget.Find("currency@go/icon@img");
                if (iconImg != null)
                {
                    var img = iconImg.GetComponent<Image>();
                    if (img != null && img.sprite != null)
                    {
                        string spriteName = img.sprite.name ?? "";
                        // Sprite names are numeric:
                        // "1(Clone)" = gold coin (what we want)
                        // "4(Clone)" = theme coin (star - skip)
                        // "2(Clone)" = diamond (skip)
                        bool isGold = spriteName.StartsWith("1");
                        if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] Currency sprite: {spriteName}, isGold={isGold}"); }
                        return isGold;
                    }
                    else
                    {
                        LogAutoBuy(" Currency Image component or sprite is null");
                    }
                }
                else
                {
                    // No currency icon found - might be gold by default, allow it
                    LogAutoBuy(" No currency icon found, allowing item");
                    return true;
                }
            }
            catch (Exception ex)
            {
                if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] IsGoldCurrencyItem error: {ex.Message}"); }
            }
            // Default to true (allow) if we can't determine currency type
            return true;
        }

        private bool TryClickVisibleCookingStoreItemByMatch(Transform content, string match)
        {
            if (content == null) return false;
            string[] matchCandidates = LocalizationManager.GetTranslationCandidates(match);
            for (int i = 0; i < content.childCount; i++)
            {
                Transform gw = content.GetChild(i);
                if (gw == null) continue;
                // primary reliable name path
                Transform nameT = gw.Find("AniRoot@ani/info@group/titleName/name@txt") ?? gw.Find("AniRoot@ani/info@group/titleName/titleNameNormal_img");
                string txtVal = null;
                if (nameT != null)
                {
                    Text t = nameT.GetComponent<Text>();
                    if (t != null) txtVal = t.text;
                }
                // fallback: any child Text
                if (string.IsNullOrEmpty(txtVal))
                {
                    var any = gw.GetComponentInChildren<Text>(true);
                    if (any != null) txtVal = any.text;
                }
                bool isMatch = false;
                if (!string.IsNullOrEmpty(txtVal))
                {
                    for (int c = 0; c < matchCandidates.Length; c++)
                    {
                        string candidate = matchCandidates[c];
                        if (!string.IsNullOrWhiteSpace(candidate) && txtVal.IndexOf(candidate, StringComparison.InvariantCultureIgnoreCase) >= 0)
                        {
                            isMatch = true;
                            break;
                        }
                    }
                }

                if (isMatch)
                {
                    // Only click if this is a gold currency item (not star currency)
                    if (!IsGoldCurrencyItem(gw))
                    {
                        if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] Skipping {txtVal} - not gold currency (star/diamond item)"); }
                        continue;
                    }
                    Transform card = gw.Find("AniRoot@ani/card@btn") ?? gw.Find("card@btn");
                    if (card != null)
                    {
                        var b = card.GetComponent<Button>() ?? card.GetComponentInChildren<Button>(true);
                        if (b != null && b.interactable) { b.onClick.Invoke(); if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] Clicked item {txtVal}"); } return true; }
                        if (SimulateClick(card.gameObject)) { if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[AutoBuy] SimClicked item {txtVal}"); } return true; }
                    }
                }
            }
            return false;
        }

        private static void SetCookingStoreScrollPosition(ScrollRect scrollRect, float normalized)
        {
            if (scrollRect == null) return;
            scrollRect.verticalNormalizedPosition = Mathf.Clamp01(normalized);
        }

        private bool ClickCookingStoreItemByMatch(string match)
        {
            try
            {
                GameObject shop = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Full/ShopPanel(Clone)");
                if (shop == null) return false;
                Transform scrollTransform = shop.transform.Find("goods@scroll");
                Transform content = shop.transform.Find("goods@scroll/Content");
                if (content == null) return false;
                // if content exists but not populated yet, log and return false so caller can retry
                if (content.childCount == 0)
                {
                    LogAutoBuy(" Shop content empty - will retry shortly");
                    return false;
                }

                ScrollRect scrollRect = null;
                if (scrollTransform != null)
                {
                    scrollRect = scrollTransform.GetComponent<ScrollRect>() ?? scrollTransform.GetComponentInChildren<ScrollRect>(true);
                }

                if (TryClickVisibleCookingStoreItemByMatch(content, match)) return true;

                if (scrollRect != null)
                {
                    const int scrollSteps = 12;
                    if (this.autoBuyShopScrollStep < 0)
                    {
                        this.autoBuyShopScrollStep = 0;
                        SetCookingStoreScrollPosition(scrollRect, 1f);
                        return false;
                    }
                    else if (this.autoBuyShopScrollStep < scrollSteps)
                    {
                        this.autoBuyShopScrollStep++;
                        float normalized = 1f - ((float)this.autoBuyShopScrollStep / (float)scrollSteps);
                        SetCookingStoreScrollPosition(scrollRect, normalized);
                        return false;
                    }
                }
            }
            catch (Exception ex) { LogAutoBuy(" ClickCookingStoreItemByMatch error: " + ex.Message); }
            return false;
        }

