                        this.autoBuyGardenSubState = 2;
                        this.autoBuyGardenStepTimer = now + 0.8f;
                        LogAutoBuy("[Garden] Teleporting to NPC front position");
                        break;
                    case 2: // waiting for dialogue - click chat icon until dialogue shows
                        if (now < this.autoBuyGardenStepTimer) break;
                        if (TryClickNpcChatIcon()) { this.autoBuyGardenStepTimer = now + 0.5f; }
                        else { this.autoBuyGardenStepTimer = now + 0.12f; }
                        GameObject dlg = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)");
                        if (dlg != null && dlg.activeInHierarchy)
                        {
                            this.autoBuyGardenSubState = 3; this.autoBuyGardenStepTimer = now + 0.2f; LogAutoBuy("[Garden] Dialogue opened");
                        }
                        break;
                    case 3: // select gardening store
                        if (now < this.autoBuyGardenStepTimer) break;
                        if (!HasDialogueOptionsVisible())
                        {
                            if (TryAdvanceDialogueText())
                            {
                                LogAutoBuy("[Garden] Advanced dialogue text, waiting for options");
                            }
                            this.autoBuyGardenStepTimer = now + 0.12f;
                            break;
                        }
                        if (ClickDialogueOptionByKeywords(new string[] { "gardening store", "garden", "store" }))
                        {
                            this.autoBuyGardenSubState = 31;
                            this.autoBuyGardenStepTimer = now + 0.25f;
                            this.autoBuyGardenShopWaitStartedAt = now;
                            this.autoBuyGardenStoreSelectRetryCount++;
                            LogAutoBuy("[Garden] Selected Gardening Store, waiting for shop content");
                        }
                        else { this.autoBuyGardenStepTimer = now + 0.15f; }
                        break;
                    case 31: // wait for ShopPanel to appear and be populated
                        if (now < this.autoBuyGardenStepTimer) break;
                        GameObject shopChk = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Full/ShopPanel(Clone)");
                        if (shopChk != null && shopChk.activeInHierarchy)
                        {
                            Transform contentChk = shopChk.transform.Find("goods@scroll/Content");
                            if (contentChk != null && contentChk.childCount > 0)
                            {
                                this.autoBuyGardenSubState = 4; this.autoBuyGardenStepTimer = now + 0.12f; LogAutoBuy("[Garden] ShopPanel populated, proceeding to buy");
                                break;
                            }
                            else
                            {
                                LogAutoBuy("[Garden] Waiting for ShopPanel content to populate...");
                                this.autoBuyGardenStepTimer = now + 0.25f;
                                break;
                            }
                        }
                        if (ClickDialogueOptionByKeywords(new string[] { "gardening store", "garden", "store" }))
                        {
                            this.autoBuyGardenStoreSelectRetryCount++;
                            this.autoBuyGardenStepTimer = now + 0.25f;
                            LogAutoBuy("[Garden] Retried Gardening Store option while waiting for shop");
                            break;
                        }
                        if (TryAdvanceDialogueText())
                        {
                            this.autoBuyGardenStepTimer = now + 0.12f;
                            break;
                        }
                        if (this.autoBuyGardenShopWaitStartedAt <= 0f) this.autoBuyGardenShopWaitStartedAt = now;
                        if ((now - this.autoBuyGardenShopWaitStartedAt) > 2.5f)
                        {
                            LogAutoBuy("[Garden] Shop panel did not open yet, returning to store selection");
                            this.autoBuyGardenSubState = 3;
                            this.autoBuyGardenStepTimer = now + 0.1f;
                            this.autoBuyGardenShopWaitStartedAt = 0f;
                            break;
                        }
                        this.autoBuyGardenStepTimer = now + 0.25f;
                        break;
                    case 4: // buying items
                        if (now < this.autoBuyGardenStepTimer) break;
                        if (this.autoBuyGardenCurrentItemIndex >= this.autoBuyGardenItemsMatch.Length)
                        {
                            this.autoBuyGardenSubState = 5;
                            this.autoBuyGardenStepTimer = now + 3f;
                            LogAutoBuy("[Garden] Finished item loop, waiting before return");
                            break;
                        }
                        string match = this.autoBuyGardenItemsMatch[this.autoBuyGardenCurrentItemIndex];
                        if (this.autoBuyGardenPurchasedCount >= this.autoBuyGardenMaxPerItem)
                        {
                            this.autoBuyGardenPurchasedCount = 0; this.autoBuyGardenCurrentItemIndex++; this.autoBuyGardenShopScrollStep = -1; this.autoBuyGardenStepTimer = now + 0.1f; break;
                        }
                        bool clicked = ClickGardenStoreItemByMatch(match);
                        if (clicked)
                        {
                            this.autoBuyGardenShopScrollStep = -1;
                            this.autoBuyGardenSubState = 41;
                            this.autoBuyGardenStepTimer = now + 0.12f;
                            if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[Garden] Opened purchase dialog for {match}"); }
                        }
                        else
                        {
                            GameObject shopProbe = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Full/ShopPanel(Clone)");
                            Transform contentProbe = shopProbe != null ? shopProbe.transform.Find("goods@scroll/Content") : null;
                            if (shopProbe != null && contentProbe != null && contentProbe.childCount == 0)
                            {
                                if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[Garden] Shop content empty for item {match}, retrying shortly"); }
                                this.autoBuyGardenStepTimer = now + 0.25f;
                            }
                            else if (this.autoBuyGardenShopScrollStep >= 0 && this.autoBuyGardenShopScrollStep < 12)
                            {
                                this.autoBuyGardenStepTimer = now + 0.15f;
                            }
                            else
                            {
                                this.autoBuyGardenPurchasedCount = 0; this.autoBuyGardenCurrentItemIndex++; this.autoBuyGardenShopScrollStep = -1; this.autoBuyGardenStepTimer = now + 0.2f;
                                if (this.autoBuyLogsEnabled) { ModLogger.Msg("[Garden] Item " + match + " not found or sold out, skipping"); }
                            }
                        }
                        break;
                    case 41: // handle purchase dialog: press +10 until target then Purchase
                        if (now < this.autoBuyGardenStepTimer) break;
                        GameObject sale = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Top/SalePanel(Clone)");
                        if (sale == null || !sale.activeInHierarchy)
                        {
                            this.autoBuyGardenPurchasedCount = 0; this.autoBuyGardenCurrentItemIndex++; this.autoBuyGardenShopScrollStep = -1; this.autoBuyGardenStepTimer = now + 0.2f; this.autoBuyGardenSubState = 4;
                            LogAutoBuy("[Garden] Sale panel not found, skipping"); break;
                        }
                        int currentCount = GetSalePanelCurrentCount(sale);
                        int remainingStock = GetSalePanelRemainingStock(sale);
                        if (currentCount < 0) currentCount = 1;
                        int effectiveMax = this.autoBuyGardenMaxPerItem;
                        if (remainingStock > 0) effectiveMax = Mathf.Min(this.autoBuyGardenMaxPerItem, remainingStock);
                        if (currentCount >= effectiveMax)
                        {
                            if (ClickSalePurchase(sale))
                            {
                                this.autoBuyGardenPurchasedCount = currentCount;
                                if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[Garden] Purchased {currentCount} items (target: {effectiveMax})"); }
                            }
                            this.autoBuyGardenPurchasedCount = 0; this.autoBuyGardenCurrentItemIndex++; this.autoBuyGardenShopScrollStep = -1; this.autoBuyGardenSubState = 4; this.autoBuyGardenStepTimer = now + 0.25f;
                            break;
                        }
                        int needed = effectiveMax - currentCount;
                        int clicks = Mathf.CeilToInt((float)needed / 10f);
                        int doClicks = Mathf.Min(clicks, 3);
                        bool anyClicked = false;
                        for (int i = 0; i < doClicks; i++)
                        {
                            if (ClickSaleAddMore(sale)) { anyClicked = true; }
                        }
                        this.autoBuyGardenStepTimer = now + 0.12f;
                        if (!anyClicked)
                        {
                            if (currentCount > 0 && ClickSalePurchase(sale))
                            {
                                this.autoBuyGardenPurchasedCount = currentCount;
                                if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[Garden] Purchased {currentCount} items (shop stock limited, target was {effectiveMax})"); }
                            }
                            else
                            {
                                LogAutoBuy("[Garden] Could not purchase item - no stock available");
                            }
                            this.autoBuyGardenPurchasedCount = 0; this.autoBuyGardenCurrentItemIndex++; this.autoBuyGardenShopScrollStep = -1; this.autoBuyGardenSubState = 4; this.autoBuyGardenStepTimer = now + 0.25f;
                        }
                        break;
                    case 5: // return
                        this.CloseAutoBuyPanels();
                        if (now < this.autoBuyGardenStepTimer) break;
                        this.StopAutoBuyGarden("Done, returning");
                        break;
                }
            }
            catch (Exception ex) { LogAutoBuy("[Garden] Run error: " + ex.Message); this.StopAutoBuyGarden("Error"); }
        }

        // --- Auto Buy Fishing Store helpers + logic ---
        private void StartAutoBuyFishing()
        {
            try
            {
                GameObject p = GameObject.Find("p_player_skeleton(Clone)");
                if (p != null) this.autoBuyFishingSavedPosition = p.transform.position;
                this.autoBuyFishingSubState = 1;
                this.autoBuyFishingStepTimer = Time.unscaledTime + 0.1f;
                this.autoBuyFishingShopWaitStartedAt = 0f;
                this.autoBuyFishingStoreSelectRetryCount = 0;
                this.autoBuyFishingCurrentItemIndex = 0;
                this.autoBuyFishingPurchasedCount = 0;
                this.autoBuyFishingShopScrollStep = -1;
                this.autoBuyFishingPreviousGameSpeed = this.gameSpeed;
                this.SetGameSpeed(5f);
                this.autoBuyFishingForcedGameSpeed = true;
                this.TeleportToLocation(this.autoBuyFishingNearbyPos);
                LogAutoBuy("[Fishing] Started: teleporting to nearby position (Game Speed x5.0)");
            }
            catch (Exception ex) { LogAutoBuy("[Fishing] Start error: " + ex.Message); this.StopAutoBuyFishing("Start error"); }
        }

        private void StopAutoBuyFishing(string reason)
        {
            LogAutoBuy("[Fishing] Stopped: " + reason);
            this.CloseAutoBuyPanels();
            this.autoBuyFishingEnabled = false;
            this.autoBuyFishingSubState = 0;
            this.autoBuyFishingShopScrollStep = -1;
            if (this.autoBuyFishingForcedGameSpeed)
            {
                this.SetGameSpeed(Mathf.Max(1f, this.autoBuyFishingPreviousGameSpeed));
                this.autoBuyFishingForcedGameSpeed = false;
            }
            if (this.autoBuyFishingSavedPosition != Vector3.zero)
            {
                this.TeleportToLocation(this.autoBuyFishingSavedPosition);
                this.autoBuyFishingSavedPosition = Vector3.zero;
            }
        }

        private void RunAutoBuyFishingLogic()
        {
            try
            {
                if (!this.autoBuyFishingEnabled)
                {
                    if (this.autoBuyFishingForcedGameSpeed)
                    {
                        this.SetGameSpeed(Mathf.Max(1f, this.autoBuyFishingPreviousGameSpeed));
                        this.autoBuyFishingForcedGameSpeed = false;
                    }
                    return;
                }
                float now = Time.unscaledTime;

                // Close any popup that appears
                if (now >= this.autoBuyPopupCloseRetryAt && this.TryCloseAutoBuyObtainedPopup())
                {
                    this.autoBuyPopupCloseRetryAt = now + 0.12f;
                    this.autoBuyFishingStepTimer = now + 0.12f;
                    return;
                }
                if (now >= this.autoBuyPopupCloseRetryAt)
                {
                    this.autoBuyPopupCloseRetryAt = now + 0.2f;
                }

                switch (this.autoBuyFishingSubState)
                {
                    case 1: // teleporting to nearby position
                        if (this.teleportFramesRemaining <= 0)
                        {
                            this.autoBuyFishingSubState = 12;
                            this.autoBuyFishingStepTimer = now + 3f;
                            LogAutoBuy("[Fishing] Arrived at nearby position, waiting before approaching NPC");
                        }
                        break;
                    case 12: // waiting at nearby pos, then teleport to NPC front
                        if (now < this.autoBuyFishingStepTimer) break;
                        this.TeleportToLocation(this.autoBuyFishingTargetPos);
                        this.autoBuyFishingSubState = 2;
                        this.autoBuyFishingStepTimer = now + 0.8f;
                        LogAutoBuy("[Fishing] Teleporting to NPC front position");
                        break;
                    case 2: // waiting for dialogue - click chat icon until dialogue shows
                        if (now < this.autoBuyFishingStepTimer) break;
                        if (TryClickNpcChatIcon()) { this.autoBuyFishingStepTimer = now + 0.5f; }
                        else { this.autoBuyFishingStepTimer = now + 0.12f; }
                        GameObject dlg = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Scene/DialoguePanel(Clone)");
                        if (dlg != null && dlg.activeInHierarchy)
                        {
                            this.autoBuyFishingSubState = 3; this.autoBuyFishingStepTimer = now + 0.2f; LogAutoBuy("[Fishing] Dialogue opened");
                        }
                        break;
                    case 3: // select fishing store
                        if (now < this.autoBuyFishingStepTimer) break;
                        if (!HasDialogueOptionsVisible())
                        {
                            if (TryAdvanceDialogueText())
                            {
                                LogAutoBuy("[Fishing] Advanced dialogue text, waiting for options");
                            }
                            this.autoBuyFishingStepTimer = now + 0.12f;
                            break;
                        }
                        if (ClickDialogueOptionByKeywords(new string[] { "fishing store", "fishing", "store" }))
                        {
                            this.autoBuyFishingSubState = 31;
                            this.autoBuyFishingStepTimer = now + 0.25f;
                            this.autoBuyFishingShopWaitStartedAt = now;
                            this.autoBuyFishingStoreSelectRetryCount++;
                            LogAutoBuy("[Fishing] Selected Fishing Store, waiting for shop content");
                        }
                        else { this.autoBuyFishingStepTimer = now + 0.15f; }
                        break;
                    case 31: // wait for ShopPanel to appear and be populated
                        if (now < this.autoBuyFishingStepTimer) break;
                        GameObject shopChk = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Full/ShopPanel(Clone)");
                        if (shopChk != null && shopChk.activeInHierarchy)
                        {
                            Transform contentChk = shopChk.transform.Find("goods@scroll/Content");
                            if (contentChk != null && contentChk.childCount > 0)
                            {
                                this.autoBuyFishingSubState = 4; this.autoBuyFishingStepTimer = now + 0.12f; LogAutoBuy("[Fishing] ShopPanel populated, proceeding to buy");
                                break;
                            }
                            else
                            {
                                LogAutoBuy("[Fishing] Waiting for ShopPanel content to populate...");
                                this.autoBuyFishingStepTimer = now + 0.25f;
                                break;
                            }
                        }
                        if (ClickDialogueOptionByKeywords(new string[] { "fishing store", "fishing", "store" }))
                        {
                            this.autoBuyFishingStoreSelectRetryCount++;
                            this.autoBuyFishingStepTimer = now + 0.25f;
                            LogAutoBuy("[Fishing] Retried Fishing Store option while waiting for shop");
                            break;
                        }
                        if (TryAdvanceDialogueText())
                        {
                            this.autoBuyFishingStepTimer = now + 0.12f;
                            break;
                        }
                        if (this.autoBuyFishingShopWaitStartedAt <= 0f) this.autoBuyFishingShopWaitStartedAt = now;
                        if ((now - this.autoBuyFishingShopWaitStartedAt) > 2.5f)
                        {
                            LogAutoBuy("[Fishing] Shop panel did not open yet, returning to store selection");
                            this.autoBuyFishingSubState = 3;
                            this.autoBuyFishingStepTimer = now + 0.1f;
                            this.autoBuyFishingShopWaitStartedAt = 0f;
                            break;
                        }
                        this.autoBuyFishingStepTimer = now + 0.25f;
                        break;
                    case 4: // buying items
                        if (now < this.autoBuyFishingStepTimer) break;
                        if (this.autoBuyFishingCurrentItemIndex >= this.autoBuyFishingItemsMatch.Length)
                        {
                            this.autoBuyFishingSubState = 5;
                            this.autoBuyFishingStepTimer = now + 3f;
                            LogAutoBuy("[Fishing] Finished item loop, waiting before return");
                            break;
                        }
                        string match = this.autoBuyFishingItemsMatch[this.autoBuyFishingCurrentItemIndex];
                        if (this.autoBuyFishingPurchasedCount >= this.autoBuyFishingMaxPerItem)
                        {
                            this.autoBuyFishingPurchasedCount = 0; this.autoBuyFishingCurrentItemIndex++; this.autoBuyFishingShopScrollStep = -1; this.autoBuyFishingStepTimer = now + 0.1f; break;
                        }
                        bool clicked = ClickFishingStoreItemByMatch(match);
                        if (clicked)
                        {
                            this.autoBuyFishingShopScrollStep = -1;
                            this.autoBuyFishingSubState = 41;
                            this.autoBuyFishingStepTimer = now + 0.12f;
                            if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[Fishing] Opened purchase dialog for {match}"); }
                        }
                        else
                        {
                            GameObject shopProbe = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Full/ShopPanel(Clone)");
                            Transform contentProbe = shopProbe != null ? shopProbe.transform.Find("goods@scroll/Content") : null;
                            if (shopProbe != null && contentProbe != null && contentProbe.childCount == 0)
                            {
                                if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[Fishing] Shop content empty for item {match}, retrying shortly"); }
                                this.autoBuyFishingStepTimer = now + 0.25f;
                            }
                            else if (this.autoBuyFishingShopScrollStep >= 0 && this.autoBuyFishingShopScrollStep < 12)
                            {
                                this.autoBuyFishingStepTimer = now + 0.15f;
                            }
                            else
                            {
                                this.autoBuyFishingPurchasedCount = 0; this.autoBuyFishingCurrentItemIndex++; this.autoBuyFishingShopScrollStep = -1; this.autoBuyFishingStepTimer = now + 0.2f; if (this.autoBuyLogsEnabled) { ModLogger.Msg("[Fishing] Item " + match + " not found or sold out, skipping"); }
                            }
                        }
                        break;
                    case 41: // handle purchase dialog
                        if (now < this.autoBuyFishingStepTimer) break;
                        GameObject sale = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Top/SalePanel(Clone)");
                        if (sale == null || !sale.activeInHierarchy)
                        {
                            this.autoBuyFishingPurchasedCount = 0; this.autoBuyFishingCurrentItemIndex++; this.autoBuyFishingShopScrollStep = -1; this.autoBuyFishingSubState = 4; LogAutoBuy("[Fishing] Sale panel not found, skipping"); break;
                        }
                        int currentCount = GetSalePanelCurrentCount(sale);
                        int remainingStock = GetSalePanelRemainingStock(sale);
                        if (currentCount < 0) currentCount = 1;
                        int effectiveMax = this.autoBuyFishingMaxPerItem;
                        if (remainingStock > 0) effectiveMax = Mathf.Min(this.autoBuyFishingMaxPerItem, remainingStock);
                        if (currentCount >= effectiveMax)
                        {
                            if (ClickSalePurchase(sale))
                            {
                                this.autoBuyFishingPurchasedCount = currentCount;
                                if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[Fishing] Purchased {currentCount} items"); }
                            }
                            this.autoBuyFishingPurchasedCount = 0; this.autoBuyFishingCurrentItemIndex++; this.autoBuyFishingShopScrollStep = -1; this.autoBuyFishingSubState = 4; this.autoBuyFishingStepTimer = now + 0.25f;
                        }
                        else
                        {
                            int remaining = effectiveMax - currentCount;
                            int doClicks = Math.Min(10, remaining);
                            bool anyClicked = false;
                            for (int i = 0; i < doClicks; i++)
                            {
                                if (ClickSaleAddMore(sale)) { anyClicked = true; }
                            }
                            this.autoBuyFishingStepTimer = now + 0.12f;
                            if (!anyClicked)
                            {
                                if (currentCount > 0 && ClickSalePurchase(sale))
                                {
                                    this.autoBuyFishingPurchasedCount = currentCount;
                                    if (this.autoBuyLogsEnabled) { ModLogger.Msg($"[Fishing] Purchased {currentCount} items (shop stock limited)"); }
                                }
                                else
                                {
                                    LogAutoBuy("[Fishing] Could not purchase item - no stock available");
                                }
                                this.autoBuyFishingPurchasedCount = 0; this.autoBuyFishingCurrentItemIndex++; this.autoBuyFishingShopScrollStep = -1; this.autoBuyFishingSubState = 4; this.autoBuyFishingStepTimer = now + 0.25f;
                            }
                        }
                        break;
                    case 5: // return
                        this.CloseAutoBuyPanels();
                        if (now < this.autoBuyFishingStepTimer) break;
                        this.StopAutoBuyFishing("Done, returning");
                        break;
                }
            }
            catch (Exception ex) { LogAutoBuy("[Fishing] Run error: " + ex.Message); this.StopAutoBuyFishing("Error"); }
        }

        // --- PATROL SAVE/LOAD ---
        private string GetPatrolPath()
        {
            return HelperPaths.GetFile("patrol_points.json");
        }

        private void SavePatrolPoints()
        {
            try
            {
                UnifiedConfigData config = this.LoadOrCreateUnifiedConfig();
                this.PopulateAllConfigSections(config);
                this.SaveUnifiedConfig(config);
                ModLogger.Msg("Patrol points saved!");
            }
            catch (Exception ex)
            {
                ModLogger.Msg("Error saving patrol points: " + ex.Message);
            }
        }

        private void LoadPatrolPoints()
        {
            try
            {
                UnifiedConfigData config = this.LoadUnifiedConfig();
                if (config != null)
                {
                    patrolPoints.Clear();
                    foreach (SerializableVector3 point in config.Patrol.Points)
                    {
                        if (point != null) patrolPoints.Add(point.ToVector3());
                    }
                    ModLogger.Msg($"Loaded {patrolPoints.Count} patrol points.");
                    return;
                }
                string path = this.GetPatrolPath();
                if (!File.Exists(path)) return;
                string json = File.ReadAllText(path);
                patrolPoints.Clear();
                string[] lines = json.Split('{');
                foreach (string line in lines)
                {
                    if (line.Contains("\"x\":"))
                    {
                        float x = float.Parse(ExtractJsonVal(line, "\"x\":"), System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture);
                        float y = float.Parse(ExtractJsonVal(line, "\"y\":"), System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture);
                        float z = float.Parse(ExtractJsonVal(line, "\"z\":"), System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture);
                        patrolPoints.Add(new Vector3(x, y, z));
                    }
                }
                ModLogger.Msg($"Loaded {patrolPoints.Count} patrol points.");
            }
            catch (Exception ex)
            {
                ModLogger.Msg("Error loading patrol points: " + ex.Message);
            }
        }

        private string ExtractJsonVal(string src, string key)
        {
            int start = src.IndexOf(key) + key.Length;
            int end = src.IndexOf(",", start);
            if (end == -1) end = src.IndexOf("}", start);
            return src.Substring(start, end - start).Trim();
        }

        // --- COOKING PATROL SAVE/LOAD ---
        private string GetCookingPatrolSaveDirectory()
        {
            return HelperPaths.GetDirectory("cooking_patrol_saves");
        }

        private string SanitizeCookingPatrolSaveName(string name)
        {
            string candidate = string.IsNullOrWhiteSpace(name) ? "" : name.Trim();
            foreach (char c in Path.GetInvalidFileNameChars())
            {
                candidate = candidate.Replace(c, '_');
            }
            return string.IsNullOrWhiteSpace(candidate) ? "" : candidate;
        }

        private string GetCookingPatrolPath(string saveName = null)
        {
            string safeName = this.SanitizeCookingPatrolSaveName(saveName ?? this.cookingPatrolSaveName);
            return Path.Combine(this.GetCookingPatrolSaveDirectory(), safeName + ".json");
        }

        private List<string> GetCookingPatrolSaveNames()
        {
            UnifiedConfigData config = this.LoadUnifiedConfig();
            if (config != null)
            {
                List<string> configSaves = new List<string>();
                foreach (NamedCookingPatrolSave save in config.CookingPatrolSaves)
                {
                    string name = this.SanitizeCookingPatrolSaveName(save?.Name);
                    if (!string.IsNullOrWhiteSpace(name) && !configSaves.Contains(name))
                    {
                        configSaves.Add(name);
                    }
                }
                configSaves.Sort(StringComparer.OrdinalIgnoreCase);
                return configSaves;
            }
            List<string> saves = new List<string>();
            try
            {
                string dir = this.GetCookingPatrolSaveDirectory();
                string[] files = Directory.GetFiles(dir, "*.json");
                foreach (string file in files)
                {
                    string name = Path.GetFileNameWithoutExtension(file);
                    if (!string.IsNullOrWhiteSpace(name) && !saves.Contains(name))
                    {
                        saves.Add(name);
                    }
                    if (!this.customDisplayIdEnabled && !string.IsNullOrEmpty(this.customDisplayId))
                    {
                        this.customDisplayIdEnabled = true;
                    }
                }
            }
            catch
            {
            }
            saves.Sort(StringComparer.OrdinalIgnoreCase);
            return saves;
        }

        private bool DeleteCookingPatrolSave(string saveName)
        {
            string safeName = this.SanitizeCookingPatrolSaveName(saveName);
            if (string.IsNullOrEmpty(safeName))
            {
                this.AddMenuNotification("Enter a save name to delete", new Color(1f, 0.5f, 0.5f));
                return false;
            }

            try
            {
                UnifiedConfigData config = this.LoadUnifiedConfig();
                if (config != null)
                {
                    int removed = config.CookingPatrolSaves.RemoveAll(s => string.Equals(this.SanitizeCookingPatrolSaveName(s?.Name), safeName, StringComparison.OrdinalIgnoreCase));
                    if (removed <= 0)
                    {
                        this.AddMenuNotification($"Save not found: {safeName}", new Color(1f, 0.5f, 0.5f));
                        return false;
                    }
                    this.SaveUnifiedConfig(config);
                    ModLogger.Msg($"Deleted cooking patrol save '{safeName}'.");
                    this.AddMenuNotification($"Deleted: {safeName}", new Color(1f, 0.75f, 0.45f));
                    return true;
                }
                string path = this.GetCookingPatrolPath(safeName);
                if (!File.Exists(path))
                {
                    this.AddMenuNotification($"Save not found: {safeName}", new Color(1f, 0.5f, 0.5f));
                    return false;
                }
                File.Delete(path);
                ModLogger.Msg($"Deleted cooking patrol save '{safeName}'.");
                this.AddMenuNotification($"Deleted: {safeName}", new Color(1f, 0.75f, 0.45f));
                return true;
            }
            catch (Exception ex)
            {
                ModLogger.Msg("Error deleting cooking patrol save: " + ex.Message);
                this.AddMenuNotification("Failed to delete patrol save", new Color(1f, 0.4f, 0.4f));
                return false;
            }
        }

        private string GetTreeFarmPatrolPath()
        {
            return HelperPaths.GetFile("tree_farm_patrol_points.json");
        }

        private void SaveCookingPatrolPoints(string saveName = null)
        {
            try
            {
                string safeName = this.SanitizeCookingPatrolSaveName(saveName ?? this.cookingPatrolSaveName);
                if (string.IsNullOrEmpty(safeName))
                {
                    this.AddMenuNotification("Enter a save name before saving", new Color(1f, 0.5f, 0.5f));
                    return;
                }
                this.cookingPatrolSaveName = safeName;
                UnifiedConfigData config = this.LoadOrCreateUnifiedConfig();
                this.PopulateAllConfigSections(config);
                this.SaveUnifiedConfig(config);
                ModLogger.Msg($"Cooking patrol points saved to '{safeName}'! ({cookingPatrolPoints.Count} points with rotations)");
                this.AddMenuNotification($"Cooking patrol saved: {safeName}", new Color(0.55f, 0.88f, 1f));
            }
            catch (Exception ex)
            {
                ModLogger.Msg("Error saving cooking patrol points: " + ex.Message);
                this.AddMenuNotification("Failed to save cooking patrol", new Color(1f, 0.4f, 0.4f));
            }
        }

        private void LoadCookingPatrolPoints(string saveName = null)
        {
            try
            {
                string safeName = this.SanitizeCookingPatrolSaveName(saveName ?? this.cookingPatrolSaveName);
                if (string.IsNullOrEmpty(safeName))
                {
                    this.AddMenuNotification("Enter a save name before loading", new Color(1f, 0.5f, 0.5f));
                    return;
                }
                this.cookingPatrolSaveName = safeName;
                UnifiedConfigData config = this.LoadUnifiedConfig();
                if (config != null)
                {
                    NamedCookingPatrolSave save = config.CookingPatrolSaves.FirstOrDefault(s => string.Equals(this.SanitizeCookingPatrolSaveName(s?.Name), safeName, StringComparison.OrdinalIgnoreCase));
                    if (save == null)
                    {
                        ModLogger.Msg($"Cooking patrol slot '{safeName}' not found.");
                        this.AddMenuNotification($"Patrol save not found: {safeName}", new Color(1f, 0.5f, 0.5f));
                        return;
                    }
                    cookingPatrolPoints.Clear();
                    foreach (CookingPatrolPoint point in save.Points)
                    {
                        if (point != null) cookingPatrolPoints.Add(point);
                    }
                    ModLogger.Msg($"Loaded {cookingPatrolPoints.Count} cooking patrol points from '{safeName}' (with rotations: true).");
                    this.AddMenuNotification($"Cooking patrol loaded: {safeName}", new Color(0.55f, 0.88f, 1f));
                    return;
                }
                string path = this.GetCookingPatrolPath(safeName);
                if (!File.Exists(path))
                {
                    ModLogger.Msg($"Cooking patrol slot '{safeName}' not found.");
                    this.AddMenuNotification($"Patrol save not found: {safeName}", new Color(1f, 0.5f, 0.5f));
                    return;
                }
                cookingPatrolPoints.Clear();
                string json = File.ReadAllText(path);

                // Check if this is the new format (with Rotation) or old format (just Vector3)
                bool hasRotation = json.Contains("\"Rotation\"");

                // Parse JSON manually - find all coordinate blocks
                int pointsStart = json.IndexOf("[");
                int pointsEnd = json.LastIndexOf("]");
                if (pointsStart == -1 || pointsEnd == -1) return;

                string pointsSection = json.Substring(pointsStart + 1, pointsEnd - pointsStart - 1);

                if (hasRotation)
                {
                    // New format with Position and Rotation
                    string[] pointBlocks = pointsSection.Split(new string[] { "    }" }, StringSplitOptions.RemoveEmptyEntries);

                    foreach (string block in pointBlocks)
                    {
                        if (!block.Contains("Position")) continue;

                        // Extract Position block (between "Position": { and })
                        int posStart = block.IndexOf("\"Position\"");
                        if (posStart == -1) continue;
                        int posObjStart = block.IndexOf("{", posStart);
                        int posObjEnd = block.IndexOf("}", posObjStart);
                        string posBlock = block.Substring(posObjStart, posObjEnd - posObjStart + 1);

                        float px = ExtractCoordinate(posBlock, "x");
                        float py = ExtractCoordinate(posBlock, "y");
                        float pz = ExtractCoordinate(posBlock, "z");

                        // Extract Rotation block (between "Rotation": { and })
                        int rotStart = block.IndexOf("\"Rotation\"");
                        Quaternion rotation = Quaternion.identity;
                        if (rotStart != -1)
                        {
                            int rotObjStart = block.IndexOf("{", rotStart);
                            int rotObjEnd = block.IndexOf("}", rotObjStart);
                            string rotBlock = block.Substring(rotObjStart, rotObjEnd - rotObjStart + 1);

                            float rx = ExtractCoordinate(rotBlock, "x");
                            float ry = ExtractCoordinate(rotBlock, "y");
                            float rz = ExtractCoordinate(rotBlock, "z");
                            float rw = ExtractCoordinate(rotBlock, "w");
                            rotation = new Quaternion(rx, ry, rz, rw);
                        }

                        cookingPatrolPoints.Add(new CookingPatrolPoint(new Vector3(px, py, pz), rotation));
                    }
                }
                else
                {
                    // Old format - just Vector3 positions, use default rotation
                    string[] pointBlocks = pointsSection.Split(new string[] { "}," }, StringSplitOptions.RemoveEmptyEntries);

                    foreach (string block in pointBlocks)
                    {
                        string cleanBlock = block.Trim().Trim('{').Trim('}').Trim(',');
                        if (string.IsNullOrEmpty(cleanBlock)) continue;

                        // Extract x, y, z values
                        float x = ExtractCoordinate(cleanBlock, "\"x\"");
                        float y = ExtractCoordinate(cleanBlock, "\"y\"");
                        float z = ExtractCoordinate(cleanBlock, "\"z\"");

                        cookingPatrolPoints.Add(new CookingPatrolPoint(new Vector3(x, y, z), Quaternion.identity));
                    }
                }
                ModLogger.Msg($"Loaded {cookingPatrolPoints.Count} cooking patrol points from '{safeName}' (with rotations: {hasRotation}).");
                this.AddMenuNotification($"Cooking patrol loaded: {safeName}", new Color(0.55f, 0.88f, 1f));
            }
            catch (Exception ex)
            {
                ModLogger.Msg("Error loading cooking patrol points: " + ex.Message);
                this.AddMenuNotification("Failed to load cooking patrol", new Color(1f, 0.4f, 0.4f));
            }
        }

