                this.AddMenuNotification("Failed to load tree farm points", new Color(1f, 0.4f, 0.4f));
            }
        }

        private float ExtractCoordinate(string block, string coord)
        {
            // Match both "x": value and x: value formats
            string pattern = $"\"?{coord}\"?:\\s*([+-]?\\d*\\.?\\d+([eE][+-]?\\d+)?)";
            System.Text.RegularExpressions.Match match = System.Text.RegularExpressions.Regex.Match(block, pattern);
            if (match.Success)
            {
                return float.Parse(match.Groups[1].Value, System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture);
            }
            throw new FormatException($"Could not find \"{coord}\" coordinate in block: {block}");
        }

        // --- AUTO REPAIR METHODS ---
        private bool IsAutoRepairInProgress()
        {
            return this.isRepairing || this.autoRepairWaiting || this.repairStep != 0;
        }

        private bool IsAutoEatActiveOrQueued()
        {
            return this.isAutoEating || this.pendingAutoEatRequest;
        }

        private bool IsAutoRepairActiveOrQueued()
        {
            return this.IsAutoRepairInProgress() || this.pendingAutoRepairRequest;
        }

        private bool IsBagAutomationActiveOrQueued()
        {
            return this.IsAutoRepairActiveOrQueued() || this.IsAutoEatActiveOrQueued();
        }

        private bool AreHeavyFarmAutomationsActive()
        {
            return BirdNetFarm.IsEnabled || InsectNetFarm.IsEnabled;
        }

        private float GetEffectiveAutoEatTriggerCheckInterval()
        {
            return this.AreHeavyFarmAutomationsActive() ? FarmActiveAutoEatTriggerCheckInterval : AutoEatTriggerCheckInterval;
        }

        private float GetEffectiveAutoRepairTriggerCheckInterval()
        {
            return this.AreHeavyFarmAutomationsActive() ? FarmActiveAutoRepairTriggerCheckInterval : AutoRepairTriggerCheckInterval;
        }

        private float GetEffectiveToolDurabilityPollInterval()
        {
            return this.AreHeavyFarmAutomationsActive() ? FarmActiveToolDurabilityPollInterval : ToolDurabilityPollInterval;
        }

        void StartRepair(bool bypassDebounce = false)
        {
            if (this.isAutoEating)
            {
                if (!this.pendingAutoRepairRequest)
                {
                    this.pendingAutoRepairRequest = true;
                    this.AutoEatRepairLog("[StartRepair] queued because auto eat is still running");
                }
                else
                {
                    this.AutoEatRepairLog("[StartRepair] ignored duplicate queue request while auto eat is still running");
                }
                return;
            }

            // Debounce: ignore triggers that happen within the configured auto-repair pause window
            float repairStartNow = Time.unscaledTime;
            if (!bypassDebounce && repairStartNow - this.lastRepairTriggerTime < this.resourceAutoRepairPauseSeconds)
            {
                this.AutoEatRepairLog($"[StartRepair] Ignored trigger due to debounce. Now={repairStartNow} LastTrigger={this.lastRepairTriggerTime} Wait={this.resourceAutoRepairPauseSeconds}");
                return;
            }

            // Prevent re-entrancy: if a repair is already running, ignore subsequent starts
            if (this.IsAutoRepairActiveOrQueued())
            {
                this.AutoEatRepairLog("[StartRepair] ignored re-entry (repair already active or queued)");
                return;
            }

            this.lastRepairTriggerTime = repairStartNow;
            this.AutoEatRepairLog($"[StartRepair] invoked at Time.unscaledTime={repairStartNow}");

            bool autoTriggeredRepair = this.lastStartWasAutoRepair;

            // Auto-triggered repair is safer without moving the player because farm teleports
            // or partially loaded terrain can cause a sudden reposition into bad ground.
            if (this.repairTeleportBackEnabled && !autoTriggeredRepair)
            {
                try
                {
                    GameObject p = GetPlayer();
                    if (p != null)
                    {
                        Vector3 cur = p.transform.position;
                        Vector3 back = Vector3.zero;
                        try { back = p.transform.forward; } catch { back = new Vector3(0f, 0f, 1f); }
                        Vector3 target = cur - back.normalized * this.repairTeleportBackDistance;
                        target.y = cur.y; // preserve vertical position
                        this.AutoEatRepairLog($"[StartRepair] Teleporting player backward from {cur} to {target}");
                        TeleportTo(target);
                    }
                }
                catch (Exception ex)
                {
                    this.AutoEatRepairLog("[StartRepair] Teleport backward failed: " + ex.Message);
                }
            }

            // Determine whether this was triggered by durability detection (auto)
            // and initialize auto-repair counters accordingly. We use the
            // `lastStartWasAutoRepair` flag (set by the caller) to detect auto
            // starts; clear it immediately after reading.
            isAutoRepairRunning = autoTriggeredRepair;
            this.lastStartWasAutoRepair = false;
            this.pendingAutoRepairRequest = false;
            autoRepairUseCount = 0;
            autoRepairWaiting = false;
            this.lastRepairUseNetId = 0U;
            this.lastRepairUseCountBefore = 0;
            this.ClearCachedRepairKit();
            this.repairVerifyChecks = 0;
            this.repairUseRetryAttempts = 0;
            repairUsesTarget = Mathf.Clamp(this.autoRepairUseTarget, 1, 3);

            isRepairing = true;
            repairStep = DIRECT_REPAIR_STEP_USE;
            stepTimer = Time.unscaledTime;

            // Pause resource farm teleports while repairing to avoid overlapping actions
            this.resourceRepairPauseUntil = Time.time + this.resourceAutoRepairPauseSeconds;
            InsectNetFarm.NotifyRepairTriggered();
        }

        void StartAutoEat(bool forceSingleUse = false)
        {
            if (this.isRepairing)
            {
                this.pendingAutoEatRequest = true;
                this.AutoEatRepairLog("[AutoEat] StartAutoEat queued because repair is still running.");
                return;
            }

            isAutoEating = true;
            autoEatStep = DIRECT_EAT_STEP_USE;
            autoEatAttempts = 0;
            autoEatForceSingleUse = forceSingleUse;
            autoEatStepTimer = Time.unscaledTime;
            InsectNetFarm.NotifyAutoEatTriggered();
        }

        private void ProcessPendingBagAutomation()
        {
            if (this.isRepairing || this.isAutoEating)
            {
                return;
            }

            if (this.pendingAutoRepairRequest)
            {
                this.pendingAutoRepairRequest = false;
                this.lastStartWasAutoRepair = true;
                this.AutoEatRepairLog("[AutoRepair] Running queued durability repair request.");
                this.StartRepair(true);
                this.resourceRepairPauseUntil = Time.time + this.resourceAutoRepairPauseSeconds;
                return;
            }

            if (this.pendingAutoEatRequest)
            {
                if (!this.autoEatAutoTriggerEnabled || !this.IsEnergyAtOrBelowAutoEatTrigger() || Time.unscaledTime < this.nextAutoEatDirectRetryAt)
                {
                    this.pendingAutoEatRequest = false;
                    return;
                }

                this.pendingAutoEatRequest = false;
                this.AutoEatRepairLog($"[AutoEat] Running queued energy panel request ({this.GetCurrentEnergyDisplay()}, threshold={this.autoEatTriggerPercent}%).");
                this.StartAutoEat();
            }
        }

        private bool TryHandleDurabilityAutoRepairTrigger(string source)
        {
            float now = Time.time;
            float cooldownUntil = Math.Max(this.nextAutoRepairToastAllowedAt, this.resourceRepairPauseUntil);
            if (now < cooldownUntil)
            {
                this.AutoEatRepairLog($"[AutoRepair] Durability trigger ignored from {source}; repair toast cooldown active ({cooldownUntil - now:F1}s left).");
                return false;
            }

            if (this.IsAutoRepairInProgress())
            {
                this.nextAutoRepairToastAllowedAt = now + Mathf.Max(2f, this.resourceAutoRepairPauseSeconds);
                this.AutoEatRepairLog("[AutoRepair] Durability trigger ignored from " + source + " because repair is already running.");
                return false;
            }

            if (this.pendingAutoRepairRequest)
            {
                this.nextAutoRepairToastAllowedAt = now + Mathf.Max(2f, this.resourceAutoRepairPauseSeconds);
                this.AutoEatRepairLog("[AutoRepair] Durability trigger ignored from " + source + " because repair is already queued.");
                return false;
            }

            if (this.isAutoEating)
            {
                if (!this.pendingAutoRepairRequest)
                {
                    this.pendingAutoRepairRequest = true;
                    this.nextAutoRepairToastAllowedAt = now + Mathf.Max(2f, this.resourceAutoRepairPauseSeconds);
                    this.AutoEatRepairLog("[AutoRepair] Durability trigger queued from " + source + " because bag automation is busy.");
                    return true;
                }

                this.AutoEatRepairLog("[AutoRepair] Durability trigger ignored from " + source + " because repair is already queued.");
                return false;
            }

            this.AutoEatRepairLog("[AutoRepair] Durability toast requested StartRepair (" + source + ")");
            this.lastStartWasAutoRepair = true;
            this.StartRepair();
            if (!this.isRepairing)
            {
                this.AutoEatRepairLog("[AutoRepair] Durability trigger from " + source + " did not start because StartRepair rejected it.");
                return false;
            }

            this.nextAutoRepairToastAllowedAt = now + Mathf.Max(2f, this.resourceAutoRepairPauseSeconds);
            this.resourceRepairPauseUntil = now + this.resourceAutoRepairPauseSeconds;
            this.AddMenuNotification(this.L("Auto Repair started"), new Color(0.45f, 1f, 0.55f));
            return true;
        }

        void ExecuteRepairStep()
        {
            switch (repairStep)
            {
                case DIRECT_REPAIR_STEP_USE:
                    if (this.TryDirectUseRepairKit())
                    {
                        this.lastRepairUseNetId = this.lastDirectBackpackMatchedNetId;
                        this.lastRepairUseCountBefore = this.lastDirectBackpackMatchedCount;
                        this.repairVerifyChecks = 0;
                        repairStep = DIRECT_REPAIR_STEP_VERIFY;
                        stepTimer = Time.unscaledTime + 1.25f;
                        this.AutoEatRepairLog($"[AutoRepair] Direct repair kit use sent; verifying inventory before counting ({autoRepairUseCount}/{repairUsesTarget}, countBefore={this.lastRepairUseCountBefore}).");
                    }
                    else
                    {
                        this.AutoEatRepairLog("[AutoRepair] Direct repair failed; stopped without opening bag UI.");
                        isRepairing = false;
                        repairStep = 0;
                    }
                    break;

                case DIRECT_REPAIR_STEP_VERIFY:
                    repairVerifyChecks++;
                    if (this.VerifyLastRepairUseSucceeded())
                    {
                        autoRepairUseCount++;
                        repairUseRetryAttempts = 0;
                        this.AutoEatRepairLog($"[AutoRepair] Repair kit use verified ({autoRepairUseCount}/{repairUsesTarget}).");
                        if (autoRepairUseCount < repairUsesTarget)
                        {
                            autoRepairWaiting = true;
                            autoRepairWaitTimer = Time.unscaledTime + autoRepairWaitDuration;
                            stepTimer = autoRepairWaitTimer;
                            repairStep = DIRECT_REPAIR_STEP_WAIT;
                        }
                        else
                        {
                            isRepairing = false;
                            repairStep = 0;
                        }
                    }
                    else if (repairVerifyChecks < 2)
                    {
                        this.AutoEatRepairLog("[AutoRepair] Repair kit use not reflected yet; checking again.");
                        stepTimer = Time.unscaledTime + 1.25f;
                    }
                    else if (repairUseRetryAttempts < 3)
                    {
                        repairUseRetryAttempts++;
                        repairVerifyChecks = 0;
                        this.AutoEatRepairLog($"[AutoRepair] Repair kit was not consumed; retrying use ({repairUseRetryAttempts}/3). Avoid jumping/vehicle while retrying.");
                        repairStep = DIRECT_REPAIR_STEP_USE;
                        stepTimer = Time.unscaledTime + 0.75f;
                    }
                    else
                    {
                        this.AutoEatRepairLog("[AutoRepair] Repair kit was not consumed after retries; stopped to avoid spam.");
                        isRepairing = false;
                        repairStep = 0;
                    }
                    break;

                case DIRECT_REPAIR_STEP_WAIT:
                    if (autoRepairWaiting && Time.unscaledTime >= autoRepairWaitTimer)
                    {
                        autoRepairWaiting = false;
                        repairStep = DIRECT_REPAIR_STEP_USE;
                        stepTimer = Time.unscaledTime;
                    }
                    break;

                default:
                    this.AutoEatRepairLog("[AutoRepair] Unknown repair step " + repairStep + "; stopping.");
                    isRepairing = false;
                    repairStep = 0;
                    break;
            }
        }

        void ExecuteAutoEatStep()
        {
            switch (autoEatStep)
            {
                case DIRECT_EAT_STEP_USE:
                    if (!this.autoEatForceSingleUse && IsEnergyFull())
                    {
                        isAutoEating = false;
                        autoEatStep = 0;
                        this.AutoEatRepairLog($"[Auto Eat] Skipped - energy already full ({this.GetCurrentEnergyDisplay()})");
                        break;
                    }
                    if (!this.autoEatForceSingleUse && autoEatAttempts >= this.maxAutoEatAttempts)
                    {
                        isAutoEating = false;
                        autoEatStep = 0;
                        this.AutoEatRepairLog($"[Auto Eat] Stopped after max attempts ({autoEatAttempts}) - energy at {this.GetCurrentEnergyDisplay()}");
                        break;
                    }
                    if (this.TryDirectUseFood())
                    {
                        autoEatAttempts++;
                        autoEatStep = DIRECT_EAT_STEP_DELAY;
                        autoEatStepTimer = Time.unscaledTime + 0.75f;
                        this.AutoEatRepairLog($"[Auto Eat] Direct food use sent ({this.GetAutoEatFoodOptionLabel(this.autoEatFoodType)}), attempt {autoEatAttempts}.");
                    }
                    else
                    {
                        this.AutoEatRepairLog("[Auto Eat] Direct food use failed; stopped without opening bag UI.");
                        isAutoEating = false;
                        autoEatStep = 0;
                        autoEatForceSingleUse = false;
                        nextAutoEatDirectRetryAt = Time.unscaledTime + 5f;
                    }
                    break;

                case DIRECT_EAT_STEP_DELAY:
                    if (this.autoEatForceSingleUse)
                    {
                        isAutoEating = false;
                        autoEatStep = 0;
                        autoEatForceSingleUse = false;
                        this.AutoEatRepairLog($"[Auto Eat] Used selected food once ({this.GetAutoEatFoodOptionLabel(this.autoEatFoodType)}).");
                    }
                    else if (!IsEnergyFull() && autoEatAttempts < this.maxAutoEatAttempts)
                    {
                        autoEatStep = DIRECT_EAT_STEP_USE;
                        autoEatStepTimer = Time.unscaledTime;
                        this.AutoEatRepairLog($"[Auto Eat] Energy not full yet ({this.GetCurrentEnergyDisplay()}), direct eating another {this.GetAutoEatFoodOptionLabel(this.autoEatFoodType)}... (attempt {autoEatAttempts})");
                    }
                    else
                    {
                        isAutoEating = false;
                        autoEatStep = 0;
                        autoEatForceSingleUse = false;
                        if (IsEnergyFull())
                        {
                            this.AutoEatRepairLog("[Auto Eat] Energy restored to maximum!");
                        }
                        else
                        {
                            this.AutoEatRepairLog($"[Auto Eat] Stopped after {autoEatAttempts} attempts - energy at {this.GetCurrentEnergyDisplay()}");
                        }
                    }
                    break;

                default:
                    this.AutoEatRepairLog("[Auto Eat] Unknown eat step " + autoEatStep + "; stopping.");
                    isAutoEating = false;
                    autoEatStep = 0;
                    autoEatForceSingleUse = false;
                    break;
            }
        }

        private bool TryDirectUseRepairKit()
        {
            try
            {
                string repairKey = (this.autoRepairType >= 0 && this.autoRepairType < this.autoRepairKeys.Length) ? this.autoRepairKeys[this.autoRepairType] : this.autoRepairKeys[0];
                this.AutoEatRepairLog("[AutoRepair] Direct repair requested. key=" + repairKey + " option=" + this.autoRepairOptions[Mathf.Clamp(this.autoRepairType, 0, this.autoRepairOptions.Length - 1)]);
                if (this.TryUseCachedRepairKit(repairKey))
                {
                    return true;
                }

                if (!this.TryFindDirectBackpackItem(repairKey, false, out uint netId) || netId == 0U)
                {
                    this.AutoEatRepairLog("[AutoRepair] Direct backpack item not found for " + repairKey);
                    this.ShowMissingRepairItemNotification();
                    return false;
                }

                this.CacheRepairKitMatch(repairKey);
                this.AutoEatRepairLog("[AutoRepair] Direct repair matched netId=" + netId + " staticId=" + this.lastDirectBackpackMatchedStaticId + "; sending BagModule ToolRestorer function.");
                return this.TryExecuteDirectBackpackItemFunc(113, netId);
            }
            catch (Exception ex)
            {
                this.AutoEatRepairLog("[AutoRepair] Direct repair exception: " + ex.Message);
                return false;
            }
        }

        private bool TryUseCachedRepairKit(string repairKey)
        {
            if (string.IsNullOrEmpty(repairKey)
                || this.cachedRepairKitNetId == 0U
                || !string.Equals(this.cachedRepairKitKey, repairKey, StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (!this.TryGetDirectBackpackItemCountByNetId(this.cachedRepairKitNetId, out int currentCount, false))
            {
                this.ClearCachedRepairKit();
                return false;
            }

            this.lastDirectBackpackMatchedNetId = this.cachedRepairKitNetId;
            this.lastDirectBackpackMatchedStaticId = this.cachedRepairKitStaticId;
            this.lastDirectBackpackMatchedEntityType = 0;
            this.lastDirectBackpackMatchedCount = currentCount;
            this.cachedRepairKitCount = currentCount;

            this.AutoEatRepairLog("[AutoRepair] Cached repair kit matched netId=" + this.cachedRepairKitNetId + " count=" + currentCount + "; sending BagModule ToolRestorer function.");
            if (this.TryExecuteDirectBackpackItemFunc(113, this.cachedRepairKitNetId))
            {
                return true;
            }

            this.ClearCachedRepairKit();
            return false;
        }

        private void CacheRepairKitMatch(string repairKey)
        {
            this.cachedRepairKitKey = repairKey ?? "";
            this.cachedRepairKitNetId = this.lastDirectBackpackMatchedNetId;
            this.cachedRepairKitStaticId = this.lastDirectBackpackMatchedStaticId;
            this.cachedRepairKitCount = this.lastDirectBackpackMatchedCount;
        }

        private void ClearCachedRepairKit()
        {
            this.cachedRepairKitKey = "";
            this.cachedRepairKitNetId = 0U;
            this.cachedRepairKitStaticId = 0;
            this.cachedRepairKitCount = 0;
        }

        private bool TryUseCachedFood(string foodKey, bool anyFood)
        {
            if (this.cachedFoodNetId == 0U
                || this.cachedFoodAnyFood != anyFood
                || !string.Equals(this.cachedFoodKey, foodKey ?? string.Empty, StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (!this.TryGetDirectBackpackItemCountByNetId(this.cachedFoodNetId, out int currentCount, false) || currentCount <= 0)
            {
                this.ClearCachedFood();
                return false;
            }

            this.lastDirectBackpackMatchedNetId = this.cachedFoodNetId;
            this.lastDirectBackpackMatchedStaticId = this.cachedFoodStaticId;
            this.lastDirectBackpackMatchedEntityType = this.cachedFoodEntityType;
            this.lastDirectBackpackMatchedCount = currentCount;
            this.cachedFoodCount = currentCount;

            this.AutoEatRepairLog("[Auto Eat] Cached food matched netId=" + this.cachedFoodNetId + " count=" + currentCount + "; sending BagModule Eat function.");
            if (this.TryExecuteDirectBackpackItemFunc(112, this.cachedFoodNetId))
            {
                return true;
            }

            this.ClearCachedFood();
            return false;
        }

        private void CacheFoodMatch(string foodKey, bool anyFood)
        {
            this.cachedFoodKey = foodKey ?? "";
            this.cachedFoodAnyFood = anyFood;
            this.cachedFoodNetId = this.lastDirectBackpackMatchedNetId;
            this.cachedFoodStaticId = this.lastDirectBackpackMatchedStaticId;
            this.cachedFoodEntityType = this.lastDirectBackpackMatchedEntityType;
            this.cachedFoodCount = this.lastDirectBackpackMatchedCount;
        }

        private void ClearCachedFood()
        {
            this.cachedFoodKey = "";
            this.cachedFoodAnyFood = false;
            this.cachedFoodNetId = 0U;
            this.cachedFoodStaticId = 0;
            this.cachedFoodEntityType = 0;
            this.cachedFoodCount = 0;
        }

        private void InvalidateDirectBackpackRuntimeSnapshot()
        {
            this.directBackpackRuntimeSnapshotAt = -999f;
            this.directBackpackRuntimeSnapshotSource = "";
            this.directBackpackRuntimeItems.Clear();
            this.ClearCachedRepairKit();
            this.ClearCachedFood();
        }

        private bool VerifyLastRepairUseSucceeded()
        {
            try
            {
                uint previousNetId = this.lastRepairUseNetId;
                int previousCount = this.lastRepairUseCountBefore;

                if (previousNetId == 0U)
                {
                    this.AutoEatRepairLog("[AutoRepair] Repair verification has no previous netId; accepting use.");
                    return true;
                }

                if (!this.TryGetDirectBackpackItemCountByNetId(previousNetId, out int currentCount, true))
                {
                    if (this.cachedRepairKitNetId == previousNetId)
                    {
                        this.ClearCachedRepairKit();
                    }

                    this.AutoEatRepairLog("[AutoRepair] Repair verification success: previous repair kit netId disappeared.");
                    return true;
                }

                if (previousCount > 0 && currentCount > 0)
                {
                    bool consumed = currentCount < previousCount;
                    if (consumed && this.cachedRepairKitNetId == previousNetId)
                    {
                        this.cachedRepairKitCount = currentCount;
                    }

                    this.AutoEatRepairLog("[AutoRepair] Repair verification count check: netId=" + previousNetId + " before=" + previousCount + " after=" + currentCount + " consumed=" + consumed);
                    return consumed;
                }

                if (previousCount <= 0 || currentCount <= 0)
                {
                    this.AutoEatRepairLog("[AutoRepair] Repair verification count unavailable; accepting use to avoid a false retry. before=" + previousCount + " after=" + currentCount);
                    return true;
                }

                this.AutoEatRepairLog("[AutoRepair] Repair verification failed: item still appears unchanged. netId=" + previousNetId + " before=" + previousCount + " after=" + currentCount);
                return false;
            }
            catch (Exception ex)
            {
                this.AutoEatRepairLog("[AutoRepair] Repair verification exception; accepting use. " + ex.Message);
                return true;
            }
        }

        private bool TryGetDirectBackpackItemCountByNetId(uint targetNetId, out int count, bool forceRefresh = false)
        {
            count = 0;
            if (targetNetId == 0U)
            {
                return false;
            }

            if (this.TryRefreshDirectBackpackRuntimeSnapshot(forceRefresh))
            {
                for (int i = 0; i < this.directBackpackRuntimeItems.Count; i++)
                {
                    DirectBackpackRuntimeItem item = this.directBackpackRuntimeItems[i];
                    if (item != null && item.NetId == targetNetId)
                    {
                        count = item.Count;
                        return true;
                    }
                }
            }

            if (this.TryGetDirectBackpackItemCountByNetIdManaged(targetNetId, out count))
            {
                return true;
            }

            return DirectBackpackUnsafeAuraMonoFallbackEnabled
                && this.TryGetDirectBackpackItemCountByNetIdAuraMono(targetNetId, out count);
        }

        private bool TryGetDirectBackpackItemCountByNetIdManaged(uint targetNetId, out int count)
        {
            count = 0;
            try
            {
                if (!this.TryGetDirectBackpackSystem(out object backPackObj, out MethodInfo getAllItem, out Type storageType, out bool getAllItemNeedsStorage))
                {
                    return false;
                }

                object backpackStorage = storageType != null && storageType.IsEnum ? Enum.ToObject(storageType, 1) : (object)1;
                object itemListObj = getAllItemNeedsStorage
                    ? getAllItem.Invoke(backPackObj, new[] { backpackStorage })
                    : getAllItem.Invoke(backPackObj, null);

                IEnumerable items = itemListObj as IEnumerable;
                if (items == null)
                {
                    return false;
                }

                foreach (object item in items)
                {
                    if (item == null)
                    {
                        continue;
                    }

                    if (this.TryGetManagedUInt32Member(item, "netId", out uint candidateNetId)
                        && candidateNetId == targetNetId)
                    {
                        this.TryGetManagedBackpackItemCount(item, out count);
                        return true;
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        private bool TryGetDirectBackpackItemCountByNetIdAuraMono(uint targetNetId, out int count)
        {
            count = 0;
            try
            {
                if (!this.TryResolveAuraMonoModule("XDTGameSystem.GameplaySystem.BackPack.BackPackSystem", out IntPtr backPackSystemObj) || backPackSystemObj == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr backPackClass = auraMonoObjectGetClass != null ? auraMonoObjectGetClass(backPackSystemObj) : IntPtr.Zero;
                IntPtr getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 1);
                bool getAllItemNeedsStorageType = true;
                if (getAllItemMethod == IntPtr.Zero)
                {
                    getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 0);
                    getAllItemNeedsStorageType = false;
                }
                if (getAllItemMethod == IntPtr.Zero || auraMonoRuntimeInvoke == null)
                {
                    return false;
                }

                IntPtr exc = IntPtr.Zero;
                int storageTypeBackpack = 1;
                IntPtr itemListObj;
                unsafe
                {
                    IntPtr* args = stackalloc IntPtr[1];
                    args[0] = (IntPtr)(&storageTypeBackpack);
                    itemListObj = auraMonoRuntimeInvoke(getAllItemMethod, backPackSystemObj, getAllItemNeedsStorageType ? (IntPtr)args : IntPtr.Zero, ref exc);
                }
                if (exc != IntPtr.Zero || itemListObj == IntPtr.Zero)
                {
                    return false;
                }

                List<IntPtr> items = new List<IntPtr>();
                if (!this.TryEnumerateAuraMonoCollectionItems(itemListObj, items) || items.Count == 0)
                {
                    return false;
                }

                foreach (IntPtr itemObj in items)
                {
                    if (itemObj == IntPtr.Zero)
                    {
                        continue;
                    }

                    if (this.TryGetDirectBackpackItemNetId(itemObj, out uint candidateNetId)
                        && candidateNetId == targetNetId)
                    {
                        this.TryGetDirectBackpackItemCount(itemObj, out count);
                        return true;
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        private bool TryDirectUseFood()
        {
            try
            {
                string foodKey = this.GetAutoEatFoodKey();
                bool anyFood = this.autoEatFoodType == this.autoEatFoodOptions.Length - 2;
                this.AutoEatRepairLog("[Auto Eat] Direct food requested. key=" + foodKey + " anyFood=" + anyFood + " option=" + this.GetAutoEatFoodOptionLabel(this.autoEatFoodType) + " energy=" + this.GetCurrentEnergyDisplay());
                if (this.TryUseCachedFood(foodKey, anyFood))
                {
                    return true;
                }

                if (!this.TryFindDirectBackpackItem(foodKey, anyFood, out uint netId) || netId == 0U)
                {
                    this.AutoEatRepairLog("[Auto Eat] Direct backpack food not found for " + this.GetAutoEatFoodOptionLabel(this.autoEatFoodType));
                    this.ClearCachedFood();
                    this.ShowMissingFoodNotification();
                    return false;
                }

                this.CacheFoodMatch(foodKey, anyFood);
                this.AutoEatRepairLog("[Auto Eat] Direct food matched netId=" + netId + " staticId=" + this.lastDirectBackpackMatchedStaticId + " entityType=" + this.lastDirectBackpackMatchedEntityType + "; sending BagModule Eat function.");
                return this.TryExecuteDirectBackpackItemFunc(112, netId);
            }
            catch (Exception ex)
            {
                this.AutoEatRepairLog("[Auto Eat] Direct food exception: " + ex.Message);
                return false;
            }
        }

        private void ShowMissingRepairItemNotification()
        {
            if (Time.unscaledTime < this.nextMissingRepairItemNotificationAt)
            {
                return;
            }

            this.nextMissingRepairItemNotificationAt = Time.unscaledTime + 6f;
            string repairName = this.GetAutoRepairOptionLabel(Mathf.Clamp(this.autoRepairType, 0, this.autoRepairOptions.Length - 1));
            this.AddMenuNotification("Auto Repair stopped - no " + repairName + " found", new Color(1f, 0.65f, 0.45f));
        }

        private void ShowMissingFoodNotification()
        {
            if (Time.unscaledTime < this.nextMissingFoodNotificationAt)
            {
                return;
            }

            this.nextMissingFoodNotificationAt = Time.unscaledTime + 6f;
            this.AddMenuNotification("Auto Eat stopped - no " + this.GetAutoEatFoodOptionLabel(this.autoEatFoodType) + " found", new Color(1f, 0.65f, 0.45f));
        }

        private string GetAutoEatFoodKey()
        {
            if (this.autoEatFoodType == this.autoEatFoodOptions.Length - 1 && !string.IsNullOrWhiteSpace(this.autoEatCustomFoodName))
            {
                return this.NormalizeAutoEatFoodLookupKey(this.autoEatCustomFoodName);
            }

            if (this.autoEatFoodType >= 0 && this.autoEatFoodType < this.autoEatFoodKeys.Length)
            {
                return this.autoEatFoodKeys[this.autoEatFoodType];
            }

            return AUTO_EAT_FOOD_KEY;
        }

        private string NormalizeAutoEatFoodLookupKey(string key)
        {
            string text = (key ?? string.Empty).Trim().ToLowerInvariant();
            if (string.IsNullOrEmpty(text))
            {
                return string.Empty;
            }

            if (text.StartsWith("ui_item_normal_", StringComparison.Ordinal))
            {
                text = text.Substring("ui_item_normal_".Length);
            }
            else if (text.StartsWith("ui_item_", StringComparison.Ordinal))
            {
                text = text.Substring("ui_item_".Length);
            }

            return text;
        }

        private void AutoSellLog(string message)
        {
            if (AutoSellLogsEnabled)
            {
                ModLogger.Msg("[AutoSell] " + message);
            }
        }

        private void AutoSellLogSellResult(string message)
        {
            ModLogger.Msg("[AutoSell] " + message);
        }

        private void ProcessAutoSell()
        {
            if (!this.autoSellEnabled)
            {
                return;
            }
            if (Time.unscaledTime < this.nextAutoSellAt)
            {
                return;
            }

            this.nextAutoSellAt = Time.unscaledTime + Mathf.Clamp(this.autoSellInterval, 1f, 120f);
            if (string.IsNullOrWhiteSpace(this.GetActiveAutoSellMatchKey()) || this.GetActiveAutoSellMatchKey().Length < 2)
            {
                this.autoSellStatus = "Waiting for item selection";
                return;
            }
            if (this.isRepairing || this.isAutoEating)
            {
                this.autoSellStatus = "Waiting for bag automation";
                return;
            }
            if (!this.IsAutoSellWorldReady())
            {
                this.autoSellStatus = "Waiting for world";
                return;
            }

            this.ExecuteDirectAutoSell(true);
        }

        private bool ExecuteDirectAutoSell(bool fromAuto)
        {
            if (!this.IsAutoSellWorldReady())
            {
                this.autoSellStatus = "Waiting for world";
                if (!fromAuto)
                {
                    this.AddMenuNotification("Auto Sell waits until you are in-world", new Color(1f, 0.85f, 0.35f));
                }
                return false;
            }

            if (this.autoSellFestivalTokensEnabled)
            {
                this.TryRefreshDirectBackpackRuntimeSnapshot(false);
            }

            Dictionary<uint, int> sellItems = this.BuildDirectSellItemMap(out int matchedBagTotal, out int reservedKept);
            if (sellItems.Count == 0)
            {
                bool reservedAll = matchedBagTotal > 0 && reservedKept > 0 && this.autoSellReserveCount > 0 && matchedBagTotal <= reservedKept;
                this.autoSellStatus = reservedAll
                    ? "Keep Per Item reserved all matches"
                    : string.IsNullOrWhiteSpace(this.NormalizeAutoSellMatchKey(this.autoSellItemKey))
                    ? "Select or type an item first"
                    : "No matching sellable items";
                if (reservedAll && !fromAuto)
                {
                    this.AddMenuNotification("Nothing sold - Keep Per Item reserved all matches", new Color(1f, 0.85f, 0.35f));
                }
                return false;
            }

            int totalCount = 0;
            foreach (int count in sellItems.Values)
            {
                totalCount += Math.Max(0, count);
            }

            this.AutoSellLogSellResult("QuickSell request. stacks=" + sellItems.Count + " totalCount=" + totalCount + " key=" + this.GetActiveAutoSellMatchKey());
            if (!string.IsNullOrWhiteSpace(this.autoSellSelectedDetails))
            {
                this.AutoSellLog("QuickSell items: " + this.autoSellSelectedDetails);
            }

            bool sent;
            if (this.autoSellFestivalTokensEnabled && this.TryGetFestivalSellCurrencyId(out int festivalCurrencyId))
            {
                Dictionary<uint, int> festivalItems = new Dictionary<uint, int>();
                Dictionary<uint, int> coinItems = new Dictionary<uint, int>();
                string festivalCurrencyStatus = string.Empty;
                try
                {
                    this.SplitSellItemsByPeriodCurrency(festivalCurrencyId, sellItems, out festivalItems, out coinItems, out festivalCurrencyStatus);
                }
                catch (Exception ex)
                {
                    coinItems = new Dictionary<uint, int>(sellItems);
                    festivalCurrencyStatus = "split exception: " + ex.GetType().Name + ": " + ex.Message + " -> all coin";
                    this.AutoSellLogSellResult(festivalCurrencyStatus);
                }

                int festivalCount = this.SumAutoSellItemCounts(festivalItems);
                int coinCount = this.SumAutoSellItemCounts(coinItems);
                this.autoSellLastMatchSummary += "\nSell split: " + festivalItems.Count + " token stack(s), " + coinItems.Count + " coin stack(s)";
                ModLogger.Msg("[AutoSell] " + festivalCurrencyStatus);
                this.AutoSellLogSellResult("Festival sell batch count=" + festivalItems.Count + " coin batch count=" + coinItems.Count);
                bool sentFestival = festivalItems.Count == 0 || this.TryQuickSellItemsBatched(festivalItems, festivalCurrencyId);
                bool sentCoins = coinItems.Count == 0 || this.TryQuickSellItemsBatched(coinItems, 0);
                this.AutoSellLogSellResult("Festival sell result tokenOk=" + sentFestival + " coinOk=" + sentCoins);
                sent = (festivalItems.Count > 0 || coinItems.Count > 0)
                    && (festivalItems.Count == 0 || sentFestival)
                    && (coinItems.Count == 0 || sentCoins);
                if (sent)
                {
                    this.autoSellStatus = festivalCount > 0 && coinCount > 0
                        ? ("Sell sent: " + festivalCount + " token(s), " + coinCount + " coin(s)")
                        : festivalCount > 0
                        ? ("Sell sent: " + festivalCount + " festival token item(s)")
                        : ("Sell sent: " + coinCount + " for coins");
                }
                else if (sentCoins && festivalItems.Count > 0)
                {
                    this.autoSellStatus = "Sold " + coinCount + " for coins; token sell failed";
                }
                else if (sentFestival && coinItems.Count > 0)
                {
                    this.autoSellStatus = "Sold " + festivalCount + " for tokens; coin sell failed";
                }
                else
                {
                    this.autoSellStatus = "Sell failed";
                }
            }
            else if (this.autoSellFestivalTokensEnabled)
            {
                sent = this.TryQuickSellItemsBatched(sellItems, 0);
                this.autoSellStatus = sent ? ("Sell sent for coins (festival currency unavailable)") : "Sell failed";
            }
            else
            {
                sent = this.TryQuickSellItemsBatched(sellItems, 0);
                this.autoSellStatus = sent ? ("Sell sent: " + totalCount + " item(s)") : "Sell failed";
            }

            if (!sent && fromAuto)
            {
                this.autoSellEnabled = false;
                this.autoSellStatus = "Sell failed - auto disabled";
                this.AutoSellLog("Auto sell disabled after failed send to prevent repeated unsafe retries.");
            }
            if (sent && !fromAuto)
            {
                this.AddMenuNotification("Auto Sell: " + totalCount + " item(s)", new Color(0.45f, 1f, 0.55f));
                this.FinalizeManualAutoSellSend(sellItems);
            }
            else if (!sent && !fromAuto)
            {
                this.AddMenuNotification("Auto Sell failed - check logs", new Color(1f, 0.55f, 0.55f));
            }
            return sent;
        }

        private void FinalizeManualAutoSellSend(Dictionary<uint, int> soldMap)
        {
            if (soldMap == null || soldMap.Count == 0)
            {
                return;
            }

            string statusMessage = this.autoSellStatus;
            this.ApplyOptimisticAutoSellToItemList(soldMap);
            this.autoSellStatus = statusMessage;
            this.ScheduleAutoSellListRescan();
        }

        private void ApplyOptimisticAutoSellToItemList(Dictionary<uint, int> soldMap)
        {
            if (this.autoSellBagItems == null || soldMap == null || soldMap.Count == 0)
            {
                return;
            }

            for (int i = this.autoSellBagItems.Count - 1; i >= 0; i--)
            {
                AutoSellBagItemEntry entry = this.autoSellBagItems[i];
                if (entry == null || !soldMap.TryGetValue(entry.NetId, out int soldQty) || soldQty <= 0)
                {
                    continue;
                }

                entry.Count -= soldQty;
                if (entry.Count <= 0)
                {
                    this.autoSellBagItems.RemoveAt(i);
                }
                else if (entry.StackCount > 1)
                {
                    entry.StackCount = Math.Max(1, entry.StackCount - 1);
                }
            }
        }

        private void ScheduleAutoSellListRescan()
        {
            this.autoSellPendingRescanAt = Time.unscaledTime + 0.35f;
            this.autoSellPendingRescanRetries = 6;
        }

        private void ProcessPendingAutoSellListRescan()
        {
            if (this.autoSellPendingRescanRetries <= 0)
            {
                return;
            }

            if (!this.showMenu || this.selectedTab != 3 || this.automationSubTab != 4)
            {
                this.autoSellPendingRescanRetries = 0;
                return;
            }

            if (Time.unscaledTime < this.autoSellPendingRescanAt)
            {
                return;
            }

            string statusMessage = this.autoSellStatus;
            this.autoSellBagItems = this.ScanBackpackForAutoSellItems();
            this.autoSellStatus = statusMessage;
            this.autoSellPendingRescanRetries--;
            this.autoSellPendingRescanAt = Time.unscaledTime + 0.3f;
        }

        private bool IsAutoSellWorldReady()
        {
            try
            {
                GameObject loginPanel = GameObject.Find(LOGIN_PANEL_PATH);
                if (loginPanel != null && loginPanel.activeInHierarchy)
                {
                    return false;
                }

                GameObject loginRoomPanel = GameObject.Find(LOGIN_ROOM_PANEL_PATH);
                if (loginRoomPanel != null && loginRoomPanel.activeInHierarchy)
                {
                    return false;
                }

                GameObject player = GetPlayer();
                if (player == null || !player.activeInHierarchy)
                {
                    return false;
                }

                GameObject bagButton = GameObject.Find(BAG_BUTTON_PATH);
                if (bagButton == null)
                {
                    GameObject statusPanel = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Status/StatusPanel(Clone)");
                    if (statusPanel == null || !statusPanel.activeInHierarchy)
                    {
                        return false;
                    }
                }

                return true;
            }
            catch
            {
                return false;
            }
        }

        public bool IsFishingAutomationWorldReady()
        {
            try
            {
                GameObject loginPanel = GameObject.Find(LOGIN_PANEL_PATH);
                if (loginPanel != null && loginPanel.activeInHierarchy)
                {
                    return false;
                }

                GameObject loginRoomPanel = GameObject.Find(LOGIN_ROOM_PANEL_PATH);
                if (loginRoomPanel != null && loginRoomPanel.activeInHierarchy)
                {
                    return false;
                }

                GameObject player = GetPlayer();
                if (player == null || !player.activeInHierarchy)
                {
                    return false;
                }

                return true;
            }
            catch
            {
                return false;
            }
        }

        public bool IsFishingAutomationRuntimeReady(out string status)
        {
            status = "Managed player unavailable";

            try
            {
                if (this.TryGetManagedSelfPlayerObject(out object playerObj, out string playerSource) && playerObj != null)
                {
                    status = "Managed player ready via " + playerSource;
                    return true;
                }

                if (this.TryGetManagedInteractSystemObject(out object interactSystemObj, out string interactSource) && interactSystemObj != null)
                {
                    if (this.TryGetManagedInteractPlayerObject(interactSystemObj, out object interactPlayerObj, out string interactPlayerSource) && interactPlayerObj != null)
                    {
                        status = "Managed interact player ready via " + interactPlayerSource;
                        return true;
                    }

                    status = "Interact ready but player unresolved via " + interactSource;
                    return false;
                }

                status = "Managed interact unavailable";
                return false;
            }
            catch (Exception ex)
            {
                status = "Runtime readiness exception: " + ex.Message;
                return false;
            }
        }

        private Dictionary<uint, int> BuildDirectSellItemMap(out int matchedBagTotal, out int reservedKept)
        {
            matchedBagTotal = 0;
            reservedKept = 0;
            Dictionary<uint, int> sellItems = new Dictionary<uint, int>();
            Dictionary<uint, int> bagCountsByNetId = new Dictionary<uint, int>();
            Dictionary<uint, string> reserveGroupsByNetId = new Dictionary<uint, string>();
            Dictionary<uint, string> sellDetailsByNetId = new Dictionary<uint, string>();
            this.autoSellCollectedStaticIdsByNetId.Clear();
            string key = this.GetActiveAutoSellMatchKey();
            if (string.IsNullOrWhiteSpace(key) || key.Length < 2)
            {
                this.autoSellLastMatchSummary = "Safety: match item is empty/too short.";
                this.autoSellSelectedDetails = "";
                this.AutoSellLog("Scan blocked because match item is empty or too short.");
                return sellItems;
            }

            List<string> skippedSamples = new List<string>();
            int inspected = 0;
            int skippedStarFilter = 0;
            bool includeWarehouse = Mathf.Clamp(this.autoSellScanSource, 0, 2) != 0;

            this.TryRefreshDirectBackpackRuntimeSnapshot(true);
            int runtimeSnapshotItems = this.directBackpackRuntimeItems.Count;
            this.CollectDirectSellItemsFromRuntimeSnapshot(key, bagCountsByNetId, reserveGroupsByNetId, sellDetailsByNetId, skippedSamples, ref inspected, ref skippedStarFilter);
            this.CollectDirectSellItemsManaged(key, bagCountsByNetId, reserveGroupsByNetId, sellDetailsByNetId, skippedSamples, ref inspected, ref skippedStarFilter, true, includeWarehouse);
            this.CollectDirectSellItemsMono(key, bagCountsByNetId, reserveGroupsByNetId, sellDetailsByNetId, skippedSamples, ref inspected, ref skippedStarFilter, true, includeWarehouse);

            int matchedStacks = bagCountsByNetId.Count;
            foreach (int count in bagCountsByNetId.Values)
            {
                matchedBagTotal += Math.Max(0, count);
            }

            reservedKept = this.ApplyAutoSellReserve(sellItems, reserveGroupsByNetId, bagCountsByNetId);
            if (!this.autoSellAllMatchingStacks && !this.autoSellFestivalTokensEnabled)
            {
                this.LimitAutoSellToSingleStack(sellItems);
            }
            int totalCount = 0;
            foreach (int count in sellItems.Values)
            {
                totalCount += Math.Max(0, count);
            }

            List<string> finalSellSamples = new List<string>();
            foreach (KeyValuePair<uint, int> kv in sellItems.Take(12))
            {
                sellDetailsByNetId.TryGetValue(kv.Key, out string detail);
                finalSellSamples.Add("netId=" + kv.Key + " x" + Math.Max(0, kv.Value) + (string.IsNullOrWhiteSpace(detail) ? "" : " " + detail));
            }

            this.autoSellLastMatchSummary = "Selected stacks=" + sellItems.Count + ", matchedStacks=" + matchedStacks + ", bag=" + matchedBagTotal + ", sell=" + totalCount + ", inspected=" + inspected + ", runtimeItems=" + runtimeSnapshotItems + (reservedKept > 0 ? ", kept=" + reservedKept : "") + (skippedStarFilter > 0 ? ", skipped star filter=" + skippedStarFilter : "");
            this.autoSellSelectedDetails = finalSellSamples.Count > 0 ? string.Join("; ", finalSellSamples.ToArray()) : "";
            if (finalSellSamples.Count > 0)
            {
                this.autoSellLastMatchSummary += "\nSelected: " + string.Join("; ", finalSellSamples.Take(3).ToArray());
            }
            else if (matchedBagTotal > 0 && totalCount == 0)
            {
                int keep = Mathf.Clamp(this.autoSellReserveCount, 0, 200);
                this.autoSellLastMatchSummary += matchedBagTotal <= keep
                    ? "\nKeep Per Item reserved all matching items. Set Keep Per Item to 0 to sell them."
                    : "\nNo sellable quantity after Keep Per Item (single-count stacks are skipped). Lower Keep or raise Cap.";
            }
            if (skippedSamples.Count > 0)
            {
                this.autoSellLastMatchSummary += "\nSkipped: " + string.Join("; ", skippedSamples.Take(3).ToArray());
            }
            this.autoSellLastSellDetailsByNetId = new Dictionary<uint, string>(sellDetailsByNetId);
            this.AutoSellLogSellResult(this.autoSellLastMatchSummary.Replace("\n", " "));
            return sellItems;
        }

        private void RememberAutoSellCollectedStaticId(uint netId, int staticId)
        {
            if (netId == 0U || staticId <= 0)
            {
                return;
            }

            this.autoSellCollectedStaticIdsByNetId[netId] = staticId;
        }

        private bool CollectDirectSellItemsFromRuntimeSnapshot(string normalizedKey, Dictionary<uint, int> bagCountsByNetId, Dictionary<uint, string> reserveGroupsByNetId, Dictionary<uint, string> sellDetailsByNetId, List<string> skippedSamples, ref int inspected, ref int skippedStarFilter)
        {
            if (Mathf.Clamp(this.autoSellScanSource, 0, 2) == 1)
            {
                return false;
            }

            if (!this.TryRefreshDirectBackpackRuntimeSnapshot(false))
            {
                return false;
            }

            foreach (DirectBackpackRuntimeItem item in this.directBackpackRuntimeItems)
            {
                if (item == null || item.NetId == 0U)
                {
                    continue;
                }

                inspected++;
                string descriptor = item.Descriptor ?? string.Empty;
                if (!this.AutoSellDescriptorMatches(descriptor, normalizedKey))
                {
                    continue;
                }

                int count = Math.Max(1, item.Count);
                if (!this.AutoSellRuntimeSnapshotItemStarMatches(item, descriptor, count, out int starRate))
                {
                    skippedStarFilter++;
                    if (skippedSamples.Count < 6)
                    {
                        skippedSamples.Add("skip star=" + starRate + " " + descriptor);
                    }
                    continue;
                }

                this.MergeAutoSellBagCount(bagCountsByNetId, item.NetId, count);
                this.RememberAutoSellCollectedStaticId(item.NetId, item.StaticId);
                reserveGroupsByNetId[item.NetId] = this.GetAutoSellReserveGroupKey(descriptor, starRate);
                sellDetailsByNetId[item.NetId] = (starRate > 0 ? starRate + "* " : "") + descriptor;
            }

            return true;
        }

        private void MergeAutoSellBagCount(Dictionary<uint, int> bagCountsByNetId, uint netId, int stackCount)
        {
            if (bagCountsByNetId == null || netId == 0U)
            {
                return;
            }

            int count = Math.Max(1, stackCount);
            if (bagCountsByNetId.TryGetValue(netId, out int existing))
            {
                bagCountsByNetId[netId] = Math.Max(existing, count);
            }
            else
            {
                bagCountsByNetId[netId] = count;
            }
        }

        private int ApplyAutoSellReserve(Dictionary<uint, int> sellItems, Dictionary<uint, string> reserveGroupsByNetId, Dictionary<uint, int> bagCountsByNetId)
        {
            sellItems?.Clear();
            if (sellItems == null || bagCountsByNetId == null || bagCountsByNetId.Count == 0)
            {
                return 0;
            }

            int reserve = Mathf.Clamp(this.autoSellReserveCount, 0, 200);
            Dictionary<string, List<uint>> groupedNetIds = new Dictionary<string, List<uint>>(StringComparer.OrdinalIgnoreCase);
            foreach (KeyValuePair<uint, int> kv in bagCountsByNetId)
            {
                if (kv.Key == 0U || kv.Value <= 0)
                {
                    continue;
                }

                string groupKey = null;
                if (reserveGroupsByNetId != null)
                {
                    reserveGroupsByNetId.TryGetValue(kv.Key, out groupKey);
                }

                if (string.IsNullOrWhiteSpace(groupKey))
                {
                    groupKey = "net:" + kv.Key;
                }

                if (!groupedNetIds.TryGetValue(groupKey, out List<uint> netIds))
                {
                    netIds = new List<uint>();
                    groupedNetIds[groupKey] = netIds;
                }

                netIds.Add(kv.Key);
            }

            int reservedTotal = 0;
            foreach (List<uint> netIds in groupedNetIds.Values)
            {
                int totalBag = 0;
                for (int i = 0; i < netIds.Count; i++)
                {
                    if (bagCountsByNetId.TryGetValue(netIds[i], out int bagCount))
                    {
                        totalBag += Math.Max(0, bagCount);
                    }
                }

                if (totalBag <= 0)
                {
                    continue;
                }

                int reservedForGroup = Math.Min(reserve, totalBag);
                int sellablePool = Math.Max(0, totalBag - reservedForGroup);
                reservedTotal += reservedForGroup;
                netIds.Sort((uint a, uint b) =>
                {
                    int countA = bagCountsByNetId.TryGetValue(a, out int bagA) ? bagA : 0;
                    int countB = bagCountsByNetId.TryGetValue(b, out int bagB) ? bagB : 0;
                    return countA.CompareTo(countB);
                });

                int remainingKeep = reservedForGroup;
                for (int i = 0; i < netIds.Count && sellablePool > 0; i++)
                {
                    uint netId = netIds[i];
                    if (!bagCountsByNetId.TryGetValue(netId, out int bagCount) || bagCount <= 0)
                    {
                        continue;
                    }

                    int keptFromStack = Math.Min(bagCount, remainingKeep);
                    remainingKeep -= keptFromStack;
                    int sellableFromStack = bagCount - keptFromStack;
                    if (sellableFromStack <= 0)
                    {
                        continue;
                    }

                    int allocateFromStack = Math.Min(sellableFromStack, sellablePool);
                    int sellCount = this.GetAutoSellStackSellCount(allocateFromStack);
                    if (sellCount <= 0)
                    {
                        continue;
                    }

                    sellItems[netId] = sellCount;
                    sellablePool -= allocateFromStack;
                }
            }

            return reservedTotal;
        }

        private void LimitAutoSellToSingleStack(Dictionary<uint, int> sellItems)
        {
            if (sellItems == null || sellItems.Count <= 1)
            {
                return;
            }

            uint bestNetId = 0U;
            int bestSellCount = 0;
            foreach (KeyValuePair<uint, int> kv in sellItems)
            {
                if (bestNetId == 0U || kv.Value > bestSellCount)
                {
                    bestNetId = kv.Key;
                    bestSellCount = kv.Value;
                }
            }

            if (bestNetId == 0U)
            {
                sellItems.Clear();
                return;
            }

            sellItems.Clear();
            sellItems[bestNetId] = bestSellCount;
        }

        private string GetAutoSellReserveGroupKey(string descriptor, int starRate)
        {
            string matchKey = this.ExtractAutoSellMatchKeyFromDescriptor(descriptor);
            if (string.IsNullOrWhiteSpace(matchKey))
            {
                matchKey = this.NormalizeAutoSellMatchKey(descriptor);
            }
            if (string.IsNullOrWhiteSpace(matchKey))
            {
                matchKey = "unknown";
            }

            int normalizedStar = this.NormalizeAutoSellStarRateForDescriptor(starRate, descriptor);
            return this.NormalizeAutoSellMatchKey(matchKey) + "|star:" + Mathf.Clamp(normalizedStar, 0, 5);
        }

        private int GetAutoSellStackSellCount(int stackCount)
        {
            int count = Math.Max(1, stackCount);
            if (this.autoSellFullStack)
            {
                return count;
            }

            int cap = Mathf.Clamp(this.autoSellMaxPerStack, 0, 200);
            return Math.Min(count, cap);
        }

        private void CollectDirectSellItemsManaged(string normalizedKey, Dictionary<uint, int> bagCountsByNetId, Dictionary<uint, string> reserveGroupsByNetId, Dictionary<uint, string> sellDetailsByNetId, List<string> skippedSamples, ref int inspected, ref int skippedStarFilter, bool includeBackpack = true, bool includeWarehouse = true)
        {
            try
            {
                Type backPackType = this.FindLoadedType("XDTGameSystem.GameplaySystem.BackPack.BackPackSystem", "BackPackSystem");
                if (backPackType == null)
                {
                    this.AutoSellLog("Managed backpack unavailable.");
                    return;
                }

                if (!this.TryGetManagedModule(backPackType, out object backPackObj) || backPackObj == null)
                {
                    backPackObj = this.TryGetStaticObjectAcrossHierarchy(backPackType, "Instance", "_instance");
                }
                if (backPackObj == null)
                {
                    this.AutoSellLog("Managed backpack instance unavailable.");
                    return;
                }

                Type storageType = this.FindLoadedType("EcsClient.XDT.Scene.Shared.Data.StaticPartial.EStorageType", "EStorageType");
                object storageProbe = storageType != null && storageType.IsEnum ? Enum.ToObject(storageType, 1) : (object)1;
                MethodInfo getAllItem = backPackObj.GetType().GetMethod("GetAllItem", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, new[] { storageProbe.GetType() }, null);
                if (getAllItem == null)
                {
                    getAllItem = backPackObj.GetType().GetMethod("GetAllItem", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, Type.EmptyTypes, null);
                }
                if (getAllItem == null)
                {
                    return;
                }

                foreach (int storageTypeValue in this.GetAutoSellStorageTypeValues())
                {
                    if ((storageTypeValue == 1 && !includeBackpack) || (storageTypeValue != 1 && !includeWarehouse))
                    {
                        continue;
                    }

                    object storageArg = storageType != null && storageType.IsEnum ? Enum.ToObject(storageType, storageTypeValue) : (object)storageTypeValue;
                    object itemListObj = getAllItem.GetParameters().Length == 1
                        ? getAllItem.Invoke(backPackObj, new[] { storageArg })
                        : getAllItem.Invoke(backPackObj, null);
                    IEnumerable items = itemListObj as IEnumerable;
                    if (items == null)
                    {
                        continue;
                    }

                    foreach (object item in items)
                    {
                        if (item == null)
                        {
                            continue;
                        }
                        inspected++;
                        if (!this.TryGetManagedUInt32Member(item, "netId", out uint netId) || netId == 0U)
                        {
                            continue;
                        }

                        string descriptor = this.GetManagedBackpackItemDescriptor(item);
                        if (!this.AutoSellDescriptorMatches(descriptor, normalizedKey))
                        {
                            continue;
                        }

                        int count = 1;
                        int staticId = 0;
                        this.TryGetManagedBackpackItemCount(item, out count);
                        this.TryGetManagedInt32Member(item, "staticId", out staticId);
                        if (staticId <= 0)
                        {
                            this.TryGetManagedInt32Member(item, "StaticId", out staticId);
                        }
                        if (!this.AutoSellManagedItemStarMatches(item, netId, descriptor, count, out int starRate))
                        {
                            skippedStarFilter++;
                            if (skippedSamples.Count < 6)
                            {
                                string photoId = this.GetManagedBackpackItemPhotoId(item);
                                int step = this.GetManagedBackpackItemStep(item);
                                skippedSamples.Add("skip star=" + starRate + " step=" + step + (string.IsNullOrWhiteSpace(photoId) ? "" : " photo=" + photoId) + " " + descriptor);
                            }
                            continue;
                        }

                        this.MergeAutoSellBagCount(bagCountsByNetId, netId, count);
                        this.RememberAutoSellCollectedStaticId(netId, staticId);
                        reserveGroupsByNetId[netId] = this.GetAutoSellReserveGroupKey(descriptor, starRate);
                        sellDetailsByNetId[netId] = (starRate > 0 ? starRate + "* " : "") + descriptor;
                    }
                }
            }
            catch (Exception ex)
            {
                this.AutoSellLog("Managed scan exception: " + ex.GetType().Name + ": " + ex.Message);
            }
        }

        private void CollectDirectSellItemsMono(string normalizedKey, Dictionary<uint, int> bagCountsByNetId, Dictionary<uint, string> reserveGroupsByNetId, Dictionary<uint, string> sellDetailsByNetId, List<string> skippedSamples, ref int inspected, ref int skippedStarFilter, bool includeBackpack = true, bool includeWarehouse = true)
        {
            try
            {
                if (!this.TryResolveAuraMonoModule("XDTGameSystem.GameplaySystem.BackPack.BackPackSystem", out IntPtr backPackSystemObj) || backPackSystemObj == IntPtr.Zero)
                {
                    this.AutoSellLog("Mono backpack module unavailable.");
                    return;
                }

                IntPtr backPackClass = auraMonoObjectGetClass != null ? auraMonoObjectGetClass(backPackSystemObj) : IntPtr.Zero;
                IntPtr getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 1);
                bool getAllItemNeedsStorageType = true;
                if (getAllItemMethod == IntPtr.Zero)
                {
                    getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 0);
                    getAllItemNeedsStorageType = false;
                }
                if (getAllItemMethod == IntPtr.Zero || auraMonoRuntimeInvoke == null)
                {
                    this.AutoSellLog("Mono GetAllItem unavailable.");
                    return;
                }

                bool sawItems = false;
                foreach (int storageTypeValue in this.GetAutoSellStorageTypeValues())
                {
                    if ((storageTypeValue == 1 && !includeBackpack) || (storageTypeValue != 1 && !includeWarehouse))
                    {
                        continue;
                    }

                    IntPtr exc = IntPtr.Zero;
                    IntPtr itemListObj;
                    unsafe
                    {
                        IntPtr* args = stackalloc IntPtr[1];
                        args[0] = (IntPtr)(&storageTypeValue);
                        itemListObj = auraMonoRuntimeInvoke(getAllItemMethod, backPackSystemObj, getAllItemNeedsStorageType ? (IntPtr)args : IntPtr.Zero, ref exc);
                    }
                    if (exc != IntPtr.Zero || itemListObj == IntPtr.Zero)
                    {
                        continue;
                    }

                    List<IntPtr> items = new List<IntPtr>();
                    if (!this.TryEnumerateAuraMonoCollectionItems(itemListObj, items) || items.Count == 0)
                    {
                        continue;
                    }
                    sawItems = true;

                    foreach (IntPtr itemObj in items)
                    {
                        if (itemObj == IntPtr.Zero)
                        {
                            continue;
                        }
                        inspected++;
                        if (!this.TryGetDirectBackpackItemNetId(itemObj, out uint netId) || netId == 0U)
                        {
                            continue;
                        }

                        string descriptor = this.GetDirectBackpackItemDescriptor(itemObj);
                        if (!this.AutoSellDescriptorMatches(descriptor, normalizedKey))
                        {
                            continue;
                        }

                        int count = 1;
                        int staticId = 0;
                        this.TryGetDirectBackpackItemCount(itemObj, out count);
                        this.TryGetDirectBackpackItemStaticId(itemObj, out staticId);
                        if (!this.AutoSellMonoItemStarMatches(itemObj, netId, descriptor, count, out int starRate))
                        {
                            skippedStarFilter++;
                            if (skippedSamples.Count < 6)
                            {
                                string photoId = this.GetDirectBackpackItemPhotoId(itemObj);
                                int step = this.GetDirectBackpackItemStep(itemObj);
                                skippedSamples.Add("skip star=" + starRate + " step=" + step + (string.IsNullOrWhiteSpace(photoId) ? "" : " photo=" + photoId) + " " + descriptor);
                            }
                            continue;
                        }

                        this.MergeAutoSellBagCount(bagCountsByNetId, netId, count);
                        this.RememberAutoSellCollectedStaticId(netId, staticId);
                        reserveGroupsByNetId[netId] = this.GetAutoSellReserveGroupKey(descriptor, starRate);
                        sellDetailsByNetId[netId] = (starRate > 0 ? starRate + "* " : "") + descriptor;
                    }
                }

                if (!sawItems)
                {
                    this.AutoSellLog("Mono " + this.GetAutoSellScanSourceLabel().ToLowerInvariant() + " list empty/unreadable.");
                }
            }
            catch (Exception ex)
            {
                this.AutoSellLogSellResult("Mono scan exception: " + ex.Message);
            }
        }

        private string NormalizeAutoSellMatchKey(string value)
        {
            string text = (value ?? string.Empty).Trim().ToLowerInvariant();
            text = text.Replace("ui_item_normal_", string.Empty);
            text = text.Replace("ui_item_special_", string.Empty);
            text = text.Replace("sprite_", string.Empty);
            return text;
        }

        private string GetActiveAutoSellMatchKey()
        {
            string key = this.NormalizeAutoSellMatchKey(this.autoSellItemKey);
            return this.autoSellMatchFamily ? this.GetAutoSellFamilyKey(key) : key;
        }

        private string GetAutoSellFamilyKey(string matchKey)
        {
            string key = this.NormalizeAutoSellMatchKey(matchKey);
            if (string.IsNullOrWhiteSpace(key))
            {
                return string.Empty;
            }

            if (key.Contains("birdphoto"))
            {
                return key.StartsWith("p_", StringComparison.Ordinal) ? "p_birdphoto" : "birdphoto";
            }

            string trimmed = this.TrimTrailingDigitsAndUnderscores(key);
            if (!string.IsNullOrWhiteSpace(trimmed) && trimmed.Length >= 2)
            {
                return trimmed;
            }

            return key;
        }

        private string TrimTrailingDigitsAndUnderscores(string value)
        {
            string text = this.NormalizeAutoSellMatchKey(value);
            int end = text.Length;
            while (end > 0 && char.IsDigit(text[end - 1]))
            {
                end--;
            }
            while (end > 0 && text[end - 1] == '_')
            {
                end--;
            }
            return end > 0 ? text.Substring(0, end) : text;
        }

        private bool AutoSellManagedItemStarMatches(object item, uint netId, string descriptor, int stackCount, out int starRate)
        {
            starRate = 0;
            bool hasStarRate = this.TryGetAutoSellQualityComponentStar(netId, out starRate)
                || this.TryGetManagedBackpackItemStarRate(item, out starRate);
            starRate = this.NormalizeAutoSellStarRateForDescriptor(starRate, descriptor);
            if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
            {
                if (this.TryGetAutoSellCachedUiStar(descriptor, stackCount, out int uiStar))
                {
                    starRate = uiStar;
                    hasStarRate = true;
                }
            }
            if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
            {
                int step = this.GetManagedBackpackItemStep(item);
                if (step >= 1 && step <= 5)
                {
                    starRate = step;
                    hasStarRate = true;
                }
            }
            if (Mathf.Clamp(this.autoSellStarFilter, 0, 5) > 0 && (!hasStarRate || starRate <= 0))
            {
                return false;
            }
            return this.AutoSellStarMatches(starRate);
        }

        private bool AutoSellMonoItemStarMatches(IntPtr itemObj, uint netId, string descriptor, int stackCount, out int starRate)
        {
            starRate = 0;
            bool hasStarRate = this.TryGetAutoSellQualityComponentStar(netId, out starRate)
                || this.TryGetDirectBackpackItemStarRate(itemObj, out starRate);
            starRate = this.NormalizeAutoSellStarRateForDescriptor(starRate, descriptor);
            if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
            {
                if (this.TryGetAutoSellCachedUiStar(descriptor, stackCount, out int uiStar))
                {
                    starRate = uiStar;
                    hasStarRate = true;
                }
            }
            if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
            {
                int step = this.GetDirectBackpackItemStep(itemObj);
                if (step >= 1 && step <= 5)
                {
                    starRate = step;
                    hasStarRate = true;
                }
            }
            if (Mathf.Clamp(this.autoSellStarFilter, 0, 5) > 0 && (!hasStarRate || starRate <= 0))
            {
                return false;
            }
            return this.AutoSellStarMatches(starRate);
        }

        private bool AutoSellRuntimeSnapshotItemStarMatches(DirectBackpackRuntimeItem item, string descriptor, int stackCount, out int starRate)
        {
            starRate = 0;
            if (item == null)
            {
                return this.AutoSellStarMatches(starRate);
            }

            bool hasStarRate = this.TryGetAutoSellQualityComponentStar(item.NetId, out starRate);
            if (!hasStarRate && item.ManagedItem != null)
            {
                hasStarRate = this.TryGetManagedBackpackItemStarRate(item.ManagedItem, out starRate);
            }
            if (!hasStarRate && item.MonoItem != IntPtr.Zero)
            {
                hasStarRate = this.TryGetDirectBackpackItemStarRate(item.MonoItem, out starRate);
            }

            starRate = this.NormalizeAutoSellStarRateForDescriptor(starRate, descriptor);
            if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
            {
                if (this.TryGetAutoSellCachedUiStar(descriptor, stackCount, out int uiStar))
                {
                    starRate = uiStar;
                    hasStarRate = true;
                }
            }
            if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
            {
                int step = item.ManagedItem != null
                    ? this.GetManagedBackpackItemStep(item.ManagedItem)
                    : (item.MonoItem != IntPtr.Zero ? this.GetDirectBackpackItemStep(item.MonoItem) : 0);
                if (step >= 1 && step <= 5)
                {
                    starRate = step;
                    hasStarRate = true;
                }
            }
            if (Mathf.Clamp(this.autoSellStarFilter, 0, 5) > 0 && (!hasStarRate || starRate <= 0))
            {
                return false;
            }

            return this.AutoSellStarMatches(starRate);
        }

        private bool IsAutoSellBirdPhotoDescriptor(string descriptor)
        {
            return this.NormalizeAutoSellMatchKey(descriptor).Contains("birdphoto");
        }

        private bool TryGetAutoSellQualityComponentStar(uint netId, out int starRate)
        {
            starRate = 0;
            if (netId == 0U)
            {
                return false;
            }

            try
            {
                if (!this.EnsureAutoSellQualityLookupReady())
                {
                    return this.TryGetAutoSellBackpackItemDataStar(netId, out starRate);
                }

                object netIdArg = this.CreateAutoSellNetIdArgument(netId);
                if (netIdArg == null)
                {
                    return false;
                }

                Type qualityType = this.cachedAutoSellTryGetQualityComponentMethod.GetGenericArguments().Length == 0
                    ? null
                    : this.cachedAutoSellTryGetQualityComponentMethod.GetParameters()[1].ParameterType.GetElementType();
                object qualityValue = qualityType != null && qualityType.IsValueType ? Activator.CreateInstance(qualityType) : null;
                object[] args = { netIdArg, qualityValue };
                object result = this.cachedAutoSellTryGetQualityComponentMethod.Invoke(null, args);
                if (!(result is bool ok) || !ok || args.Length < 2 || args[1] == null)
                {
                    return false;
                }

                if (this.TryGetManagedInt32Member(args[1], "Quality", out int quality))
                {
                    starRate = this.NormalizeAutoSellStarRate(quality);
                    return starRate > 0;
                }
            }
            catch (Exception ex)
            {
                this.AutoSellLog("Quality lookup exception: " + ex.GetType().Name + ": " + ex.Message);
            }

            return false;
        }

        private unsafe bool TryGetAutoSellBackpackItemDataStar(uint netId, out int starRate)
        {
            starRate = 0;
            if (netId == 0U
                || !this.EnsureAuraMonoApiReady()
                || !this.AttachAuraMonoThread()
                || auraMonoObjectGetClass == null
                || auraMonoRuntimeInvoke == null)
            {
                return false;
            }

            try
            {
                if (!this.TryResolveAuraMonoModule("XDTGameSystem.GameplaySystem.BackPack.BackPackSystem", out IntPtr backPackSystemObj) || backPackSystemObj == IntPtr.Zero)
                {
                    return false;
                }

                if (!this.TryGetMonoObjectMember(backPackSystemObj, "_itemData", out IntPtr itemDataDictObj) || itemDataDictObj == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr dictClass = auraMonoObjectGetClass(itemDataDictObj);
                IntPtr getItemMethod = this.FindAuraMonoMethodOnHierarchy(dictClass, "get_Item", 1);
                if (getItemMethod == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr itemDataObj;
                IntPtr exc = IntPtr.Zero;
                IntPtr* args = stackalloc IntPtr[1];
                args[0] = (IntPtr)(&netId);
                itemDataObj = auraMonoRuntimeInvoke(getItemMethod, itemDataDictObj, (IntPtr)args, ref exc);
                if (exc != IntPtr.Zero || itemDataObj == IntPtr.Zero)
                {
                    return false;
                }

                if (this.TryGetMonoInt32Member(itemDataObj, "starRate", out int rawStar))
                {
                    starRate = this.NormalizeAutoSellStarRate(rawStar);
                    return starRate > 0;
                }
            }
            catch
            {
            }

            starRate = 0;
            return false;
        }

        private bool EnsureAutoSellQualityLookupReady()
        {
            if (this.autoSellQualityLookupResolved)
            {
                return this.cachedAutoSellTryGetQualityComponentMethod != null && this.cachedAutoSellNetIdType != null;
            }

            this.autoSellQualityLookupResolved = true;
            try
            {
                Type dataCenterType = this.FindLoadedType(
                    "XDTDataAndProtocol.ComponentsData.DataCenter",
                    "DataCenter");
                Type qualityType = this.FindLoadedType(
                    "XDT.Scene.Shared.Entity.QualityComponent",
                    "QualityComponent");
                this.cachedAutoSellNetIdType = this.FindLoadedType(
                    "EcsClient.XDT.Scene.Shared.Data.SharedData.NetId",
                    "NetId");

                if (dataCenterType == null || qualityType == null || this.cachedAutoSellNetIdType == null)
                {
                    this.AutoSellLog("Quality lookup unavailable. DataCenter=" + (dataCenterType != null) + " QualityComponent=" + (qualityType != null) + " NetId=" + (this.cachedAutoSellNetIdType != null));
                    return false;
                }

                foreach (MethodInfo method in dataCenterType.GetMethods(BindingFlags.Static | BindingFlags.Public | BindingFlags.NonPublic))
                {
                    if (method == null || method.Name != "TryGetComponentData" || !method.IsGenericMethodDefinition)
                    {
                        continue;
                    }

                    ParameterInfo[] parameters = method.GetParameters();
                    if (parameters.Length == 2
                        && parameters[0].ParameterType == this.cachedAutoSellNetIdType
                        && parameters[1].ParameterType.IsByRef)
                    {
                        this.cachedAutoSellTryGetQualityComponentMethod = method.MakeGenericMethod(qualityType);
                        break;
                    }
                }

                if (this.cachedAutoSellTryGetQualityComponentMethod == null)
                {
                    this.AutoSellLog("Quality lookup unavailable. TryGetComponentData<T>(NetId, out T) not found.");
                    return false;
                }

                foreach (MethodInfo method in this.cachedAutoSellNetIdType.GetMethods(BindingFlags.Static | BindingFlags.Public | BindingFlags.NonPublic))
                {
                    if (method != null
                        && method.Name == "op_Implicit"
                        && method.ReturnType == this.cachedAutoSellNetIdType)
                    {
                        ParameterInfo[] parameters = method.GetParameters();
                        if (parameters.Length == 1 && parameters[0].ParameterType == typeof(uint))
                        {
                            this.cachedAutoSellNetIdFromUIntMethod = method;
                            break;
                        }
                    }
                }

                this.AutoSellLog("Quality lookup ready via DataCenter.TryGetComponentData<QualityComponent>.");
                return true;
            }
            catch (Exception ex)
            {
                this.AutoSellLog("Quality lookup setup exception: " + ex.GetType().Name + ": " + ex.Message);
                return false;
            }
        }

        private object CreateAutoSellNetIdArgument(uint netId)
        {
            if (this.cachedAutoSellNetIdType == null)
            {
                return null;
            }

            try
            {
                if (this.cachedAutoSellNetIdFromUIntMethod != null)
                {
                    return this.cachedAutoSellNetIdFromUIntMethod.Invoke(null, new object[] { netId });
                }

                object boxed = Activator.CreateInstance(this.cachedAutoSellNetIdType);
                FieldInfo valueField = this.cachedAutoSellNetIdType.GetField("value", BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
                if (valueField != null)
                {
                    valueField.SetValue(boxed, netId);
                    return boxed;
                }
            }
            catch
            {
            }

            return null;
        }

        private bool AutoSellStarMatches(int starRate)
        {
            int filter = Mathf.Clamp(this.autoSellStarFilter, 0, 5);
            if (filter <= 0)
            {
                return true;
            }
            return this.NormalizeAutoSellStarRate(starRate) == filter;
        }

        private int NormalizeAutoSellStarRate(int starRate)
        {
            if (starRate <= 0)
            {
                return 0;
            }
            return Mathf.Clamp(starRate, 1, 5);
        }

        private int NormalizeAutoSellStarRateForDescriptor(int rawStarRate, string descriptor)
        {
            return this.NormalizeAutoSellStarRate(rawStarRate);
        }

        private bool AutoSellDescriptorMatches(string descriptor, string normalizedKey)
        {
            if (string.IsNullOrWhiteSpace(descriptor) || string.IsNullOrWhiteSpace(normalizedKey))
            {
                return false;
            }

            string text = this.NormalizeAutoSellMatchKey(descriptor);
            if (text.Contains(normalizedKey))
            {
                return true;
            }
            if (!normalizedKey.StartsWith("p_", StringComparison.Ordinal) && text.Contains("p_" + normalizedKey))
            {
                return true;
            }
            return false;
        }

        // BattlePassSellPanel indexes PeriodCurrencySales by currency, then matches BackpackItem.staticId to row entityId.
        private void SplitSellItemsByPeriodCurrency(int currencyTypeId, Dictionary<uint, int> sellItems, out Dictionary<uint, int> festivalItems, out Dictionary<uint, int> coinItems, out string diagnostics)
        {
            festivalItems = new Dictionary<uint, int>();
            coinItems = new Dictionary<uint, int>();
            diagnostics = "festival split unavailable";
            if (sellItems == null || sellItems.Count == 0)
            {
                diagnostics = "no sell stacks";
                return;
            }

            if (currencyTypeId <= 0)
            {
                foreach (KeyValuePair<uint, int> kv in sellItems)
                {
                    if (kv.Key != 0U && kv.Value > 0)
                    {
                        coinItems[kv.Key] = kv.Value;
                    }
                }

                diagnostics = "currency id unresolved -> all coin";
                return;
            }

            HashSet<int> allowedStaticIds = null;
            string tablePath = "allowlist:unavailable";
            if (this.TryGetAllowedPeriodCurrencyStaticIds(currencyTypeId, out allowedStaticIds) && allowedStaticIds.Count > 0)
            {
                tablePath = "allowlist:" + allowedStaticIds.Count;
            }
            else
            {
                allowedStaticIds = null;
            }
            bool useAllowlist = allowedStaticIds != null;
            foreach (KeyValuePair<uint, int> kv in sellItems)
            {
                if (kv.Key == 0U || kv.Value <= 0)
                {
                    continue;
                }
                string descriptor = string.Empty;
                this.autoSellLastSellDetailsByNetId?.TryGetValue(kv.Key, out descriptor);
                this.ClassifyPeriodCurrencyStack(currencyTypeId, kv.Key, descriptor, allowedStaticIds, useAllowlist, out bool isFestival);
                if (isFestival)
                {
                    festivalItems[kv.Key] = kv.Value;
                }
                else
                {
                    coinItems[kv.Key] = kv.Value;
                }
            }
            diagnostics = "currency=" + currencyTypeId + " " + tablePath
                + " tokenStacks=" + festivalItems.Count + " coinStacks=" + coinItems.Count;
        }

        private void ClassifyPeriodCurrencyStack(int currencyTypeId, uint netId, string descriptor, HashSet<int> allowedStaticIds, bool useAllowlist, out bool isFestival)
        {
            isFestival = false;
            this.CollectPeriodCurrencyCandidateEntityIds(netId, descriptor, allowedStaticIds, out List<int> candidateIds, out _);
            for (int c = 0; c < candidateIds.Count; c++)
            {
                int candidateId = candidateIds[c];
                if (candidateId <= 0)
                {
                    continue;
                }
                if (useAllowlist ? allowedStaticIds.Contains(candidateId) : this.TryLookupPeriodCurrencySale(currencyTypeId, candidateId, out _))
                {
                    isFestival = true;
                    return;
                }
            }
        }

        private int SumAutoSellItemCounts(Dictionary<uint, int> items)
        {
            if (items == null || items.Count == 0)
            {
                return 0;
            }
            int total = 0;
            foreach (int count in items.Values)
            {
                total += Math.Max(0, count);
            }
            return total;
        }

        private void CollectPeriodCurrencyCandidateEntityIds(uint netId, string descriptor, HashSet<int> periodAllowlist, out List<int> candidateIds, out string diagnostics)
        {
            candidateIds = new List<int>(12);
            diagnostics = string.Empty;
            HashSet<int> seen = new HashSet<int>();

            int primaryStaticId = 0;
            if (this.TryResolveStaticIdForSell(netId, descriptor, out primaryStaticId, out string staticSource))
            {
                this.AddPeriodCurrencyCandidate(primaryStaticId, staticSource, seen, candidateIds, ref diagnostics);
            }

            int descriptorSubId = 0;
            if (this.TryExtractStaticIdFromAutoSellText(descriptor, out descriptorSubId))
            {
                this.AddPeriodCurrencyCandidate(descriptorSubId, "descriptor", seen, candidateIds, ref diagnostics);
            }

            if (this.TryExtractStaticIdFromAutoSellText(this.autoSellItemKey, out int keyId))
            {
                this.AddPeriodCurrencyCandidate(keyId, "matchKey", seen, candidateIds, ref diagnostics);
            }

            if (periodAllowlist == null || periodAllowlist.Count == 0)
            {
                if (primaryStaticId > 0 && this.TryDecodeEntityTypeIdFromStaticId(primaryStaticId, out int decodedTypeId))
                {
                    this.AddPeriodCurrencyCandidate(decodedTypeId, "decodedType", seen, candidateIds, ref diagnostics);
                }
            }
            if (primaryStaticId >= 1000)
            {
                this.AddPeriodCurrencyCandidate(primaryStaticId % 1000, "mod1000", seen, candidateIds, ref diagnostics);
                this.AddPeriodCurrencyCandidate(primaryStaticId % 10000, "mod10000", seen, candidateIds, ref diagnostics);
            }

            this.AddDerivedPeriodCurrencyTableEntityIds(primaryStaticId, descriptorSubId, periodAllowlist, seen, candidateIds, ref diagnostics);

            if (primaryStaticId <= 0 && this.TryResolveStaticIdFromLiveMonoBackpack(netId, out int liveStaticId))
            {
                this.AddPeriodCurrencyCandidate(liveStaticId, "liveMono", seen, candidateIds, ref diagnostics);
                if (this.TryDecodeEntityTypeIdFromStaticId(liveStaticId, out int liveDecoded))
                {
                    this.AddPeriodCurrencyCandidate(liveDecoded, "liveDecoded", seen, candidateIds, ref diagnostics);
                }

                int liveSubId = 0;
                if (this.TryExtractStaticIdFromAutoSellText(descriptor, out liveSubId))
                {
                    this.AddDerivedPeriodCurrencyTableEntityIds(liveStaticId, liveSubId, periodAllowlist, seen, candidateIds, ref diagnostics);
                }
            }
        }

        private void AddDerivedPeriodCurrencyTableEntityIds(int backpackStaticId, int descriptorSubId, HashSet<int> periodAllowlist, HashSet<int> seen, List<int> candidateIds, ref string diagnostics)
        {
            int subId = descriptorSubId > 0 ? descriptorSubId : (backpackStaticId > 0 ? backpackStaticId % 1000 : 0);
            if (subId <= 0)
            {
                return;
            }

            List<int> prefixes = this.GetPeriodCurrencyTableIdPrefixes(periodAllowlist);
            for (int i = 0; i < prefixes.Count; i++)
            {
                int prefix = prefixes[i];
                if (prefix <= 0)
                {
                    continue;
                }

                int derivedId = prefix + subId;
                if (periodAllowlist != null && periodAllowlist.Count > 0 && !periodAllowlist.Contains(derivedId))
                {
                    continue;
                }

                this.AddPeriodCurrencyCandidate(derivedId, "table" + prefix + "+" + subId, seen, candidateIds, ref diagnostics);
            }
        }

        private List<int> GetPeriodCurrencyTableIdPrefixes(HashSet<int> periodAllowlist)
        {
            List<int> prefixes = new List<int>(4);
            if (periodAllowlist != null && periodAllowlist.Count > 0)
            {
                HashSet<int> unique = new HashSet<int>();
                foreach (int entityId in periodAllowlist)
                {
                    if (entityId < 1000)
                    {
                        continue;
                    }

                    int prefix = (entityId / 1000) * 1000;
                    if (prefix > 0)
                    {
                        unique.Add(prefix);
                    }
                }

                prefixes.AddRange(unique);
                prefixes.Sort();
                if (prefixes.Count > 0)
                {
                    return prefixes;
                }
            }

            prefixes.Add(732000);
            prefixes.Add(769000);
            return prefixes;
        }

        private void AddPeriodCurrencyCandidate(int value, string label, HashSet<int> seen, List<int> candidateIds, ref string diagnostics)
        {
            if (value <= 0 || seen == null || candidateIds == null || !seen.Add(value))
            {
                return;
            }

            candidateIds.Add(value);
            diagnostics += (diagnostics.Length > 0 ? "," : "") + value + ":" + label;
        }

        private bool TryDecodeEntityTypeIdFromStaticId(int staticId, out int entityTypeId)
        {
            entityTypeId = 0;
            if (staticId <= 0)
            {
                return false;
            }

            try
            {
                Type tableDataType = this.FindManagedTableDataType();
                if (tableDataType == null)
                {
                    return false;
                }

                MethodInfo getEntityTypeId = tableDataType.GetMethod("GetEntityTypeID", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static, null, new[] { typeof(int) }, null);
                if (getEntityTypeId == null)
                {
                    return false;
                }

                entityTypeId = Convert.ToInt32(getEntityTypeId.Invoke(null, new object[] { staticId }));
                return entityTypeId > 0;
            }
            catch
            {
                return false;
            }
        }

        private bool TryLookupPeriodCurrencySale(int currencyTypeId, int entityId, out string lookupPath)
        {
            lookupPath = string.Empty;
            if (currencyTypeId <= 0 || entityId <= 0)
            {
                return false;
            }

#if BEPINEX
            if (this.TryLookupPeriodCurrencySaleIl2CppContains(currencyTypeId, entityId))
            {
                lookupPath = "il2cpp[ContainsKey]";
                return true;
            }
#endif

            if (this.TryLookupPeriodCurrencySaleAura(currencyTypeId, entityId))
            {
                lookupPath = "aura[PeriodCurrencySales]";
                return true;
            }

            if (this.TryLookupPeriodCurrencySaleManaged(currencyTypeId, entityId))
            {
                lookupPath = "managed[PeriodCurrencySales]";
                return true;
            }

            if (this.TryLookupPeriodCurrencySaleFlatTable(currencyTypeId, entityId, out lookupPath))
            {
                return true;
            }

            return false;
        }

        private bool TryLookupPeriodCurrencySaleFlatTable(int currencyTypeId, int entityId, out string lookupPath)
        {
            lookupPath = string.Empty;
            if (this.TryFlatTableContainsPeriodCurrencyEntityManaged(currencyTypeId, entityId))
            {
                lookupPath = "flatManaged";
                return true;
            }

            if (this.TryFlatTableContainsPeriodCurrencyEntityAura(currencyTypeId, entityId))
            {
                lookupPath = "flatAura";
                return true;
            }

            return false;
        }

        private bool TryFlatTableContainsPeriodCurrencyEntityManaged(int currencyTypeId, int entityId)
        {
            if (currencyTypeId <= 0 || entityId <= 0)
            {
                return false;
            }

            try
            {
                Type tableDataType = this.FindManagedTableDataType();
                if (tableDataType == null)
                {
                    return false;
                }

                object flatTable = null;
                FieldInfo flatField = tableDataType.GetField("TablePeriodCurrencySales", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static);
                if (flatField != null)
                {
                    flatTable = flatField.GetValue(null);
                }
                else
                {
                    PropertyInfo flatProp = tableDataType.GetProperty("TablePeriodCurrencySales", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static);
                    if (flatProp != null)
                    {
                        flatTable = flatProp.GetValue(null, null);
                    }
                }

                if (flatTable is IDictionary dictionary)
                {
                    foreach (DictionaryEntry entry in dictionary)
                    {
                        if (this.TryReadPeriodCurrencySaleRowManaged(entry.Value, out int rowCurrency, out int rowEntityId)
                            && rowCurrency == currencyTypeId
                            && rowEntityId == entityId)
                        {
                            return true;
                        }
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        private bool TryFlatTableContainsPeriodCurrencyEntityAura(int currencyTypeId, int entityId)
        {
            if (currencyTypeId <= 0 || entityId <= 0 || !this.EnsureAuraMonoApiReady() || !this.AttachAuraMonoThread())
            {
                return false;
            }

            if (!this.TryGetAutoSellAuraMonoTableDataClass(out IntPtr tableDataClass, out _))
            {
                return false;
            }

            IntPtr flatTable = IntPtr.Zero;
            string[] staticFieldNames = new[] { "TablePeriodCurrencySales", "tablePeriodCurrencySales", "_tablePeriodCurrencySales" };
            for (int i = 0; i < staticFieldNames.Length; i++)
            {
                if (this.TryGetAuraMonoStaticObjectField(tableDataClass, staticFieldNames[i], out flatTable) && flatTable != IntPtr.Zero)
                {
                    break;
                }
            }

            if (flatTable == IntPtr.Zero)
            {
                return false;
            }

            List<IntPtr> rows = new List<IntPtr>(512);
            if (!this.TryEnumerateAuraMonoCollectionItems(flatTable, rows))
            {
                return false;
            }

            for (int i = 0; i < rows.Count; i++)
            {
                IntPtr rowObj = rows[i];
                if (rowObj == IntPtr.Zero)
                {
                    continue;
                }

                IntPtr valueObj = rowObj;
                if (this.TryGetAuraMonoDictionaryEntryIntKey(rowObj, out int pairKey, out IntPtr pairValue) && pairValue != IntPtr.Zero)
                {
                    valueObj = pairValue;
                }
                else if (this.TryGetMonoObjectMember(rowObj, "Value", out IntPtr boxedValue) && boxedValue != IntPtr.Zero)
                {
                    valueObj = boxedValue;
                }

                if (this.TryReadPeriodCurrencySaleRowAura(valueObj, out int rowCurrency, out int rowEntityId)
                    && rowCurrency == currencyTypeId
                    && rowEntityId == entityId)
                {
                    return true;
                }
            }

            return false;
        }

        private bool TryLookupPeriodCurrencySaleManaged(int currencyTypeId, int entityId)
        {
            try
            {
                Type tableDataType = this.FindManagedTableDataType();
                if (tableDataType == null)
                {
                    return false;
                }

                PropertyInfo prop = tableDataType.GetProperty("PeriodCurrencySales", BindingFlags.Public | BindingFlags.Static);
                if (prop == null)
                {
                    return false;
                }

                if (!(prop.GetValue(null, null) is System.Collections.IDictionary byCurrency))
                {
                    return false;
                }

                IDictionary byEntity = null;
                foreach (DictionaryEntry bucket in byCurrency)
                {
                    int keyValue = 0;
                    try { keyValue = Convert.ToInt32(bucket.Key); } catch { continue; }
                    if (keyValue == currencyTypeId)
                    {
                        byEntity = bucket.Value as IDictionary;
                        break;
                    }
                }

                return byEntity != null && byEntity.Contains(entityId);
            }
            catch
            {
                return false;
            }
        }

#if BEPINEX
        private unsafe bool TryLookupPeriodCurrencySaleIl2CppContains(int currencyTypeId, int entityId)
        {
            if (currencyTypeId <= 0 || entityId <= 0)
            {
                return false;
            }

            IntPtr tableClass = this.TryFindIl2CppClass("TableData", "EcsClient", "Il2CppEcsClient", string.Empty);
            if (tableClass == IntPtr.Zero)
            {
                return false;
            }

            IntPtr field = IL2CPP.il2cpp_class_get_field_from_name(tableClass, "PeriodCurrencySales");
            if (field == IntPtr.Zero)
            {
                return false;
            }

            IntPtr salesObj = IL2CPP.il2cpp_field_get_value_object(field, IntPtr.Zero);
            if (salesObj == IntPtr.Zero || !this.TryIl2CppDictionaryTryGetIntObject(salesObj, currencyTypeId, out IntPtr entityMapObj) || entityMapObj == IntPtr.Zero)
            {
                return false;
            }

            return this.TryIl2CppDictionaryContainsIntKey(entityMapObj, entityId);
        }
#endif

#if BEPINEX
        private unsafe bool TryIl2CppDictionaryTryGetIntObject(IntPtr dictObj, int key, out IntPtr valueObj)
        {
            valueObj = IntPtr.Zero;
            return dictObj != IntPtr.Zero && this.TryIl2CppDictionaryContainsIntKey(dictObj, key);
        }

        private unsafe bool TryIl2CppDictionaryContainsIntKey(IntPtr dictObj, int key)
        {
            if (dictObj == IntPtr.Zero)
            {
                return false;
            }

            IntPtr dictClass = IL2CPP.il2cpp_object_get_class(dictObj);
            if (dictClass == IntPtr.Zero)
            {
                return false;
            }

            IntPtr containsKey = IL2CPP.il2cpp_class_get_method_from_name(dictClass, "ContainsKey", 1);
            if (containsKey == IntPtr.Zero)
            {
                return false;
            }

            int localKey = key;
            IntPtr* args = stackalloc IntPtr[1];
            args[0] = (IntPtr)(&localKey);
            IntPtr exc = IntPtr.Zero;
            IntPtr boxed = IL2CPP.il2cpp_runtime_invoke(containsKey, dictObj, (void**)args, ref exc);
            if (exc != IntPtr.Zero || boxed == IntPtr.Zero)
            {
                return false;
            }

            IntPtr unboxed = IL2CPP.il2cpp_object_unbox(boxed);
            return unboxed != IntPtr.Zero && Marshal.ReadByte(unboxed) != 0;
        }
#endif

        private bool TryLookupPeriodCurrencySaleAura(int currencyTypeId, int staticId)
        {
            if (!this.EnsureAuraMonoApiReady() || !this.AttachAuraMonoThread())
            {
                return false;
            }

            if (!this.TryGetAuraMonoTableDataPeriodCurrencySales(out IntPtr salesMapObj))
            {
                return false;
            }

            if (!this.TryFindAuraMonoPeriodCurrencyEntityMap(currencyTypeId, out IntPtr entityMapObj) || entityMapObj == IntPtr.Zero)
            {
                return false;
            }

            return this.TryAuraMonoDictionaryContainsIntKey(entityMapObj, staticId);
        }

        private bool TryGetAuraMonoTableDataPeriodCurrencySales(out IntPtr salesMapObj)
        {
            salesMapObj = IntPtr.Zero;
            if (!this.TryGetAutoSellAuraMonoTableDataClass(out IntPtr tableDataClass, out _))
            {
                return false;
            }

            IntPtr getSalesMethod = this.FindAuraMonoMethodOnHierarchy(tableDataClass, "get_PeriodCurrencySales", 0);
            if (getSalesMethod == IntPtr.Zero)
            {
                string[] staticFieldNames = new[]
                {
                    "PeriodCurrencySales", "periodCurrencySales", "_periodCurrencySales", "TablePeriodCurrencySales"
                };

                for (int i = 0; i < staticFieldNames.Length; i++)
                {
                    if (this.TryGetAuraMonoStaticObjectField(tableDataClass, staticFieldNames[i], out salesMapObj) && salesMapObj != IntPtr.Zero)
                    {
                        return true;
                    }
                }

                return false;
            }

            IntPtr exc = IntPtr.Zero;
            salesMapObj = auraMonoRuntimeInvoke(getSalesMethod, IntPtr.Zero, IntPtr.Zero, ref exc);
            return exc == IntPtr.Zero && salesMapObj != IntPtr.Zero;
        }

        private bool TryAuraMonoDictionaryGetIntValue(IntPtr dictObj, int key, out IntPtr valueObj)
        {
            valueObj = IntPtr.Zero;
            return dictObj != IntPtr.Zero && key > 0 && this.TryAuraMonoDictionaryContainsIntKey(dictObj, key);
        }

        private bool TryGetFestivalSellCurrencyId(out int currencyId)
        {
            currencyId = 0;
            if (!this.autoSellFestivalTokensEnabled)
            {
                return false;
            }

            return this.TryResolveBattlePassPeriodCurrencyId(out currencyId, out _);
        }

        private bool TryGetAllowedPeriodCurrencyStaticIds(int currencyTypeId, out HashSet<int> allowedStaticIds)
        {
            allowedStaticIds = new HashSet<int>();
            if (currencyTypeId <= 0)
            {
                return false;
            }
            string source = string.Empty;
            if (this.TryGetAllowedPeriodCurrencyStaticIdsAura(currencyTypeId, out allowedStaticIds) && allowedStaticIds.Count > 0)
            {
                source = "nestedAura";
            }
            else if (this.TryGetAllowedPeriodCurrencyStaticIdsManaged(currencyTypeId, out allowedStaticIds) && allowedStaticIds.Count > 0)
            {
                source = "nestedManaged";
            }
            else if (this.TryGetAllowedPeriodCurrencyStaticIdsFromFlatTable(currencyTypeId, out allowedStaticIds, out string flatSource) && allowedStaticIds.Count > 0)
            {
                source = flatSource;
            }
            if (allowedStaticIds.Count > 0)
            {
                this.AutoSellLogSellResult("Period allowlist via " + source + " count=" + allowedStaticIds.Count + " sample=" + this.FormatAutoSellIdSample(allowedStaticIds, 8) + " currency=" + currencyTypeId);
                return true;
            }
            allowedStaticIds = new HashSet<int>();
            return false;
        }

        private string FormatAutoSellIdSample(HashSet<int> ids, int maxCount)
        {
            if (ids == null || ids.Count == 0)
            {
                return string.Empty;
            }

            List<int> sample = ids.Take(Mathf.Max(1, maxCount)).ToList();
            return string.Join(",", sample.ConvertAll(x => x.ToString()).ToArray());
        }

        private bool TryGetAllowedPeriodCurrencyStaticIdsFromFlatTable(int currencyTypeId, out HashSet<int> allowedStaticIds, out string source)
        {
            allowedStaticIds = new HashSet<int>();
            source = string.Empty;
            if (currencyTypeId <= 0)
            {
                return false;
            }

            if (this.TryGetAllowedPeriodCurrencyStaticIdsFromFlatTableManaged(currencyTypeId, allowedStaticIds))
            {
                source = "flatManaged";
