        private bool TrySendTransferBatch(Dictionary<uint, int> netIdToCounts, int sourceStorageType, out string error)
        {
            error = string.Empty;
            if (netIdToCounts == null || netIdToCounts.Count == 0)
            {
                error = "Nothing selected";
                return false;
            }

            if (netIdToCounts.Count > TransferBatchMaxCount)
            {
                error = "Too many stacks (max " + TransferBatchMaxCount + ")";
                return false;
            }

            int targetStorageType = this.GetTransferTargetStorageType(sourceStorageType);
            bool sent = this.TryInvokeMoveBatchBackpackItemsAuraMono(netIdToCounts, targetStorageType)
                || this.TryInvokeMoveBatchBackpackItemsManaged(netIdToCounts, targetStorageType);
            if (!sent)
            {
                error = "MoveBatchBackpackItems unavailable";
                return false;
            }

            string destLabel = targetStorageType == 2 ? "Warehouse" : "Bag";
            ModLogger.Msg("[TRANSFER] Sent " + netIdToCounts.Count + " stack(s) to " + destLabel + " (targetStorageType=" + targetStorageType + ")");
            return true;
        }

        private Dictionary<uint, int> BuildTransferItemMapForSend(out string error)
        {
            error = string.Empty;
            Dictionary<uint, int> map = new Dictionary<uint, int>();
            int sourceStorageType = this.GetTransferScanStorageType();

            if (this.transferBatch.Count > 0)
            {
                foreach (KeyValuePair<uint, int> pair in this.transferBatch)
                {
                    if (pair.Key == 0U || pair.Value <= 0)
                    {
                        continue;
                    }

                    if (!this.TryGetTransferStackCount(pair.Key, out int maxCount, out bool isLocked) || isLocked)
                    {
                        continue;
                    }

                    int qty = Mathf.Clamp(pair.Value, 1, maxCount);
                    map[pair.Key] = qty;
                }
            }
            else
            {
                TransferItemEntry selected = this.GetSelectedTransferItemEntry();
                if (selected == null || selected.NetId == 0U)
                {
                    error = "Select an item first";
                    return null;
                }

                if (selected.IsLocked)
                {
                    error = "Selected item is locked";
                    return null;
                }

                int qty = Mathf.Clamp(this.transferQty, 1, Math.Max(1, selected.Count));
                map[selected.NetId] = qty;
            }

            if (map.Count == 0)
            {
                error = "No transferable stacks";
                return null;
            }

            if (map.Count > TransferBatchMaxCount)
            {
                error = "Too many stacks (max " + TransferBatchMaxCount + ")";
                return null;
            }

            return map;
        }

        private bool TryGetTransferStackCount(uint netId, out int count, out bool isLocked)
        {
            count = 0;
            isLocked = false;
            if (this.transferItems == null)
            {
                return false;
            }

            for (int i = 0; i < this.transferItems.Count; i++)
            {
                TransferItemEntry entry = this.transferItems[i];
                if (entry != null && entry.NetId == netId)
                {
                    count = Math.Max(1, entry.Count);
                    isLocked = entry.IsLocked;
                    return true;
                }
            }

            return false;
        }

        private void ExecuteTransferItems()
        {
            Dictionary<uint, int> map = this.BuildTransferItemMapForSend(out string error);
            if (map == null)
            {
                this.transferStatus = error;
                this.AddMenuNotification(error, new Color(1f, 0.55f, 0.55f));
                return;
            }

            if (map.Count > TransferBatchMaxCount)
            {
                this.ExecuteTransferItemsChunked();
                return;
            }

            int sourceStorageType = this.GetTransferScanStorageType();
            if (!this.TrySendTransferBatch(map, sourceStorageType, out error))
            {
                this.transferStatus = error;
                this.AddMenuNotification(error, new Color(1f, 0.55f, 0.55f));
                return;
            }

            string dest = this.GetTransferTargetStorageType(sourceStorageType) == 2 ? "Warehouse" : "Bag";
            int totalQty = 0;
            foreach (int qty in map.Values)
            {
                totalQty += qty;
            }

            string successMessage = "Sent " + map.Count + " stack(s), qty " + totalQty + " -> " + dest;
            this.transferStatus = successMessage;
            this.AddMenuNotification(successMessage, new Color(0.45f, 1f, 0.55f));
            this.FinalizeTransferSend(map, successMessage);
        }

        private void ExecuteTransferItemsChunked()
        {
            Dictionary<uint, int> fullMap = this.BuildTransferItemMapForSend(out string error);
            if (fullMap == null)
            {
                this.transferStatus = error;
                this.AddMenuNotification(error, new Color(1f, 0.55f, 0.55f));
                return;
            }

            int sourceStorageType = this.GetTransferScanStorageType();
            List<uint> keys = new List<uint>(fullMap.Keys);
            int sentStacks = 0;
            int sentQty = 0;
            for (int offset = 0; offset < keys.Count; offset += TransferBatchMaxCount)
            {
                Dictionary<uint, int> chunk = new Dictionary<uint, int>();
                int end = Math.Min(keys.Count, offset + TransferBatchMaxCount);
                for (int i = offset; i < end; i++)
                {
                    uint netId = keys[i];
                    chunk[netId] = fullMap[netId];
                }

                if (!this.TrySendTransferBatch(chunk, sourceStorageType, out error))
                {
                    this.transferStatus = error + " (after " + sentStacks + " stack(s))";
                    this.AddMenuNotification(this.transferStatus, new Color(1f, 0.75f, 0.45f));
                    return;
                }

                sentStacks += chunk.Count;
                foreach (int qty in chunk.Values)
                {
                    sentQty += qty;
                }
            }

            string dest = this.GetTransferTargetStorageType(sourceStorageType) == 2 ? "Warehouse" : "Bag";
            string successMessage = "Sent " + sentStacks + " stack(s), qty " + sentQty + " -> " + dest;
            this.transferStatus = successMessage;
            this.AddMenuNotification(successMessage, new Color(0.45f, 1f, 0.55f));
            this.FinalizeTransferSend(fullMap, successMessage);
        }

        private void FinalizeTransferSend(Dictionary<uint, int> sentMap, string statusMessage)
        {
            this.ApplyOptimisticTransferToItemList(sentMap);
            this.transferBatch.Clear();
            this.transferStatus = statusMessage;
            this.ScheduleTransferListRescan();
        }

        private void ApplyOptimisticTransferToItemList(Dictionary<uint, int> sentMap)
        {
            if (this.transferItems == null || sentMap == null || sentMap.Count == 0)
            {
                return;
            }

            uint? selectedNetId = null;
            if (this.selectedTransferIndex >= 0 && this.selectedTransferIndex < this.transferItems.Count)
            {
                TransferItemEntry selected = this.transferItems[this.selectedTransferIndex];
                if (selected != null && selected.NetId != 0U)
                {
                    selectedNetId = selected.NetId;
                }
            }

            for (int i = this.transferItems.Count - 1; i >= 0; i--)
            {
                TransferItemEntry entry = this.transferItems[i];
                if (entry == null || !sentMap.TryGetValue(entry.NetId, out int sentQty) || sentQty <= 0)
                {
                    continue;
                }

                entry.Count -= sentQty;
                if (entry.Count <= 0)
                {
                    this.transferItems.RemoveAt(i);
                    this.transferBatch.Remove(entry.NetId);
                }
                else if (this.transferBatch.TryGetValue(entry.NetId, out int batchQty))
                {
                    this.transferBatch[entry.NetId] = Mathf.Min(batchQty, entry.Count);
                }
            }

            this.selectedTransferIndex = -1;
            if (selectedNetId.HasValue)
            {
                for (int i = 0; i < this.transferItems.Count; i++)
                {
                    TransferItemEntry entry = this.transferItems[i];
                    if (entry != null && entry.NetId == selectedNetId.Value)
                    {
                        this.selectedTransferIndex = i;
                        this.transferQty = Mathf.Clamp(this.transferQty, 1, Math.Max(1, entry.Count));
                        break;
                    }
                }
            }
        }

        private void ScheduleTransferListRescan()
        {
            this.transferPendingRescanAt = Time.unscaledTime + 0.35f;
            this.transferPendingRescanRetries = 6;
        }

        private void ProcessPendingTransferListRescan()
        {
            if (this.transferPendingRescanRetries <= 0)
            {
                return;
            }

            if (!this.showMenu || this.selectedTab != 6)
            {
                this.transferPendingRescanRetries = 0;
                return;
            }

            if (Time.unscaledTime < this.transferPendingRescanAt)
            {
                return;
            }

            string statusMessage = this.transferStatus;
            this.transferItems = this.ScanTransferItems(updateStatus: false);
            this.transferStatus = statusMessage;
            this.transferPendingRescanRetries--;
            this.transferPendingRescanAt = Time.unscaledTime + 0.3f;
        }

        private bool TryResolveAuraMonoBattlePassSellMethod(out IntPtr methodPtr)
        {
            methodPtr = this.autoSellMonoBattlePassSellMethod;
            if (methodPtr != IntPtr.Zero)
            {
                return true;
            }

            if (!this.EnsureAuraMonoApiReady() || !this.AttachAuraMonoThread() || auraMonoClassFromName == null)
            {
                return false;
            }

            IntPtr dataImage = this.FindAuraMonoImage(new[] { "XDTDataAndProtocol", "XDTDataAndProtocol.dll", "Client", "Client.dll" });
            IntPtr protocolClass = dataImage != IntPtr.Zero
                ? auraMonoClassFromName(dataImage, "XDTDataAndProtocol.ProtocolService.Recycle", "RecycleProtocolManager")
                : IntPtr.Zero;
            if (protocolClass == IntPtr.Zero)
            {
                protocolClass = this.FindAuraMonoClassAcrossLoadedAssemblies("XDTDataAndProtocol.ProtocolService.Recycle", "RecycleProtocolManager");
            }
            if (protocolClass == IntPtr.Zero)
            {
                return false;
            }

            methodPtr = this.FindAuraMonoMethodOnHierarchy(protocolClass, "CmdBattlePassSell", 2);
            if (methodPtr == IntPtr.Zero)
            {
                return false;
            }

            this.autoSellMonoBattlePassSellMethod = methodPtr;
            return true;
        }















        private bool IsReadableMemoryProtect(uint protect)
        {
            return protect == 0x02U || protect == 0x04U || protect == 0x08U || protect == 0x20U || protect == 0x40U;
        }









        private unsafe bool TryCreateAuraMonoUIntIntDictionary(Dictionary<uint, int> itemsToSell, out IntPtr dictObj)
        {
            dictObj = IntPtr.Zero;
            if (itemsToSell == null || itemsToSell.Count == 0)
            {
                return false;
            }

            if (!this.EnsureAuraMonoApiReady()
                || !this.AttachAuraMonoThread()
                || auraMonoStringNew == null
                || auraMonoRuntimeInvoke == null
                || auraMonoObjectGetClass == null
                || this.auraMonoTypeGetTypeMethodPtr == IntPtr.Zero
                || this.auraMonoActivatorCreateInstanceMethodPtr == IntPtr.Zero)
            {
                return false;
            }

            string[] typeCandidates = new[]
            {
                "System.Collections.Generic.Dictionary`2[System.UInt32,System.Int32]",
                "System.Collections.Generic.Dictionary`2[[System.UInt32, mscorlib],[System.Int32, mscorlib]]"
            };

            for (int i = 0; i < typeCandidates.Length && dictObj == IntPtr.Zero; i++)
            {
                IntPtr typeNameObj = auraMonoStringNew(this.auraMonoRootDomain, typeCandidates[i]);
                if (typeNameObj == IntPtr.Zero)
                {
                    continue;
                }

                IntPtr exc = IntPtr.Zero;
                IntPtr* typeArgs = stackalloc IntPtr[1];
                typeArgs[0] = typeNameObj;
                IntPtr typeObj = auraMonoRuntimeInvoke(this.auraMonoTypeGetTypeMethodPtr, IntPtr.Zero, (IntPtr)typeArgs, ref exc);
                if (exc != IntPtr.Zero || typeObj == IntPtr.Zero)
                {
                    continue;
                }

                exc = IntPtr.Zero;
                IntPtr* createArgs = stackalloc IntPtr[1];
                createArgs[0] = typeObj;
                dictObj = auraMonoRuntimeInvoke(this.auraMonoActivatorCreateInstanceMethodPtr, IntPtr.Zero, (IntPtr)createArgs, ref exc);
                if (exc != IntPtr.Zero)
                {
                    dictObj = IntPtr.Zero;
                }
            }

            if (dictObj == IntPtr.Zero)
            {
                return false;
            }

            IntPtr dictClass = this.autoSellMonoUIntIntDictionaryClass;
            if (dictClass == IntPtr.Zero)
            {
                dictClass = auraMonoObjectGetClass(dictObj);
                this.autoSellMonoUIntIntDictionaryClass = dictClass;
            }

            IntPtr setItemMethod = this.autoSellMonoUIntIntDictionarySetItemMethod;
            if (setItemMethod == IntPtr.Zero && dictClass != IntPtr.Zero)
            {
                setItemMethod = this.FindAuraMonoMethodOnHierarchy(dictClass, "set_Item", 2);
                if (setItemMethod == IntPtr.Zero)
                {
                    setItemMethod = this.FindAuraMonoMethodOnHierarchy(dictClass, "Add", 2);
                }
                this.autoSellMonoUIntIntDictionarySetItemMethod = setItemMethod;
            }
            if (setItemMethod == IntPtr.Zero)
            {
                return false;
            }

            foreach (KeyValuePair<uint, int> entry in itemsToSell)
            {
                if (entry.Key == 0U || entry.Value <= 0)
                {
                    continue;
                }

                uint netId = entry.Key;
                int count = entry.Value;
                IntPtr exc = IntPtr.Zero;
                IntPtr* setArgs = stackalloc IntPtr[2];
                setArgs[0] = (IntPtr)(&netId);
                setArgs[1] = (IntPtr)(&count);
                auraMonoRuntimeInvoke(setItemMethod, dictObj, (IntPtr)setArgs, ref exc);
                if (exc != IntPtr.Zero)
                {
                    this.AutoSellLog("AuraMono dictionary set failed for netId=" + netId + " ptr=0x" + exc.ToInt64().ToString("X"));
                    return false;
                }
            }

            return true;
        }

        private bool TryFindDirectBackpackItem(string itemKey, bool anyFood, out uint netId)
        {
            netId = 0U;
            float now = Time.unscaledTime;
            string normalizedLookupKey = (itemKey ?? string.Empty).ToLowerInvariant();
            if (now < this.nextDirectBackpackLookupRetryAt
                && anyFood == this.lastDirectBackpackLookupAnyFood
                && string.Equals(normalizedLookupKey, this.lastDirectBackpackLookupKey, StringComparison.Ordinal))
            {
                return false;
            }

            this.lastDirectBackpackMatchedNetId = 0U;
            this.lastDirectBackpackMatchedStaticId = 0;
            this.lastDirectBackpackMatchedEntityType = 0;
            this.lastDirectBackpackMatchedCount = 0;
            bool runtimeSnapshotAvailable;
            if (this.TryFindDirectBackpackItemFromRuntimeSnapshot(itemKey, anyFood, out netId, out runtimeSnapshotAvailable))
            {
                this.lastDirectBackpackLookupKey = string.Empty;
                this.nextDirectBackpackLookupRetryAt = -999f;
                return true;
            }
            if (runtimeSnapshotAvailable)
            {
                this.lastDirectBackpackLookupKey = normalizedLookupKey;
                this.lastDirectBackpackLookupAnyFood = anyFood;
                this.nextDirectBackpackLookupRetryAt = now + DirectBackpackLookupMissBackoff;
                return false;
            }

            if (this.TryFindDirectBackpackItemManaged(itemKey, anyFood, out netId))
            {
                this.lastDirectBackpackLookupKey = string.Empty;
                this.nextDirectBackpackLookupRetryAt = -999f;
                return true;
            }

            if (!DirectBackpackUnsafeAuraMonoFallbackEnabled)
            {
                this.lastDirectBackpackLookupKey = normalizedLookupKey;
                this.lastDirectBackpackLookupAnyFood = anyFood;
                this.nextDirectBackpackLookupRetryAt = now + DirectBackpackLookupMissBackoff;
                return false;
            }

            try
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Item scan start. key=" + (itemKey ?? "") + " anyFood=" + anyFood);
                if (!this.TryResolveAuraMonoModule("XDTGameSystem.GameplaySystem.BackPack.BackPackSystem", out IntPtr backPackSystemObj) || backPackSystemObj == IntPtr.Zero)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] BackPackSystem module unavailable.");
                    return false;
                }

                IntPtr backPackClass = auraMonoObjectGetClass != null ? auraMonoObjectGetClass(backPackSystemObj) : IntPtr.Zero;
                this.AutoEatRepairLog("[DirectBackpackMono] BackPackSystem resolved. class=" + this.GetAuraMonoClassDisplayName(backPackClass) + " obj=0x" + backPackSystemObj.ToString("X"));
                IntPtr getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 1);
                bool getAllItemNeedsStorageType = true;
                if (getAllItemMethod == IntPtr.Zero)
                {
                    getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 0);
                    getAllItemNeedsStorageType = false;
                }
                this.AutoEatRepairLog("[DirectBackpackMono] GetAllItem lookup. method=0x" + getAllItemMethod.ToString("X") + " needsStorage=" + getAllItemNeedsStorageType);
                if (getAllItemMethod == IntPtr.Zero || auraMonoRuntimeInvoke == null)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] BackPackSystem.GetAllItem not found.");
                    return false;
                }

                IntPtr exc = IntPtr.Zero;
                int storageTypeBackpack = 1;
                IntPtr itemListObj;
                unsafe
                {
                    IntPtr* args = stackalloc IntPtr[1];
                    args[0] = (IntPtr)(&storageTypeBackpack);
                    itemListObj = auraMonoRuntimeInvoke(getAllItemMethod, backPackSystemObj, getAllItemNeedsStorageType ? (IntPtr)args : IntPtr.Zero, ref exc);
                }
                if (exc != IntPtr.Zero || itemListObj == IntPtr.Zero)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] GetAllItem invocation failed.");
                    return false;
                }

                List<IntPtr> items = new List<IntPtr>();
                if (!this.TryEnumerateAuraMonoCollectionItems(itemListObj, items) || items.Count == 0)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] Backpack item list empty/unreadable.");
                    return false;
                }
                this.AutoEatRepairLog("[DirectBackpackMono] Backpack item list read. count=" + items.Count);

                string normalizedKey = normalizedLookupKey;
                int inspected = 0;
                int sampleCount = 0;
                foreach (IntPtr itemObj in items)
                {
                    if (itemObj == IntPtr.Zero)
                    {
                        continue;
                    }

                    inspected++;
                    if (!this.TryGetDirectBackpackItemNetId(itemObj, out uint candidateNetId) || candidateNetId == 0U)
                    {
                        continue;
                    }

                    string descriptor = this.GetDirectBackpackItemDescriptor(itemObj).ToLowerInvariant();
                    if (string.IsNullOrEmpty(descriptor))
                    {
                        continue;
                    }
                    if (sampleCount < 6)
                    {
                        sampleCount++;
                        this.AutoEatRepairLog("[DirectBackpackMono] Item sample " + sampleCount + ": netId=" + candidateNetId + " descriptor=" + descriptor);
                    }

                    bool matches = anyFood
                        ? (descriptor.Contains("food_") || descriptor.Contains("p_food") || descriptor.Contains("ui_item_normal_p_food"))
                        : (!string.IsNullOrEmpty(normalizedKey) && descriptor.Contains(normalizedKey));

                    if (matches)
                    {
                        netId = candidateNetId;
                        this.lastDirectBackpackMatchedNetId = netId;
                        this.TryGetDirectBackpackItemStaticId(itemObj, out this.lastDirectBackpackMatchedStaticId);
                        this.TryGetDirectBackpackItemEntityType(itemObj, out this.lastDirectBackpackMatchedEntityType);
                        this.TryGetDirectBackpackItemCount(itemObj, out this.lastDirectBackpackMatchedCount);
                        this.AutoEatRepairLog("[DirectBackpackMono] Matched item netId=" + netId + " staticId=" + this.lastDirectBackpackMatchedStaticId + " entityType=" + this.lastDirectBackpackMatchedEntityType + " count=" + this.lastDirectBackpackMatchedCount + " descriptor=" + descriptor);
                        this.lastDirectBackpackLookupKey = string.Empty;
                        this.nextDirectBackpackLookupRetryAt = -999f;
                        return true;
                    }
                }

                this.AutoEatRepairLog("[DirectBackpackMono] No match. inspected=" + inspected + " key=" + normalizedKey);
            }
            catch (Exception ex)
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Item scan exception: " + ex.Message);
            }

            this.lastDirectBackpackLookupKey = normalizedLookupKey;
            this.lastDirectBackpackLookupAnyFood = anyFood;
            this.nextDirectBackpackLookupRetryAt = now + DirectBackpackLookupMissBackoff;
            return false;
        }

        private bool TryFindDirectBackpackItemFromRuntimeSnapshot(string itemKey, bool anyFood, out uint netId, out bool snapshotAvailable)
        {
            netId = 0U;
            snapshotAvailable = false;
            if (!this.TryRefreshDirectBackpackRuntimeSnapshot(false))
            {
                return false;
            }
            snapshotAvailable = true;

            string normalizedKey = (itemKey ?? string.Empty).ToLowerInvariant();
            for (int i = 0; i < this.directBackpackRuntimeItems.Count; i++)
            {
                DirectBackpackRuntimeItem item = this.directBackpackRuntimeItems[i];
                if (item == null || item.NetId == 0U)
                {
                    continue;
                }

                string descriptor = item.Descriptor ?? string.Empty;
                bool matches = anyFood
                    ? (descriptor.Contains("food_") || descriptor.Contains("p_food") || descriptor.Contains("ui_item_normal_p_food"))
                    : (!string.IsNullOrEmpty(normalizedKey) && descriptor.Contains(normalizedKey));

                if (!matches)
                {
                    continue;
                }

                netId = item.NetId;
                this.lastDirectBackpackMatchedNetId = item.NetId;
                this.lastDirectBackpackMatchedStaticId = item.StaticId;
                this.lastDirectBackpackMatchedEntityType = item.EntityType;
                this.lastDirectBackpackMatchedCount = item.Count;
                this.AutoEatRepairLog("[DirectBackpackRuntime] Matched item netId=" + item.NetId + " staticId=" + item.StaticId + " entityType=" + item.EntityType + " count=" + item.Count + " source=" + this.directBackpackRuntimeSnapshotSource + " descriptor=" + descriptor);
                return true;
            }

            return false;
        }

        private bool TryRefreshDirectBackpackRuntimeSnapshot(bool forceRefresh)
        {
            float now = Time.unscaledTime;
            if (!forceRefresh && now < this.nextDirectBackpackSnapshotRetryAt)
            {
                return false;
            }
            float snapshotTtl = this.IsBagAutomationActiveOrQueued()
                ? BusyDirectBackpackRuntimeSnapshotTtl
                : DirectBackpackRuntimeSnapshotTtl;
            if (!forceRefresh
                && this.directBackpackRuntimeItems.Count > 0
                && now - this.directBackpackRuntimeSnapshotAt <= snapshotTtl)
            {
                return true;
            }

            this.directBackpackRuntimeItems.Clear();
            this.directBackpackRuntimeSnapshotSource = "";
            if (this.TryBuildDirectBackpackRuntimeSnapshotManaged())
            {
                this.directBackpackRuntimeSnapshotAt = now;
                this.directBackpackRuntimeSnapshotSource = "managed";
                this.nextDirectBackpackSnapshotRetryAt = -999f;
                return true;
            }

            this.directBackpackRuntimeItems.Clear();
            if (DirectBackpackUnsafeAuraMonoFallbackEnabled && this.TryBuildDirectBackpackRuntimeSnapshotAuraMono())
            {
                this.directBackpackRuntimeSnapshotAt = now;
                this.directBackpackRuntimeSnapshotSource = "auraMono";
                this.nextDirectBackpackSnapshotRetryAt = -999f;
                return true;
            }

            this.directBackpackRuntimeSnapshotAt = -999f;
            this.nextDirectBackpackSnapshotRetryAt = now + DirectBackpackSnapshotFailureBackoff;
            return false;
        }

        private bool TryBuildDirectBackpackRuntimeSnapshotManaged()
        {
            try
            {
                if (!this.TryGetDirectBackpackSystem(out object backPackObj, out MethodInfo getAllItem, out Type storageType, out bool getAllItemNeedsStorage))
                {
                    return false;
                }

                object backpackStorage = storageType != null && storageType.IsEnum ? Enum.ToObject(storageType, 1) : (object)1;
                object itemListObj = getAllItemNeedsStorage
                    ? getAllItem.Invoke(backPackObj, new[] { backpackStorage })
                    : getAllItem.Invoke(backPackObj, null);

                IEnumerable items = itemListObj as IEnumerable;
                if (items == null)
                {
                    return false;
                }

                foreach (object item in items)
                {
                    if (item == null)
                    {
                        continue;
                    }

                    if (!this.TryGetManagedUInt32Member(item, "netId", out uint itemNetId) || itemNetId == 0U)
                    {
                        continue;
                    }

                    DirectBackpackRuntimeItem entry = new DirectBackpackRuntimeItem
                    {
                        NetId = itemNetId,
                        Descriptor = this.GetManagedBackpackItemDescriptor(item).ToLowerInvariant(),
                        ManagedItem = item
                    };
                    this.TryGetManagedInt32Member(item, "staticId", out entry.StaticId);
                    this.TryGetManagedInt32Member(item, "entityType", out entry.EntityType);
                    this.TryGetManagedBackpackItemCount(item, out entry.Count);
                    this.directBackpackRuntimeItems.Add(entry);
                }

                return this.directBackpackRuntimeItems.Count > 0;
            }
            catch
            {
                return false;
            }
        }

        private bool TryBuildDirectBackpackRuntimeSnapshotAuraMono()
        {
            try
            {
                this.AutoEatRepairLog("[DirectBackpackRuntime] AuraMono snapshot start.");
                if (!this.TryResolveAuraMonoModule("XDTGameSystem.GameplaySystem.BackPack.BackPackSystem", out IntPtr backPackSystemObj) || backPackSystemObj == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr backPackClass = auraMonoObjectGetClass != null ? auraMonoObjectGetClass(backPackSystemObj) : IntPtr.Zero;
                IntPtr getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 1);
                bool getAllItemNeedsStorageType = true;
                if (getAllItemMethod == IntPtr.Zero)
                {
                    getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 0);
                    getAllItemNeedsStorageType = false;
                }
                if (getAllItemMethod == IntPtr.Zero || auraMonoRuntimeInvoke == null)
                {
                    return false;
                }

                IntPtr exc = IntPtr.Zero;
                int storageTypeBackpack = 1;
                IntPtr itemListObj;
                unsafe
                {
                    IntPtr* args = stackalloc IntPtr[1];
                    args[0] = (IntPtr)(&storageTypeBackpack);
                    itemListObj = auraMonoRuntimeInvoke(getAllItemMethod, backPackSystemObj, getAllItemNeedsStorageType ? (IntPtr)args : IntPtr.Zero, ref exc);
                }
                if (exc != IntPtr.Zero || itemListObj == IntPtr.Zero)
                {
                    return false;
                }

                List<IntPtr> items = new List<IntPtr>();
                if (!this.TryEnumerateAuraMonoCollectionItems(itemListObj, items) || items.Count == 0)
                {
                    return false;
                }

                foreach (IntPtr itemObj in items)
                {
                    if (itemObj == IntPtr.Zero)
                    {
                        continue;
                    }

                    if (!this.TryGetDirectBackpackItemNetId(itemObj, out uint itemNetId) || itemNetId == 0U)
                    {
                        continue;
                    }

                    DirectBackpackRuntimeItem entry = new DirectBackpackRuntimeItem
                    {
                        NetId = itemNetId,
                        Descriptor = this.GetDirectBackpackItemDescriptor(itemObj).ToLowerInvariant(),
                        MonoItem = itemObj
                    };
                    this.TryGetDirectBackpackItemStaticId(itemObj, out entry.StaticId);
                    this.TryGetDirectBackpackItemEntityType(itemObj, out entry.EntityType);
                    this.TryGetDirectBackpackItemCount(itemObj, out entry.Count);
                    this.directBackpackRuntimeItems.Add(entry);
                }

                return this.directBackpackRuntimeItems.Count > 0;
            }
            catch
            {
                return false;
            }
        }

