                IntPtr protocolClass = dataImage != IntPtr.Zero ? auraMonoClassFromName(dataImage, "XDTDataAndProtocol.ProtocolService.BackPack", "BackpackProtocolManager") : IntPtr.Zero;
                if (protocolClass == IntPtr.Zero)
