        private bool TryGetManagedBackpackItemStarRate(object item, out int starRate)
        {
            return this.TryGetManagedBackpackItemStarRate(item, out starRate, 0);
        }

        private bool TryGetManagedBackpackItemStarRate(object item, out int starRate, int depth)
        {
            starRate = 0;
            if (item == null || depth > 3)
            {
                return false;
            }

            if (this.TryInvokeZeroArgMember(item, out object runtimeStarObj, "get_starRate", "GetStarRate") && runtimeStarObj != null)
            {
                try
                {
                    starRate = this.NormalizeAutoSellStarRate(Convert.ToInt32(runtimeStarObj));
                    return true;
                }
                catch
                {
                }
            }

            string[] intMembers = { "starRate", "_starRate", "StarRate", "star", "_star", "Star", "quality", "_quality", "Quality" };
            foreach (string member in intMembers)
            {
                if (this.TryGetManagedInt32Member(item, member, out int rawStar))
                {
                    starRate = this.NormalizeAutoSellStarRate(rawStar);
                    return true;
                }
            }

            string[] nestedMembers = { "packItem", "_packItem", "item", "_item", "itemData", "_itemData", "baseData", "_baseData", "bagData", "_bagData", "PetFoodItem", "petFoodItem" };
            foreach (string member in nestedMembers)
            {
                if (this.TryGetObjectMember(item, member, out object nested) && nested != null && !object.ReferenceEquals(nested, item))
                {
                    if (this.TryGetManagedBackpackItemStarRate(nested, out starRate, depth + 1))
                    {
                        return true;
                    }
                }
            }

            MethodInfo getItem = item.GetType().GetMethod("GetItem", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, Type.EmptyTypes, null);
            if (getItem != null)
            {
                try
                {
                    object nested = getItem.Invoke(item, null);
                    if (nested != null && this.TryGetManagedBackpackItemStarRate(nested, out starRate, depth + 1))
                    {
                        return true;
                    }
                }
                catch { }
            }

            MethodInfo getItems = item.GetType().GetMethod("GetItems", BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance, null, Type.EmptyTypes, null);
            if (getItems != null)
            {
                try
                {
                    if (getItems.Invoke(item, null) is IEnumerable nestedItems)
                    {
                        foreach (object nested in nestedItems)
                        {
                            if (this.TryGetManagedBackpackItemStarRate(nested, out starRate, depth + 1))
                            {
                                return true;
                            }
                        }
                    }
                }
                catch { }
            }

            return false;
        }

        private string GetManagedBackpackItemPhotoId(object item)
        {
            if (item == null)
            {
                return string.Empty;
            }

            string[] members = { "photoId", "_photoId", "PhotoId", "serverPhotoId", "_serverPhotoId", "ServerPhotoId" };
            foreach (string member in members)
            {
                if (this.TryGetObjectMember(item, member, out object raw) && raw != null)
                {
                    string value = raw.ToString();
                    if (!string.IsNullOrWhiteSpace(value))
                    {
                        return value;
                    }
                }
            }

            string[] nestedMembers = { "packItem", "_packItem", "item", "_item", "itemData", "_itemData", "baseData", "_baseData", "bagData", "_bagData" };
            foreach (string member in nestedMembers)
            {
                if (this.TryGetObjectMember(item, member, out object nested) && nested != null && !object.ReferenceEquals(nested, item))
                {
                    foreach (string nestedMember in members)
                    {
                        if (this.TryGetObjectMember(nested, nestedMember, out object raw) && raw != null)
                        {
                            string value = raw.ToString();
                            if (!string.IsNullOrWhiteSpace(value))
                            {
                                return value;
                            }
                        }
                    }
                }
            }

            return string.Empty;
        }

        private string GetManagedBackpackItemDescriptor(object item)
        {
            string[] members = { "icon", "_icon", "Icon", "iconName", "itemIcon", "name", "_name", "itemName", "templateId", "id", "staticId", "description" };
            List<string> parts = new List<string>();
            foreach (string member in members)
            {
                if (this.TryGetObjectMember(item, member, out object value) && value != null)
                {
                    string text = value.ToString();
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        parts.Add(text);
                    }
                }
            }

            return string.Join(" ", parts);
        }

        private bool TryResolveAuraMonoModule(string fullTypeName, out IntPtr moduleObj)
        {
            moduleObj = IntPtr.Zero;
            try
            {
                if (!this.EnsureAuraMonoApiReady() || !this.AttachAuraMonoThread() || auraMonoObjectGetClass == null || auraMonoRuntimeInvoke == null)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] Mono API not ready.");
                    return false;
                }

                IntPtr classPtr = this.FindAuraMonoClassByFullName(fullTypeName);
                this.DirectBackpackVerboseLog("[DirectBackpackMono] Resolve module " + fullTypeName + ". class=0x" + classPtr.ToString("X"));
                if (classPtr != IntPtr.Zero)
                {
                    foreach (string getterName in new[] { "get_Instance", "get_instance", "Instance", "GetInstance" })
                    {
                        IntPtr getter = this.FindAuraMonoMethodOnHierarchy(classPtr, getterName, 0);
                        if (getter == IntPtr.Zero)
                        {
                            continue;
                        }

                        IntPtr exc = IntPtr.Zero;
                        moduleObj = auraMonoRuntimeInvoke(getter, IntPtr.Zero, IntPtr.Zero, ref exc);
                        if (exc == IntPtr.Zero && moduleObj != IntPtr.Zero)
                        {
                            this.DirectBackpackVerboseLog("[DirectBackpackMono] Resolved " + fullTypeName + " via " + getterName + ".");
                            return true;
                        }
                    }

                    foreach (string fieldName in new[] { "Instance", "instance", "_instance", "_manager", "manager" })
                    {
                        if (this.TryGetAuraMonoStaticObjectField(classPtr, fieldName, out moduleObj) && moduleObj != IntPtr.Zero)
                        {
                            this.DirectBackpackVerboseLog("[DirectBackpackMono] Resolved " + fullTypeName + " via static field " + fieldName + ".");
                            return true;
                        }
                    }
                }

                return this.TryResolveAuraMonoModuleFromManagers(fullTypeName, out moduleObj);
            }
            catch (Exception ex)
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Module resolve error for " + fullTypeName + ": " + ex.Message);
                moduleObj = IntPtr.Zero;
                return false;
            }
        }

        private bool TryResolveAuraMonoModuleFromManagers(string fullTypeName, out IntPtr moduleObj)
        {
            moduleObj = IntPtr.Zero;
            IntPtr managersClass = IntPtr.Zero;
            foreach (string managerTypeName in new[]
            {
                "Managers",
                "XDTGame.Framework.Managers",
                "XDTGame.Core.Managers",
                "XDFramework.Core.Managers",
                "XDTLevelAndEntity.Managers",
                "XDTLevelAndEntity.Core.Managers"
            })
            {
                managersClass = this.FindAuraMonoClassByFullName(managerTypeName);
                if (managersClass != IntPtr.Zero)
                {
                    this.DirectBackpackVerboseLog("[DirectBackpackMono] Managers class resolved as " + managerTypeName + ".");
                    break;
                }
            }
            if (managersClass == IntPtr.Zero)
            {
                managersClass = this.FindAuraMonoClassAcrossLoadedAssemblies(string.Empty, "Managers");
                if (managersClass != IntPtr.Zero)
                {
                    this.DirectBackpackVerboseLog("[DirectBackpackMono] Managers class resolved by loaded assembly sweep.");
                }
            }
            if (managersClass == IntPtr.Zero)
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Managers class unavailable.");
                return false;
            }

            if (this.TryResolveAuraMonoModuleViaManagersGetModule(managersClass, fullTypeName, out moduleObj) && moduleObj != IntPtr.Zero)
            {
                return true;
            }

            IntPtr moduleDicObj = IntPtr.Zero;
            foreach (string fieldName in new[] { "_moduleDic", "moduleDic", "s_moduleDic", "_modules", "modules" })
            {
                if (this.TryGetAuraMonoStaticObjectField(managersClass, fieldName, out moduleDicObj) && moduleDicObj != IntPtr.Zero)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] Managers module dictionary resolved via field " + fieldName + ".");
                    break;
                }
            }
            if (moduleDicObj == IntPtr.Zero)
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Managers._moduleDic unavailable for " + fullTypeName);
                return false;
            }

            if (!this.TryGetMonoObjectMember(moduleDicObj, "Values", out IntPtr valuesObj) || valuesObj == IntPtr.Zero)
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Managers._moduleDic.Values unavailable for " + fullTypeName);
                return false;
            }

            List<IntPtr> modules = new List<IntPtr>();
            if (!this.TryEnumerateAuraMonoCollectionItems(valuesObj, modules) || modules.Count == 0)
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Managers._moduleDic empty/unreadable for " + fullTypeName);
                return false;
            }
            this.DirectBackpackVerboseLog("[DirectBackpackMono] Managers modules read. count=" + modules.Count + " target=" + fullTypeName);

            string typeName = fullTypeName.Split('.').Last();
            foreach (IntPtr candidate in modules)
            {
                if (candidate == IntPtr.Zero)
                {
                    continue;
                }

                string className = this.GetAuraMonoClassDisplayName(auraMonoObjectGetClass(candidate));
                if (!string.IsNullOrEmpty(className) && className.EndsWith(typeName, StringComparison.OrdinalIgnoreCase))
                {
                    moduleObj = candidate;
                    this.DirectBackpackVerboseLog("[DirectBackpackMono] Module matched in Managers: " + className);
                    return true;
                }
            }

            this.AutoEatRepairLog("[DirectBackpackMono] Module not found in Managers._moduleDic for " + fullTypeName);
            return false;
        }

        private unsafe bool TryResolveAuraMonoModuleViaManagersGetModule(IntPtr managersClass, string fullTypeName, out IntPtr moduleObj)
        {
            moduleObj = IntPtr.Zero;
            try
            {
                this.ResolveAuraFarmRuntimeMethodsViaMono();
                if (managersClass == IntPtr.Zero || string.IsNullOrWhiteSpace(fullTypeName) || auraMonoRuntimeInvoke == null)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] Managers.GetModule(Type) prerequisites missing. managers=0x" + managersClass.ToString("X") + " runtimeInvoke=" + (auraMonoRuntimeInvoke != null) + " stringNew=" + (auraMonoStringNew != null) + " typeGet=0x" + this.auraMonoTypeGetTypeMethodPtr.ToString("X"));
                    return false;
                }

                IntPtr getModuleMethod = this.FindAuraMonoMethodOnHierarchy(managersClass, "GetModule", 1);
                if (getModuleMethod == IntPtr.Zero)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] Managers.GetModule(Type) unavailable.");
                    return false;
                }

                if (!this.TryCreateAuraMonoSystemTypeObject(fullTypeName, out IntPtr typeObj) || typeObj == IntPtr.Zero)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] System.Type object unavailable for " + fullTypeName);
                    return false;
                }

                IntPtr* args = stackalloc IntPtr[1];
                args[0] = typeObj;
                IntPtr exc = IntPtr.Zero;
                moduleObj = auraMonoRuntimeInvoke(getModuleMethod, IntPtr.Zero, (IntPtr)args, ref exc);
                if (exc != IntPtr.Zero || moduleObj == IntPtr.Zero)
                {
                    this.AutoEatRepairLog("[DirectBackpackMono] Managers.GetModule(Type) returned null for " + fullTypeName);
                    moduleObj = IntPtr.Zero;
                    return false;
                }

                this.DirectBackpackVerboseLog("[DirectBackpackMono] Resolved " + fullTypeName + " via Managers.GetModule(Type).");
                return true;
            }
            catch (Exception ex)
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Managers.GetModule(Type) exception for " + fullTypeName + ": " + ex.Message);
                moduleObj = IntPtr.Zero;
                return false;
            }
        }

        private unsafe bool TryCreateAuraMonoSystemTypeObject(string fullTypeName, out IntPtr typeObj)
        {
            typeObj = IntPtr.Zero;
            if (string.IsNullOrWhiteSpace(fullTypeName))
            {
                return false;
            }

            if (this.TryCreateAuraMonoSystemTypeObjectFromClass(fullTypeName, out typeObj) && typeObj != IntPtr.Zero)
            {
                return true;
            }

            if (auraMonoRuntimeInvoke == null || auraMonoStringNew == null || this.auraMonoTypeGetTypeMethodPtr == IntPtr.Zero)
            {
                return false;
            }

            foreach (string candidate in this.GetAuraMonoTypeNameCandidates(fullTypeName))
            {
                IntPtr typeNameObj = IntPtr.Zero;
                try
                {
                    typeNameObj = auraMonoStringNew(this.auraMonoRootDomain, candidate);
                    if (typeNameObj == IntPtr.Zero)
                    {
                        continue;
                    }

                    IntPtr* args = stackalloc IntPtr[1];
                    args[0] = typeNameObj;
                    IntPtr exc = IntPtr.Zero;
                    IntPtr candidateTypeObj = auraMonoRuntimeInvoke(this.auraMonoTypeGetTypeMethodPtr, IntPtr.Zero, (IntPtr)args, ref exc);
                    if (exc == IntPtr.Zero && candidateTypeObj != IntPtr.Zero)
                    {
                        typeObj = candidateTypeObj;
                        this.DirectBackpackVerboseLog("[DirectBackpackMono] Type object resolved: " + candidate);
                        return true;
                    }
                }
                catch
                {
                }
            }

            return false;
        }

        private bool TryCreateAuraMonoSystemTypeObjectFromClass(string fullTypeName, out IntPtr typeObj)
        {
            typeObj = IntPtr.Zero;
            try
            {
                if (auraMonoClassGetType == null || auraMonoTypeGetObject == null || this.auraMonoRootDomain == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr classPtr = this.FindAuraMonoClassByFullName(fullTypeName);
                if (classPtr == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr monoType = auraMonoClassGetType(classPtr);
                if (monoType == IntPtr.Zero)
                {
                    return false;
                }

                typeObj = auraMonoTypeGetObject(this.auraMonoRootDomain, monoType);
                if (typeObj == IntPtr.Zero)
                {
                    return false;
                }

                this.DirectBackpackVerboseLog("[DirectBackpackMono] Type object resolved from class " + fullTypeName + ".");
                return true;
            }
            catch (Exception ex)
            {
                this.AutoEatRepairLog("[DirectBackpackMono] Type object class conversion failed for " + fullTypeName + ": " + ex.Message);
                typeObj = IntPtr.Zero;
                return false;
            }
        }

        private IEnumerable<string> GetAuraMonoTypeNameCandidates(string fullTypeName)
        {
            yield return fullTypeName;

            string[] assemblies;
            if (fullTypeName.StartsWith("XDTGameSystem.", StringComparison.Ordinal))
            {
                assemblies = new[] { "XDTGameSystem", "XDTGameSystem.dll", "Client", "Client.dll" };
            }
            else if (fullTypeName.StartsWith("XDTGame.UI.", StringComparison.Ordinal))
            {
                assemblies = new[] { "XDTGameUI", "XDTGameUI.dll", "XDTLevelAndEntity", "XDTLevelAndEntity.dll", "Client", "Client.dll" };
            }
            else if (fullTypeName.StartsWith("XDTLevelAndEntity.", StringComparison.Ordinal))
            {
                assemblies = new[] { "XDTLevelAndEntity", "XDTLevelAndEntity.dll", "Client", "Client.dll" };
            }
            else if (fullTypeName.StartsWith("XDTGame.Framework.", StringComparison.Ordinal) || fullTypeName.StartsWith("XDTGame.Core.", StringComparison.Ordinal))
            {
                assemblies = new[] { "XDTBaseService", "XDTBaseService.dll", "XDTLevelAndEntity", "XDTLevelAndEntity.dll", "Client", "Client.dll" };
            }
            else if (fullTypeName.StartsWith("EcsClient.", StringComparison.Ordinal))
            {
                assemblies = new[] { "EcsClient", "EcsClient.dll", "XDTDataAndProtocol", "XDTDataAndProtocol.dll" };
            }
            else if (fullTypeName.StartsWith("XDT.Scene.", StringComparison.Ordinal))
            {
                assemblies = new[] { "EcsClient", "EcsClient.dll", "Client", "Client.dll", "Assembly-CSharp", "Assembly-CSharp.dll" };
            }
            else
            {
                assemblies = new[] { "XDTLevelAndEntity", "XDTLevelAndEntity.dll", "XDTGameSystem", "XDTGameSystem.dll", "XDTBaseService", "XDTBaseService.dll", "EcsClient", "EcsClient.dll", "Client", "Client.dll" };
            }

            foreach (string assembly in assemblies)
            {
                yield return fullTypeName + ", " + assembly;
            }
        }

        private IntPtr FindAuraMonoClassByFullName(string fullTypeName)
        {
            if (string.IsNullOrWhiteSpace(fullTypeName))
            {
                return IntPtr.Zero;
            }

            int lastDot = fullTypeName.LastIndexOf('.');
            string ns = lastDot > 0 ? fullTypeName.Substring(0, lastDot) : string.Empty;
            string name = lastDot > 0 ? fullTypeName.Substring(lastDot + 1) : fullTypeName;
            IntPtr directClass = this.FindAuraMonoClassInLikelyImages(ns, name);
            if (directClass != IntPtr.Zero)
            {
                return directClass;
            }

            return this.FindAuraMonoClassAcrossLoadedAssemblies(ns, name);
        }

        private IntPtr FindAuraMonoClassInLikelyImages(string nameSpace, string className)
        {
            if (string.IsNullOrWhiteSpace(className) || auraMonoClassFromName == null)
            {
                return IntPtr.Zero;
            }

            string[] imageNames;
            if (!string.IsNullOrEmpty(nameSpace) && nameSpace.StartsWith("XDTGameSystem", StringComparison.Ordinal))
            {
                imageNames = new[] { "XDTGameSystem", "XDTGameSystem.dll", "Client", "Client.dll", "Assembly-CSharp", "Assembly-CSharp.dll" };
            }
            else if (!string.IsNullOrEmpty(nameSpace) && nameSpace.StartsWith("XDTGame.UI", StringComparison.Ordinal))
            {
                imageNames = new[] { "XDTGameUI", "XDTGameUI.dll", "XDTLevelAndEntity", "XDTLevelAndEntity.dll", "Client", "Client.dll", "Assembly-CSharp", "Assembly-CSharp.dll" };
            }
            else if (!string.IsNullOrEmpty(nameSpace) && nameSpace.StartsWith("XDTLevelAndEntity", StringComparison.Ordinal))
            {
                imageNames = new[] { "XDTLevelAndEntity", "XDTLevelAndEntity.dll", "Client", "Client.dll", "Assembly-CSharp", "Assembly-CSharp.dll" };
            }
            else if (!string.IsNullOrEmpty(nameSpace) && (nameSpace.StartsWith("XDTGame.Framework", StringComparison.Ordinal) || nameSpace.StartsWith("XDTGame.Core", StringComparison.Ordinal)))
            {
                imageNames = new[] { "XDTBaseService", "XDTBaseService.dll", "XDTLevelAndEntity", "XDTLevelAndEntity.dll", "Client", "Client.dll" };
            }
            else if (!string.IsNullOrEmpty(nameSpace) && nameSpace.StartsWith("XDFramework", StringComparison.Ordinal))
            {
                imageNames = new[] { "XDTBaseService", "XDTBaseService.dll", "XDFramework", "XDFramework.dll", "Client", "Client.dll" };
            }
            else if (!string.IsNullOrEmpty(nameSpace) && nameSpace.StartsWith("EcsClient", StringComparison.Ordinal))
            {
                imageNames = new[] { "EcsClient", "EcsClient.dll", "XDTDataAndProtocol", "XDTDataAndProtocol.dll" };
            }
            else if (!string.IsNullOrEmpty(nameSpace) && nameSpace.StartsWith("XDT.Scene.", StringComparison.Ordinal))
            {
                imageNames = new[] { "EcsClient", "EcsClient.dll", "Client", "Client.dll", "Assembly-CSharp", "Assembly-CSharp.dll" };
            }
            else if (!string.IsNullOrEmpty(nameSpace) && nameSpace.StartsWith("XDTDataAndProtocol", StringComparison.Ordinal))
            {
                imageNames = new[] { "XDTDataAndProtocol", "XDTDataAndProtocol.dll", "Client", "Client.dll" };
            }
            else if (!string.IsNullOrEmpty(nameSpace) && nameSpace.StartsWith("ClientSystem", StringComparison.Ordinal))
            {
                imageNames = new[] { "EcsSystem", "EcsSystem.dll", "Client", "Client.dll", "XDTDataAndProtocol", "XDTDataAndProtocol.dll" };
            }
            else
            {
                imageNames = new[]
                {
                    "XDTGameUI", "XDTGameUI.dll",
                    "XDTGameSystem", "XDTGameSystem.dll",
                    "XDTLevelAndEntity", "XDTLevelAndEntity.dll",
                    "XDTBaseService", "XDTBaseService.dll",
                    "XDTDataAndProtocol", "XDTDataAndProtocol.dll",
                    "EcsClient", "EcsClient.dll",
                    "Client", "Client.dll",
                    "Assembly-CSharp", "Assembly-CSharp.dll"
                };
            }

            IntPtr image = this.FindAuraMonoImage(imageNames);
            if (image == IntPtr.Zero)
            {
                return IntPtr.Zero;
            }

            try
            {
                return auraMonoClassFromName(image, nameSpace ?? string.Empty, className);
            }
            catch
            {
                return IntPtr.Zero;
            }
        }

        private IntPtr FindAuraMonoClassInImages(string nameSpace, string className, string[] imageNames)
        {
            if (string.IsNullOrWhiteSpace(className) || auraMonoClassFromName == null || imageNames == null)
            {
                return IntPtr.Zero;
            }

            for (int i = 0; i < imageNames.Length; i++)
            {
                string imageName = imageNames[i];
                if (string.IsNullOrWhiteSpace(imageName))
                {
                    continue;
                }

                IntPtr image = this.FindAuraMonoImage(new string[] { imageName });
                if (image == IntPtr.Zero)
                {
                    continue;
                }

                try
                {
                    IntPtr classPtr = auraMonoClassFromName(image, nameSpace ?? string.Empty, className);
                    if (classPtr != IntPtr.Zero)
                    {
                        return classPtr;
                    }
                }
                catch
                {
                }
            }

            return IntPtr.Zero;
        }

        // Returns Images scoped to the open bag panel - avoids scene-wide FindObjectsOfType allocation
        private Image[] GetBagPanelImages()
        {
            GameObject bag = GameObject.Find(BAG_PANEL_PATH);
            if (bag == null || !bag.activeInHierarchy) return System.Array.Empty<Image>();
            return bag.GetComponentsInChildren<Image>(true);
        }

        // Check if bag panel is currently open
        private bool IsBagOpen()
        {
            GameObject bag = GameObject.Find(BAG_PANEL_PATH);
            return bag != null && bag.activeInHierarchy;
        }

        // Check if user clicked on a food item in bag during pick mode
        // This detects clicks by checking for the Use/Eat button appearing
        private void CheckForBagFoodClick()
        {
            if (!IsBagOpen() || !this.customFoodPickMode) return;

            // Check if there's a selected item - look for the selection indicator
            GameObject selectedIndicator = GameObject.Find(SELECTED_ITEM_PATH);
            if (selectedIndicator != null && selectedIndicator.activeInHierarchy)
            {
                // A food item was clicked - find the food closest to selection indicator
                string clickedFood = this.GetSelectedFoodFromSelectionIndicator();
                if (!string.IsNullOrEmpty(clickedFood))
                {
                    this.lastClickedBagFood = clickedFood;
                    this.AddMenuNotification(this.LF("Detected food click: {0}", this.GetFoodDisplayName(clickedFood)), new Color(0.45f, 1f, 0.55f));
                    // Close the bag to complete the selection
                    this.CloseInventory();
                }
            }
        }

        // Get the sprite name of the currently selected food item using the selection indicator position
        private string GetSelectedFoodFromSelectionIndicator()
        {
            // Get the selection indicator GameObject
            GameObject selectedIndicator = GameObject.Find(SELECTED_ITEM_PATH);
            if (selectedIndicator == null || !selectedIndicator.activeInHierarchy) return "";

            // Get the position of the selection indicator
            Vector3 indicatorPos = selectedIndicator.transform.position;

            // Find the Image component closest to the selection indicator position
            Image closestFoodImage = null;
            float closestDistance = float.MaxValue;

            foreach (Image img in GetBagPanelImages())
            {
                if (img != null && img.sprite != null && img.gameObject.activeInHierarchy)
                {
                    string spriteName = img.sprite.name.ToLowerInvariant();
                    // Check if it's a food item sprite
                    if (spriteName.StartsWith("ui_item_normal_p_"))
                    {
                        string itemName = spriteName.Substring("ui_item_normal_p_".Length);
                        // Check if it's a food item by keywords
                        string[] foodKeywords = new[] { "food", "bread", "jam", "mushroom", "salad", "soup", "stew", "pie", "cake", "fish", "meat", "fruit", "vegetable", "berry", "apple", "cheese", "egg", "milk", "honey", "candy", "snack", "meal", "dish", "blue", "rasp", "mix", "bake" };
                        if (foodKeywords.Any(k => itemName.Contains(k)))
                        {
                            // Calculate distance to selection indicator
                            float distance = Vector3.Distance(img.transform.position, indicatorPos);
                            if (distance < closestDistance)
                            {
                                closestDistance = distance;
                                closestFoodImage = img;
                            }
                        }
                    }
                }
            }

            if (closestFoodImage != null && closestDistance < 100f) // Within reasonable UI distance
            {
                return closestFoodImage.sprite.name.ToLowerInvariant();
            }

            return "";
        }

        // Scan bag for all food items (sprites starting with "ui_item_normal_p_" and containing food keywords, or gather_ items)
        private string[] ScanBagForFoodItems()
        {
            var foodList = new System.Collections.Generic.List<string>();
            HashSet<string> seenItems = new HashSet<string>();
            this.scannedBagFoodDisplayNames.Clear();

            // Known food keywords to filter items
            string[] foodKeywords = new[] { "food", "bread", "jam", "mushroom", "salad", "soup", "stew", "pie", "cake", "fish", "meat", "fruit", "vegetable", "berry", "apple", "cheese", "egg", "milk", "honey", "candy", "snack", "meal", "dish" };

            foreach (Image img in GetBagPanelImages())
            {
                if (img != null && img.sprite != null && img.gameObject.activeInHierarchy)
                {
                    string spriteName = img.sprite.name.ToLowerInvariant();
                    bool isFood = false;
                    string itemName = "";

                    // Check if it's an item sprite (ui_item_normal_p_*)
                    if (spriteName.StartsWith("ui_item_normal_p_"))
                    {
                        itemName = spriteName.Replace("ui_item_normal_p_", "");
                        // Check if it contains any food keyword
                        foreach (string keyword in foodKeywords)
                        {
                            if (itemName.Contains(keyword))
                            {
                                isFood = true;
                                break;
                            }
                        }
                        // Also check if it contains "food_", "gather_", or "fruit_" patterns
                        if (!isFood && (itemName.Contains("food_") || itemName.Contains("gather_") || itemName.Contains("fruit_")))
                            isFood = true;
                    }
                    // Also include gather_ and fruit_ items that don't have ui_item_normal_p_ prefix
                    if (!isFood && (spriteName.Contains("gather_") || spriteName.Contains("fruit_")))
                    {
                        isFood = true;
                    }

                    if (isFood && !seenItems.Contains(spriteName))
                    {
                        seenItems.Add(spriteName);
                        foodList.Add(spriteName);
                        this.CacheScannedBagFoodDisplayName(spriteName);
                        if (!this.scannedBagFoodTextures.ContainsKey(spriteName) && this.TryLoadCachedItemIcon(spriteName, out Texture2D cachedFoodTexture))
                        {
                            this.scannedBagFoodTextures[spriteName] = cachedFoodTexture;
                            continue;
                        }
                        // Copy the sprite texture for UI display (copy to survive bag scrolling)
                        // Use RenderTexture approach since game textures are non-readable
                        if (img.sprite.texture != null)
                        {
                            Texture2D original = img.sprite.texture;
                            try
                            {
                                // Create a temporary RenderTexture to copy the non-readable texture
                                RenderTexture rt = RenderTexture.GetTemporary(original.width, original.height, 0, RenderTextureFormat.ARGB32);
                                Graphics.Blit(original, rt);
                                
                                // Create new readable texture and read from RenderTexture
                                Texture2D copy = new Texture2D(original.width, original.height, TextureFormat.RGBA32, false);
                                RenderTexture previousRT = RenderTexture.active;
                                RenderTexture.active = rt;
                                copy.ReadPixels(new Rect(0, 0, original.width, original.height), 0, 0);
                                copy.Apply();
                                RenderTexture.active = previousRT;
                                RenderTexture.ReleaseTemporary(rt);
                                
                                this.scannedBagFoodTextures[spriteName] = copy;
                                this.SaveCachedItemIcon(spriteName, copy);
                            }
                            catch (Exception texEx)
                            {
                                ModLogger.Msg($"[BagScan] Failed to copy texture for {spriteName}: {texEx.Message}");
                            }
                        }
                    }
                }
            }

            return foodList.ToArray();
        }

        private List<AutoSellBagItemEntry> ScanBagForAutoSellItems()
        {
            List<AutoSellBagItemEntry> items = new List<AutoSellBagItemEntry>();
            HashSet<string> seenItems = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            this.autoSellUiStarByMatchKey.Clear();
            this.autoSellUiStarByMatchKeyAndCount.Clear();
            int starCached = 0;
            int starAmbiguous = 0;

            foreach (Image img in GetBagPanelImages())
            {
                if (img == null || img.sprite == null || !img.gameObject.activeInHierarchy)
                {
                    continue;
                }

                string spriteName = (img.sprite.name ?? string.Empty).ToLowerInvariant();
                if (!this.IsLikelyBagItemSprite(spriteName))
                {
                    continue;
                }

                string matchKey = this.NormalizeAutoSellMatchKey(spriteName);
                int uiStar = this.TryGetAutoSellStarCountFromBagItemImage(img);
                int uiCount = this.TryGetAutoSellStackCountFromBagItemImage(img);
                if (uiStar > 0)
                {
                    if (this.CacheAutoSellUiStar(matchKey, uiCount, uiStar))
                    {
                        starCached++;
                    }
                    else
                    {
                        starAmbiguous++;
                    }
                }

                if (!seenItems.Add(spriteName))
                {
                    continue;
                }

                AutoSellBagItemEntry entry = new AutoSellBagItemEntry
                {
                    SpriteName = spriteName,
                    MatchKey = matchKey,
                    DisplayName = this.GetAutoSellItemDisplayName(spriteName),
                    Count = Math.Max(1, uiCount),
                    StarRate = uiStar
                };
                if (uiStar > 0 && uiStar < entry.StarCounts.Length)
                {
                    entry.StarCounts[uiStar] = 1;
                }
                items.Add(entry);

                if (!this.autoSellBagItemTextures.ContainsKey(spriteName) && img.sprite.texture != null)
                {
                    if (this.TryLoadCachedItemIcon(spriteName, out Texture2D cachedTexture))
                    {
                        this.autoSellBagItemTextures[spriteName] = cachedTexture;
                    }
                    else
                    {
                        Texture2D copy = this.CopySpriteTexture(img.sprite, "[AutoSell]");
                        if (copy != null)
                        {
                            this.autoSellBagItemTextures[spriteName] = copy;
                            this.SaveCachedItemIcon(spriteName, copy);
                        }
                    }
                }
            }

            this.PrimeAutoSellItemTextureCache(items);
            items.Sort((a, b) => string.Compare(a.DisplayName, b.DisplayName, StringComparison.OrdinalIgnoreCase));
            this.AutoSellLog("Bag UI item list scan found " + items.Count + " item icon(s), star cached=" + starCached + (starAmbiguous > 0 ? ", ambiguous=" + starAmbiguous : "") + ".");
            return items;
        }

        private bool CacheAutoSellUiStar(string matchKey, int stackCount, int starRate)
        {
            string key = this.ExtractAutoSellMatchKeyFromDescriptor(matchKey);
            if (string.IsNullOrWhiteSpace(key))
            {
                key = this.NormalizeAutoSellMatchKey(matchKey);
            }
            starRate = this.NormalizeAutoSellStarRate(starRate);
            if (string.IsNullOrWhiteSpace(key) || starRate <= 0)
            {
                return false;
            }

            bool specificCached = true;
            if (stackCount > 0)
            {
                string countKey = this.GetAutoSellStarCountCacheKey(key, stackCount);
                if (this.autoSellUiStarByMatchKeyAndCount.TryGetValue(countKey, out int existingCountStar))
                {
                    if (existingCountStar != starRate)
                    {
                        this.autoSellUiStarByMatchKeyAndCount[countKey] = -1;
                        specificCached = false;
                    }
                }
                else
                {
                    this.autoSellUiStarByMatchKeyAndCount[countKey] = starRate;
                }
            }

            if (this.autoSellUiStarByMatchKey.TryGetValue(key, out int existing))
            {
                if (existing == starRate)
                {
                    return specificCached;
                }

                // Same item icon can appear in multiple star versions. Mark ambiguous instead
                // of guessing, so the star filter never sells a mixed stack blindly.
                this.autoSellUiStarByMatchKey[key] = -1;
                return false;
            }

            this.autoSellUiStarByMatchKey[key] = starRate;
            return specificCached;
        }

        private bool TryGetAutoSellCachedUiStar(string descriptorOrKey, out int starRate)
        {
            return this.TryGetAutoSellCachedUiStar(descriptorOrKey, 0, out starRate);
        }

        private bool TryGetAutoSellCachedUiStar(string descriptorOrKey, int stackCount, out int starRate)
        {
            starRate = 0;
            string key = this.ExtractAutoSellMatchKeyFromDescriptor(descriptorOrKey);
            if (string.IsNullOrWhiteSpace(key))
            {
                key = this.NormalizeAutoSellMatchKey(descriptorOrKey);
            }
            if (string.IsNullOrWhiteSpace(key))
            {
                return false;
            }

            if (stackCount > 0)
            {
                string countKey = this.GetAutoSellStarCountCacheKey(key, stackCount);
                if (this.autoSellUiStarByMatchKeyAndCount.TryGetValue(countKey, out int cachedCountStar) && cachedCountStar > 0)
                {
                    starRate = cachedCountStar;
                    return true;
                }

                string countSpriteKey = this.GetAutoSellStarCountCacheKey(this.NormalizeAutoSellMatchKey(this.GetAutoSellSpriteNameFromMatchKey(key)), stackCount);
                if (!string.Equals(countSpriteKey, countKey, StringComparison.OrdinalIgnoreCase)
                    && this.autoSellUiStarByMatchKeyAndCount.TryGetValue(countSpriteKey, out cachedCountStar)
                    && cachedCountStar > 0)
                {
                    starRate = cachedCountStar;
                    return true;
                }
            }

            if (this.autoSellUiStarByMatchKey.TryGetValue(key, out int cachedStar) && cachedStar > 0)
            {
                starRate = cachedStar;
                return true;
            }

            string spriteKey = this.NormalizeAutoSellMatchKey(this.GetAutoSellSpriteNameFromMatchKey(key));
            if (!string.Equals(spriteKey, key, StringComparison.OrdinalIgnoreCase)
                && this.autoSellUiStarByMatchKey.TryGetValue(spriteKey, out cachedStar)
                && cachedStar > 0)
            {
                starRate = cachedStar;
                return true;
            }

            return false;
        }

        private string GetAutoSellStarCountCacheKey(string key, int stackCount)
        {
            return this.NormalizeAutoSellMatchKey(key) + "|x" + Math.Max(1, stackCount);
        }

        private IEnumerable<int> GetAutoSellStorageTypeValues()
        {
            switch (Mathf.Clamp(this.autoSellScanSource, 0, 2))
            {
                case 1:
                    yield return 2;
                    yield break;
                case 2:
                    yield return 1;
                    yield return 2;
                    yield break;
                default:
                    yield return 1;
                    yield break;
            }
        }

        private string GetAutoSellScanSourceLabel()
        {
            return this.autoSellScanSourceLabels[Mathf.Clamp(this.autoSellScanSource, 0, this.autoSellScanSourceLabels.Length - 1)];
        }

        private string GetAutoSellStorageLabel(bool fromBackpack, bool fromWarehouse)
        {
            if (fromBackpack && fromWarehouse)
            {
                return "Both";
            }
            if (fromWarehouse)
            {
                return "Warehouse";
            }
            return "Bag";
        }

        private int TryGetAutoSellStarCountFromBagItemImage(Image itemImage)
        {
            try
            {
                Transform packRoot = this.FindAutoSellPackWidgetRoot(itemImage != null ? itemImage.transform : null);
                if (packRoot != null)
                {
                    Transform starRoot = packRoot.Find("star@w");
                    if (starRoot != null)
                    {
                        int exactStar = this.CountActiveAutoSellStars(starRoot);
                        if (exactStar > 0)
                        {
                            return exactStar;
                        }
                    }
                }

                Transform current = itemImage != null ? itemImage.transform : null;
                for (int depth = 0; current != null && depth < 7; depth++, current = current.parent)
                {
                    int itemSpriteCount = this.CountLikelyAutoSellItemSprites(current);
                    if (itemSpriteCount != 1)
                    {
                        continue;
                    }

                    int star = this.CountActiveAutoSellStars(current);
                    if (star > 0)
                    {
                        return star;
                    }
                }
            }
            catch
            {
            }

            return 0;
        }

        private int TryGetAutoSellStackCountFromBagItemImage(Image itemImage)
        {
            try
            {
                Transform packRoot = this.FindAutoSellPackWidgetRoot(itemImage != null ? itemImage.transform : null);
                if (packRoot == null)
                {
                    packRoot = itemImage != null ? itemImage.transform : null;
                }

                int count = this.TryReadAutoSellCountText(packRoot != null ? packRoot.Find("quantity/numBg@img/num@txt") : null);
                if (count > 0)
                {
                    return count;
                }

                count = this.TryReadAutoSellCountText(packRoot != null ? packRoot.Find("topNumBg@img/leftTopNum@txt") : null);
                if (count > 0)
                {
                    return count;
                }

                if (packRoot != null)
                {
                    Text[] texts = packRoot.GetComponentsInChildren<Text>(true);
                    foreach (Text text in texts)
                    {
                        if (text == null || !text.gameObject.activeInHierarchy)
                        {
                            continue;
                        }

                        string name = (text.name ?? string.Empty).ToLowerInvariant();
                        if (!name.Contains("num") && !name.Contains("count"))
                        {
                            continue;
                        }

                        count = this.ParseAutoSellCountText(text.text);
                        if (count > 0)
                        {
                            return count;
                        }
                    }
                }
            }
            catch
            {
            }

            return 0;
        }

        private int TryReadAutoSellCountText(Transform textTransform)
        {
            if (textTransform == null || !textTransform.gameObject.activeInHierarchy)
            {
                return 0;
            }

            Text text = textTransform.GetComponent<Text>();
            return text != null ? this.ParseAutoSellCountText(text.text) : 0;
        }

        private int ParseAutoSellCountText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return 0;
            }

            string digits = new string(text.Where(char.IsDigit).ToArray());
            if (string.IsNullOrWhiteSpace(digits))
            {
                return 0;
            }

            return int.TryParse(digits, out int value) ? value : 0;
        }

        private Transform FindAutoSellPackWidgetRoot(Transform start)
        {
            Transform current = start;
            for (int depth = 0; current != null && depth < 8; depth++, current = current.parent)
            {
                string name = current.name ?? string.Empty;
                if (name == "Root" && current.Find("star@w") != null)
                {
                    return current;
                }
            }

            return null;
        }

        private int CountLikelyAutoSellItemSprites(Transform root)
        {
            if (root == null)
            {
                return 0;
            }

            int count = 0;
            Image[] images = root.GetComponentsInChildren<Image>(true);
            foreach (Image img in images)
            {
                if (img == null || img.sprite == null || !img.gameObject.activeInHierarchy)
                {
                    continue;
                }

                string spriteName = (img.sprite.name ?? string.Empty).ToLowerInvariant();
                if (this.IsLikelyBagItemSprite(spriteName))
                {
                    count++;
                }
            }
            return count;
        }

        private int CountActiveAutoSellStars(Transform root)
        {
            if (root == null)
            {
                return 0;
            }

            int star = 0;
            Transform[] transforms = root.GetComponentsInChildren<Transform>(true);
            foreach (Transform t in transforms)
            {
                if (t == null || !t.gameObject.activeInHierarchy)
                {
                    continue;
                }

                string name = (t.name ?? string.Empty).ToLowerInvariant();
                for (int i = 1; i <= 5; i++)
                {
                    if (name.Contains("star" + i) || name.Contains("star_" + i))
                    {
                        star = Math.Max(star, i);
                    }
                }
            }

            return Mathf.Clamp(star, 0, 5);
        }

        private void CacheAutoSellIconsFromOpenBag()
        {
            List<AutoSellBagItemEntry> iconEntries = this.ScanBagForAutoSellItems();
            if ((this.autoSellBagItems == null || this.autoSellBagItems.Count == 0) && iconEntries.Count > 0)
            {
                this.autoSellBagItems = iconEntries;
            }
        }

        private List<AutoSellBagItemEntry> ScanBackpackForAutoSellItems()
        {
            try
            {
                if (this.autoSellScanSource != 1 && this.IsBagOpen())
                {
                    this.CacheAutoSellIconsFromOpenBag();
                }

                List<AutoSellBagItemEntry> items = new List<AutoSellBagItemEntry>();
                Dictionary<string, AutoSellBagItemEntry> byKey = new Dictionary<string, AutoSellBagItemEntry>(StringComparer.OrdinalIgnoreCase);
                int inspected = 0;

                // Runtime snapshot occasionally hard-crashes in some game states; prefer the safer mono scan path for manual Scan Items.
                bool usedRuntimeSnapshot = false;
                this.CollectAutoSellBackpackEntriesManaged(items, byKey, ref inspected);
                this.CollectAutoSellBackpackEntriesMono(items, byKey, ref inspected, !usedRuntimeSnapshot);

                this.PrimeAutoSellItemTextureCache(items);
                items.Sort((a, b) => string.Compare(a.DisplayName, b.DisplayName, StringComparison.OrdinalIgnoreCase));
                this.AutoSellLog(this.GetAutoSellScanSourceLabel() + " item list scan found " + items.Count + " unique item(s), inspected=" + inspected + ".");
                return items;
            }
            catch (Exception ex)
            {
                this.AutoSellLog("Scan items exception: " + ex.GetType().Name + ": " + ex.Message);
                return new List<AutoSellBagItemEntry>();
            }
        }

        private void CollectAutoSellBackpackEntriesManaged(List<AutoSellBagItemEntry> items, Dictionary<string, AutoSellBagItemEntry> byKey, ref int inspected)
        {
            // The generated managed backpack assembly is not available in this game build; the Mono
            // scanner below is the reliable path and does not require the bag UI to be open.
        }

        private bool CollectAutoSellBackpackEntriesFromRuntimeSnapshot(List<AutoSellBagItemEntry> items, Dictionary<string, AutoSellBagItemEntry> byKey, ref int inspected)
        {
            if (Mathf.Clamp(this.autoSellScanSource, 0, 2) == 1)
            {
                return false;
            }

            if (!this.TryRefreshDirectBackpackRuntimeSnapshot(false))
            {
                return false;
            }

            foreach (DirectBackpackRuntimeItem item in this.directBackpackRuntimeItems)
            {
                if (item == null || item.NetId == 0U)
                {
                    continue;
                }

                inspected++;
                string descriptor = item.Descriptor ?? string.Empty;
                int count = Math.Max(1, item.Count);
                int starRate = 0;
                if (!this.TryGetAutoSellQualityComponentStar(item.NetId, out starRate))
                {
                    if (item.ManagedItem != null)
                    {
                        this.TryGetManagedBackpackItemStarRate(item.ManagedItem, out starRate);
                    }
                    else if (item.MonoItem != IntPtr.Zero)
                    {
                        this.TryGetDirectBackpackItemStarRate(item.MonoItem, out starRate);
                    }
                }
                if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
                {
                    if (this.TryGetAutoSellCachedUiStar(descriptor, count, out int uiStar))
                    {
                        starRate = uiStar;
                    }
                }
                if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
                {
                    int step = item.ManagedItem != null
                        ? this.GetManagedBackpackItemStep(item.ManagedItem)
                        : (item.MonoItem != IntPtr.Zero ? this.GetDirectBackpackItemStep(item.MonoItem) : 0);
                    if (step >= 1 && step <= 5)
                    {
                        starRate = step;
                    }
                }

                this.AddOrMergeAutoSellBackpackEntry(items, byKey, descriptor, item.NetId, count, item.StaticId, item.EntityType, starRate, true);
            }

            return true;
        }

        private void CollectAutoSellBackpackEntriesMono(List<AutoSellBagItemEntry> items, Dictionary<string, AutoSellBagItemEntry> byKey, ref int inspected, bool includeBackpack = true)
        {
            try
            {
                if (!this.TryResolveAuraMonoModule("XDTGameSystem.GameplaySystem.BackPack.BackPackSystem", out IntPtr backPackSystemObj) || backPackSystemObj == IntPtr.Zero)
                {
                    return;
                }

                IntPtr backPackClass = auraMonoObjectGetClass != null ? auraMonoObjectGetClass(backPackSystemObj) : IntPtr.Zero;
                IntPtr getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 1);
                bool getAllItemNeedsStorageType = true;
                if (getAllItemMethod == IntPtr.Zero)
                {
                    getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 0);
                    getAllItemNeedsStorageType = false;
                }
                if (getAllItemMethod == IntPtr.Zero || auraMonoRuntimeInvoke == null)
                {
                    return;
                }

                foreach (int storageTypeValue in this.GetAutoSellStorageTypeValues())
                {
                    bool fromBackpack = storageTypeValue == 1;
                    if (fromBackpack && !includeBackpack)
                    {
                        continue;
                    }

                    IntPtr exc = IntPtr.Zero;
                    IntPtr itemListObj;
                    unsafe
                    {
                        IntPtr* args = stackalloc IntPtr[1];
                        args[0] = (IntPtr)(&storageTypeValue);
                        itemListObj = auraMonoRuntimeInvoke(getAllItemMethod, backPackSystemObj, getAllItemNeedsStorageType ? (IntPtr)args : IntPtr.Zero, ref exc);
                    }
                    if (exc != IntPtr.Zero || itemListObj == IntPtr.Zero)
                    {
                        continue;
                    }

                    List<IntPtr> backpackItems = new List<IntPtr>();
                    if (!this.TryEnumerateAuraMonoCollectionItems(itemListObj, backpackItems))
                    {
                        continue;
                    }

                    foreach (IntPtr itemObj in backpackItems)
                    {
                        inspected++;
                        if (itemObj == IntPtr.Zero || !this.TryGetDirectBackpackItemNetId(itemObj, out uint netId) || netId == 0U)
                        {
                            continue;
                        }

                        int count = 1;
                        int staticId = 0;
                        int entityType = 0;
                        int starRate = 0;
                        this.TryGetDirectBackpackItemCount(itemObj, out count);
                        this.TryGetDirectBackpackItemStaticId(itemObj, out staticId);
                        this.TryGetDirectBackpackItemEntityType(itemObj, out entityType);
                        if (!this.TryGetAutoSellQualityComponentStar(netId, out starRate))
                        {
                            this.TryGetDirectBackpackItemStarRate(itemObj, out starRate);
                        }
                        string descriptor = this.GetDirectBackpackItemDescriptor(itemObj);
                        if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
                        {
                            if (this.TryGetAutoSellCachedUiStar(descriptor, count, out int uiStar))
                            {
                                starRate = uiStar;
                            }
                        }
                        if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
                        {
                            int step = this.GetDirectBackpackItemStep(itemObj);
                            if (step >= 1 && step <= 5)
                            {
                                starRate = step;
                            }
                        }
                        this.AddOrMergeAutoSellBackpackEntry(items, byKey, descriptor, netId, count, staticId, entityType, starRate, fromBackpack);
                    }
                }
            }
            catch (Exception ex)
            {
                this.AutoSellLog("Backpack list mono scan exception: " + ex.Message);
            }
        }

        private int GetTransferScanStorageType()
        {
            return Mathf.Clamp(this.transferScanSource, 0, 1) == 1 ? 2 : 1;
        }

        private string GetTransferScanSourceLabel()
        {
            return this.transferScanSourceLabels[Mathf.Clamp(this.transferScanSource, 0, this.transferScanSourceLabels.Length - 1)];
        }

        private int GetTransferTargetStorageType(int sourceStorageType)
        {
            return sourceStorageType == 1 ? 2 : 1;
        }

        private List<TransferItemEntry> ScanTransferItems(bool updateStatus = true)
        {
            try
            {
                List<TransferItemEntry> items = new List<TransferItemEntry>();
                int inspected = 0;
                this.CollectTransferItemEntriesMono(items, ref inspected);
                this.PrimeTransferItemTextureCache(items);
                items.Sort((a, b) => string.Compare(a.DisplayName, b.DisplayName, StringComparison.OrdinalIgnoreCase));
                if (updateStatus)
                {
                    this.transferStatus = items.Count > 0
                        ? (this.GetTransferScanSourceLabel() + ": " + items.Count + " stack(s), inspected=" + inspected)
                        : ("No items in " + this.GetTransferScanSourceLabel().ToLowerInvariant());
                }
                ModLogger.Msg("[TRANSFER] Scan " + this.GetTransferScanSourceLabel() + " found " + items.Count + " stack(s), inspected=" + inspected);
                return items;
            }
            catch (Exception ex)
            {
                if (updateStatus)
                {
                    this.transferStatus = "Scan failed: " + ex.Message;
                }
                ModLogger.Msg("[TRANSFER] Scan exception: " + ex.GetType().Name + ": " + ex.Message);
                return new List<TransferItemEntry>();
            }
        }

        private void CollectTransferItemEntriesMono(List<TransferItemEntry> items, ref int inspected)
        {
            try
            {
                if (!this.TryResolveAuraMonoModule("XDTGameSystem.GameplaySystem.BackPack.BackPackSystem", out IntPtr backPackSystemObj) || backPackSystemObj == IntPtr.Zero)
                {
                    return;
                }

                IntPtr backPackClass = auraMonoObjectGetClass != null ? auraMonoObjectGetClass(backPackSystemObj) : IntPtr.Zero;
                IntPtr getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 1);
                bool getAllItemNeedsStorageType = true;
                if (getAllItemMethod == IntPtr.Zero)
                {
                    getAllItemMethod = this.FindAuraMonoMethodOnHierarchy(backPackClass, "GetAllItem", 0);
                    getAllItemNeedsStorageType = false;
                }
                if (getAllItemMethod == IntPtr.Zero || auraMonoRuntimeInvoke == null)
                {
                    return;
                }

                int storageTypeValue = this.GetTransferScanStorageType();
                bool fromBackpack = storageTypeValue == 1;
                IntPtr exc = IntPtr.Zero;
                IntPtr itemListObj;
                unsafe
                {
                    IntPtr* args = stackalloc IntPtr[1];
                    args[0] = (IntPtr)(&storageTypeValue);
                    itemListObj = auraMonoRuntimeInvoke(getAllItemMethod, backPackSystemObj, getAllItemNeedsStorageType ? (IntPtr)args : IntPtr.Zero, ref exc);
                }
                if (exc != IntPtr.Zero || itemListObj == IntPtr.Zero)
                {
                    return;
                }

                List<IntPtr> backpackItems = new List<IntPtr>();
                if (!this.TryEnumerateAuraMonoCollectionItems(itemListObj, backpackItems))
                {
                    return;
                }

                foreach (IntPtr itemObj in backpackItems)
                {
                    inspected++;
                    if (itemObj == IntPtr.Zero || !this.TryGetDirectBackpackItemNetId(itemObj, out uint netId) || netId == 0U)
                    {
                        continue;
                    }

                    int count = 1;
                    int staticId = 0;
                    int entityType = 0;
                    int starRate = 0;
                    bool isLocked = false;
                    this.TryGetDirectBackpackItemCount(itemObj, out count);
                    this.TryGetDirectBackpackItemStaticId(itemObj, out staticId);
                    this.TryGetDirectBackpackItemEntityType(itemObj, out entityType);
                    this.TryGetDirectBackpackItemIsLocked(itemObj, out isLocked);
                    if (!this.TryGetAutoSellQualityComponentStar(netId, out starRate))
                    {
                        this.TryGetDirectBackpackItemStarRate(itemObj, out starRate);
                    }

                    string descriptor = this.GetDirectBackpackItemDescriptor(itemObj);

                    if (starRate <= 0 && this.IsAutoSellBirdPhotoDescriptor(descriptor))
                    {
                        if (this.TryGetAutoSellCachedUiStar(descriptor, count, out int uiStar))
                        {
                            starRate = uiStar;
                        }
                        else
                        {
                            int step = this.GetDirectBackpackItemStep(itemObj);
                            if (step >= 1 && step <= 5)
                            {
                                starRate = step;
                            }
                        }
                    }

                    this.AddTransferItemEntry(items, descriptor, netId, count, staticId, entityType, starRate, fromBackpack, isLocked);
                }
            }
            catch (Exception ex)
            {
                ModLogger.Msg("[TRANSFER] Mono scan exception: " + ex.Message);
            }
        }

        private void AddTransferItemEntry(List<TransferItemEntry> items, string descriptor, uint netId, int count, int staticId, int entityType, int starRate, bool fromBackpack, bool isLocked)
        {
            if (netId == 0U || count <= 0)
            {
                return;
            }

            string matchKey = this.ExtractAutoSellMatchKeyFromDescriptor(descriptor);
            if (string.IsNullOrWhiteSpace(matchKey))
            {
                matchKey = staticId > 0 ? staticId.ToString() : netId.ToString();
            }

            int normalizedStar = this.NormalizeAutoSellStarRateForDescriptor(starRate, descriptor);
            if (normalizedStar <= 0 && this.TryGetAutoSellCachedUiStar(matchKey, count, out int uiStar))
            {
                normalizedStar = uiStar;
            }

            string spriteName = this.GetAutoSellSpriteNameFromMatchKey(matchKey);
            string displayName = this.ResolveBagItemDisplayName(matchKey, staticId);
            this.RememberRadarStaticIdIconMapping(staticId, spriteName);
            items.Add(new TransferItemEntry
            {
                SpriteName = spriteName,
                DisplayName = displayName,
                MatchKey = matchKey,
                NetId = netId,
                Count = Math.Max(1, count),
                StaticId = staticId,
                EntityType = entityType,
                StarRate = normalizedStar,
                IsLocked = isLocked,
                FromBackpack = fromBackpack
            });
        }

        private void PrimeTransferItemTextureCache(List<TransferItemEntry> items)
        {
            if (items == null || items.Count == 0)
            {
                return;
            }

            List<AutoSellBagItemEntry> proxy = new List<AutoSellBagItemEntry>(items.Count);
            for (int i = 0; i < items.Count; i++)
            {
                TransferItemEntry entry = items[i];
                if (entry == null)
                {
                    continue;
                }

                proxy.Add(new AutoSellBagItemEntry
                {
                    SpriteName = entry.SpriteName,
                    MatchKey = entry.MatchKey,
                    DisplayName = entry.DisplayName,
                    NetId = entry.NetId,
                    Count = entry.Count,
                    StaticId = entry.StaticId,
                    EntityType = entry.EntityType,
                    StarRate = entry.StarRate,
                    FromBackpack = entry.FromBackpack,
                    FromWarehouse = !entry.FromBackpack
                });
            }

            this.PrimeAutoSellItemTextureCache(proxy);
        }

        private bool TryGetTransferItemTexture(TransferItemEntry entry, out Texture2D texture)
        {
            texture = null;
            if (entry == null)
            {
                return false;
            }

            return this.TryGetAutoSellItemTexture(new AutoSellBagItemEntry
            {
                SpriteName = entry.SpriteName,
                MatchKey = entry.MatchKey,
                DisplayName = entry.DisplayName,
                NetId = entry.NetId,
                Count = entry.Count,
                StaticId = entry.StaticId,
                EntityType = entry.EntityType,
                StarRate = entry.StarRate,
                FromBackpack = entry.FromBackpack,
                FromWarehouse = !entry.FromBackpack
            }, out texture);
        }

        private TransferItemEntry GetSelectedTransferItemEntry()
        {
            if (this.transferItems == null || this.selectedTransferIndex < 0 || this.selectedTransferIndex >= this.transferItems.Count)
            {
                return null;
            }

            return this.transferItems[this.selectedTransferIndex];
        }

        private int GetTransferTilePickQuantity(TransferItemEntry entry, int itemIndex, out bool showOnTile)
        {
            showOnTile = false;
            if (entry == null || entry.NetId == 0U)
            {
                return 1;
            }

            int maxQty = Math.Max(1, entry.Count);
            if (this.transferBatch.TryGetValue(entry.NetId, out int batchQty))
            {
                showOnTile = true;
                return Mathf.Clamp(batchQty, 1, maxQty);
            }

            if (this.selectedTransferIndex == itemIndex)
            {
                showOnTile = true;
                return Mathf.Clamp(this.transferQty, 1, maxQty);
            }

            return 1;
        }

        private void SetTransferTilePickQuantity(TransferItemEntry entry, int itemIndex, int quantity)
        {
            if (entry == null || entry.NetId == 0U)
            {
                return;
            }

            if (quantity <= 0)
            {
                if (this.transferMultiSelectMode && this.transferBatch.Remove(entry.NetId))
                {
                    this.transferQty = 1;
                    if (this.selectedTransferIndex == itemIndex)
                    {
                        this.selectedTransferIndex = -1;
                    }
                    this.ClearTransferQtyHold();
                }
                else if (!this.transferMultiSelectMode)
                {
                    this.transferQty = 1;
                }
                return;
            }

            int maxQty = Math.Max(1, entry.Count);
            int qty = Mathf.Clamp(quantity, 1, maxQty);
            this.transferQty = qty;
            if (this.transferMultiSelectMode && this.transferBatch.ContainsKey(entry.NetId))
            {
                this.transferBatch[entry.NetId] = qty;
            }
        }

        private void AdjustTransferTilePickQuantity(TransferItemEntry entry, int itemIndex, int delta)
        {
            if (entry == null)
            {
                return;
            }

            int current = this.GetTransferTilePickQuantity(entry, itemIndex, out _);
            this.SetTransferTilePickQuantity(entry, itemIndex, current + delta);
        }

        private void ClearTransferQtyHold()
        {
            this.transferQtyHoldDirection = 0;
            this.transferQtyHoldNetId = 0U;
            this.transferQtyHoldItemIndex = -1;
        }

        private void BeginTransferQtyHold(int direction, TransferItemEntry entry, int itemIndex)
        {
            if (entry == null || entry.NetId == 0U)
            {
                return;
            }

            this.transferQtyHoldDirection = direction;
            this.transferQtyHoldNetId = entry.NetId;
            this.transferQtyHoldItemIndex = itemIndex;
            this.transferQtyHoldStartedAt = Time.unscaledTime;
            // First step is applied by the click; first repeat after one interval.
            this.transferQtyHoldLastStepAt = Time.unscaledTime;
        }

        private void UpdateTransferQtyHoldRepeat()
        {
            if (this.transferQtyHoldDirection == 0)
            {
                return;
            }

            if (!this.showMenu || this.selectedTab != 6)
            {
                this.ClearTransferQtyHold();
                return;
            }

            if (!Input.GetMouseButton(0))
            {
                this.ClearTransferQtyHold();
                return;
            }

            if (this.transferItems == null
                || this.transferQtyHoldItemIndex < 0
                || this.transferQtyHoldItemIndex >= this.transferItems.Count)
            {
                this.ClearTransferQtyHold();
                return;
            }

            if (this.selectedTransferIndex != this.transferQtyHoldItemIndex)
            {
                this.ClearTransferQtyHold();
                return;
            }

            TransferItemEntry entry = this.transferItems[this.transferQtyHoldItemIndex];
            if (entry == null || entry.NetId != this.transferQtyHoldNetId)
            {
                this.ClearTransferQtyHold();
                return;
            }

            float heldSeconds = Time.unscaledTime - this.transferQtyHoldStartedAt;
            if (heldSeconds < TransferQtyHoldRepeatDelay)
            {
                return;
            }

            float repeatSeconds = heldSeconds - TransferQtyHoldRepeatDelay;
            float interval = repeatSeconds >= TransferQtyHoldFastAfterSeconds ? TransferQtyHoldFastInterval : TransferQtyHoldSlowInterval;
            if (Time.unscaledTime - this.transferQtyHoldLastStepAt < interval)
            {
                return;
            }

            this.AdjustTransferTilePickQuantity(entry, this.transferQtyHoldItemIndex, this.transferQtyHoldDirection);
            this.transferQtyHoldLastStepAt = Time.unscaledTime;
        }

        private void DrawTransferQtyStepButton(Rect rect, string label, int direction, TransferItemEntry entry, int itemIndex, GUIStyle style)
        {
            Event e = Event.current;
            if (e != null && e.button == 0 && e.type == EventType.MouseDown && rect.Contains(e.mousePosition))
            {
                this.AdjustTransferTilePickQuantity(entry, itemIndex, direction);
                this.BeginTransferQtyHold(direction, entry, itemIndex);
                e.Use();
            }

            bool holdingThisButton = this.transferQtyHoldDirection == direction
                && this.transferQtyHoldItemIndex == itemIndex
                && this.transferQtyHoldNetId == entry.NetId
                && Input.GetMouseButton(0);
            Color previousBg = GUI.backgroundColor;
            if (holdingThisButton)
            {
                GUI.backgroundColor = new Color(0.35f, 0.55f, 0.65f, 1f);
            }

            GUI.Button(rect, label, style);
            GUI.backgroundColor = previousBg;
        }

        private void SelectTransferTile(TransferItemEntry entry, int itemIndex)
        {
            if (entry == null || entry.IsLocked)
            {
                return;
            }

            int maxQty = Math.Max(1, entry.Count);
            int pickQty = this.transferSelectFullStack ? maxQty : 1;
            this.selectedTransferIndex = itemIndex;
            if (this.transferMultiSelectMode)
            {
                if (this.transferBatch.TryGetValue(entry.NetId, out int batchQty))
                {
                    if (this.transferSelectFullStack)
                    {
                        this.transferQty = maxQty;
                        this.transferBatch[entry.NetId] = maxQty;
                    }
                    else
                    {
                        this.transferQty = Mathf.Clamp(batchQty, 1, maxQty);
                    }
                    return;
                }

                this.transferQty = pickQty;
                this.transferBatch[entry.NetId] = pickQty;
            }
            else
            {
                this.transferQty = pickQty;
                this.transferBatch.Clear();
            }
        }

        private string GetTransferTileStarLabel(TransferItemEntry entry)
        {
            if (entry == null || entry.StarRate <= 0)
            {
                return string.Empty;
            }

            return entry.StarRate + "*";
        }

        private void AddOrMergeAutoSellBackpackEntry(List<AutoSellBagItemEntry> items, Dictionary<string, AutoSellBagItemEntry> byKey, string descriptor, uint netId, int count, int staticId, int entityType, int starRate, bool fromBackpack)
        {
            string matchKey = this.ExtractAutoSellMatchKeyFromDescriptor(descriptor);
            if (string.IsNullOrWhiteSpace(matchKey))
            {
                matchKey = staticId > 0 ? staticId.ToString() : netId.ToString();
            }

            int normalizedStar = this.NormalizeAutoSellStarRateForDescriptor(starRate, descriptor);
            if (normalizedStar <= 0 && this.TryGetAutoSellCachedUiStar(matchKey, count, out int uiStar))
            {
                normalizedStar = uiStar;
            }

            string listKey = matchKey + "|star:" + Mathf.Clamp(normalizedStar, 0, 5);
            if (!byKey.TryGetValue(listKey, out AutoSellBagItemEntry entry))
            {
                entry = new AutoSellBagItemEntry
                {
                    SpriteName = this.GetAutoSellSpriteNameFromMatchKey(matchKey),
                    DisplayName = this.ResolveBagItemDisplayName(matchKey, staticId) + (normalizedStar > 0 ? (" " + normalizedStar + "*") : ""),
                    MatchKey = matchKey,
                    NetId = netId,
                    Count = Math.Max(1, count),
                    StackCount = 1,
                    StaticId = staticId,
                    EntityType = entityType,
                    StarRate = normalizedStar,
                    FromBackpack = fromBackpack,
                    FromWarehouse = !fromBackpack
                };
                this.RememberRadarStaticIdIconMapping(staticId, entry.SpriteName);
                if (entry.StarRate > 0 && entry.StarRate < entry.StarCounts.Length)
                {
                    entry.StarCounts[entry.StarRate] = Math.Max(1, count);
                }
                byKey[listKey] = entry;
                items.Add(entry);
                return;
            }

            entry.Count += Math.Max(1, count);
            entry.StackCount++;
            if (normalizedStar > 0 && normalizedStar < entry.StarCounts.Length)
            {
                entry.StarCounts[normalizedStar] += Math.Max(1, count);
                if (entry.StarRate <= 0)
                {
                    entry.StarRate = normalizedStar;
                }
            }
            if (entry.NetId == 0U) entry.NetId = netId;
            if (entry.StaticId <= 0) entry.StaticId = staticId;
            if (entry.EntityType <= 0) entry.EntityType = entityType;
            if (fromBackpack) entry.FromBackpack = true;
            else entry.FromWarehouse = true;
            this.RememberRadarStaticIdIconMapping(staticId, entry.SpriteName);
        }

        private string ExtractAutoSellMatchKeyFromDescriptor(string descriptor)
        {
            string text = this.NormalizeAutoSellMatchKey(descriptor);
            if (string.IsNullOrWhiteSpace(text))
            {
                return string.Empty;
            }

            string[] tokens = text.Split(new[] { ' ', ',', ';', '|', '/', '\\', '\t', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
            string best = tokens.FirstOrDefault(x => x.StartsWith("p_", StringComparison.Ordinal));
            if (!string.IsNullOrWhiteSpace(best)) return best;
            best = tokens.FirstOrDefault(x => x.Contains("_birdphoto") || x.Contains("_gather_") || x.Contains("_food_") || x.StartsWith("food_", StringComparison.Ordinal));
            if (!string.IsNullOrWhiteSpace(best)) return best;
            best = tokens.FirstOrDefault(x => x.Any(char.IsLetter));
            return best ?? text;
        }

        private string GetAutoSellSpriteNameFromMatchKey(string matchKey)
        {
            string key = this.NormalizeAutoSellMatchKey(matchKey);
            if (string.IsNullOrWhiteSpace(key))
            {
                return string.Empty;
            }

            return key.StartsWith("ui_item_", StringComparison.Ordinal) ? key : (key.StartsWith("p_", StringComparison.Ordinal) ? "ui_item_normal_" + key : key);
        }

        private List<string> GetAutoSellItemTextureKeys(AutoSellBagItemEntry entry)
        {
            List<string> keys = new List<string>();
            HashSet<string> seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            if (entry == null)
            {
                return keys;
            }

            this.AddAutoSellItemTextureKey(keys, seen, entry.SpriteName);
            this.AddAutoSellItemTextureKey(keys, seen, this.GetAutoSellSpriteNameFromMatchKey(entry.MatchKey));
            this.AddAutoSellItemTextureKey(keys, seen, entry.MatchKey);
            if (entry.StaticId > 0 && this.TryGetRadarStaticIdIconKey(entry.StaticId, out string staticSpriteKey))
            {
                this.AddAutoSellItemTextureKey(keys, seen, staticSpriteKey);
            }

            return keys;
        }

        private void AddAutoSellItemTextureKey(List<string> keys, HashSet<string> seen, string key)
        {
            string normalized = this.NormalizeAutoSellMatchKey(key);
            if (string.IsNullOrWhiteSpace(normalized) || !seen.Add(normalized))
            {
                return;
            }

            keys.Add(normalized);
        }

        private void PrimeAutoSellItemTextureCache(List<AutoSellBagItemEntry> items)
        {
            if (items == null || items.Count == 0)
            {
                return;
            }

            Dictionary<string, List<string>> aliasesByTarget = new Dictionary<string, List<string>>(StringComparer.OrdinalIgnoreCase);
            int missingBeforeResolve = 0;

            foreach (AutoSellBagItemEntry entry in items)
            {
                List<string> keys = this.GetAutoSellItemTextureKeys(entry);
                bool hasTexture = false;

                foreach (string key in keys)
                {
                    if (this.autoSellBagItemTextures.TryGetValue(key, out Texture2D existing) && existing != null)
                    {
                        hasTexture = true;
                        break;
                    }

                    if (this.TryLoadCachedItemIcon(key, out Texture2D cached) && cached != null)
                    {
                        this.autoSellBagItemTextures[key] = cached;
                        hasTexture = true;
                        break;
                    }
                }

                if (hasTexture)
                {
                    continue;
                }

                missingBeforeResolve++;
                foreach (string key in keys)
                {
                    if (!aliasesByTarget.TryGetValue(key, out List<string> aliases))
                    {
                        aliases = new List<string>();
                        aliasesByTarget[key] = aliases;
                    }

                    foreach (string alias in keys)
                    {
                        if (!aliases.Contains(alias))
                        {
                            aliases.Add(alias);
                        }
                    }
                }
            }

            if (aliasesByTarget.Count == 0)
            {
                return;
            }

            int resolved = 0;
            try
            {
                Sprite[] sprites = Resources.FindObjectsOfTypeAll<Sprite>();
                if (sprites == null || sprites.Length == 0)
                {
                    return;
                }

                for (int i = 0; i < sprites.Length; i++)
                {
                    Sprite sprite = sprites[i];
                    if (sprite == null || string.IsNullOrWhiteSpace(sprite.name))
                    {
                        continue;
                    }

                    string normalizedName = this.NormalizeAutoSellMatchKey(sprite.name);
                    if (!aliasesByTarget.TryGetValue(normalizedName, out List<string> aliases))
                    {
                        continue;
                    }

                    Texture2D copy = this.CopySpriteTexture(sprite, "[AutoSell]");
                    if (copy == null)
                    {
                        continue;
                    }

                    foreach (string alias in aliases)
                    {
                        this.autoSellBagItemTextures[alias] = copy;
                        this.SaveCachedItemIcon(alias, copy);
                        this.autoSellLoadedSpriteResolveFailures.Remove(alias);
                    }

                    resolved++;
                    aliasesByTarget.Remove(normalizedName);
                    if (aliasesByTarget.Count == 0)
                    {
                        break;
                    }
                }
            }
            catch
            {
            }

            if (resolved > 0)
            {
                this.AutoSellLog("Resolved " + resolved + " missing auto-sell icon(s) from loaded sprites.");
            }

            foreach (string unresolved in aliasesByTarget.Keys)
            {
                this.autoSellLoadedSpriteResolveFailures.Add(unresolved);
            }

            if (resolved == 0 && missingBeforeResolve > 0)
            {
                this.AutoSellLog("Loaded sprite fallback could not resolve " + aliasesByTarget.Count + " icon key(s) yet.");
            }
        }

        private bool TryGetAutoSellItemTexture(AutoSellBagItemEntry entry, out Texture2D texture)
        {
            texture = null;
            if (entry == null)
            {
                return false;
            }

            foreach (string key in this.GetAutoSellItemTextureKeys(entry))
            {
                if (this.autoSellBagItemTextures.TryGetValue(key, out texture) && texture != null)
                {
                    return true;
                }
                if (this.TryLoadCachedItemIcon(key, out texture) && texture != null)
                {
                    this.autoSellBagItemTextures[key] = texture;
                    return true;
                }
            }

            return false;
        }

        private string GetAutoSellItemInitials(string displayName)
        {
            string text = (displayName ?? string.Empty).Trim();
            if (string.IsNullOrWhiteSpace(text))
            {
                return "?";
            }

            string[] parts = text.Split(new[] { ' ', '_' }, StringSplitOptions.RemoveEmptyEntries);
            if (parts.Length == 1)
            {
                return parts[0].Substring(0, Math.Min(2, parts[0].Length)).ToUpperInvariant();
            }

            return (parts[0].Substring(0, 1) + parts[parts.Length - 1].Substring(0, 1)).ToUpperInvariant();
        }

        private string GetAutoSellStarSummary(AutoSellBagItemEntry entry)
        {
            if (entry == null)
            {
                return string.Empty;
            }

            List<string> parts = new List<string>();
            if (entry.StarCounts != null)
            {
                for (int i = 1; i < entry.StarCounts.Length; i++)
                {
                    if (entry.StarCounts[i] > 0)
                    {
                        parts.Add(i + "*:" + entry.StarCounts[i]);
                    }
                }
            }
            if (parts.Count > 0)
            {
                return "  stars " + string.Join(" ", parts.ToArray());
            }
            return entry.StarRate > 0 ? ("  " + entry.StarRate + "*") : string.Empty;
        }

        private AutoSellBagItemEntry GetSelectedAutoSellBagItemEntry()
        {
            if (this.autoSellBagItems == null || this.autoSellBagItems.Count == 0)
            {
                return null;
            }

            string key = this.GetActiveAutoSellMatchKey();
            if (string.IsNullOrWhiteSpace(key))
            {
                return null;
            }

            AutoSellBagItemEntry fallback = null;
            for (int i = 0; i < this.autoSellBagItems.Count; i++)
            {
                AutoSellBagItemEntry entry = this.autoSellBagItems[i];
                string entryKey = entry != null && this.autoSellMatchFamily ? this.GetAutoSellFamilyKey(entry.MatchKey) : (entry != null ? entry.MatchKey : "");
                if (entry != null && string.Equals(entryKey, key, StringComparison.OrdinalIgnoreCase))
                {
                    if (this.autoSellStarFilter > 0 && entry.StarRate == this.autoSellStarFilter)
                    {
                        return entry;
                    }
                    if (fallback == null)
                    {
                        fallback = entry;
                    }
                }
            }

            return fallback;
        }

        private bool IsLikelyBagItemSprite(string spriteName)
        {
            if (string.IsNullOrWhiteSpace(spriteName))
            {
                return false;
            }

            return spriteName.StartsWith("ui_item_normal_p_", StringComparison.Ordinal)
                || spriteName.StartsWith("ui_item_special_p_", StringComparison.Ordinal)
                || spriteName.StartsWith("p_", StringComparison.Ordinal)
                || spriteName.Contains("_birdphoto")
                || spriteName.Contains("_gather_")
                || spriteName.Contains("_food_");
        }

        private string GetAutoSellItemDisplayName(string spriteName)
        {
            string itemName = this.NormalizeAutoSellMatchKey(spriteName)
                .Replace("p_", "")
                .Replace("gather_", "")
                .Replace("food_", "")
                .Replace("fruit_", "")
                .Replace("_", " ");
            if (string.IsNullOrWhiteSpace(itemName))
            {
                return "Unknown Item";
            }

            return System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(itemName);
        }

        private string ResolveBagItemDisplayName(string matchKey, int staticId)
        {
            if (staticId > 0 && this.TryGetResolvedFoodNameFromStaticId(staticId, out string tableName) && !this.IsPoorBagItemDisplayName(tableName, staticId))
            {
                return tableName;
            }

            string spriteName = this.GetAutoSellItemDisplayName(matchKey);
            if (!this.IsPoorBagItemDisplayName(spriteName, staticId))
            {
                return spriteName;
            }

            return staticId > 0 ? ("Item " + staticId) : (string.IsNullOrWhiteSpace(spriteName) ? "Unknown Item" : spriteName);
        }

        private bool IsPoorBagItemDisplayName(string displayName, int staticId)
        {
            if (string.IsNullOrWhiteSpace(displayName))
            {
                return true;
            }

            string trimmed = displayName.Trim();
            if (staticId > 0 && trimmed.StartsWith(staticId.ToString(), StringComparison.Ordinal))
            {
                string suffix = trimmed.Substring(staticId.ToString().Length).Trim();
                if (suffix.Length == 0 || this.IsNumericTokenSequence(suffix))
                {
                    return true;
                }
            }

            if (this.IsNumericTokenSequence(trimmed))
            {
                return true;
            }

            for (int i = 0; i < trimmed.Length; i++)
            {
                if (!char.IsDigit(trimmed[i]))
                {
                    return false;
                }
            }

            return trimmed.Length > 0;
        }

        private bool IsNumericTokenSequence(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return false;
            }

            string[] tokens = value.Split(new[] { ' ', '\t', ',', ';', '|', '/' }, StringSplitOptions.RemoveEmptyEntries);
            if (tokens.Length < 2)
            {
                return false;
            }

            for (int i = 0; i < tokens.Length; i++)
            {
                if (!int.TryParse(tokens[i], out _))
                {
                    return false;
                }
            }

            return true;
        }

        private void CacheScannedBagFoodDisplayName(string spriteName)
        {
            string normalizedSprite = this.NormalizeAutoSellMatchKey(spriteName);
            if (string.IsNullOrWhiteSpace(normalizedSprite) || this.scannedBagFoodDisplayNames.ContainsKey(normalizedSprite))
            {
                return;
            }

            string resolvedName = this.TryResolveScannedBagFoodDisplayName(spriteName, normalizedSprite, out string displayName)
                ? displayName
                : this.GetFoodDisplayName(spriteName);

            if (!string.IsNullOrWhiteSpace(resolvedName))
            {
                this.scannedBagFoodDisplayNames[normalizedSprite] = resolvedName;
            }
        }

        private bool TryResolveScannedBagFoodDisplayName(string spriteName, string normalizedSprite, out string displayName)
        {
            displayName = string.Empty;

            if (this.autoSellBagItems != null)
            {
                for (int i = 0; i < this.autoSellBagItems.Count; i++)
                {
                    AutoSellBagItemEntry entry = this.autoSellBagItems[i];
                    if (entry == null)
                    {
                        continue;
                    }

                    if (!this.DoesBagItemEntryMatchSprite(entry, normalizedSprite))
                    {
                        continue;
                    }

                    if (this.TryGetResolvedFoodNameFromStaticId(entry.StaticId, out displayName))
                    {
                        return true;
                    }

                    string entryName = this.CleanResolvedBagFoodName(entry.DisplayName);
                    if (!string.IsNullOrWhiteSpace(entryName))
                    {
                        displayName = entryName;
                        return true;
                    }
                }
            }

            if (this.TryRefreshDirectBackpackRuntimeSnapshot(false))
            {
                for (int i = 0; i < this.directBackpackRuntimeItems.Count; i++)
                {
                    DirectBackpackRuntimeItem item = this.directBackpackRuntimeItems[i];
                    if (item == null || !this.DoesRuntimeBackpackItemMatchSprite(item, normalizedSprite))
                    {
                        continue;
                    }

                    if (this.TryGetResolvedFoodNameFromStaticId(item.StaticId, out displayName))
                    {
                        return true;
                    }

                    string descriptorName = this.CleanResolvedBagFoodName(item.Descriptor);
                    if (!string.IsNullOrWhiteSpace(descriptorName))
                    {
                        displayName = descriptorName;
                        return true;
                    }
                }
            }

            return false;
        }

        private bool DoesBagItemEntryMatchSprite(AutoSellBagItemEntry entry, string normalizedSprite)
        {
            if (entry == null || string.IsNullOrWhiteSpace(normalizedSprite))
            {
                return false;
            }

            string[] keys =
            {
                this.NormalizeAutoSellMatchKey(entry.SpriteName),
                this.NormalizeAutoSellMatchKey(entry.MatchKey),
                this.NormalizeAutoSellMatchKey(this.GetAutoSellSpriteNameFromMatchKey(entry.MatchKey))
            };

            for (int i = 0; i < keys.Length; i++)
            {
                if (!string.IsNullOrWhiteSpace(keys[i]) && string.Equals(keys[i], normalizedSprite, StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }
            }

            return false;
        }

        private bool DoesRuntimeBackpackItemMatchSprite(DirectBackpackRuntimeItem item, string normalizedSprite)
        {
            if (item == null || string.IsNullOrWhiteSpace(normalizedSprite))
            {
                return false;
            }

            string matchKey = this.ExtractAutoSellMatchKeyFromDescriptor(item.Descriptor);
            if (string.IsNullOrWhiteSpace(matchKey))
            {
                matchKey = item.StaticId > 0 ? item.StaticId.ToString() : string.Empty;
            }

            string[] keys =
            {
                this.NormalizeAutoSellMatchKey(matchKey),
                this.NormalizeAutoSellMatchKey(this.GetAutoSellSpriteNameFromMatchKey(matchKey))
            };

            for (int i = 0; i < keys.Length; i++)
            {
                if (!string.IsNullOrWhiteSpace(keys[i]) && string.Equals(keys[i], normalizedSprite, StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }
            }

            return false;
        }

        private bool TryGetResolvedFoodNameFromStaticId(int staticId, out string displayName)
        {
            displayName = string.Empty;
            if (staticId <= 0)
            {
                return false;
            }

            try
            {
                Type tableDataType = this.FindLoadedType("TableData", "EcsClient.TableData");
                if (tableDataType != null)
                {
                    MethodInfo getBackpackNameMethod = tableDataType.GetMethod("GetBackPackName", BindingFlags.Static | BindingFlags.Public | BindingFlags.NonPublic, null, new[] { typeof(int), typeof(int), typeof(uint) }, null);
                    if (getBackpackNameMethod != null)
                    {
                        object rawName = getBackpackNameMethod.Invoke(null, new object[] { staticId, 0, 0U });
                        string cleanedName = this.CleanResolvedBagFoodName(rawName?.ToString());
                        if (!string.IsNullOrWhiteSpace(cleanedName))
                        {
                            displayName = cleanedName;
                            return true;
                        }
                    }

                    MethodInfo getEntityMethod = tableDataType.GetMethod("GetEntity", BindingFlags.Static | BindingFlags.Public | BindingFlags.NonPublic, null, new[] { typeof(int), typeof(bool) }, null);
                    if (getEntityMethod != null)
                    {
                        object entityObj = getEntityMethod.Invoke(null, new object[] { staticId, false });
                        if (entityObj != null && this.TryGetResolvedFoodNameFromEntityObject(entityObj, out displayName))
                        {
                            return true;
                        }
                    }
                }
            }
            catch
            {
            }

            return this.TryGetResolvedFoodNameFromStaticIdAuraMono(staticId, out displayName);
        }

        private unsafe bool TryGetResolvedFoodNameFromStaticIdAuraMono(int staticId, out string displayName)
        {
            displayName = string.Empty;
            if (staticId <= 0 || !this.EnsureAuraMonoApiReady() || auraMonoClassFromName == null || auraMonoRuntimeInvoke == null)
            {
                return false;
            }

            try
            {
                IntPtr ecsImage = this.FindAuraMonoImage(new[] { "EcsClient", "EcsClient.dll" });
                if (ecsImage == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr tableDataClass = auraMonoClassFromName(ecsImage, string.Empty, "TableData");
                if (tableDataClass == IntPtr.Zero)
                {
                    tableDataClass = auraMonoClassFromName(ecsImage, "EcsClient", "TableData");
                }

                if (tableDataClass == IntPtr.Zero)
                {
                    return false;
                }

                IntPtr getBackpackNameMethod = this.FindAuraMonoMethodOnHierarchy(tableDataClass, "GetBackPackName", 3);
                if (getBackpackNameMethod != IntPtr.Zero)
                {
                    int starRate = 0;
                    uint netId = 0U;
                    IntPtr exc = IntPtr.Zero;
                    IntPtr* args = stackalloc IntPtr[3];
                    args[0] = (IntPtr)(&staticId);
                    args[1] = (IntPtr)(&starRate);
                    args[2] = (IntPtr)(&netId);
                    IntPtr nameObj = auraMonoRuntimeInvoke(getBackpackNameMethod, IntPtr.Zero, (IntPtr)args, ref exc);
                    if (exc == IntPtr.Zero && nameObj != IntPtr.Zero && this.TryReadMonoString(nameObj, out string rawName))
                    {
                        displayName = this.CleanResolvedBagFoodName(rawName);
                        if (!string.IsNullOrWhiteSpace(displayName))
                        {
                            return true;
                        }
                    }
                }

                if (this.TryResolveNetCookRecipeNameFromTableDataMono(tableDataClass, staticId, out displayName))
                {
                    displayName = this.CleanResolvedBagFoodName(displayName);
                    if (!string.IsNullOrWhiteSpace(displayName))
                    {
                        return true;
                    }
                }

                return false;
            }
            catch
            {
                displayName = string.Empty;
                return false;
            }
        }

        private bool TryGetResolvedFoodNameFromEntityObject(object entityObj, out string displayName)
        {
            displayName = string.Empty;
            if (entityObj == null)
            {
                return false;
            }

            foreach (string memberName in new[] { "name", "_name", "Name", "displayName", "_displayName", "DisplayName" })
            {
                if (this.TryGetObjectMember(entityObj, memberName, out object rawName) && rawName != null)
                {
                    string cleanedName = this.CleanResolvedBagFoodName(rawName.ToString());
                    if (!string.IsNullOrWhiteSpace(cleanedName))
                    {
                        displayName = cleanedName;
                        return true;
                    }
                }
            }

            return false;
        }

        private string CleanResolvedBagFoodName(string value)
        {
            string name = (value ?? string.Empty).Trim();
            if (string.IsNullOrWhiteSpace(name))
            {
                return string.Empty;
            }

            name = name.Replace("\r", " ").Replace("\n", " ").Replace("\t", " ").Trim();
            if (int.TryParse(name, out _) || this.IsNumericTokenSequence(name))
            {
                return string.Empty;
            }

            string lowered = name.ToLowerInvariant();
            if (lowered.StartsWith("ui_item_normal_") || lowered.StartsWith("ui_item_special_") || lowered.StartsWith("p_"))
            {
                return string.Empty;
            }

            if (lowered.Contains("templateid") || lowered.Contains("icon"))
            {
                return string.Empty;
            }

            return name;
        }

        private Texture2D CopySpriteTexture(Sprite sprite, string logPrefix)
        {
            try
            {
                if (sprite == null || sprite.texture == null)
                {
                    return null;
                }

                Texture2D original = sprite.texture;
                RenderTexture rt = RenderTexture.GetTemporary(original.width, original.height, 0, RenderTextureFormat.ARGB32);
                Graphics.Blit(original, rt);

                Texture2D copy = new Texture2D(original.width, original.height, TextureFormat.RGBA32, false);
                RenderTexture previousRT = RenderTexture.active;
                RenderTexture.active = rt;
                copy.ReadPixels(new Rect(0, 0, original.width, original.height), 0, 0);
                copy.Apply();
                RenderTexture.active = previousRT;
                RenderTexture.ReleaseTemporary(rt);
                return copy;
            }
            catch (Exception ex)
            {
                ModLogger.Msg((logPrefix ?? "[BagScan]") + " Failed to copy texture: " + ex.Message);
                return null;
            }
        }

        private string GetItemIconCacheDirectory()
        {
            return HelperPaths.GetDirectory("Cache", ITEM_ICON_CACHE_FOLDER);
        }

        private string GetItemIconCachePath(string key)
        {
            string safeName = this.SanitizeCacheFileName(this.NormalizeAutoSellMatchKey(key));
            if (string.IsNullOrWhiteSpace(safeName))
            {
                safeName = this.SanitizeCacheFileName(key);
            }
            if (string.IsNullOrWhiteSpace(safeName))
            {
                safeName = "unknown";
            }

            return Path.Combine(this.GetItemIconCacheDirectory(), safeName + ".png");
        }

        private string SanitizeCacheFileName(string value)
        {
            string safe = (value ?? string.Empty).Trim().ToLowerInvariant();
            foreach (char c in Path.GetInvalidFileNameChars())
            {
                safe = safe.Replace(c, '_');
            }
            safe = safe.Replace(' ', '_');
            while (safe.Contains("__"))
            {
                safe = safe.Replace("__", "_");
            }
            return safe.Trim('_');
        }

        private bool TryLoadCachedItemIcon(string key, out Texture2D texture)
        {
            texture = null;
            try
            {
                string path = this.GetItemIconCachePath(key);
                if (!File.Exists(path))
                {
                    if (this.TryLoadEmbeddedItemIcon(key, out texture) && texture != null)
                    {
                        this.SaveCachedItemIcon(key, texture);
                        return true;
                    }

                    return false;
                }

                byte[] bytes = File.ReadAllBytes(path);
                if (bytes == null || bytes.Length == 0)
                {
                    return false;
                }

                Texture2D loaded = new Texture2D(2, 2, TextureFormat.RGBA32, false);
                if (!loaded.LoadImage(bytes))
                {
                    Object.Destroy(loaded);
                    return false;
                }

                texture = loaded;
                return true;
            }
            catch
            {
                return false;
            }
        }

        private bool TryLoadEmbeddedItemIcon(string key, out Texture2D texture)
        {
            texture = null;
            string normalizedKey = this.NormalizeAutoSellMatchKey(key);
            string embeddedFileName;
            switch (normalizedKey)
            {
                case "tree":
                    embeddedFileName = "tree.png";
                    break;
                case "rare_tree":
                    embeddedFileName = "rare_tree.png";
                    break;
                default:
                    return false;
            }

            try
            {
                Assembly assembly = typeof(HeartopiaComplete).Assembly;
                string[] resourceNames = assembly.GetManifestResourceNames();
                if (resourceNames == null || resourceNames.Length == 0)
                {
                    return false;
                }

                string resourceName = resourceNames.FirstOrDefault(name =>
                    !string.IsNullOrWhiteSpace(name) &&
                    name.EndsWith(".Assets." + embeddedFileName, StringComparison.OrdinalIgnoreCase));
                if (string.IsNullOrWhiteSpace(resourceName))
                {
                    resourceName = resourceNames.FirstOrDefault(name =>
                        !string.IsNullOrWhiteSpace(name) &&
                        name.EndsWith("." + embeddedFileName, StringComparison.OrdinalIgnoreCase));
                }
                if (string.IsNullOrWhiteSpace(resourceName))
                {
                    return false;
                }

                using (Stream stream = assembly.GetManifestResourceStream(resourceName))
                {
                    if (stream == null)
                    {
                        return false;
                    }

                    byte[] bytes = new byte[stream.Length];
                    int read = stream.Read(bytes, 0, bytes.Length);
                    if (read <= 0)
                    {
                        return false;
                    }

                    Texture2D loaded = new Texture2D(2, 2, TextureFormat.RGBA32, false);
                    if (!loaded.LoadImage(bytes))
                    {
                        Object.Destroy(loaded);
                        return false;
                    }

                    texture = loaded;
                    return true;
                }
            }
            catch
            {
                return false;
            }
        }

        private void SaveCachedItemIcon(string key, Texture2D texture)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(key) || texture == null)
                {
                    return;
                }

                string path = this.GetItemIconCachePath(key);
                if (File.Exists(path))
                {
                    return;
                }

                byte[] png = texture.EncodeToPNG();
                if (png == null || png.Length == 0)
                {
                    return;
                }

                File.WriteAllBytes(path, png);
            }
            catch (Exception ex)
            {
                ModLogger.Msg("[IconCache] Failed to save item icon: " + ex.Message);
            }
        }

        // Get display name from sprite name
        private string GetFoodDisplayName(string spriteName)
        {
            if (string.IsNullOrEmpty(spriteName))
                return "Unknown Food";

            string normalizedSprite = this.NormalizeAutoSellMatchKey(spriteName);
            if (!string.IsNullOrWhiteSpace(normalizedSprite)
                && this.scannedBagFoodDisplayNames.TryGetValue(normalizedSprite, out string cachedName)
                && !string.IsNullOrWhiteSpace(cachedName))
            {
                return cachedName;
            }

            // Extract item name from sprite name
            string itemName = spriteName
                .Replace("ui_item_normal_p_", "")
                .Replace("gather_", "")
                .Replace("fruit_", "")
                .Replace("_", " ");

            // Capitalize first letter of each word
            var words = itemName.Split(' ');
            for (int i = 0; i < words.Length; i++)
            {
                if (words[i].Length > 0)
                    words[i] = char.ToUpper(words[i][0]) + words[i].Substring(1);
            }
            return string.Join(" ", words);
        }

        private string GetCurrentFoodKey()
        {
            // Custom food is the last option - use the saved custom food name
            if (this.autoEatFoodType == this.autoEatFoodOptions.Length - 1)
            {
                return this.autoEatCustomFoodName?.ToLowerInvariant() ?? "";
            }
            return this.autoEatFoodKeys[this.autoEatFoodType];
        }

        private string GetCurrentRepairKey()
        {
            return this.autoRepairKeys[this.autoRepairType];
        }

        bool SimulateLegacyClick(GameObject target)
        {
            if (target == null)
            {
                return false;
            }

            try
            {
                var eventTrigger = target.GetComponent<EventTrigger>();
                if (eventTrigger != null && eventTrigger.triggers.Count > 0)
                {
                    PointerEventData eventData = new PointerEventData(EventSystem.current);
                    foreach (var trigger in eventTrigger.triggers)
                    {
                        if (trigger.eventID == EventTriggerType.PointerClick ||
                            trigger.eventID == EventTriggerType.PointerDown)
                        {
                            trigger.callback.Invoke(eventData);
                            return true;
                        }
                    }
                }

                return ExecuteEvents.Execute(target, new PointerEventData(EventSystem.current), ExecuteEvents.pointerClickHandler) ||
                       ExecuteEvents.Execute(target, new PointerEventData(EventSystem.current), ExecuteEvents.pointerDownHandler);
            }
            catch
            {
                return false;
            }
        }

        bool SimulateClick(GameObject target)
        {
            EventSystem eventSystem = this.EnsureGameplayEventSystemAvailable();
            PointerEventData eventData = new PointerEventData(eventSystem);
            var eventTrigger = target.GetComponent<EventTrigger>();
            if (eventTrigger != null && eventTrigger.triggers.Count > 0)
            {
                foreach (var trigger in eventTrigger.triggers)
                {
                    if (trigger.eventID == EventTriggerType.PointerClick ||
                        trigger.eventID == EventTriggerType.PointerDown ||
                        trigger.eventID == EventTriggerType.PointerUp ||
                        trigger.eventID == EventTriggerType.Submit)
                    {
                        trigger.callback.Invoke(eventData);
                        return true;
                    }
                }
            }
            bool handled =
                ExecuteEvents.Execute(target, eventData, ExecuteEvents.submitHandler) ||
                ExecuteEvents.Execute(target, eventData, ExecuteEvents.pointerClickHandler) ||
                ExecuteEvents.Execute(target, eventData, ExecuteEvents.pointerDownHandler) ||
                ExecuteEvents.Execute(target, eventData, ExecuteEvents.pointerUpHandler);

            if (handled)
            {
                return true;
            }

            try
            {
                foreach (Component component in target.GetComponents<Component>())
                {
                    if (component == null) continue;
                    Type type = component.GetType();
                    MethodInfo method =
                        type.GetMethod("OnClick", BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic) ??
                        type.GetMethod("Click", BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic) ??
                        type.GetMethod("OnPointerClick", BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
                    if (method == null) continue;
                    ParameterInfo[] parameters = method.GetParameters();
                    if (parameters.Length == 0)
                    {
                        method.Invoke(component, null);
                        return true;
                    }
                    if (parameters.Length == 1)
                    {
                        method.Invoke(component, new object[] { eventData });
                        return true;
                    }
                }
            }
            catch { }
            return false;
        }

        bool OpenInventory()
        {
            Button btn = GameObject.Find(BAG_BUTTON_PATH)?.GetComponent<Button>();
            if ((btn == null || !btn.interactable) && !this.TryFindFallbackBagButton(out btn))
            {
                return false;
            }

            if (btn != null && btn.interactable)
            {
                btn.onClick.Invoke();
                return true;
            }
            return false;
        }

        private bool TryFindFallbackBagButton(out Button button)
        {
            button = null;

            try
            {
                GameObject statusPanel = GameObject.Find(STATUS_PANEL_PATH) ?? GameObject.Find("StatusPanel(Clone)");
                if (statusPanel != null)
                {
                    Button[] statusButtons = statusPanel.GetComponentsInChildren<Button>(true);
                    for (int i = 0; i < statusButtons.Length; i++)
                    {
                        Button candidate = statusButtons[i];
                        if (candidate == null || candidate.gameObject == null || !candidate.interactable)
                        {
                            continue;
                        }

                        string lower = (candidate.gameObject.name ?? string.Empty).ToLowerInvariant();
                        if (!lower.Contains("bag"))
                        {
                            continue;
                        }

                        button = candidate;
                        return true;
                    }
                }

                Button[] allButtons = Resources.FindObjectsOfTypeAll<Button>();
                for (int i = 0; i < allButtons.Length; i++)
                {
                    Button candidate = allButtons[i];
                    if (candidate == null || candidate.gameObject == null || !candidate.gameObject.activeInHierarchy || !candidate.interactable)
                    {
                        continue;
                    }

                    string path = this.GetTransformPath(candidate.transform).ToLowerInvariant();
                    if (path.Contains("statuspanel") && path.Contains("bag@"))
                    {
                        button = candidate;
                        return true;
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        bool ClickUseButton()
        {
            var btn = GameObject.Find(USE_BUTTON_PATH)?.GetComponent<Button>();
            if (btn != null && btn.interactable)
            {
                var txt = btn.GetComponentInChildren<Text>();
                if (txt == null)
                {
                    btn.onClick.Invoke();
                    return true;
                }
                string actionText = txt.text == null ? string.Empty : txt.text.Trim();

                foreach (string candidate in LocalizationManager.GetTranslationCandidates("Use"))
                {
                    if (actionText.Equals(candidate, StringComparison.OrdinalIgnoreCase))
                    {
                        btn.onClick.Invoke();
                        return true;
                    }
                }

                foreach (string candidate in LocalizationManager.GetTranslationCandidates("Eat"))
                {
                    if (actionText.Equals(candidate, StringComparison.OrdinalIgnoreCase))
                    {
                        btn.onClick.Invoke();
                        return true;
                    }
                }
            }
            return false;
        }

        void CloseInventory()
        {
            var btn = GameObject.Find(CLOSE_BUTTON_PATH)?.GetComponent<Button>();
            btn?.onClick?.Invoke();
        }

        private void StopAllAutoFishing()
        {
            AutoFishingFarm.ForceStop(this);
            this.showFishShadowRadar = false;
        }

