            num += 25;

            if (GUI.Button(new Rect(20f, (float)num, 120f, 35f), "SAVE"))
            {
                SavePatrolPoints();
            }
            if (GUI.Button(new Rect(160f, (float)num, 120f, 35f), "LOAD"))
            {
                LoadPatrolPoints();
            }
            num += 45;

            if (GUI.Button(new Rect(20f, (float)num, 260f, 40f), "ADD CURRENT POSITION"))
