        private bool IsDurabilityToastMessage(string message)
        {
            if (string.IsNullOrEmpty(message))
            {
                return false;
            }

            string s = message.Trim();
            return this.ToastContainsLocalizedPhrase(s, "Tool durability depleted") ||
                   this.ToastContainsLocalizedPhrase(s, "Scanner Durability low");
        }

        private bool IsBirdFarmMaxPhotoToastMessage(string message)
        {
            if (string.IsNullOrEmpty(message))
            {
                return false;
            }

            string lower = message.Trim().ToLowerInvariant();
            return lower.Contains("maxphoto")
                || (lower.Contains("photo") && lower.Contains("limit"))
                || (lower.Contains("info") && lower.Contains("limit"))
                || (lower.Contains("card") && lower.Contains("limit"))
                || (lower.Contains("max") && lower.Contains("photo"));
        }

        private bool CheckForDurabilityNotification()
        {
            try
            {
                // Scan all toast children like HeartopiaBuddy4 does (more reliable than single path)
                GameObject toastPanel = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Tip/TipPanel(Clone)/ToastPanel(Clone)/toasts@t");
                if (toastPanel != null)
                {
                    int childCount = toastPanel.transform.childCount;
                    for (int i = 0; i < childCount; i++)
                    {
                        Transform child = toastPanel.transform.GetChild(i);
                        if (child != null && child.gameObject.activeInHierarchy)
                        {
                            Transform textTransform = child.Find("AniRoot@ani/root_visible@go/root_visible/value@txt");
                            if (textTransform != null && textTransform.gameObject.activeInHierarchy)
                            {
                                var text = textTransform.GetComponent<Text>();
                                if (text != null && this.IsDurabilityToastMessage(text.text))
                                {
                                    return true;
                                }
                            }
                        }
                    }
                }
            }
            catch
            {
            }
            return false;
        }

        // Called by Harmony postfix when UIManager.ShowToast is invoked in-game.
        public void OnToastDetected(string msg)
        {
            this.OnToastDetected(msg, 0);
        }

        private void OnToastDetected(string msg, int toastObjectId)
        {
            try
            {
                if (string.IsNullOrEmpty(msg)) return;
                string s = msg.Trim();
                float now = Time.unscaledTime;

                // Avoid duplicate handling when both the UI hook and panel scanner see the same toast,
                // but still allow a new toast instance with identical text later.
                bool sameToastObject = toastObjectId != 0
                    && toastObjectId == this.lastDetectedToastObjectId
                    && string.Equals(s, this.lastDetectedToast, StringComparison.Ordinal);
                bool sameHookToastBurst = toastObjectId == 0
                    && string.Equals(s, this.lastDetectedToast, StringComparison.Ordinal)
                    && now - this.lastDetectedToastAt < 0.75f;
                if (sameToastObject || sameHookToastBurst) return;

                this.lastDetectedToast = s;
                this.lastDetectedToastObjectId = toastObjectId;
                this.lastDetectedToastAt = now;

                if (BirdNetFarm.IsAutoScareMaxPhotoEnabled && this.IsBirdFarmMaxPhotoToastMessage(s))
                {
                    this.BirdFarmNetLog("[MaxPhotoFallback] Limit toast observed: " + s);
                    this.TryHandleBirdFarmMaxPhotoAutoScare("toast fallback");
                    return;
                }

                // Durability notifications
                if (this.autoRepairOnToastEnabled && this.IsDurabilityToastMessage(s))
                {
                    this.AutoEatRepairLog("[AutoRepair] Durability toast observed; using toast fallback trigger.");
                    this.TryHandleDurabilityAutoRepairTrigger("toast fallback");
                    return;
                }

            }
            catch (Exception ex)
            {
                ModLogger.Msg("[OnToastDetected] Error: " + ex.Message);
            }
        }

        private void CheckToastPanel()
        {
            if (!this.autoRepairOnToastEnabled && !BirdNetFarm.IsAutoScareMaxPhotoEnabled)
            {
                return;
            }

            float now = Time.unscaledTime;
            if (now - this.lastToastCheckAt < TOAST_CHECK_INTERVAL) return;
            this.lastToastCheckAt = now;
            try
            {
                GameObject toastsRoot = this.cachedToastRootObj;
                if (toastsRoot == null || !toastsRoot.activeInHierarchy)
                {
                    this.cachedToastRootObj = null;
                    this.cachedToastTextObj = null;
                    if (now < this.nextToastRootPathScanAt)
                    {
                        return;
                    }

                    this.nextToastRootPathScanAt = now + 2f;
                    toastsRoot = GameObject.Find("GameApp/startup_root(Clone)/XDUIRoot/Tip/TipPanel(Clone)/ToastPanel(Clone)/toasts@t");
                    if (toastsRoot == null)
                    {
                        return;
                    }

                    this.cachedToastRootObj = toastsRoot;
                }

                int childCount = toastsRoot.transform.childCount;
                for (int i = 0; i < childCount; i++)
                {
                    Transform child = toastsRoot.transform.GetChild(i);
                    if (child == null || !child.gameObject.activeInHierarchy) continue;
                    Transform txtTransform = child.Find("AniRoot@ani/root_visible@go/root_visible/value@txt");
                    if (txtTransform == null) continue;
                    GameObject txtObj = txtTransform.gameObject;
                    if (txtObj == null || !txtObj.activeInHierarchy) continue;

                    string text = null;
                    var uiText = txtObj.GetComponent<UnityEngine.UI.Text>();
                    if (uiText != null) text = uiText.text;
                    else
                    {
                        foreach (Component comp in txtObj.GetComponents<Component>())
                        {
                            if (comp == null) continue;
                            try
                            {
                                var ilType = comp.GetIl2CppType();
                                if (ilType != null && ilType.Name == "XDText")
                                {
                                    var prop = ilType.GetProperty("text");
                                    if (prop != null)
                                    {
                                        var val = prop.GetValue(comp);
                                        text = (val != null) ? val.ToString() : null;
                                        break;
                                    }
                                }
                            }
                            catch { }
                        }
                    }

                    if (!string.IsNullOrEmpty(text))
                    {
                        string s = text.Trim();
                        int toastObjectId = child.gameObject.GetInstanceID();
                        if (s != this.lastDetectedToast || toastObjectId != this.lastDetectedToastObjectId)
                        {
                            this.OnToastDetected(s, toastObjectId);
                            return;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                ModLogger.Msg("[CheckToastPanel] error: " + ex.Message);
            }
        }

        private float GetCurrentEnergy()
        {
            try
            {
                string energyStr = this.TryGetCurrentEnergyText();
                if (!string.IsNullOrEmpty(energyStr) && energyStr.Contains("/"))
                {
                    string[] parts = energyStr.Split('/');
                    if (parts.Length >= 2)
                    {
                        string currentDigits = new string(parts[0].Where(c => char.IsDigit(c) || c == '.' || c == '-').ToArray());
                        string maxDigits = new string(parts[1].Where(c => char.IsDigit(c) || c == '.' || c == '-').ToArray());
                        if (float.TryParse(currentDigits, out float current) && float.TryParse(maxDigits, out float max) && max > 0f)
                        {
                            float ratio = current / max;
                            this.lastKnownEnergyRatio = ratio;
                            this.lastKnownEnergyDisplay = energyStr.Trim();
                            return ratio;
                        }
                    }
                }
            }
            catch
            {
            }
            return this.lastKnownEnergyRatio;
        }

        private string GetCurrentEnergyDisplay()
        {
            try
            {
                string energyText = this.TryGetCurrentEnergyText();
                if (!string.IsNullOrEmpty(energyText))
                {
                    this.lastKnownEnergyDisplay = energyText.Trim();
                    return this.lastKnownEnergyDisplay;
                }
            }
            catch
            {
            }

            return this.lastKnownEnergyDisplay;
        }

        private string GetRepairStatusDisplay()
        {
            if (this.IsAutoRepairInProgress())
            {
                return this.L("In Progress");
            }

            if (this.pendingAutoRepairRequest)
            {
                return this.L("Queued");
            }

            return this.L("Ready");
        }

        private string GetAutoEatStatusDisplay()
        {
            if (this.isAutoEating)
            {
                return this.L("In Progress");
            }

            if (this.pendingAutoEatRequest)
            {
                return this.L("Queued");
            }

            return this.L("Ready");
        }

        private void RefreshFoodRepairUiStatusSnapshot(bool force = false)
        {
            float now = Time.unscaledTime;
            if (!force && now < this.nextFoodRepairUiStatusRefreshAt)
            {
                return;
            }

            this.nextFoodRepairUiStatusRefreshAt = now + 1f;
            try
            {
                string energyDisplay = this.GetCurrentEnergyDisplay();
                if (!string.IsNullOrWhiteSpace(energyDisplay))
                {
                    this.cachedFoodRepairEnergyStatusDisplay = energyDisplay;
                }
            }
            catch
            {
            }

            this.cachedToolDurabilityStatusDisplay = this.FormatCachedToolDurabilityStatusDisplay();
        }

        private string GetCurrentToolDurabilityStatusDisplay()
        {
            return this.FormatCachedToolDurabilityStatusDisplay();
        }

        private string FormatCachedToolDurabilityStatusDisplay()
        {
            try
            {
                if (this.lastObservedToolId > 0 && this.lastObservedToolMaxDurability > 0)
                {
                    string toolName = this.GetAutoRepairSupportedToolName(this.lastObservedToolId);
                    if (string.IsNullOrEmpty(toolName))
                    {
                        toolName = "Tool " + this.lastObservedToolId;
                    }

                    float ratio = (float)this.lastObservedToolDurability / (float)this.lastObservedToolMaxDurability;
                    return string.Format(
                        System.Globalization.CultureInfo.InvariantCulture,
                        "{0} {1}/{2} ({3:P1})",
                        toolName,
                        this.lastObservedToolDurability,
                        this.lastObservedToolMaxDurability,
                        ratio);
                }
            }
            catch
            {
            }

            return this.L("Unavailable");
        }

